INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '22d80739-46fb-4e16-87fc-a4165dffd718',
  'Moqueta Ferial Ecológica',
  'moqueta-ferial-ecologica',
  'Disstands es distribuidor oficial de la Moqueta Ecológica, la única de su clase a nivel mundial. Diseñada específicamente para el sector de eventos, ofrece una solución sostenible, funcional y visualmente atractiva, fabricada con monomaterial 100% reciclable, completamente libre de látex y de fác...',
  'Disstands es distribuidor oficial de la Moqueta Ecológica, la única de su clase a nivel mundial. Diseñada específicamente para el sector de eventos, ofrece una solución sostenible, funcional y visualmente atractiva, fabricada con monomaterial 100% reciclable, completamente libre de látex y de fácil reciclaje post-uso. Innovación sostenible sin precedentes Su composición exclusiva sin látex y el proceso de fabricación basado en tecnología de última generación marcan un hito en la industria. La producción se realiza sin uso de agua y con una reducción superior al 80% en el consumo energético (electricidad y gas), lo que se traduce en una disminución drástica de emisiones de CO₂. Estas características la convierten en la opción más responsable para empresas comprometidas con la sostenibilidad. Versatilidad y diseño profesional Disponible en 30 colores elegantes de aspecto plano, esta moqueta ecológica se adapta a cualquier identidad corporativa o diseño de stand. Su formato en rollo de 2 metros de ancho está pensado para facilitar instalaciones rápidas y limpias en ferias, congresos y todo tipo de eventos efímeros, optimizando tiempos de montaje y desmontaje. Especificaciones y aplicaciones Ideal para: Stands feriales con certificación ecológica Eventos corporativos sostenibles Congresos y convenciones eco-friendly Instalaciones temporales con compromiso ambiental Proyectos que requieren materiales reciclables Su estructura monomaterial facilita el reciclaje completo al finalizar su uso, cerrando el ciclo de economía circular. La ausencia de látex la hace hipoalergénica y segura para todos los usuarios. Información de compra Precio indicado por metro cuadrado. Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 2,65 €/m² = 5,30 € Nota importante: Los cortes no admiten devoluciones. Para medidas personalizadas o consultas específicas, contacta con nosotros en: ventas@disstands.com Elige la Moqueta Ecológica y demuestra el compromiso ambiental de tu empresa sin renunciar a la calidad y elegancia que tus eventos merecen.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  2.65,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b3dfa787-2e64-43ab-8647-f3f3e8279e3e',
  'Moqueta Ferial Colores Especiales',
  'moqueta-ferial-colores-especiales',
  'La moqueta ferial colores especiales destaca por su espesor de 3,5 mm y su exclusiva gama de tonos pastel únicos. Este revestimiento textil ofrece una estética diferenciada difícil de encontrar en otros fabricantes. Por lo tanto, es la elección perfecta para profesionales que buscan diferenciarse...',
  'La moqueta ferial colores especiales destaca por su espesor de 3,5 mm y su exclusiva gama de tonos pastel únicos. Este revestimiento textil ofrece una estética diferenciada difícil de encontrar en otros fabricantes. Por lo tanto, es la elección perfecta para profesionales que buscan diferenciarse en eventos y ferias mediante colores exclusivos. Diseñada específicamente para proporcionar un acabado elegante y distintivo, combina calidad superior dentro del segmento ferial con un precio altamente competitivo. Asimismo, garantiza resultados profesionales sin comprometer el presupuesto del proyecto. Características Técnicas del Revestimiento Ferial En primer lugar, esta moqueta ferial colores especiales incorpora una película protectora especial que mejora significativamente su resistencia al desgaste. Además, esta protección permite su instalación sobre múltiples superficies con total garantía de durabilidad. Compatibilidad universal: Es compatible con suelos duros, tarimas, asfalto, hormigón e incluso arena. De este modo, se adapta a cualquier entorno ferial o evento sin limitaciones. Como resultado, ofrece máxima versatilidad para instaladores y organizadores. Grosor óptimo de 3,5 mm: Proporciona el equilibrio perfecto entre confort de pisada y facilidad de transporte. Por consiguiente, resulta ideal para montajes temporales que requieren eficiencia logística. Aplicaciones Versátiles para Eventos Profesionales Este pavimento textil se convierte en la solución ideal para múltiples aplicaciones: Ferias comerciales y stands profesionales: Crea espacios distintivos que captan la atención de visitantes. Especialmente efectiva para destacar entre la competencia. Congresos y convenciones internacionales: Aporta elegancia y sofisticación a eventos corporativos de alto nivel. Exposiciones temporales y showrooms: Los tonos pastel exclusivos realzan productos y crean ambientes memorables. Eventos corporativos y presentaciones: Proporciona acabados premium que reflejan la calidad de tu marca. Fiestas y celebraciones especiales: Transforma espacios ordinarios en entornos únicos y fotografiables. Aplicaciones creativas en paredes o techos: Su ligereza permite usos innovadores más allá del suelo tradicional. Instalación Rápida y Eficiente Por otro lado, la instalación es extraordinariamente rápida y sencilla mediante cinta adhesiva de doble cara. En consecuencia, resulta perfecta para montajes temporales que requieren máxima eficiencia temporal. Igualmente, el desmontaje es ágil y limpio, sin dejar residuos molestos en las superficies. De este modo, protege los espacios alquilados y facilita la logística posterior al evento. Seguridad Certificada: Normativa Bfl-s1 Esta moqueta ferial colores especiales cumple rigurosamente con la normativa europea de seguridad contra incendios Bfl-s1. Por lo tanto, garantiza tranquilidad absoluta en espacios públicos y eventos con alta afluencia de personas. Asimismo, facilita la obtención de permisos y licencias necesarias. Paleta Exclusiva en Tonos Pastel El revestimiento ofrece una paleta cromática única y diferenciadora: Beige jaspe: Elegancia neutra con sutiles variaciones que aportan profundidad visual. Salmón: Calidez moderna perfecta para espacios acogedores y fotografiables. Azafrán: Energía positiva que transmite vitalidad sin resultar agresivo. Rosa palo: Suavidad sofisticada ideal para eventos relacionados con belleza y bienestar. Verde menta: Frescura contemporánea que conecta con tendencias actuales de diseño. Turquesa jaspe: Distinción premium con personalidad propia que no pasa desapercibida. Estos tonos pastel exclusivos permiten crear ambientes únicos y memorables. Además, se adaptan perfectamente a las tendencias actuales de diseño de eventos. Como resultado, tus espacios destacan por su estética diferenciada. Stock Permanente y Disponibilidad Inmediata Contamos con stock permanente en nuestro almacén. Por consiguiente, garantizamos disponibilidad inmediata para proyectos urgentes sin tiempos de espera. Asimismo, ofrecemos corte personalizado según las necesidades específicas de cada proyecto. Esta disponibilidad constante elimina riesgos de desabastecimiento en fechas críticas. De este modo, puedes planificar tus eventos con total seguridad logística. Especificaciones Técnicas Grosor: 3,5 mm profesional Acabado: Tonos pastel exclusivos Protección: Película especial resistente al desgaste Instalación: Cinta adhesiva de doble cara Certificación: Bfl-s1 europea contra incendios Ancho de rollo: 2 metros estándar Disponibilidad: Stock permanente Aplicaciones: Múltiples superficies Información de Compra y Medidas Precio indicado por metro cuadrado Formato disponible: Rollo de 2 metros de ancho Ejemplo de cálculo: 1 metro lineal × 2 metros de ancho = 2 m² 2 m² × 2,65 €/m² = 5,30 € Más ejemplos: 5 metros lineales × 2 metros = 10 m² = 26,50 € 10 metros lineales × 2 metros = 20 m² = 53,00 € Corte Personalizado - Condiciones Importantes Nota importante: Los cortes personalizados no admiten devoluciones. ¿Necesitas medidas especiales o asesoramiento técnico para tu evento? Contacta con nuestro equipo especializado: Email: ventas@disstands.com Nuestros expertos en instalaciones feriales te ayudarán a calcular exactamente la cantidad que necesitas, optimizando el material y evitando desperdicios. La moqueta ferial colores especiales representa la elección perfecta para profesionales que buscan diferenciarse mediante tonos exclusivos, manteniendo los más altos estándares de calidad y seguridad en sus instalaciones.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  2.65,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
