INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '4c1a8cea-37ea-4c36-86c5-3d53616d08ea',
  'Moqueta Velour Lux',
  'moqueta-velour-lux',
  'Velour Lux es una moqueta de terciopelo de alta densidad que combina confort, resistencia y una estética elegante. Su efecto sombreado al pisar realza cualquier espacio, convirtiéndola en la opción ideal tanto para eventos profesionales como para interiores domésticos que buscan un acabado premiu...',
  'Velour Lux es una moqueta de terciopelo de alta densidad que combina confort, resistencia y una estética elegante. Su efecto sombreado al pisar realza cualquier espacio, convirtiéndola en la opción ideal tanto para eventos profesionales como para interiores domésticos que buscan un acabado premium. Características Técnicas Superiores Esta moqueta de terciopelo destaca por su construcción de alta densidad que garantiza durabilidad excepcional incluso en condiciones de uso intensivo. El característico efecto sombreado que se produce al caminar sobre ella crea un juego visual dinámico que aporta sofisticación y movimiento a cualquier espacio. Su superficie aterciopelada no solo es visualmente atractiva, sino que proporciona una experiencia táctil incomparable, convirtiendo cada paso en una sensación de confort premium. Aplicaciones Versátiles La moqueta Velour Lux es perfecta para eventos de alto nivel, ferias exclusivas, showrooms de lujo y presentaciones de productos premium. Su acabado elegante la hace especialmente adecuada para zonas VIP, pasarelas de moda, recepciones de hoteles y espacios comerciales que buscan transmitir calidad y distinción. En el ámbito residencial, transforma salones, dormitorios y despachos en espacios de lujo accesible. Especificaciones y Formato El rollo estándar de moqueta Velour ofrece 50 metros lineales con un ancho de 2 metros, proporcionando 100 m² de superficie total. Este formato profesional permite cubrir grandes espacios de manera eficiente, minimizando juntas y optimizando la instalación. Información de Compra Precio competitivo: 4,05 €/m² Cálculo sencillo: 1 metro lineal x 2 metros de ancho = 2 m². Precio total: 8,10 € Los cortes se realizan a medida según necesidades específicas del proyecto. Importante: Los cortes personalizados no admiten devoluciones, garantizando así precios ajustados y servicio ágil. Para solicitar medidas personalizadas o recibir asesoramiento profesional sobre la moqueta Velour Lux, contacta con nuestro equipo especializado en ventas@disstands.com. Ofrecemos atención personalizada para proyectos de cualquier envergadura.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  4.05,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
