INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '8be01066-91cc-4270-8401-1017f0ca0d54',
  'Moqueta Las Vegas',
  'moqueta-las-vegas',
  'La Moqueta Las Vegas combina elegancia y funcionalidad para transformar cualquier espacio, desde ferias y stands hasta entornos residenciales o comerciales. Con una superficie lisa de poliamida de alta calidad y un reverso Action Back, es ideal para quienes buscan confort, resistencia y una estét...',
  'La Moqueta Las Vegas combina elegancia y funcionalidad para transformar cualquier espacio, desde ferias y stands hasta entornos residenciales o comerciales. Con una superficie lisa de poliamida de alta calidad y un reverso Action Back, es ideal para quienes buscan confort, resistencia y una estética impecable en instalaciones temporales o permanentes. Características y Ventajas Principales Esta moqueta profesional ha sido específicamente diseñada para satisfacer las demandas más exigentes del sector eventos y ferias. Su composición de poliamida garantiza una durabilidad excepcional, resistiendo el tránsito intenso característico de exposiciones comerciales, congresos, presentaciones de producto y eventos corporativos. La tecnología Action Back en su reverso proporciona estabilidad dimensional superior, facilitando una instalación rápida y segura que ahorra tiempo valioso durante el montaje. Versatilidad de Aplicaciones La Moqueta Las Vegas destaca por su versatilidad, siendo la elección perfecta para múltiples aplicaciones: stands feriales, showrooms, oficinas temporales, espacios de networking, áreas VIP y zonas de recepción. Su superficie lisa y uniforme crea un ambiente profesional y acogedor, mientras que su excelente relación calidad-precio la convierte en una inversión inteligente para empresas de organización de eventos, agencias de publicidad y empresas expositoras. Especificaciones Técnicas y Mantenimiento El diseño liso de esta moqueta facilita su limpieza y mantenimiento, permitiendo aspirado regular y limpieza profesional cuando sea necesario. Su estructura resistente soporta el uso continuado sin deformaciones, manteniendo su aspecto impecable evento tras evento. Compatible con cintas adhesivas profesionales para ferias, permite crear instalaciones seguras y sin arrugas. Información de Compra Precio competitivo: 13,75 €/m² Sistema de cálculo: El precio se calcula por metro cuadrado. Por ejemplo, 1 metro lineal x 2 metros de ancho equivale a 2 m², resultando en 27,50 €. Importante: Los cortes personalizados no admiten devoluciones, garantizando así precios ajustados. Para medidas personalizadas o asesoramiento técnico, contacta con nuestro equipo especializado en ventas@disstands.com. La Moqueta Las Vegas representa la solución definitiva para profesionales que buscan combinar elegancia, funcionalidad y durabilidad en sus proyectos de revestimiento temporal o permanente.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  13.75,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
