INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3dc18245-749e-45a4-8101-4f6833a78de4',
  'Moqueta Salsdis',
  'moqueta-ignifuga-eventos-salsdis',
  'La moqueta ignífuga eventos Salsdis representa la solución más segura y confortable para eventos profesionales. Esta moqueta ignífuga eventos cuenta con certificación de seguridad y una construcción de triple capa que la diferencia de las moquetas convencionales del mercado. Construcción Superior...',
  'La moqueta ignífuga eventos Salsdis representa la solución más segura y confortable para eventos profesionales. Esta moqueta ignífuga eventos cuenta con certificación de seguridad y una construcción de triple capa que la diferencia de las moquetas convencionales del mercado. Construcción Superior de Triple Capa en Moqueta Ignífuga Eventos La moqueta ignífuga eventos Salsdis destaca gracias a su innovadora tecnología de triple capa. Su base de goma antideslizante garantiza seguridad total, eliminando el riesgo de desplazamientos durante ferias y congresos. La capa intermedia de látex proporciona una amortiguación excepcional que reduce la fatiga al caminar, mientras que la película protectora superior preserva la estética impecable durante todo el evento. Con un grosor aproximado de 5 mm, esta moqueta ignífuga ofrece el mayor confort del mercado profesional. Ventajas de la Moqueta Ignífuga para Eventos Profesionales Esta moqueta ignífuga eventos supera a las moquetas velours tradicionales en múltiples aspectos. Su certificación ignífuga cumple con las normativas más exigentes de seguridad para espacios públicos y eventos multitudinarios. La superficie antideslizante proporciona confianza tanto a organizadores como a asistentes, especialmente importante en eventos con gran afluencia de público. Además, su resistencia al desgaste garantiza que mantenga su aspecto impecable desde el montaje hasta el desmontaje del evento. Aplicaciones Profesionales de Alto Standing Diseñada para eventos VIP, congresos internacionales, bodas elegantes y pasarelas de moda, esta moqueta ignífuga eventos transforma cualquier superficie en una experiencia premium. Su base antideslizante la hace especialmente segura para zonas de alto tráfico, escaleras y áreas donde la estabilidad es fundamental. La amplia gama de colores disponibles permite adaptarse a cualquier concepto de diseño, desde ambientes corporativos sobrios hasta eventos creativos vibrantes. Formato y Disponibilidad La moqueta se suministra en rollos completos para proyectos de gran envergadura. También ofrecemos servicio de corte personalizado que permite optimizar el material según las dimensiones específicas de cada proyecto, reduciendo desperdicios y ajustándose perfectamente a tus necesidades. Información de Compra Precio por metro cuadrado para máxima transparencia en presupuestos. Los cortes personalizados no admiten devoluciones, garantizando así precios competitivos y servicio eficiente. Para solicitar medidas personalizadas o consultar disponibilidad de colores específicos, contacta con nuestro equipo especializado en ventas@disstands.com.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  5.38,
  1,
  'm²',
  true,
  true,
  NULL
