INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '294541fd-3528-4d03-80c7-a31afa6b5b9c',
  'Moqueta Revexdis',
  'moqueta-revexdis-eventos',
  'Moqueta Revexdis Eventos: Solución Práctica y Económica La moqueta Revexdis eventos es una opción práctica y económica diseñada específicamente para cubrir suelos en eventos, ferias o exposiciones. Además, esta solución versátil destaca por su superficie tipo dilour suave al tacto. Por otro lado,...',
  'Moqueta Revexdis Eventos: Solución Práctica y Económica La moqueta Revexdis eventos es una opción práctica y económica diseñada específicamente para cubrir suelos en eventos, ferias o exposiciones. Además, esta solución versátil destaca por su superficie tipo dilour suave al tacto. Por otro lado, se adapta perfectamente a distintas superficies y viene presentada en rollos de 30 metros lineales. ¿Por qué elegir la moqueta Revexdis eventos? Esta moqueta combina ligereza y resistencia, siendo ideal para instalaciones rápidas en espacios feriales. Asimismo, está disponible en muchos colores que permiten adaptarse a cualquier marca o diseño de stand. Su principal ventaja es la certificación ignífuga Cfl-s1, lo que la hace totalmente segura para interiores. Por lo tanto, cumple con las normativas más exigentes del sector. Instalación fácil y rápida Esta moqueta destaca por su excelente relación calidad-precio. En consecuencia, se convierte en la elección ideal para organizadores de eventos que buscan optimizar su presupuesto sin perder calidad. Además, su textura tipo dilour proporciona una sensación agradable al tacto y mejora la estética de cualquier espacio expositivo. Adaptable a cualquier superficie La versatilidad permite su instalación en todo tipo de suelos. Por ejemplo, desde suelos de cemento en pabellones feriales hasta tarimas y estructuras modulares en stands. Además, su peso ligero facilita el transporte y la manipulación durante el montaje. Como resultado, se reducen los tiempos de instalación y los costes logísticos. Seguridad certificada La certificación ignífuga Cfl-s1 garantiza el cumplimiento de las estrictas normas de seguridad contra incendios. Estas son exigidas en recintos feriales, centros de congresos y espacios públicos. Por lo tanto, esta certificación convierte al producto en una opción segura y fiable para eventos de cualquier tamaño. Opciones de compra flexibles Precio indicado por metro cuadrado. Esta moqueta se vende en rollos completos de 30 metros lineales. Sin embargo, también ofrecemos opción de corte personalizado para adaptarnos a las necesidades específicas de tu proyecto. De esta manera, optimizas tu inversión y evitas desperdicios innecesarios. Importante: Los cortes personalizados no admiten devoluciones. Para solicitar medidas personalizadas o recibir asesoramiento técnico sobre tu proyecto, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  4.40,
  1,
  'm²',
  true,
  true,
  NULL
