INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ac8e40fd-fe4e-48b0-8684-b24cf08d57c3',
  'Césped Greendis 7MM',
  'cesped-greendis-7mm',
  'El césped artificial 7mm Greendis es la solución perfecta para proyectos decorativos, paisajismo y espacios donde se busca un acabado limpio y uniforme. Este césped artificial decorativo de 7mm combina practicidad y estética con mínimo mantenimiento. Características del césped artificial 7mm Este...',
  'El césped artificial 7mm Greendis es la solución perfecta para proyectos decorativos, paisajismo y espacios donde se busca un acabado limpio y uniforme. Este césped artificial decorativo de 7mm combina practicidad y estética con mínimo mantenimiento. Características del césped artificial 7mm Este césped artificial 7mm está fabricado con hilo fibrilado de polipropileno de alta calidad. Su altura de 7 milímetros lo convierte en una opción ideal para áreas decorativas, balcones, terrazas, stands comerciales y proyectos de paisajismo donde se prioriza la uniformidad visual. El césped artificial decorativo 7mm Greendis incorpora efecto memoria, una característica técnica que permite que las fibras vuelvan a su posición erguida después del uso, manteniendo siempre un aspecto impecable. Ventajas del césped decorativo de 7mm Resistencia al sol: Protección UV que evita la decoloración incluso con exposición solar prolongada. Resistente a la humedad: Perfecto para exteriores, con sistema de drenaje eficiente. Tolerancia a temperaturas extremas: Mantiene sus propiedades tanto en frío como en calor. Bajo mantenimiento: Sin necesidad de riego, corte ni tratamientos especiales. Aspecto natural uniforme: Acabado limpio y homogéneo ideal para decoración. Aplicaciones del césped artificial 7mm Este modelo de césped artificial decorativo es perfecto para balcones, terrazas urbanas, jardines pequeños, áreas comerciales, escaparates, ferias y eventos, zonas de piscina, decoración interior y proyectos de paisajismo ornamental. Formato de venta y precio Rollo: 25 metros lineales x 2 metros de ancho Precio: 5,72 €/m² Los cortes personalizados son ventas finales y no admiten devoluciones. Para asesoramiento sobre medidas, instalación o consultas técnicas, contacta con nuestro equipo en ventas@disstands.com Instalación del césped artificial decorativo Instalar césped artificial 7mm es sencillo. Limpia y nivela la superficie, despliega el rollo, recorta si es necesario y fija los bordes. Para más detalles, consulta nuestra guía de instalación de césped artificial. Descubre también otros modelos en nuestra categoría de césped artificial decorativo o explora opciones de mayor altura en nuestra sección de césped artificial para jardín. Invierte en césped artificial 7mm Greendis y transforma cualquier espacio en una zona verde atractiva, duradera y sin complicaciones.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  5.72,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
