INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '893a9fb1-a2bc-424f-8dbb-359fde9e4698',
  'Césped Darkberdis 10MM',
  'cesped-artificial-10mm-resistente',
  'Césped Artificial 10mm Resistente: Solución Profesional El césped artificial 10mm resistente Dakar es una opción funcional para espacios que requieren una solución estética, económica y de fácil mantenimiento. Este césped artificial resistente ofrece un acabado limpio y uniforme con su altura esp...',
  'Césped Artificial 10mm Resistente: Solución Profesional El césped artificial 10mm resistente Dakar es una opción funcional para espacios que requieren una solución estética, económica y de fácil mantenimiento. Este césped artificial resistente ofrece un acabado limpio y uniforme con su altura específica de 10 mm. Además, resulta ideal para decoración de terrazas, escaparates, stands y zonas de paso con alto tránsito. Por tanto, proporciona el equilibrio perfecto entre aspecto natural y practicidad, permitiendo un tránsito cómodo sin comprometer la apariencia verde y fresca del espacio. Materiales de Alta Calidad Fabricado con materiales resistentes de alta calidad, este césped artificial 10mm soporta excelentemente la intemperie, la humedad y el uso frecuente intensivo. Asimismo, las fibras de polietileno están tratadas con protección UV avanzada, garantizando que mantengan su color verde vibrante incluso bajo exposición solar directa y prolongada. Su base perforada asegura un drenaje eficiente del agua, evitando encharcamientos problemáticos. En consecuencia, permite su uso inmediato después de la lluvia. Perfecto para proyectos de paisajismo urbano, ferias comerciales, jardines efímeros o instalaciones comerciales. Versatilidad para Eventos y Espacios Comerciales La versatilidad del césped resistente de 10mm Dakar lo convierte en la elección preferida de profesionales de eventos y diseñadores de espacios comerciales. Posteriormente, su instalación rápida y sencilla permite transformar cualquier superficie en un área verde atractiva en cuestión de minutos. Además, no requiere riego, corte, fertilizantes ni tratamientos especiales. Por tanto, representa un ahorro significativo en tiempo y recursos de mantenimiento continuo. Durabilidad y Seguridad Este césped artificial 10mm resistente destaca por su tacto suave y su capacidad de recuperación tras el pisado intenso. Asimismo, mantiene siempre un aspecto impecable incluso con uso frecuente. Es antialérgico, libre de elementos tóxicos y seguro para el contacto con personas y mascotas. Finalmente, su durabilidad excepcional garantiza años de uso sin pérdida de calidad, convirtiéndolo en una inversión inteligente para negocios, hogares y espacios públicos de alto tránsito. Especificaciones del Producto Rollo: 30 ml x 2 m de ancho Precio indicado: Por metro cuadrado Venta: Rollos completos (opción de corte según disponibilidad) Devoluciones: Los cortes no admiten devoluciones Para medidas personalizadas o consultas específicas, escríbenos a: ventas@disstands.com o llama al 934 850 085.',
