INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b81ef3af-3472-4df5-8ccf-92aaf1d7c59f',
  'Césped Capridis 8MM',
  'cesped-capridis-8mm',
  'Césped Artificial 8mm Decorativo: Solución Versátil El césped artificial 8mm decorativo Capridis es un recubrimiento sintético de fibra corta diseñado específicamente para aplicaciones decorativas y prácticas donde prima la estética sobre el volumen. Este césped artificial decorativo con su altur...',
  'Césped Artificial 8mm Decorativo: Solución Versátil El césped artificial 8mm decorativo Capridis es un recubrimiento sintético de fibra corta diseñado específicamente para aplicaciones decorativas y prácticas donde prima la estética sobre el volumen. Este césped artificial decorativo con su altura compacta de 8 mm resulta perfecto para proyectos de interiorismo, eventos temporales, escaparates comerciales y espacios donde se requiere una superficie uniforme, ligera y de fácil instalación. Además, está disponible en color verde natural y en versión multicolor para proyectos creativos diferenciados. Aplicaciones Decorativas del Césped 8mm Este césped decorativo de 8mm es la elección ideal para múltiples aplicaciones profesionales. Por tanto, resulta perfecto para decoración de interiores, stands feriales, escaparates comerciales, eventos corporativos, decoración de terrazas urbanas, áreas infantiles, proyectos de interiorismo creativo y cualquier espacio donde se busque un toque verde sin requerir gran amortiguación. Asimismo, su altura reducida facilita el tránsito cómodo con cualquier tipo de calzado. Ventajas del Formato Compacto La altura de 8 mm del césped artificial decorativo ofrece ventajas significativas para aplicaciones específicas. En consecuencia, es más ligero y fácil de transportar que opciones de mayor altura. Además, su instalación es rápida y sencilla, permitiendo cubrir grandes superficies en tiempo récord. Posteriormente, no requiere mantenimiento: sin riego, sin corte, sin fertilizantes ni tratamientos especiales. Disponibilidad en Colores Disponible tanto en color verde natural como en versión multicolor, este césped de 8mm permite crear diseños personalizados y proyectos diferenciados. Finalmente, la opción multicolor es perfecta para áreas infantiles, eventos temáticos, instalaciones artísticas y proyectos creativos que requieren impacto visual. Información de Compra Rollo: 30 ml x 2 m de ancho Precio indicado por metro cuadrado. Ejemplo de 