INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1fd33c87-b5f4-4676-8fc4-6737ab4bff85',
  'Césped Londis 20MM',
  'cesped-londis-20mm',
  'El césped artificial 20mm Londis es la solución perfecta si buscas un jardín impecable todo el año. Este modelo combina durabilidad y estética natural, ideal para quienes desean un espacio verde sin mantenimiento. Ventajas del césped sintético Londis Este producto destaca por su acabado realista ...',
  'El césped artificial 20mm Londis es la solución perfecta si buscas un jardín impecable todo el año. Este modelo combina durabilidad y estética natural, ideal para quienes desean un espacio verde sin mantenimiento. Ventajas del césped sintético Londis Este producto destaca por su acabado realista gracias a su mezcla de hilo recto monofilamento y rizado. Con una altura de 20 milímetros, ofrece la densidad perfecta para jardines residenciales, terrazas y zonas de paisajismo. La textura suave y confortable invita a disfrutar del espacio al aire libre en cualquier época del año. Características principales del modelo 20mm El césped sintético Londis está fabricado con materiales de alta calidad que garantizan resistencia al sol, la humedad y las temperaturas extremas. Su sistema de drenaje permite la evacuación rápida del agua, evitando encharcamientos. Además, cuenta con protección UV para mantener su color vibrante durante años. Aplicaciones versátiles para tu hogar Este modelo de 20mm es perfecto para jardines privados, áreas alrededor de piscinas, terrazas, áticos, zonas decorativas y proyectos de paisajismo comercial. Descubre más opciones en nuestra categoría de césped artificial para exteriores. Garantía y durabilidad El producto incluye 5 años de garantía en condiciones normales de uso, respaldando su calidad y resistencia a largo plazo. Precio y formato de compra Precio: 9,23 €/m² Ejemplo de cálculo: Si necesitas 1 metro lineal x 2 metros de ancho = 2 m² Total: 2 m² x 9,23 €/m² = 18,46 € Los cortes personalizados no admiten devoluciones. Para asesoramiento sobre medidas específicas, consulta nuestra guía de instalación o escríbenos a ventas@disstands.com Instalación sencilla paso a paso Instalar este tipo de pavimento verde es fácil. Prepara la base, compacta el terreno y añade una capa de arena para mejorar el drenaje. Si necesitas ayuda profesional, visita nuestros servicios de instalación. Invierte en el modelo Londis y transforma tu jardín en un espacio perfecto los 365 días del año, sin riego, sin corte y sin complicaciones.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  11.29,
  1,
  'm²',
  true,
  true,
  NULL
