INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '45cf5e5d-a66b-4a25-8ec1-10384cef4b3a',
  'Césped Kids Colores',
  'cesped-infantil-colores-24mm',
  'Césped Artificial Infantil Colores 24mm - Seguridad y Diversión para Espacios de Juego El césped artificial infantil colores de 24 mm es la solución ideal para crear áreas de juego seguras, cómodas y llenas de vida. Además, este césped artificial infantil en colores vivos está diseñado específica...',
  'Césped Artificial Infantil Colores 24mm - Seguridad y Diversión para Espacios de Juego El césped artificial infantil colores de 24 mm es la solución ideal para crear áreas de juego seguras, cómodas y llenas de vida. Además, este césped artificial infantil en colores vivos está diseñado específicamente pensando en los más pequeños, combinando funcionalidad, seguridad y un aspecto visual atractivo que transforma cualquier espacio recreativo. Características técnicas del césped artificial infantil colores En primer lugar, está fabricado con fibra monofilamento texturizada de alta calidad. Por otro lado, este césped artificial destaca por sus propiedades antielectrostáticas que garantizan la máxima seguridad durante el juego. Asimismo, con una altura de pelo de 24 mm y una densidad de 22.570 puntadas por metro cuadrado, ofrece una superficie uniforme, suave al tacto y extraordinariamente resistente al uso intensivo que caracteriza las zonas infantiles. Además, el backing de látex proporciona una excelente estabilidad dimensional y facilita notablemente su instalación sobre diferentes tipos de superficies, ya sean de hormigón, tierra compactada o bases preparadas específicamente para césped sintético. Cumplimiento normativo y seguridad certificada Por supuesto, este césped artificial infantil colores cumple rigurosamente con la normativa oficial de Parques y Jardines. Esto significa que ha superado todos los controles de calidad y seguridad exigidos para instalaciones infantiles. De hecho, esta certificación es fundamental para colegios, guarderías y espacios públicos que requieren materiales homologados. Colores vibrantes para espacios creativos Por otra parte, está disponible en cuatro colores vivos - verde, rojo, azul y amarillo - que permiten diseñar zonas de juego diferenciadas y visualmente estimulantes. Igualmente, estos tonos brillantes no solo aportan alegría al entorno, sino que también facilitan la creación de circuitos, áreas temáticas o sistemas de señalización mediante el uso del color. Aplicaciones y versatilidad En consecuencia, resulta ideal para colegios, parques infantiles, guarderías, patios de recreo, terrazas comunitarias y cualquier zona recreativa donde los niños desarrollen sus actividades. Además, su superficie acolchada minimiza el impacto en caso de caídas, proporcionando mayor tranquilidad a padres y educadores. Información de compra Finalmente, el precio indicado es por metro cuadrado. Por ejemplo: 1 metro lineal x 2 metros de ancho = 2 m². Por lo tanto: 2 m² x 18,15 €/m² = 36,30 €. Importante: Los cortes personalizados no admiten devoluciones. Sin embargo, para consultas sobre medidas específicas o proyectos especiales, contacta con nuestro equipo en ventas@disstands.com',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  18.55,
  1,
  'm²',
  true,
  true,
  NULL
