INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a622b902-8e4e-41a8-8474-cc7dde9281b5',
  'Césped Elbedis 23MM',
  'cesped-artificial-elbedis-23mm',
  'Nuestro césped artificial de 23 mm de altura representa la elección perfecta para quienes buscan un equilibrio ideal entre estética natural, funcionalidad y precio competitivo. Esta altura media ha sido especialmente seleccionada para ofrecer una apariencia realista que imita fielmente el césped ...',
  'Nuestro césped artificial de 23 mm de altura representa la elección perfecta para quienes buscan un equilibrio ideal entre estética natural, funcionalidad y precio competitivo. Esta altura media ha sido especialmente seleccionada para ofrecer una apariencia realista que imita fielmente el césped natural, mientras proporciona una pisada cómoda y agradable que invita al disfrute de los espacios. Aplicaciones Versátiles Este césped artificial es extraordinariamente versátil y se adapta a múltiples usos y entornos: Eventos y celebraciones: Perfecto para bodas, ferias, stands comerciales, inauguraciones y todo tipo de eventos donde se requiera crear un ambiente natural y acogedor de forma rápida y eficaz. Jardines residenciales: Transforma tu jardín en un espacio verde permanente, sin preocuparte por el riego, el corte o los parches secos. Ideal para familias que desean disfrutar de un jardín impecable todo el año. Terrazas y balcones: Convierte tu terraza o balcón en un oasis urbano, aportando calidez y naturalidad a espacios exteriores de viviendas, áticos o locales comerciales. Zonas de piscina: Crea áreas seguras y confortables alrededor de piscinas, sin barro ni hierba que se adhiera a los pies. Espacios comerciales: Showrooms, escaparates, áreas infantiles en centros comerciales y espacios que buscan un toque natural diferenciador. Ventajas y Características Técnicas La altura de 23 mm proporciona un aspecto natural sin resultar excesivamente denso, facilitando el mantenimiento y garantizando una excelente relación calidad-precio. Entre sus principales ventajas destacan: Bajo mantenimiento: Olvídate del riego, el corte, los fertilizantes y los tratamientos. Un simple cepillado ocasional y limpieza básica son suficientes. Durabilidad excepcional: Fabricado con materiales resistentes a los rayos UV, mantiene su color verde intenso sin decolorarse con el sol. Resistencia al uso: Soporta el tránsito regular sin aplanarse ni deteriorarse, manteniendo su aspecto original temporada tras temporada. Drenaje eficiente: Sistema de drenaje incorporado que permite la evacuación rápida del agua, evitando encharcamientos. Confort al pisado: Textura suave y agradable que proporciona comodidad al caminar descalzo. Formato y Presentación El producto se presenta en rollos de 25 metros lineales x 2 metros de ancho, facilitando la instalación en superficies de diferentes dimensiones. Precio y Sistema de Venta El precio indicado es por metro cuadrado (m²): 8,25 €/m² Puedes solicitar cortes personalizados según tus necesidades específicas. El ancho del rollo es fijo de 2 metros, y tú decides los metros lineales que necesitas. Ejemplo práctico de cálculo: Si solicitas 1 metro lineal de corte × 2 metros de ancho = 2 m² Precio: 2 m² × 8,25 €/m² = 16,50 € Importante - Política de Cortes: ⚠️ Los cortes personalizados no admiten devoluciones, ya que se realizan específicamente según las medidas solicitadas por cada cliente. Medidas Personalizadas Si necesitas asesoramiento para calcular la cantidad exacta que requieres, tienes dudas sobre la instalación o deseas solicitar medidas especiales, nuestro equipo está a tu disposición. Contáctanos en: ventas@disstands.com',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  8.75,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
