INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'd67e0aa8-05ff-4176-8f4f-6fc21267bdb5',
  'Césped Mondis 40MM',
  'cesped-artificial-mondis-40mm',
  'Césped artificial Mondis 40mm: naturalidad y confort para espacios exteriores El césped artificial Mondis 40mm combina una estética natural extraordinaria con un tacto suave y realista que invita a caminar descalzo. Este césped es ideal para jardines residenciales, terrazas urbanas, zonas de jueg...',
  'Césped artificial Mondis 40mm: naturalidad y confort para espacios exteriores El césped artificial Mondis 40mm combina una estética natural extraordinaria con un tacto suave y realista que invita a caminar descalzo. Este césped es ideal para jardines residenciales, terrazas urbanas, zonas de juego infantil, áreas comunes de comunidades y cualquier espacio exterior que busque belleza verde permanente sin las complicaciones del césped tradicional. Su altura de 40mm ofrece un equilibrio perfecto entre comodidad al pisar, resistencia al uso diario y apariencia exuberante que imita fielmente un césped natural bien cuidado. Gracias a esta altura óptima, el césped mantiene su volumen y aspecto vertical incluso con tráfico moderado, recuperando su forma original de manera natural. El césped artificial Mondis 40mm se mantiene impecable durante todo el año con mínimo mantenimiento. Olvídate de cortar, regar, fertilizar o resembrar. Un simple cepillado ocasional y limpieza puntual son suficientes para mantenerlo perfecto. Esto se traduce en ahorro considerable de tiempo, dinero en agua y productos de jardinería, además de contribuir al cuidado del medio ambiente. Fabricado con fibras de alta calidad con protección UV integrada, este césped resiste perfectamente la exposición solar sin decoloración. Su sistema de drenaje perforado permite la evacuación rápida del agua de lluvia, evitando encharcamientos y garantizando que tu jardín esté seco y listo para usar en minutos. La suavidad excepcional de sus fibras lo hace perfecto para familias con niños y mascotas, proporcionando una superficie segura y confortable para jugar. Además, su aspecto natural realista con variaciones de tonos verdes crea un efecto visual auténtico que embellece cualquier espacio exterior. Precio y formato de venta: Precio indicado por metro cuadrado: 16,30 €/m² Formato de venta: Corte personalizado según necesidades Ejemplo de cálculo: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 16,30 €/m² = 32,60 € Importante: Los cortes no admiten devoluciones debido a la naturaleza personalizada del producto. ¿Necesitas medidas personalizadas? Escríbenos a: ventas@disstands.com y te prepararemos un presupuesto ajustado a tu proyecto. Transforma tu espacio exterior con el césped artificial Mondis 40mm y disfruta de un jardín verde perfecto los 365 días del año sin esfuerzo.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  16.30,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
