INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '32361458-d0c6-40f4-808b-d7a903a7d1e2',
  'Césped Prada 25MM',
  'cesped-prada-25mm',
  'El césped artificial de colores 25 mm Prada representa una alternativa decorativa innovadora que rompe con los esquemas tradicionales del revestimiento exterior. Con una altura de fibra de 25 milímetros, este producto combina estética vibrante con prestaciones técnicas sobresalientes, convirtiénd...',
  'El césped artificial de colores 25 mm Prada representa una alternativa decorativa innovadora que rompe con los esquemas tradicionales del revestimiento exterior. Con una altura de fibra de 25 milímetros, este producto combina estética vibrante con prestaciones técnicas sobresalientes, convirtiéndose en la elección perfecta para quienes buscan personalizar sus espacios con un toque de color y originalidad. Aplicaciones Versátiles para Múltiples Espacios Este césped artificial destaca por su adaptabilidad a diversos entornos. En jardines y terrazas, transforma áreas convencionales en espacios llenos de vida y personalidad. Los espacios infantiles se benefician especialmente de su superficie mullida y segura, mientras que en escaparates comerciales genera un impacto visual inmediato que capta la atención del público. También resulta ideal para zonas de eventos, donde la creatividad y la diferenciación son elementos clave. Características Técnicas Destacadas La composición del césped Prada garantiza una textura suave al tacto, proporcionando confort en cada pisada. Su construcción técnica incorpora resistencia excepcional frente a condiciones climáticas adversas, soportando tanto la radiación solar intensa como las bajas temperaturas y la humedad. Esta durabilidad asegura que el color y la estructura se mantengan inalterados durante años, sin necesidad de mantenimientos complejos. Formato de Venta y Cálculo de Precio El producto se comercializa en rollos de 25 metros lineales por 2 metros de ancho, con el precio establecido por metro cuadrado. Para facilitar el cálculo: un metro lineal de 2 metros de ancho equivale a 2 m², que multiplicado por 27,93 €/m² resulta en 55,86 €. Importante: Los cortes realizados no admiten devoluciones. Si requieres medidas personalizadas o asesoramiento específico para tu proyecto, nuestro equipo está disponible en ventas@disstands.com para ofrecerte soluciones a medida.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
