INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '18499f11-f0c2-4c7e-8fe9-09de01ce1d16',
  'Césped Sungdis Padel Pro 12MM',
  'cesped-artificial-para-pistas-de-padel-12-mm',
  'Césped artificial para pistas de pádel 12 mm: la superficie técnica de alto rendimiento El césped artificial para pistas de pádel 12 mm es una superficie técnica desarrollada específicamente para proporcionar un rendimiento deportivo óptimo en cada partido. Este césped artificial para pistas de p...',
  'Césped artificial para pistas de pádel 12 mm: la superficie técnica de alto rendimiento El césped artificial para pistas de pádel 12 mm es una superficie técnica desarrollada específicamente para proporcionar un rendimiento deportivo óptimo en cada partido. Este césped artificial para pistas de pádel 12 mm está fabricado con hilo fibrilado de polietileno de alta resistencia y estabilizado contra los rayos UV, garantizando una excelente durabilidad incluso en las condiciones climáticas más exigentes. Nuestro césped artificial para pistas de pádel 12 mm se ha convertido en la elección preferida de instaladores profesionales y clubes deportivos que buscan calidad superior. Características técnicas superiores El césped artificial para pistas de pádel 12 mm destaca por su estructura y densidad cuidadosamente diseñadas para proporcionar el agarre perfecto, velocidad de juego adecuada y mínima abrasión durante la práctica deportiva. El sistema de drenaje eficiente permite que el agua se evacue rápidamente, evitando charcos y garantizando que tu pista esté lista para jugar en minutos tras la lluvia. Su comportamiento deportivo constante asegura que los jugadores disfruten de las mismas condiciones de juego durante toda la vida útil del producto. Ventajas del césped artificial de 12 mm para pádel Este césped artificial para pistas de pádel 12 mm es ideal tanto para instalaciones profesionales como para clubes amateur que buscan calidad superior. La fibra de polietileno de alta resistencia soporta el uso intensivo sin perder sus propiedades, mientras que la protección UV evita la decoloración y el deterioro prematuro del material. La altura de 12 mm proporciona el equilibrio perfecto entre confort, velocidad de bola y durabilidad, cumpliendo con los estándares más exigentes del deporte. Aplicaciones versátiles El césped artificial para pistas de pádel 12 mm es perfecto para pistas indoor y outdoor, centros deportivos, clubes privados, instalaciones municipales y complejos residenciales. Su versatilidad y resistencia lo convierten en la solución definitiva para cualquier proyecto de pádel que requiera una superficie fiable y de alto rendimiento deportivo. Especificaciones técnicas: Rollo: 20.25 ml x 2 m de ancho Altura: 12 mm Material: Polietileno fibrilado con protección UV Precio: Indicado por metro cuadrado Formato de venta: Rollos completos Importante: Este césped se vende exclusivamente en rollos completos. Los cortes no admiten devoluciones. ¿Necesitas medidas personalizadas? Escríbenos a: ventas@disstands.com Invierte en calidad profesional con césped artificial para pistas de pádel 12 mm y disfruta de una superficie perfecta durante años.',
