INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e280aaf2-d1e4-4925-8a2e-9f0a6a16b4e1',
  'Jardin Vertical Villandis',
  'jardin-vertical-villandis',
  'Jardín vertical Villadis 100x100: elegancia natural sin mantenimiento El jardín vertical Villadis 100x100 es un panel artificial decorativo de alta densidad que simula setos naturales para colocación en vertical, recreando a la perfección paredes vegetales realistas. Este jardín vertical Villa 10...',
  'Jardín vertical Villadis 100x100: elegancia natural sin mantenimiento El jardín vertical Villadis 100x100 es un panel artificial decorativo de alta densidad que simula setos naturales para colocación en vertical, recreando a la perfección paredes vegetales realistas. Este jardín vertical Villa 100x100 ha sido diseñado específicamente para transformar espacios con elegancia y sin las complicaciones del mantenimiento tradicional de plantas naturales. Diseño versátil del jardín vertical Villandis Nuestro jardín vertical Villandis 100x100 ha sido creado para decorar terrazas, balcones, techos, columnas, fachadas, cercas, vallas publicitarias y escaparates con estilo. Convierte un muro o pared aburrida en un hermoso jardín vertical artificial lleno de vida y color. Asimismo, estos paneles transforman instantáneamente cualquier ambiente en un espacio acogedor y natural que impresiona a visitantes y clientes. Densidad excepcional de 1.539 hojas por panel Con una impresionante densidad de 1.539 hojas por panel, el modelo Villandis ofrece una cobertura densa y frondosa que replica fielmente los setos naturales. De esta manera, logramos un aspecto natural sin mantenimiento que imita perfectamente jardines reales. Por consiguiente, cada jardín vertical Villadis 100x100 presenta una estética orgánica y equilibrada que engaña al ojo más crítico con su realismo excepcional. Materiales de alta calidad con protección UV superior El jardín vertical Villandis 100x100 está fabricado en polietileno 100%, un material de alta calidad totalmente resistente a los rayos UV con más de 5.000 horas de protección certificada. Esto consigue por tanto una resistencia perfecta al paso del tiempo, tanto en interiores como en exteriores. Además, esta protección UV garantiza que los colores permanezcan vivos y brillantes durante años sin decoloración ni deterioro visible. Formato estándar de 100x100 cm Cada pieza del jardín vertical Villandis 100x100 mide exactamente 100 cm x 100 cm con un peso de solo 2.950 gramos, un formato perfecto que permite crear instalaciones modulares de cualquier tamaño. Por otro lado, su construcción de marco con hojas integradas facilita enormemente la instalación y permite combinar varios paneles para cubrir grandes superficies. De esta forma, puedes diseñar muros vegetales completos adaptados a tus necesidades específicas de proyecto. Seguridad y sostenibilidad garantizadas El jardín vertical Villandis 100x100 está libre de plomo y metales pesados, garantizando total seguridad para cualquier entorno. Además, es 100% reciclable, contribuyendo a un consumo más responsable con el medio ambiente. Con una garantía de 8 años, este panel ofrece tranquilidad y durabilidad a largo plazo. Ventajas del modelo Villandis El jardín vertical Villandis 100x100 elimina completamente la necesidad de riego, poda, fertilización o luz natural específica. No requiere sistemas de drenaje complicados ni genera problemas de humedad en las paredes. Asimismo, es perfecto para espacios sin luz natural donde las plantas reales no sobrevivirían, como pasillos interiores, sótanos iluminados o espacios comerciales cerrados. Aplicaciones ideales del jardín Villandis Este panel artificial decorativo es perfecto para terrazas residenciales, balcones urbanos, techos y cubiertas, columnas decorativas, fachadas de edificios, cercas perimetrales, vallas publicitarias y decoración de escaparates comerciales. Características principales Modelo: Villandis Dimensiones: 100 cm x 100 cm por panel Peso: 2.950 g Material: 100% Polietileno Categoría: Setos Densidad: 1.539 hojas por panel Colores: Varios tonos naturales Construcción: Marco + hojas integradas Protección UV: >5.000 horas Garantía: 8 años Seguridad: Libre de plomo y metales pesados Reciclabilidad: 100% reciclable Uso: Interior y exterior Elige el jardín vertical Villandis 100x100 para disfrutar de paredes vegetales espectaculares sin esfuerzo, mantenimiento ni preocupaciones. NO IGNÍFUGO, SE PUEDE IGNIFUGAR',
