INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '66c236bd-cef7-404c-8392-44a7f606664b',
  'Césped Náutica y Piscinas Wellnedis',
  'cesped-artificial-piscinas',
  'El césped artificial piscinas Wellnedis es la solución perfecta para quienes buscan una superficie decorativa, segura y de bajo mantenimiento alrededor de zonas acuáticas. Diseñado con fibras sintéticas de alta calidad, combina durabilidad, confort y un aspecto natural que se mantiene durante tod...',
  'El césped artificial piscinas Wellnedis es la solución perfecta para quienes buscan una superficie decorativa, segura y de bajo mantenimiento alrededor de zonas acuáticas. Diseñado con fibras sintéticas de alta calidad, combina durabilidad, confort y un aspecto natural que se mantiene durante todo el año. En la introducción, destacamos que el césped artificial piscinas ofrece un drenaje eficiente que evita la acumulación de agua, proporcionando una superficie seca y antideslizante ideal para áreas junto a piscinas, jacuzzis y zonas húmedas. Su estructura permeable permite un flujo constante del agua, manteniendo la higiene y seguridad en entornos de alto tránsito. Este césped artificial destaca por su resistencia a los rayos UV, asegurando que el color verde permanezca brillante y uniforme incluso con exposición prolongada al sol. Además, su textura suave y libre de látex lo convierte en una opción cómoda y ecológica frente al césped natural. Disponible en distintas alturas y tonalidades, el césped artificial piscinas Wellnedis se adapta a jardines residenciales, terrazas, hoteles y proyectos de paisajismo decorativo. Su instalación es sencilla y no requiere riego, fertilizantes ni corte, reduciendo significativamente el mantenimiento y el consumo de recursos. Cada rollo se comercializa por metro cuadrado, permitiendo ajustes a medida según la superficie disponible.Ejemplo de corte:1 m lineal × 2 m de ancho = 2 m²2 m² × 35,34 €/m² = 70,68 € Los cortes no admiten devoluciones.Para medidas personalizadas o pedidos grandes, contáctanos en ventas@disstands.com. Con el césped artificial piscinas Wellnedis podrás crear espacios seguros, atractivos y funcionales, combinando estética, resistencia y facilidad de mantenimiento durante todo el año. Es la elección ideal para quienes buscan calidad, confort y un acabado natural en cualquier proyecto exterior.',
