INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '917f68af-2f75-45b7-8e30-aaf5410cf120',
  'PVC Las Vegas Brillo',
  'suelo-vinilico-las-vegas-brillo',
  'El suelo vinílico Las Vegas Brillo Lux es una solución de alta calidad con grosor de 2 mm, ideal para espacios interiores que necesitan un acabado elegante y extraordinariamente resistente. Este suelo vinílico Las Vegas está diseñado para durar años, soportar el uso diario sin desgastarse y mante...',
  'El suelo vinílico Las Vegas Brillo Lux es una solución de alta calidad con grosor de 2 mm, ideal para espacios interiores que necesitan un acabado elegante y extraordinariamente resistente. Este suelo vinílico Las Vegas está diseñado para durar años, soportar el uso diario sin desgastarse y mantenerse estable con el tiempo. Construcción y Acabado Premium En primer lugar, este suelo vinílico Las Vegas destaca por su construcción robusta de 2 mm que garantiza resistencia excepcional. Además, su característico acabado brillo aporta luminosidad y amplitud visual a cualquier espacio. Como resultado, crea ambientes más elegantes y sofisticados que causan excelente impresión. El acabado brillo lux refleja la luz natural de manera óptima. Por consiguiente, los espacios parecen más amplios y acogedores. Asimismo, este efecto brillante se mantiene impecable durante años con el mantenimiento adecuado. Protección Higiénica Certificada Por otro lado, incluye protección antibacteriana y fungicida integrada en su composición. Este tratamiento inhibe activamente el crecimiento de bacterias dañinas. De este modo, garantiza un ambiente higiénico constante en tu comercio o vivienda. Además, incorpora un acabado especial que facilita enormemente su limpieza. En consecuencia, el mantenimiento diario se realiza de manera rápida y sencilla con productos convencionales. Especialmente útil en espacios comerciales donde la higiene es prioritaria. Compromiso Ecológico y Seguridad Este suelo vinílico Las Vegas es un producto ecológico certificado. En primer lugar, está fabricado sin disolventes nocivos que puedan emitir compuestos volátiles. Igualmente, no contiene metales pesados peligrosos como plomo o cadmio. Por lo tanto, cumple rigurosamente con los estándares europeos de seguridad y calidad. Asimismo, cuenta con certificaciones CE reconocidas internacionalmente. De este modo, protege la salud de usuarios, empleados y clientes. Aplicaciones Versátiles Perfecto para tiendas y boutiques que buscan un pavimento elegante y duradero. Igualmente ideal para oficinas modernas donde se requiere mínimo mantenimiento y máxima resistencia. También excelente para espacios comerciales como consultas, farmacias, salones de belleza y showrooms. En entornos residenciales, este suelo vinílico Las Vegas transforma salones, cocinas y baños en espacios de alto standing. Su acabado brillo aporta distinción premium a cualquier hogar. Ventajas Principales Durabilidad comprobada: Resiste el tráfico intenso sin perder propiedades ni aspecto durante años. Estabilidad dimensional: No se expande ni contrae con cambios de temperatura o humedad. Fácil instalación: Se coloca rápidamente sobre superficies existentes, reduciendo tiempos de obra. Mantenimiento económico: Limpieza simple con productos habituales sin tratamientos especiales. Resistencia química: Tolera productos de limpieza profesionales y desinfectantes. Confort acústico: Reduce el ruido de pisadas creando ambientes más agradables. Especificaciones Técnicas Grosor: 2 mm para uso intensivo Acabado: Brillo lux elegante Tratamientos: Antibacteriano y fungicida Ancho de rollo: 150cm Composición: PVC de alta calidad Sostenibilidad: Sin disolventes ni metales pesados Normativas: Cumple estándares europeos CE Información de Compra y Medidas Precio indicado por metro cuadrado Formato disponible: Rollo de 150cm de ancho Ejemplos de corte personalizado: 1 metro lineal × 2 metros de ancho = 2 m² 3 metros lineales × 2 metros de ancho = 6 m² 5 metros lineales × 2 metros de ancho = 10 m² Cálculo de precio ejemplo: 2 m² × 19,20 €/m² = 38,40 € Corte Bajo Pedido - Condiciones Importantes Los cortes personalizados no admiten devoluciones ¿Necesitas medidas específicas para tu proyecto? Contáctanos para asesoramiento profesional: Email: ventas@disstands.com Nuestro equipo técnico te ayudará a calcular exactamente la cantidad de suelo vinílico Las Vegas que necesitas, optimizando el material y evitando desperdicios en tu instalación.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  19.20,
  1,
  'm²',
  true,
