INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '024271aa-0c04-43b5-8307-77d318f5ec56',
  'PVC Unidis',
  'suelo-vinilico-comercial-pvc-unidis',
  'El suelo vinílico comercial PVC Unidis es la solución de alto rendimiento ideal para espacios comerciales ligeros que necesitan durabilidad, higiene y fácil mantenimiento. Este suelo vinílico comercial combina resistencia excepcional con propiedades técnicas superiores. Por lo tanto, garantiza un...',
  'El suelo vinílico comercial PVC Unidis es la solución de alto rendimiento ideal para espacios comerciales ligeros que necesitan durabilidad, higiene y fácil mantenimiento. Este suelo vinílico comercial combina resistencia excepcional con propiedades técnicas superiores. Por lo tanto, garantiza un rendimiento óptimo en entornos profesionales exigentes. Estructura Resistente para Uso Comercial En primer lugar, este suelo vinílico comercial cuenta con una estructura robusta de 2 mm de espesor diseñada específicamente para soportar el tráfico diario. Además, incorpora una capa de uso resistente que protege contra el desgaste intensivo. Como resultado, mantiene su aspecto impecable incluso después de años de uso continuado. La construcción multicapa del PVC Unidis garantiza estabilidad dimensional y resistencia superior. Asimismo, esta estructura técnica proporciona confort acústico y amortiguación al caminar. Higiene y Seguridad Certificadas Por otro lado, este suelo vinílico comercial incluye importantes tratamientos sanitarios: Tratamiento antibacteriano: Inhibe el crecimiento de bacterias dañinas en la superficie. Por consiguiente, es perfecto para comercios alimentarios, farmacias y centros sanitarios. Protección fungicida: Previene la aparición de hongos y moho. De este modo, garantiza un ambiente higiénico constante. Acabado especial de limpieza: Facilita enormemente el mantenimiento diario. En consecuencia, reduce tiempo y costes de limpieza profesional. Superficie antideslizante: Proporciona seguridad incluso en zonas húmedas o con tráfico intenso. Igualmente, cumple con normativas de prevención de riesgos laborales. Resistencias Múltiples: Suelo Vinílico Comercial Completo Este suelo vinílico comercial ofrece resistencia certificada a múltiples factores: Resistencia al desgaste: Soporta el tráfico diario de clientes y empleados sin deterioro visible. Especialmente diseñado para comercios de tráfico ligero a moderado. Resistencia al fuego: Cumple con normativas europeas de seguridad contra incendios. Por lo tanto, es apropiado para instalaciones que requieren certificaciones específicas. Resistencia química: Tolera productos de limpieza profesionales y derrames accidentales. Asimismo, resiste desinfectantes y productos químicos habituales en entornos comerciales. Resistencia a la humedad: No se deteriora en ambientes húmedos ni con limpieza frecuente con agua. Compromiso Ecológico: Suelo Vinílico Comercial Sostenible El PVC Unidis es una opción ecológica certificada que respeta el medio ambiente: Libre de disolventes: No emite compuestos volátiles nocivos durante su vida útil. En consecuencia, contribuye a la calidad del aire interior. Sin metales pesados: Fabricado sin elementos tóxicos peligrosos. De este modo, protege la salud de empleados y clientes. Cumplimiento normativo: Satisface todas las normativas europeas de calidad, seguridad y medio ambiente. Igualmente, cuenta con certificaciones internacionales reconocidas. Aplicaciones Perfectas para Suelo Vinílico Comercial Este suelo vinílico comercial es especialmente adecuado para: Tiendas y boutiques: Proporciona una superficie elegante y fácil de mantener que realza los productos. Oficinas y despachos: Crea ambientes profesionales con mínimo mantenimiento y máxima durabilidad. Consultas médicas: Sus propiedades antibacterianas y fungicidas lo hacen ideal para entornos sanitarios. Farmacias: Combina higiene certificada con resistencia química a productos farmacéuticos. Peluquerías y centros estéticos: Resiste productos químicos y facilita la limpieza tras cada servicio. Pequeños comercios alimentarios: El tratamiento antibacteriano garantiza máxima higiene alimentaria. Zonas de recepción: Su aspecto profesional y durabilidad causan excelente primera impresión. Espacios de coworking: Soporta el tráfico constante manteniendo su apariencia impecable. Ventajas del Suelo Vinílico Comercial PVC Unidis Instalación eficiente: Fácil de instalar sobre diferentes superficies, reduciendo tiempos y costes. Mantenimiento económico: La limpieza diaria se realiza con productos convencionales. Por consiguiente, reduce costes operativos. Durabilidad comprobada: Mantiene sus propiedades técnicas y estéticas durante años. Asimismo, resiste el uso intensivo sin requerir tratamientos especiales. Confort acústico: Reduce el ruido de pisadas y ambiental. De este modo, mejora la experiencia de clientes y empleados. Estética profesional: Disponible en múltiples acabados que complementan cualquier diseño comercial. Inversión rentable: Su relación calidad-precio y larga vida útil lo convierten en una inversión inteligente. Especificaciones Técnicas Composición: PVC multicapa de alto rendimiento Espesor total: 2 mm para uso comercial ligero Capa de uso: Reforzada contra desgaste Tratamientos: Antibacteriano, fungicida y acabado especial Propiedades: Antideslizante, ignífugo, resistente químico Sostenibilidad: Sin disolventes ni metales pesados Normativas: Cumple regulaciones europeas CE Ancho de rollo: 2 metros para instalación eficiente Información de Compra y Medidas Precio indicado por metro cuadrado Formato disponible: Rollo de 2 metros de ancho Ejemplo de corte personalizado: 1 metro lineal × 2 metros de ancho = 2 m² 2 metros lineales × 2 metros de ancho = 4 m² 5 metros lineales × 2 metros de ancho = 10 m² Cálculo de precio ejemplo: 2 m² × 15,70 €/m² = 31,40 € Corte Bajo Pedido - Condiciones Importantes Los cortes personalizados no admiten devoluciones ¿Necesitas medidas específicas para tu comercio? Contáctanos para asesoramiento profesional: Email: ventas@disstands.com Nuestro equipo técnico te ayudará a calcular exactamente la cantidad de suelo vinílico comercial que necesitas. De este modo, optimizamos el material y evitamos desperdicios en tu instalación profesional.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
