INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a9daf4f4-9a10-4adf-869a-b94d90e2bff7',
  'PVC Artic',
  'pvc-artic',
  'Pavimento Vinílico Decorativo Efecto Damero o Chapa El pavimento vinílico decorativo efecto damero o chapa PVC Artic es una línea innovadora de suelos vinílicos pensada específicamente para aportar estilo, contraste visual y funcionalidad en espacios como stands feriales, tiendas comerciales, sho...',
  'Pavimento Vinílico Decorativo Efecto Damero o Chapa El pavimento vinílico decorativo efecto damero o chapa PVC Artic es una línea innovadora de suelos vinílicos pensada específicamente para aportar estilo, contraste visual y funcionalidad en espacios como stands feriales, tiendas comerciales, showrooms o viviendas creativas que buscan diferenciarse. Con su distintivo diseño en damero blanco y negro o llamativo efecto metálico de chapa, este pavimento vinílico decorativo ofrece un acabado visualmente impactante, fácil de instalar y mantener. Por tanto, resulta ideal para aplicaciones temporales o interiores con personalidad que requieren una solución rápida y eficaz. Características del Pavimento Vinílico Decorativo Este pavimento vinílico decorativo efecto damero destaca por su versatilidad y practicidad excepcional. Además, su formato en rollo permite cubrir grandes superficies sin juntas visibles, creando un efecto continuo y profesional. Asimismo, la instalación es sencilla y no requiere obras ni adhesivos permanentes en muchas aplicaciones, lo que reduce tiempos y costes. En consecuencia, es perfecto para eventos, ferias comerciales, pop-up stores o renovaciones rápidas de espacios comerciales. La superficie del PVC Artic con efecto damero o chapa es resistente al desgaste cotidiano y fácil de limpiar con productos convencionales. Posteriormente, si necesitas actualizar el diseño de tu espacio, el desmontaje es igualmente sencillo. El efecto visual del damero blanco y negro aporta un toque clásico y elegante, mientras que la versión con efecto metálico crea ambientes más modernos e industriales. Consulta nuestras moquetas para eventos como complemento. Información de Compra y Medidas Precio indicado por metro cuadrado. Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 11,05 €/m² = 22,10 € Corte bajo pedido Los cortes se realizan según las necesidades específicas de cada cliente y no admiten devoluciones debido a su naturaleza personalizada. Para solicitar medidas personalizadas, presupuestos o resolver cualquier consulta técnica sobre instalación y compatibilidad con tu proyecto, escríbenos directamente a: moquetas@disstands.com Nuestro equipo técnico te asesorará sobre la mejor solución para tu espacio, garantizando resultados profesionales y duraderos. Descubre también nuestros accesorios para instalación.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  11.05,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
