INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '6fcbf4d2-33c3-4201-878b-d171c03e0dd1',
  'PVC Imitación Cemento',
  'pvc-imitacion-cemento',
  'Suelo Vinílico Imitación Cemento: Estética Industrial con Máxima Funcionalidad El suelo vinílico imitación cemento es una excelente alternativa para quienes desean un acabado industrial y contemporáneo sin complicaciones. Su apariencia realista en tonos gris claro u oscuro ofrece una solución est...',
  'Suelo Vinílico Imitación Cemento: Estética Industrial con Máxima Funcionalidad El suelo vinílico imitación cemento es una excelente alternativa para quienes desean un acabado industrial y contemporáneo sin complicaciones. Su apariencia realista en tonos gris claro u oscuro ofrece una solución estética moderna que combina perfectamente con estilos minimalistas, urbanos o nórdicos. Este revestimiento vinílico destaca por su alta resistencia al uso doméstico intensivo, ideal para viviendas, oficinas o espacios comerciales que requieren durabilidad y bajo mantenimiento. Su espesor reforzado de 2,40 mm y una capa de uso de 0,35 mm garantizan una larga vida útil, incluso en zonas de mucho tránsito. Además, el suelo vinílico imitación cemento es una opción higiénica y práctica. Su superficie es completamente lavable, resistente a la humedad y fácil de instalar. Esto lo convierte en la solución ideal para reformas rápidas, ya que puede colocarse sobre suelos existentes sin necesidad de obras complicadas. El diseño de cemento aporta una estética sobria y elegante, sin el peso, la porosidad ni el mantenimiento que requiere el cemento auténtico. Este suelo vinílico combina lo mejor de ambos mundos: la belleza del cemento y las prestaciones técnicas del vinilo de alta calidad. Ejemplo de corte:1 metro lineal x 2 metros de ancho = 2 m²2 m² x 16,84 €/m² = 33,68 € Corte bajo pedido. No se admiten devoluciones. Para medidas personalizadas, escríbenos a: ventas@disstands.com',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  16.84,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
