INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'dc4d48bc-97a5-4285-8773-b3bd58e16d40',
  'Moqueta Velour Lumdis 600',
  'moqueta-impresa-personalizada-ferias-las-vegas-lumdis-600',
  'La moqueta impresa personalizada Las Vegas Lumdis 600 es la solución perfecta para empresas que buscan destacar en ferias comerciales, eventos corporativos y espacios retail con diseños únicos y personalizados. Esta moqueta impresa con tecnología de impresión digital de alta definición permite re...',
  'La moqueta impresa personalizada Las Vegas Lumdis 600 es la solución perfecta para empresas que buscan destacar en ferias comerciales, eventos corporativos y espacios retail con diseños únicos y personalizados. Esta moqueta impresa con tecnología de impresión digital de alta definición permite reproducir logotipos, imágenes, patrones y diseños corporativos con una calidad excepcional y colores vibrantes que captan la atención de tu público. Fabricada en poliamida de alta calidad con pelo cortado, la moqueta Las Vegas Lumdis 600 está especialmente diseñada para soportar alto tránsito de personas, lo que la convierte en la opción ideal para stands feriales, eventos temporales, showrooms, tiendas y espacios comerciales donde la resistencia y la estética son fundamentales. Su construcción robusta garantiza durabilidad incluso en las condiciones más exigentes de uso intensivo. Una de las principales ventajas de esta moqueta personalizada para ferias es su formato en rollos de 4 metros de ancho, que permite cubrir grandes superficies minimizando las juntas y logrando un acabado profesional y continuo. Además, cuenta con la opción de base antideslizante, proporcionando mayor seguridad para visitantes y expositores, cumpliendo con las normativas de seguridad en eventos. La instalación de la moqueta Las Vegas Lumdis 600 es rápida y sencilla, perfecta para montajes feriales con tiempos ajustados. Su mantenimiento es mínimo y los colores permanecen vivos incluso después de múltiples usos, lo que la convierte en una inversión rentable para empresas que participan regularmente en eventos. Esta moqueta impresa es ideal para branding corporativo, lanzamientos de productos, congresos, convenciones, tiendas pop-up, escaparates y cualquier espacio donde necesites comunicar tu identidad visual de forma impactante. La personalización total te permite crear ambientes únicos que refuerzan tu imagen de marca y generan experiencias memorables para tus clientes.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  47.00,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
