INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'fa3fc1b4-c36a-45d4-8e8e-0500c5be045f',
  'Moqueta Ferial Impresa Personalizable',
  'moqueta-ferial-personalizada',
  'La solución profesional para eventos con imagen de marca impecable La Moqueta Ferial con trasera gris es la elección ideal para eventos que exigen personalización total y acabado premium. Fabricada sobre fondo blanco de alta calidad, permite imprimir cualquier diseño: desde logotipos corporativos...',
  'La solución profesional para eventos con imagen de marca impecable La Moqueta Ferial con trasera gris es la elección ideal para eventos que exigen personalización total y acabado premium. Fabricada sobre fondo blanco de alta calidad, permite imprimir cualquier diseño: desde logotipos corporativos hasta gráficos complejos en colores Pantone exactos. Esta moqueta se ha convertido en el estándar de la industria para empresas y organizadores que buscan diferenciarse y crear experiencias memorables desde el primer momento. Personalización sin límites para tu marca Cada evento es único, y tu suelo también debería serlo. Con nuestra moqueta ferial personalizable, puedes plasmar la identidad visual completa de tu empresa o evento. Admite cualquier tipo de diseño: logotipos en alta resolución, patrones corporativos, fotografías, ilustraciones y combinaciones de colores específicas según tu carta Pantone. El fondo blanco garantiza que los colores se reproduzcan con máxima fidelidad y brillo, creando un impacto visual potente que capta la atención de los visitantes. Versatilidad para cualquier evento: Perfecta para ferias comerciales, congresos internacionales, stands personalizados, pasarelas de moda, presentaciones corporativas, lanzamientos de producto, showrooms temporales y eventos promocionales de cualquier escala. Su adaptabilidad la convierte en la opción preferida tanto para pequeños espacios boutique como para grandes superficies expositivas. Ventajas principales: Impresión directa de alta definición que garantiza colores vívidos y duraderos incluso con tráfico intenso Base estable con trasera gris antideslizante para máxima seguridad de visitantes y expositores Instalación rápida y sencilla sin necesidad de especialistas ni herramientas complejas Personalización 100% adaptada a tu identidad corporativa y necesidades específicas del evento Material resistente y reutilizable para múltiples eventos, optimizando tu inversión Fácil transporte y almacenamiento gracias a su flexibilidad y peso reducido Calidad técnica que marca la diferencia La tecnología de impresión directa utilizada asegura una reproducción exacta de tu diseño, con colores brillantes que no se decoloran ni pierden intensidad durante el evento. La trasera gris proporciona estabilidad adicional y evita deslizamientos, cumpliendo con los estándares de seguridad más exigentes para espacios con alto tránsito de personas. Plazo de entrega: 3-5 días laborables Presupuesto personalizado: Envía un correo con las medidas y diseño requerido Convierte tu espacio en una experiencia visual que refuerza tu marca desde el primer paso.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
