INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e21e0fd4-7608-4e20-82a7-c0e013070a64',
  'Césped Bredis 30MM',
  'cesped-artificial-ligero-paisajismo',
  'Césped Artificial Ligero Paisajismo: Bredis 30mm El césped artificial ligero paisajismo Bredis es una solución funcional y equilibrada, perfecta para quienes buscan un producto estético, resistente y fácil de instalar en proyectos residenciales o decorativos. Este césped artificial ligero combina...',
  'Césped Artificial Ligero Paisajismo: Bredis 30mm El césped artificial ligero paisajismo Bredis es una solución funcional y equilibrada, perfecta para quienes buscan un producto estético, resistente y fácil de instalar en proyectos residenciales o decorativos. Este césped artificial ligero combina una altura de 30 mm con densidad uniforme de fibras PE+PP (polietileno y polipropileno), ofreciendo un acabado natural que se adapta tanto a jardines privados como a zonas decorativas de bajo o medio tránsito. Además, es cómodo al pisar y está fabricado conforme a la estricta normativa europea REACH. Composición y Acabado Natural La combinación de fibras de polietileno (PE) y polipropileno (PP) proporciona al césped ligero para paisajismo Bredis el equilibrio perfecto entre suavidad visual y resistencia estructural. Por tanto, el polietileno aporta apariencia natural y tacto agradable, mientras que el polipropileno garantiza durabilidad y recuperación tras el pisado. Asimismo, la altura de 30 mm crea un efecto volumétrico realista sin comprometer la facilidad de mantenimiento. Seguridad y Certificaciones Este césped artificial paisajismo cumple rigurosamente con la normativa REACH sobre sustancias químicas. En consecuencia, está completamente libre de plomo y cadmio, garantizando máxima seguridad para contacto humano y presencia de mascotas. Además, su buena resistencia a los rayos UV protege contra la decoloración solar, manteniendo el color verde natural durante años de exposición exterior. Instalación y Aplicaciones Versátiles Bredis destaca por su sencillez de instalación, permitiendo transformar rápidamente cualquier espacio en un área verde atractiva. Posteriormente, su mantenimiento es mínimo: no requiere riego, corte ni fertilizantes. Por tanto, resulta ideal para jardines privados, terrazas, zonas decorativas, áreas perimetrales y espacios con tránsito bajo o medio donde se busca estética natural sin las exigencias del césped tradicional. Su ligereza facilita el transporte e instalación, mientras que su densidad uniforme garantiza un aspecto homogéneo y profesional. Finalmente, ofrece comodidad al caminar descalzo, convirtiéndolo en la elección inteligente para proyectos residenciales que combinan funcionalidad con belleza natural.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
