INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'cb74ed9a-77b0-4277-8d15-6732cce9f969',
  'Césped Danudis 40MM',
  'danudis-cesped-premium',
  'El modelo Danudis ha sido desarrollado para quienes buscan un césped artificial con acabados de alta gama y prestaciones excepcionales. Con una altura de pelo de 40 mm y una densidad extraordinaria de 24.000 puntadas/m², ofrece una cobertura visual impresionante y un tacto extraordinariamente sua...',
  'El modelo Danudis ha sido desarrollado para quienes buscan un césped artificial con acabados de alta gama y prestaciones excepcionales. Con una altura de pelo de 40 mm y una densidad extraordinaria de 24.000 puntadas/m², ofrece una cobertura visual impresionante y un tacto extraordinariamente suave que replica fielmente el césped natural. Características técnicas superiores La combinación de 40 mm de altura con la máxima densidad del mercado crea un efecto visual y táctil incomparable: Realismo excepcional con movimiento natural de las fibras Pisada mullida y confortable ideal para zonas de descanso Cobertura total sin calvas ni zonas visibles de base Recuperación elástica que mantiene las fibras erguidas Aspecto exuberante durante todo el año sin mantenimiento Durabilidad y resistencia garantizadas Su estructura incorpora tecnología avanzada para máxima durabilidad: Sistema de drenaje eficiente de 60 litros/minuto/m² Resistencia UV certificada que previene la decoloración Fibras con memoria que resisten el aplastamiento Base permeable que evita encharcamientos Garantía de 8 años contra degradación solar Seguridad y sostenibilidad Danudis cumple los más estrictos estándares de seguridad: Libre de plomo y cadmio certificado Sin sustancias tóxicas para niños y mascotas Materiales reciclables en su composición Tratamiento antibacteriano opcional disponible Certificaciones europeas de seguridad infantil Aplicaciones ideales Perfecto para: Jardines residenciales de alto standing Áreas de piscina con tráfico intenso Zonas infantiles que requieren máxima seguridad Terrazas y áticos urbanos premium Paisajismo comercial de espacios exclusivos Instalación y mantenimiento La instalación profesional garantiza resultados óptimos con mínimo mantenimiento posterior. Solo requiere cepillado ocasional y riego esporádico para mantener su frescura. Su estructura robusta soporta mobiliario de jardín sin deformaciones permanentes. El césped Danudis representa la perfecta fusión entre naturaleza y tecnología, ofreciendo un espacio verde permanente que combina belleza natural con prestaciones técnicas superiores para los proyectos más exigentes.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
