INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1bd6cd89-e1dc-4c7e-8ff6-6081b2563774',
  'Césped Viserdis 45MM',
  'cesped-artificial-premium-paisajismo-viserdis-45mm',
  'El césped artificial premium paisajismo Viserdis representa la excelencia para proyectos profesionales. Está diseñado específicamente para quienes no admiten concesiones en calidad. De hecho, este modelo de gama alta se ha convertido en la elección preferida de arquitectos y paisajistas. Además, ...',
  'El césped artificial premium paisajismo Viserdis representa la excelencia para proyectos profesionales. Está diseñado específicamente para quienes no admiten concesiones en calidad. De hecho, este modelo de gama alta se ha convertido en la elección preferida de arquitectos y paisajistas. Además, particulares exigentes lo eligen para transformar sus espacios exteriores en áreas verdes impecables durante todo el año. Tecnología avanzada en césped artificial premium Con sus 45 mm de altura y fibra de alta carga, Viserdis ofrece una densidad excepcional. Como resultado, logra una apariencia voluminosa, frondosa y sorprendentemente natural. Su tacto suave y sedoso simula a la perfección el césped natural recién cortado. Sin embargo, no requiere ninguno de los cuidados que este demanda. Por otro lado, la composición bicomponente en polietileno y polipropileno ha sido cuidadosamente equilibrada. El PE aporta suavidad y resistencia al pisado. Mientras tanto, el PP proporciona estructura y memoria de fibra. Esto garantiza que el césped recupere su posición vertical incluso tras uso intensivo. Resistencia superior para proyectos de paisajismo Este césped está preparado para soportar las condiciones más exigentes. En primer lugar, su sistema de drenaje perforado de alta capacidad evacúa el agua rápidamente. Por lo tanto, evita encharcamientos incluso en episodios de lluvia intensa. Asimismo, los estabilizadores UV de última generación protegen las fibras contra la degradación solar. Consecuentemente, mantiene el color verde vibrante y las propiedades mecánicas intactas año tras año. Aplicaciones para césped artificial premium paisajismo Viserdis es la solución ideal para múltiples aplicaciones profesionales. Por ejemplo, jardines residenciales de alto standing y terrazas con tránsito frecuente. También es perfecto para áreas decorativas comerciales y zonas perimetrales de piscinas. Finalmente, destaca en proyectos de interiorismo verde donde la belleza y funcionalidad deben ir de la mano. En definitiva, Viserdis transforma cada proyecto en un oasis verde de mantenimiento mínimo y disfrute máximo.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
