INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '10bd6bfa-11f1-47e5-8d5a-d50c4a252300',
  'Césped Elbedis 22MM',
  'cesped-artificial-decorativo-elbe',
  'Césped Artificial Decorativo Elbe: Solución Premium de 22mm El césped artificial decorativo Elbe de 22 mm está especialmente diseñado para proyectos de paisajismo decorativo que requieren estética natural y funcionalidad duradera. Este césped artificial decorativo combina polietileno y polipropil...',
  'Césped Artificial Decorativo Elbe: Solución Premium de 22mm El césped artificial decorativo Elbe de 22 mm está especialmente diseñado para proyectos de paisajismo decorativo que requieren estética natural y funcionalidad duradera. Este césped artificial decorativo combina polietileno y polipropileno de alta calidad para crear una superficie ligera, resistente y visualmente uniforme. Además, con más de 13.000 puntadas por metro cuadrado, garantiza densidad superior y aspecto natural excepcional que imita perfectamente el césped natural. Composición Técnica del Césped Decorativo Elbe La composición dual de polietileno y polipropileno del césped artificial Elbe ofrece ventajas significativas para cualquier proyecto paisajístico. Por tanto, el polietileno aporta suavidad táctil y apariencia natural realista, mientras que el polipropileno proporciona resistencia estructural y durabilidad a largo plazo. Asimismo, el respaldo drenante eficiente permite evacuación rápida del agua de lluvia, evitando encharcamientos problemáticos y facilitando notablemente el mantenimiento rutinario. En consecuencia, resulta ideal para climas húmedos, zonas con precipitaciones frecuentes o áreas propensas a retención de agua. Seguridad y Certificaciones Europeas Este césped decorativo de 22mm cumple rigurosamente con la estricta normativa europea REACH sobre sustancias químicas. Además, está completamente libre de plomo y cadmio, garantizando máxima seguridad para contacto humano directo y presencia de animales domésticos. Por tanto, es perfecto para jardines residenciales, zonas infantiles, terrazas urbanas y espacios exteriores de uso familiar donde la seguridad es prioritaria. Durabilidad y Resistencia UV Garantizada La estabilidad UV certificada de hasta 8 años protege el césped artificial decorativo Elbe contra la decoloración solar progresiva. Posteriormente, mantiene su color verde natural intenso y vivacidad original incluso bajo exposición solar intensa, constante y prolongada durante años. Asimismo, la alta densidad de 13.000 puntadas por metro cuadrado garantiza excelente resistencia al pisoteo ocasional y uso esporádico sin deformarse, aplastarse ni perder su aspecto estético. Aplicaciones Ideales para Paisajismo Perfecto para paisajismo decorativo profesional, jardines residenciales de bajo mantenimiento, espacios exteriores con uso esporádico, zonas perimetrales ornamentales, áreas de exhibición y proyectos arquitectónicos donde prima la estética natural con mínimo mantenimiento. Su altura equilibrada de 22mm proporciona apariencia realista convincente sin requerir cuidados intensivos ni recursos hídricos.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
