INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '5c3db1d5-457b-4be6-8912-b6a8bf3ba991',
  'Moqueta Las Vegas - Domésticos',
  'moqueta-las-vegas-domestica',
  'Moqueta Las Vegas: Elegancia y Confort para tu Hogar La Moqueta Las Vegas combina elegancia y funcionalidad para transformar cualquier espacio de tu hogar. Con una superficie lisa de poliamida y un reverso Action Back, es ideal para quienes buscan confort, resistencia y una estética impecable en ...',
  'Moqueta Las Vegas: Elegancia y Confort para tu Hogar La Moqueta Las Vegas combina elegancia y funcionalidad para transformar cualquier espacio de tu hogar. Con una superficie lisa de poliamida y un reverso Action Back, es ideal para quienes buscan confort, resistencia y una estética impecable en instalaciones permanentes. Su versatilidad la convierte en la solución perfecta para dormitorios, salones, despachos domésticos y cualquier estancia donde se valore el bienestar y el diseño. Confort Diario en tu Hogar Esta moqueta está especialmente diseñada para el uso doméstico, proporcionando una pisada suave y agradable que mejora significativamente el confort de tu vivienda. Su superficie de poliamida ofrece una textura lisa y sedosa al tacto, creando un ambiente acogedor y cálido en cualquier habitación. El sistema Action Back garantiza estabilidad dimensional y una instalación sencilla, características fundamentales para proyectos de reforma o decoración del hogar. Durabilidad para el Día a Día La resistencia de la Moqueta Las Vegas la hace perfecta para el tránsito habitual de una vivienda, manteniendo su aspecto impecable incluso en zonas de paso frecuente como pasillos o escaleras. Su composición de poliamida asegura una larga vida útil, resistiendo el desgaste diario y facilitando el mantenimiento rutinario. Además, proporciona aislamiento térmico y acústico, contribuyendo al confort general de tu hogar. Versatilidad Decorativa Esta moqueta se adapta perfectamente a diferentes estilos decorativos, desde ambientes clásicos hasta diseños contemporáneos. Su acabado elegante aporta distinción y calidez a cualquier estancia, convirtiéndose en el complemento ideal para crear espacios acogedores donde disfrutar en familia. Información de Compra Precio indicado por metro cuadrado: 13,75 €/m² (IVA no incluido) Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 13,75 €/m² = 27,50 € Importante: Los cortes personalizados no admiten devoluciones. Para medidas personalizadas, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
