INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'd4eb92b9-3ef4-4108-83d5-e82583db1ee8',
  'Moqueta Oceadis',
  'moqueta-oceadis',
  'Moqueta Oceadis: Diseño Elegante y Sostenibilidad Oceadis es una moqueta de diseño elegante y textura suave. Está fabricada con 100% poliamida mediante técnica tufting velour 1/10". Además, destaca por su base en juta sintética y excelente absorción acústica. Por ello, se convierte en una solució...',
  'Moqueta Oceadis: Diseño Elegante y Sostenibilidad Oceadis es una moqueta de diseño elegante y textura suave. Está fabricada con 100% poliamida mediante técnica tufting velour 1/10". Además, destaca por su base en juta sintética y excelente absorción acústica. Por ello, se convierte en una solución funcional y estética para espacios interiores exigentes. Esta moqueta es reciclable y cuenta con bajas emisiones VOC (clase A+). Asimismo, ofrece un acabado refinado y moderno. Por tanto, es ideal para entornos residenciales y comerciales que valoran la sostenibilidad. Características Técnicas Destacadas La técnica tufting velour 1/10" garantiza una superficie uniforme y densa. Como resultado, obtienes una moqueta resistente al desgaste diario. Su composición de poliamida proporciona durabilidad excepcional y facilidad de mantenimiento. La base de juta sintética ofrece estabilidad dimensional superior. Además, facilita la instalación en diversos tipos de superficies. Esta característica la hace versátil para múltiples proyectos de decoración. Confort Acústico y Seguridad Oceadis destaca por su excelente absorción acústica. En consecuencia, reduce significativamente el ruido entre estancias. Esto crea ambientes más tranquilos y confortables en tu hogar u oficina. Su baja carga electrostática es otra ventaja importante. Por ello, minimiza las descargas eléctricas molestas. Esta propiedad mejora el confort diario, especialmente en climas secos. Compromiso Medioambiental Esta moqueta es 100% reciclable al final de su vida útil. Además, cuenta con certificación de bajas emisiones VOC clase A+. Por tanto, garantiza un ambiente interior saludable y libre de compuestos orgánicos volátiles nocivos. Aplicaciones Ideales Oceadis es perfecta para dormitorios, salones, despachos y oficinas. También es excelente para espacios comerciales que requieren elegancia y funcionalidad. Su acabado moderno se adapta a diferentes estilos decorativos. Información de Compra Precio: 22,97 €/m² (IVA no incluido) Ejemplo de cálculo: Si necesitas una pieza de 1 metro de largo x 2 metros de ancho: 1 m x 2 m = 2 m² 2 m² x 22,97 €/m² = 45,94 € Importante: Los cortes personalizados no admiten devoluciones. Para medidas personalizadas o asesoramiento técnico, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
