INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '732c7f35-fb4c-4496-8c35-9744ff5b30b5',
  'Moqueta Nobledis',
  'nobledis',
  'Nobledis es una moqueta de pelo cortado tipo saxony, reconocida por su suavidad, densidad y apariencia elegante. Fabricada con 100% poliamida y una estructura robusta en Actionbac, ofrece un acabado de alta gama ideal para interiores sofisticados. Con un espesor total de 11 mm y una densidad supe...',
  'Nobledis es una moqueta de pelo cortado tipo saxony, reconocida por su suavidad, densidad y apariencia elegante. Fabricada con 100% poliamida y una estructura robusta en Actionbac, ofrece un acabado de alta gama ideal para interiores sofisticados. Con un espesor total de 11 mm y una densidad superior a 161.000 puntos/m², es la elección preferida en el sector hotelero para revestir dormitorios, gracias a su confort, estética y resistencia al uso. Esta moqueta destaca por su construcción técnica superior, donde cada fibra ha sido cuidadosamente tratada para proporcionar una pisada mullida y confortable. El pelo tipo saxony, característico por sus fibras cortadas y retorcidas, crea una superficie uniforme y aterciopelada que aporta calidez visual y táctil a cualquier espacio. La base Actionbac garantiza estabilidad dimensional y durabilidad excepcional, elementos fundamentales para instalaciones de alto tránsito. Su certificación ignífuga Cfl-s1 la convierte en una solución segura para proyectos contract, cumpliendo con las normativas más exigentes del sector. Además, su clasificación A+ en emisiones al aire interior asegura un ambiente saludable, libre de compuestos orgánicos volátiles nocivos. Estas características técnicas, combinadas con su estética refinada, posicionan a Nobledis como una opción premium para hoteles de categoría superior, residencias de lujo y espacios corporativos exclusivos. Precio indicado por metro cuadrado. Ejemplo de corte:1 metro lineal x 2 metros de ancho = 2 m²2 m² x 23,80 €/m² = 47,60 € Los cortes no admiten devoluciones.Para medidas personalizadas, escríbenos a: ventas@disstands.com Bajo pedido',
