INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '0c1287a7-5fd5-4408-81d3-1b58e52b452e',
  'Moqueta Nexdis',
  'moqueta-nexdis-velours-poliamida',
  'Moqueta Nexdis: Tecnología y Elegancia en Pelo Cortado Velours Nexdis es una moqueta de pelo cortado tipo velours, fabricada con tecnología tufting 5/64" y compuesta por fibras 100% poliamida 6.6 de alto rendimiento. Su soporte de juta sintética y su elevada densidad de puntadas garantizan una ex...',
  'Moqueta Nexdis: Tecnología y Elegancia en Pelo Cortado Velours Nexdis es una moqueta de pelo cortado tipo velours, fabricada con tecnología tufting 5/64" y compuesta por fibras 100% poliamida 6.6 de alto rendimiento. Su soporte de juta sintética y su elevada densidad de puntadas garantizan una excelente resistencia al desgaste, aislamiento acústico y confort bajo los pies. Con una altura total de 8 mm y acabados certificados, es ideal para aplicaciones tanto residenciales como contract que requieren estética elegante y durabilidad profesional. Tecnología de Fabricación Superior La tecnología tufting 5/64" empleada en la fabricación de Nexdis asegura una distribución uniforme de las fibras, creando una superficie homogénea y densa que resiste el uso intensivo sin perder su apariencia original. Las fibras de poliamida 6.6 representan la más alta calidad en materiales sintéticos para revestimientos textiles, ofreciendo una resistencia excepcional a la abrasión, excelente recuperación tras la compresión y facilidad de mantenimiento a largo plazo. El soporte de juta sintética proporciona estabilidad dimensional superior, evitando deformaciones y garantizando que la moqueta mantenga su forma y características técnicas durante toda su vida útil. Esta base robusta facilita además la instalación, tanto en proyectos domésticos como en grandes superficies comerciales. Confort y Funcionalidad La moqueta Nexdis destaca por su capacidad de aislamiento acústico, reduciendo significativamente la transmisión de ruidos entre plantas y creando ambientes más silenciosos y confortables. Su textura tipo velours ofrece una pisada suave y agradable, aportando calidez táctil y visual a cualquier espacio. Con 8 mm de altura total, proporciona el equilibrio perfecto entre confort y practicidad, siendo suficientemente mullida sin dificultar el tránsito o el movimiento de mobiliario. Aplicaciones Versátiles Esta moqueta es perfecta para dormitorios, salones, despachos, hoteles, oficinas, salas de reuniones y cualquier espacio que requiera un revestimiento de calidad profesional. Su estética refinada y sus prestaciones técnicas la convierten en una solución integral para proyectos exigentes donde se valora tanto la durabilidad como la apariencia impecable. Información de Compra Precio indicado por metro cuadrado: 29,85 €/m² (IVA no incluido) Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 29,85 €/m² = 59,70 € Importante: Los cortes personalizados no admiten devoluciones. Para medidas personalizadas o consultas técnicas, escríbenos a: ventas@disstands.com',
