INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7b3ca705-ba6b-44ff-835b-03bdbecc8abb',
  'Moqueta Erodis',
  'moqueta-erodis-velluto',
  'Moqueta Erodis: Lujo y Confort en Velluto de Alta Gama Erodis es una moqueta tipo velluto de alta gama. Ofrece un equilibrio perfecto entre suavidad, resistencia y elegancia. Además, está fabricada con 100% poliamida extra soft y construida con tecnología tufted cut pile 1/10". Por ello, proporci...',
  'Moqueta Erodis: Lujo y Confort en Velluto de Alta Gama Erodis es una moqueta tipo velluto de alta gama. Ofrece un equilibrio perfecto entre suavidad, resistencia y elegancia. Además, está fabricada con 100% poliamida extra soft y construida con tecnología tufted cut pile 1/10". Por ello, proporciona una textura lujosa al tacto y una apariencia refinada. Esta moqueta es ideal para entornos domésticos exigentes. También es perfecta para espacios comerciales que requieran confort visual y acústico. Su base de juta sintética, junto a su excelente rendimiento térmico y acústico, la convierten en una solución versátil y sostenible. Tecnología y Materiales Premium La tecnología tufted cut pile 1/10" garantiza una densidad excepcional. Asimismo, crea una distribución uniforme de las fibras. Como resultado, obtienes una superficie homogénea de aspecto aterciopelado. La poliamida extra soft representa el más alto estándar en fibras sintéticas. Por tanto, ofrece una suavidad incomparable sin comprometer la resistencia. Esta combinación resulta en una moqueta que mantiene su apariencia impecable durante años. El soporte de juta sintética proporciona estabilidad dimensional. Además, facilita la instalación en diversos proyectos. Esta base robusta evita deformaciones y garantiza durabilidad a largo plazo. Confort Sensorial y Funcional La moqueta Erodis destaca por su extraordinaria capacidad de aislamiento acústico. En consecuencia, reduce significativamente la transmisión de ruidos entre estancias. Esto contribuye a crear ambientes más tranquilos y privados. Su rendimiento térmico superior ayuda a mantener una temperatura agradable. Por ello, reduce pérdidas de calor y mejora la eficiencia energética del espacio. La textura tipo velluto ofrece una pisada mullida y envolvente. De esta manera, proporciona una experiencia táctil de máximo confort. Esta característica la hace ideal para dormitorios principales, salones de estar y bibliotecas domésticas. Aplicaciones y Versatilidad Esta moqueta premium es perfecta para viviendas de alto standing. También es excelente para hoteles boutique, despachos ejecutivos y salas VIP. Su estética sofisticada la posiciona como una solución integral donde se valora la excelencia en diseño. Información de Compra Precio: 38,49 €/m² (IVA no incluido) Ejemplo de cálculo: Si necesitas una pieza de 1 metro de largo x 2 metros de ancho: 1 m x 2 m = 2 m² 2 m² x 38,49 €/m² = 76,98 € Importante: Los cortes personalizados no admiten devoluciones. Para medidas personalizadas o asesoramiento técnico, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
