INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '722f07ec-1265-4c5b-8742-9cac2cb634d8',
  'Moqueta Dividis',
  'moqueta-dividis-velours-poliamida',
  'Moqueta Dividis Velours Poliamida: Calidad Premium La moqueta Dividis velours poliamida es una solución de alta gama con textura aterciopelada. Está fabricada con 100% poliamida 6 mediante técnica tufting velours 5/64". Además, ofrece un equilibrio perfecto entre confort, durabilidad y diseño ele...',
  'Moqueta Dividis Velours Poliamida: Calidad Premium La moqueta Dividis velours poliamida es una solución de alta gama con textura aterciopelada. Está fabricada con 100% poliamida 6 mediante técnica tufting velours 5/64". Además, ofrece un equilibrio perfecto entre confort, durabilidad y diseño elegante para espacios exigentes. Esta moqueta Dividis velours poliamida es ideal para múltiples aplicaciones. Por tanto, funciona perfectamente tanto en hogares como en espacios comerciales de alto tránsito. Especificaciones Técnicas Premium La moqueta Dividis velours poliamida cuenta con una densidad excepcional de 300.000 puntos por metro cuadrado. Como resultado, proporciona una superficie uniforme y resistente al desgaste intensivo. Su altura de pelo de 9,5 mm ofrece una pisada mullida y confortable. El peso de fibra de 1.725 g/m² garantiza una calidad superior. Además, el peso total de 2.470 g/m² asegura robustez y durabilidad a largo plazo. Estas características técnicas posicionan a Dividis como una opción premium. Base y Estabilidad Su base de juta sintética mejora considerablemente la estabilidad dimensional. Por ello, facilita la instalación en diversos tipos de superficies. Esta característica la hace versátil para proyectos residenciales y comerciales. La altura total de 12 mm proporciona el grosor perfecto. En consecuencia, ofrece confort sin complicar el tránsito. Confort Acústico y Térmico Esta moqueta presenta excelentes propiedades de aislamiento acústico (ΔLw 30 dB). Por tanto, reduce significativamente la transmisión de ruidos entre plantas. Esto crea ambientes más tranquilos. Su resistencia térmica de 0,17 m²K/W ayuda a mantener la temperatura. Además, la absorción acústica de 0,20 W mejora el confort general. Sostenibilidad y Seguridad La moqueta Dividis velours poliamida es completamente reciclable. Asimismo, cuenta con certificación A+ en emisiones de compuestos volátiles. Por ello, garantiza un ambiente interior saludable. La certificación ignífuga Cfl-s1 cumple con las normativas más exigentes. En consecuencia, es perfecta para proyectos contract. Aplicaciones Versátiles Esta moqueta es ideal para hoteles, oficinas, salas de reuniones y dormitorios. También funciona perfectamente en salones y despachos. Su ancho de rollo de 400 cm facilita la instalación en grandes superficies. Información de Compra Para consultar precio, disponibilidad o medidas personalizadas, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
