INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '86c76a21-d426-4972-806d-fb40df8b9efb',
  'Moquetas Montecadis',
  'moqueta-lana-natural-premium',
  'Moqueta de Lana Natural Premium: Lujo y Confort Excepcional La moqueta de lana natural premium Montecadis representa la máxima expresión del lujo y confort en revestimientos textiles de alta gama. Esta moqueta de lana natural combina a la perfección un 90% de lana natural con un 10% de poliéster,...',
  'Moqueta de Lana Natural Premium: Lujo y Confort Excepcional La moqueta de lana natural premium Montecadis representa la máxima expresión del lujo y confort en revestimientos textiles de alta gama. Esta moqueta de lana natural combina a la perfección un 90% de lana natural con un 10% de poliéster, logrando un equilibrio ideal entre suavidad suprema, resistencia estructural y durabilidad a largo plazo. Además, fabricada mediante la técnica tufting velluto 1/8", garantiza calidad superior en cada detalle. Acabado y Propiedades de la Moqueta Premium Su elegante acabado de pelo cortado, con una altura de 6,3 mm, crea una superficie uniforme que aporta calidez y sofisticación a cualquier espacio residencial o comercial. Por tanto, el respaldo de yute sintético garantiza estabilidad dimensional y resistencia excepcional. Asimismo, su densidad extraordinaria de 126.000 puntos por metro cuadrado asegura una textura excepcionalmente rica, consistente y duradera que mantiene su aspecto impecable durante años. Aislamiento Acústico y Térmico Superior La moqueta premium de lana natural Montecadis no solo destaca por su estética refinada, sino también por sus extraordinarias propiedades funcionales. En consecuencia, ofrece un excelente aislamiento acústico de 32 dB que reduce significativamente el ruido ambiental. Además, proporciona aislamiento térmico superior, contribuyendo notablemente al confort ambiental y eficiencia energética. Su certificación A+ en emisiones de compuestos orgánicos volátiles garantiza un impacto mínimo en la calidad del aire interior, protegiendo la salud de los ocupantes. Aplicaciones de Alto Standing Disponible en un generoso ancho de 400 cm, esta moqueta de lana natural premium es la elección perfecta para proyectos residenciales de alto standing, hoteles boutique, oficinas ejecutivas, despachos profesionales y cualquier entorno donde se busque combinar elegancia atemporal con prestaciones técnicas superiores y confort excepcional. Información de Compra Precio indicado por metro cuadrado. Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 40,02 €/m² = 80,04 € Los cortes no admiten devoluciones. Para medidas personalizadas, escríbenos a: ventas@disstands.com o llama al 934 850 085.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  40.02,
