INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ce8dfd87-7640-4aae-8ae0-fd23229952c6',
  'Moqueta Deadis',
  'moqueta-deadis',
  'La moqueta Deadis poliamida es la elección perfecta para espacios residenciales que buscan combinar elegancia, confort y durabilidad excepcional. Esta moqueta Deadis poliamida fabricada mediante técnica tufting ofrece una experiencia táctil superior. Por lo tanto, transforma cualquier habitación ...',
  'La moqueta Deadis poliamida es la elección perfecta para espacios residenciales que buscan combinar elegancia, confort y durabilidad excepcional. Esta moqueta Deadis poliamida fabricada mediante técnica tufting ofrece una experiencia táctil superior. Por lo tanto, transforma cualquier habitación en un espacio acogedor y sofisticado. Construcción de Pelo Cortado Premium En primer lugar, esta moqueta Deadis poliamida destaca por su construcción de pelo cortado de 14mm de altura. Fabricada en 100% poliamida de primera calidad, proporciona una superficie uniforme y extraordinariamente suave. Además, esta generosa altura de pelo crea una sensación de confort excepcional bajo los pies. La técnica tufting profesional garantiza una distribución perfecta de las fibras. Como resultado, obtienes un acabado velours elegante con apariencia uniforme en toda la superficie. Asimismo, este proceso asegura resistencia al desgaste y durabilidad prolongada. Respaldo de Juta Sintética: Estabilidad y Durabilidad Por otro lado, incorpora un respaldo de juta sintética robusta que aporta múltiples ventajas. En primer lugar, garantiza estabilidad dimensional excepcional que previene deformaciones. Además, facilita la instalación profesional y mantiene la forma perfecta durante años. El ancho de rollo de 400cm minimiza significativamente las juntas en instalaciones de gran superficie. De este modo, consigues un resultado estético superior y una instalación más rápida y eficiente. Certificaciones y Calidad Ambiental Esta moqueta Deadis poliamida cuenta con importantes certificaciones de calidad: Certificación EN14041: Cumple con los estándares europeos más exigentes para revestimientos textiles. Por consiguiente, garantiza seguridad y calidad comprobada. Clasificación A+ en emisiones: Asegura un ambiente interior saludable con mínimas emisiones de compuestos volátiles. En consecuencia, es perfecta para espacios donde pasas mucho tiempo, especialmente dormitorios infantiles. Calidad Radici Pietro: Fabricada con fibras del prestigioso fabricante italiano reconocido mundialmente. De este modo, obtienes garantía de materiales premium y rendimiento superior. Aplicaciones Ideales en Espacios Residenciales La moqueta Deadis poliamida es especialmente adecuada para: Salones y salas de estar: Crea ambientes cálidos y acogedores donde el confort es prioritario. Asimismo, su apariencia elegante complementa cualquier estilo decorativo. Dormitorios principales: Proporciona una sensación lujosa al levantarte cada mañana. Además, su suavidad invita a caminar descalzo. Dormitorios infantiles: Gracias a su certificación A+ en emisiones, garantiza un ambiente saludable. Igualmente, su superficie mullida es perfecta para el juego. Estudios y despachos: Aporta sofisticación profesional y confort acústico. Por lo tanto, mejora la concentración reduciendo el ruido ambiental. Escaleras interiores: Su construcción robusta resiste el tráfico frecuente sin perder apariencia. Ventajas de la Moqueta Deadis Poliamida Confort táctil excepcional: Los 14mm de altura de pelo proporcionan una pisada mullida y lujosa que mejora la experiencia diaria. Resistencia al desgaste: La poliamida de calidad garantiza larga vida útil incluso en zonas de paso frecuente. Aislamiento acústico: Reduce significativamente el ruido de impacto y ambiental. En consecuencia, crea espacios más tranquilos y relajantes. Aislamiento térmico: Aporta calidez adicional, especialmente beneficiosa en plantas bajas o sobre garajes. Mantenimiento sencillo: La poliamida resiste manchas y permite limpieza fácil con aspirador regular. Asimismo, mantiene su aspecto impecable con cuidados básicos. Estética atemporal: El acabado velours uniforme se adapta a cualquier estilo decorativo, desde clásico hasta contemporáneo. Especificaciones Técnicas Composición: 100% poliamida de primera calidad Técnica de fabricación: Tufting profesional con acabado velours Altura de pelo: 14mm para máximo confort Respaldo: Juta sintética robusta Ancho de rollo: 400cm para instalaciones sin juntas Certificación: EN14041 y A+ en emisiones Aplicación: Uso residencial intensivo Información de Compra y Medidas Precio indicado por metro cuadrado Formato disponible: Rollo de 4 metros de ancho Ejemplo de corte personalizado: 1 metro lineal × 4 metros de ancho = 4 m² 2 metros lineales × 4 metros de ancho = 8 m² Cálculo de precio ejemplo: 2 m² × 57,90 €/m² = 115,80 € Corte Bajo Pedido - Condiciones Importantes Los cortes personalizados no admiten devoluciones ¿Necesitas medidas específicas para tu proyecto residencial? Contáctanos para asesoramiento personalizado: Email: ventas@disstands.com Nuestro equipo te ayudará a calcular exactamente la cantidad de moqueta Deadis poliamida que necesitas, optimizando el material y evitando desperdicios en tu instalación.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  63.30,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
