INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ce224ace-f3ac-4680-88e8-cd1121f8fb00',
  'Rollo Ambiendis',
  'moqueta-ambiendis-econyl-sostenible',
  'La moqueta Ambiendis Econyl sostenible es un producto de alta calidad con técnica de bucle rizo. Está fabricada al 100% con poliamida 6-Econyl, un material duradero y completamente reciclable. Además, proporciona un efecto tonal elegante que marca la diferencia en cualquier espacio. Esta moqueta ...',
  'La moqueta Ambiendis Econyl sostenible es un producto de alta calidad con técnica de bucle rizo. Está fabricada al 100% con poliamida 6-Econyl, un material duradero y completamente reciclable. Además, proporciona un efecto tonal elegante que marca la diferencia en cualquier espacio. Esta moqueta Ambiendis Econyl sostenible cuenta con un respaldo de yuta sintética. Por ello, garantiza una mayor estabilidad y resistencia durante toda su vida útil. Con una altura de pelo de aproximadamente 4,4 mm y una altura total de 7,2 mm, ofrece una textura suave y cómoda bajo los pies. Durabilidad y Resistencia Superior Su peso total de aproximadamente 1900 g/m² asegura una excelente durabilidad. Como resultado, ofrece una resistencia excepcional al desgaste diario. Esta característica la convierte en una inversión inteligente a largo plazo. La técnica de bucle rizo crea una superficie robusta y uniforme. Por tanto, mantiene su apariencia impecable incluso en zonas de alto tránsito. Su construcción garantiza años de uso sin pérdida de calidad. Confort Acústico y Térmico Diseñada para ofrecer un alto nivel de confort, esta moqueta es ideal tanto para entornos domésticos como comerciales. Su capacidad de aislamiento acústico reduce significativamente el ruido. Además, su resistencia térmica ayuda a mantener una temperatura agradable en los espacios. Estas propiedades la hacen perfecta para una variedad de aplicaciones. En consecuencia, funciona excelentemente en dormitorios, salones, oficinas y espacios comerciales. Compromiso con la Sostenibilidad Este producto es completamente reciclable. Por ello, refleja nuestro compromiso con la sostenibilidad y el cuidado del medio ambiente. El material Econyl se fabrica a partir de residuos reciclados, lo que reduce el impacto ambiental. Asimismo, al elegir Ambiendis contribuyes activamente a la economía circular. Esta característica es cada vez más valorada en proyectos de construcción sostenible y certificaciones ambientales. Efecto Tonal Elegante El efecto tonal del bucle rizo aporta sofisticación visual. Por tanto, se adapta perfectamente a diversos estilos decorativos. Su apariencia discreta y elegante complementa tanto diseños modernos como clásicos. Información de Compra Precio: 22,39 €/m² (IVA no incluido) Ejemplo de cálculo: Si necesitas una pieza de 1 metro de largo x 2 metros de ancho: 1 m x 2 m = 2 m² 2 m² x 22,39 €/m² = 44,78 € Importante: Los cortes personalizados no admiten devoluciones. Para medidas personalizadas o asesoramiento técnico, escríbenos a: ventas@disstands.com',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  28.46,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
