INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '70d5e69e-3a1a-4a63-8fca-e5a0440ef4b0',
  'Moqueta Forudis',
  'moqueta-forudis-poliamida',
  'La moqueta Forudis poliamida es la solución perfecta cuando buscas combinar elegancia y resistencia en un mismo revestimiento textil profesional. Esta moqueta Forudis poliamida está diseñada específicamente para espacios comerciales y residenciales exigentes. Por lo tanto, ofrece resultados excep...',
  'La moqueta Forudis poliamida es la solución perfecta cuando buscas combinar elegancia y resistencia en un mismo revestimiento textil profesional. Esta moqueta Forudis poliamida está diseñada específicamente para espacios comerciales y residenciales exigentes. Por lo tanto, ofrece resultados excepcionales en cualquier proyecto. Construcción Tufted: Calidad y Durabilidad En primer lugar, esta moqueta Forudis poliamida destaca por su construcción tufted cortada de alta densidad. Fabricada en 100% poliamida de primera calidad, garantiza una durabilidad excepcional incluso en zonas de alto tránsito. Además, su fibra sintética resiste eficazmente el desgaste diario sin perder sus propiedades. La altura de pelo de 6 mm proporciona un tacto suave y confortable que invita a caminar descalzo. Asimismo, esta medida equilibra perfectamente confort y resistencia. Por consiguiente, resulta ideal para espacios donde se requiere pisada agradable y mantenimiento sencillo. Base de Yute Sintético: Estabilidad Garantizada Por otro lado, incorpora una base de yute sintético que aporta múltiples ventajas. En primer lugar, proporciona mayor estabilidad dimensional al revestimiento. Además, facilita la instalación profesional y garantiza un resultado duradero. De este modo, evita deformaciones y ondulaciones con el paso del tiempo. Ventajas de la Moqueta Forudis Poliamida Versatilidad de uso excepcional: Esta moqueta Forudis poliamida es perfecta para oficinas modernas, comercios de alto tránsito, hoteles de categoría, viviendas de diseño y espacios contract que requieren prestaciones superiores. Mantenimiento simplificado: La poliamida de alta calidad resiste eficazmente las manchas cotidianas. Asimismo, permite una limpieza sencilla con aspirador y productos convencionales. Por lo tanto, mantiene su aspecto impecable durante años sin tratamientos especiales. Confort acústico superior: Reduce significativamente el ruido ambiental y el impacto de pisadas. En consecuencia, crea espacios más agradables, silenciosos y profesionales. Instalación eficiente: Su base estable de yute sintético facilita el proceso de instalación. Igualmente, garantiza un resultado profesional duradero sin complicaciones técnicas. Resistencia comprobada: Especialmente diseñada para soportar tráfico intenso en espacios comerciales. De hecho, su construcción tufted cortada asegura larga vida útil incluso en condiciones exigentes. Especificaciones Técnicas Detalladas Composición: 100% poliamida tufted cortada de alta densidad Altura de pelo: 6 mm para equilibrio perfecto entre confort y resistencia Base: Yute sintético estabilizado para máxima durabilidad Formato: Rollo de 4 metros de ancho para instalaciones eficientes Aplicaciones: Espacios comerciales, residenciales y contract de alto nivel Información de Compra y Medidas Precio indicado por metro cuadrado Formato disponible: Rollo de 4 metros de ancho para cubrir grandes superficies Ejemplo de corte personalizado: 1 metro lineal × 4 metros de ancho = 4 m² 2 metros lineales × 4 metros de ancho = 8 m² 3 metros lineales × 4 metros de ancho = 12 m² Cálculo de precio: Multiplica los metros cuadrados necesarios por el precio unitario mostrado. Corte Bajo Pedido - Condiciones Importantes Los cortes personalizados no admiten devoluciones ¿Necesitas medidas específicas para tu proyecto? Contáctanos para asesoramiento personalizado y cálculo exacto de cantidades: Email: ventas@disstands.com Nuestro equipo técnico te ayudará a calcular exactamente la cantidad de moqueta Forudis poliamida que necesitas. De este modo, optimizamos el material y evitamos desperdicios innecesarios en tu instalación.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
