INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '66cffa8f-27e4-49b6-88d6-0cd050911682',
  'Moqueta Auradis',
  'moquetas-pet-reciclado-sostenibles-auradis',
  'Las moquetas PET reciclado sostenibles Auradis representan la nueva generación de revestimientos ecológicos de alta calidad. Fabricadas 100% con botellas PET recicladas, estas moquetas PET reciclado sostenibles combinan responsabilidad ambiental con un diseño excepcional y confort superior. Con 9...',
  'Las moquetas PET reciclado sostenibles Auradis representan la nueva generación de revestimientos ecológicos de alta calidad. Fabricadas 100% con botellas PET recicladas, estas moquetas PET reciclado sostenibles combinan responsabilidad ambiental con un diseño excepcional y confort superior. Con 9,5mm de espesor, son ideales para espacios residenciales, comerciales y ferias que buscan soluciones sustentables sin comprometer la estética. Innovación Sostenible: De Botellas Plásticas a Revestimientos Premium La composición en PET reciclado representa un avance significativo en la industria de revestimientos textiles. En efecto, cada metro cuadrado de Auradis incorpora el equivalente a aproximadamente 50 botellas de plástico recicladas, transformando residuos potencialmente contaminantes en superficies funcionales y estéticas. Por consiguiente, este proceso no solo desvía plásticos de vertederos y océanos, sino que también requiere hasta un 60% menos energía que la producción de fibras vírgenes. Como resultado, se reduce significativamente la huella de carbono del producto. Características Técnicas y Confort Espesor Optimizado de 9,5mm El espesor de 9,5 mm proporciona un equilibrio óptimo entre confort y practicidad. Por un lado, esta dimensión ofrece suficiente acolchado para crear una pisada agradable y reducir la fatiga al caminar. Por otro lado, mantiene un perfil lo suficientemente bajo para facilitar transiciones suaves con otros pavimentos. Además, las propiedades aislantes inherentes al PET contribuyen tanto al aislamiento acústico como térmico, mejorando así el confort ambiental general del espacio. Seguridad y Certificaciones La certificación Cfl garantiza que Auradis cumple con estándares de seguridad contra incendios, haciéndola apta para instalaciones comerciales y residenciales donde la normativa es prioritaria. Por esta razón, esta clasificación, combinada con su origen reciclado, la posiciona perfectamente para proyectos que buscan certificaciones de construcción sostenible como LEED o BREEAM. Versatilidad Cromática y Diseño Contemporáneo Su versatilidad cromática responde a las tendencias contemporáneas en diseño de interiores, donde la sostenibilidad no debe comprometer la expresión creativa. En primer lugar, puedes elegir desde tonos neutros que aportan serenidad hasta colores vibrantes que energizan espacios. En conclusión, Auradis demuestra que la responsabilidad ambiental y la excelencia estética pueden coexistir armoniosamente, convirtiéndola en la elección consciente para el diseño del futuro. Información de Compra Precio indicado por metro cuadrado: 15,80 €/m² (IVA no incluido) Ejemplo de cálculo Por ejemplo: 1 metro lineal x 2 metros de ancho = 2 m² Por lo tanto: 2 m² x 15,80 €/m² = 31,60 € Importante: Los cortes no admiten devoluciones. Sin embargo, para medidas personalizadas, puedes escribirnos a: ventas@disstands.com',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  15.80,
  1,
  'm²',
  true,
  true,
  NULL
