INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1b494f54-a6c4-4a4e-8050-e55db5f00227',
  'Moqueta Musdis',
  'moqueta-musdis',
  'La moqueta poliamida premium Musdis representa la excelencia en revestimientos textiles de alta gama, fabricada con fibra 100% poliamida (nylon) de primera calidad. Diseñada específicamente para ofrecer una pisada extraordinariamente suave, resistente y duradera, satisface las exigencias más elev...',
  'La moqueta poliamida premium Musdis representa la excelencia en revestimientos textiles de alta gama, fabricada con fibra 100% poliamida (nylon) de primera calidad. Diseñada específicamente para ofrecer una pisada extraordinariamente suave, resistente y duradera, satisface las exigencias más elevadas en confort y estética. Características técnicas superiores Con un espesor total de 12,5 mm, la Musdis proporciona un nivel excepcional de confort acústico y térmico. Esta dimensión generosa no solo garantiza una pisada mullida y agradable, sino que además ofrece múltiples beneficios. Confort y aislamiento Por un lado, conseguirás una reducción acústica significativa que minimiza el ruido de pisadas. Por otro lado, el aislamiento térmico mejora la eficiencia energética de tu espacio. Además, la durabilidad extrema gracias a la densidad de sus fibras asegura una larga vida útil. Finalmente, la recuperación elástica evita marcas permanentes del mobiliario. Seguridad y certificaciones La certificación Cfl en resistencia al fuego garantiza el cumplimiento de los estándares europeos más estrictos de seguridad en interiores. Por esta razón, esta clasificación permite su instalación tanto en entornos residenciales exigentes como en espacios comerciales sofisticados: hoteles de lujo, oficinas ejecutivas, salas de juntas, teatros y espacios públicos de alto standing. Gama de colores y aplicaciones Disponible en 11 colores cuidadosamente seleccionados, desde tonos neutros como marfil y beige hasta opciones más distintivas como oro y burdeos, esta moqueta poliamida premium se adapta a cualquier proyecto de interiorismo. Ventajas de la poliamida 100% En primer lugar, su composición en poliamida 100% asegura colores inalterables con el paso del tiempo. Asimismo, ofrece resistencia superior a las manchas y facilidad de limpieza y mantenimiento. Como resultado, mantendrás un aspecto impecable durante años sin esfuerzo adicional. Información de compra Precio: 22,90 €/m² (IVA no incluido) Ejemplo de cálculo Por ejemplo, si necesitas 1 metro lineal x 2 metros de ancho = 2 m². Por lo tanto, el cálculo sería: 2 m² x 22,90 €/m² = 45,80 € Formato: Corte bajo pedido según necesidades del proyecto Importante: Los cortes personalizados no admiten devoluciones. Sin embargo, para medidas específicas o asesoramiento técnico, puedes contactar con nuestro equipo especializado en: ventas@disstands.com En conclusión, la moqueta poliamida premium Musdis no es simplemente un revestimiento, sino una inversión en calidad, confort y elegancia duradera para espacios que demandan lo mejor.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  22.90,
  1,
  'm²',
  true,
  true,
  NULL
