INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '8bb8c08b-60cd-49aa-826b-b1bb8ff45712',
  'Moqueta Agadis',
  'moqueta-agadis',
  'Agadis es una moqueta de diseño elegante y tacto confortable, fabricada con 100% poliamida (nylon) para garantizar una gran resistencia al desgaste diario. Con un espesor total de 10,5 mm, ofrece una excelente pisada y propiedades aislantes tanto acústicas como térmicas. Es una opción ideal para ...',
  'Agadis es una moqueta de diseño elegante y tacto confortable, fabricada con 100% poliamida (nylon) para garantizar una gran resistencia al desgaste diario. Con un espesor total de 10,5 mm, ofrece una excelente pisada y propiedades aislantes tanto acústicas como térmicas. Es una opción ideal para interiores que requieren durabilidad, confort y una estética cuidada. Gracias a su clasificación Cfl en resistencia al fuego, cumple con los requisitos de seguridad para instalaciones residenciales y comerciales. La poliamida 100% empleada en Agadis representa lo mejor en tecnología de fibras sintéticas. Este material, conocido comercialmente como nylon, destaca por su excepcional resistencia a la abrasión, elasticidad y capacidad de recuperación. Las fibras mantienen su forma original incluso después de soportar tráfico intenso, evitando el aplastamiento permanente que sufren otros materiales. Además, la poliamida resiste naturalmente las manchas y permite una limpieza profunda sin deterioro del color o la textura. El espesor de 10,5 mm no es solo una característica de confort; representa una barrera efectiva contra el ruido y las pérdidas térmicas. Esta dimensión generosa absorbe hasta 30 decibelios de ruido ambiental, creando espacios más tranquilos y productivos. Térmicamente, actúa como aislante natural que puede reducir las pérdidas de calor por el suelo hasta en un 12%, contribuyendo al ahorro energético del edificio. La certificación Cfl en comportamiento al fuego posiciona a Agadis como una solución segura para cualquier tipo de instalación. Esta clasificación garantiza que, en caso de incendio, la moqueta no contribuirá significativamente a la propagación de las llamas, cumpliendo con las normativas europeas más estrictas para espacios públicos y privados. Agadis se presenta como la síntesis perfecta entre funcionalidad técnica y refinamiento estético, satisfaciendo las necesidades de arquitectos y diseñadores que buscan materiales que no comprometan ningún aspecto del proyecto. Su versatilidad la hace apropiada tanto para hogares que priorizan el confort como para espacios comerciales que demandan resistencia y facilidad de mantenimiento. Precio indicado por metro cuadrado. Ejemplo de corte:1 metro lineal x 2 metros de ancho = 2 m²2 m² x 15,80 €/m² = 31,60 € Los cortes no admiten devoluciones.Para medidas personalizadas, escríbenos a: ventas@disstands.com',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  19.80,
  1,
  'm²',
  true,
  true,
  NULL
