INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '0f134bd9-e4e7-4d47-8a96-1779604395e8',
  'Moqueta Teidedis',
  'moqueta-teidedis',
  'Teidedis es una moqueta premium que combina tradición, elegancia y confort natural. Fabricada con 100 % lana virgen, su textura de pelo cortado y su técnica de confección Wilton face-to-face garantizan un acabado de alta calidad, duradero y visualmente cálido. Con 12 mm de espesor total y 1.850 g...',
  'Teidedis es una moqueta premium que combina tradición, elegancia y confort natural. Fabricada con 100 % lana virgen, su textura de pelo cortado y su técnica de confección Wilton face-to-face garantizan un acabado de alta calidad, duradero y visualmente cálido. Con 12 mm de espesor total y 1.850 g/m² de felpa, proporciona una pisada envolvente, ideal para ambientes exclusivos tanto residenciales como comerciales. Además, su compatibilidad con estándares LEED® la convierte en una opción sostenible sin renunciar al estilo.',
