INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '17f039b7-cee7-40c2-8164-06785ac9df5c',
  'Moqueta Anabellis',
  'moqueta-lana-virgen-premium',
  'La moqueta lana virgen premium Annabellis representa la excelencia en revestimientos textiles, tejida con 100% pura lana virgen mediante la prestigiosa técnica Raschel Face to Face. Esta moqueta lana virgen premium ofrece una superficie de pelo cortado, su generoso espesor de 12 mm y su gran peso...',
  'La moqueta lana virgen premium Annabellis representa la excelencia en revestimientos textiles, tejida con 100% pura lana virgen mediante la prestigiosa técnica Raschel Face to Face. Esta moqueta lana virgen premium ofrece una superficie de pelo cortado, su generoso espesor de 12 mm y su gran peso aportan una pisada cálida, silenciosa y elegante que transforma cualquier espacio en un refugio de confort y distinción. Perfecta para espacios residenciales sofisticados y ambientes comerciales exclusivos, esta moqueta de lana virgen premium encarna el lujo sostenible del siglo XXI. La técnica Raschel Face to Face empleada en su fabricación garantiza una densidad y uniformidad excepcionales. Este proceso de tejido doble crea dos moquetas simultáneamente, unidas por el pelo que posteriormente se corta con precisión milimétrica. El resultado es una superficie de textura impecable y durabilidad superior, donde cada fibra de lana virgen mantiene sus propiedades naturales intactas: termorregulación, resistencia al aplastamiento y capacidad de recuperación elástica. Su composición en lana virgen 100% natural ofrece beneficios incomparables. Este material noble proporciona un aislamiento térmico óptimo, reduciendo significativamente los costos energéticos, mientras que sus propiedades fonoabsorbentes crean ambientes silenciosos y acogedores. La lana también actúa como purificador natural del aire, absorbiendo y neutralizando contaminantes volátiles, contribuyendo a espacios más saludables. La certificación LEED® compatible posiciona a Annabellis como una elección responsable para proyectos arquitectónicos vanguardistas. Su fabricación sostenible, desde la obtención de la materia prima hasta los procesos de producción, minimiza el impacto ambiental. La lana, siendo biodegradable y renovable, refuerza el compromiso con la economía circular. Con sus 12 mm de espesor, Annabellis ofrece una experiencia sensorial única: cada paso se amortigua suavemente, proporcionando confort ergonómico y reduciendo la fatiga. Su paleta cromática refinada permite integraciones armoniosas en diversos conceptos decorativos, desde minimalismo contemporáneo hasta clasicismo renovado. Ideal para hoteles boutique, oficinas ejecutivas, residencias de lujo y espacios que demandan excelencia estética y funcional sin comprometer la sostenibilidad ambiental.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
