INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '38c61901-943d-4085-8949-bacdb8b46f0f',
  'Moqueta Zenidis',
  'moqueta-zenidis-lana-lujo',
  'La moqueta Zenidis de lana de lujo representa el máximo exponente en revestimientos premium para interiores. Con su superficie de pelo cortado de 14 mm fabricada en lana 100% natural, esta moqueta de lujo ofrece una experiencia sensorial incomparable. El tratamiento antipolillas especializado gar...',
  'La moqueta Zenidis de lana de lujo representa el máximo exponente en revestimientos premium para interiores. Con su superficie de pelo cortado de 14 mm fabricada en lana 100% natural, esta moqueta de lujo ofrece una experiencia sensorial incomparable. El tratamiento antipolillas especializado garantiza durabilidad excepcional en los espacios más exclusivos. Características técnicas excepcionales Su generoso pelo de 14 mm proporciona una pisada extraordinariamente cálida y mullida, creando una sensación de confort absoluto. La lana natural aporta beneficios únicos: Regulación térmica natural que mantiene la temperatura ideal Absorción acústica superior para ambientes silenciosos Resistencia inherente a las manchas y la suciedad Elasticidad natural que mantiene su aspecto original durante décadas Propiedades hipoalergénicas y purificadoras del aire Seguridad y compatibilidad técnica La certificación ignífuga Cfl-s1 garantiza los más altos estándares de seguridad contra incendios, permitiendo su instalación en espacios públicos y privados sin restricciones. Especialmente diseñada para ser compatible con suelo radiante, la Zenidis optimiza la eficiencia energética mientras mantiene el máximo confort térmico, convirtiéndola en ideal para viviendas exclusivas y entornos comerciales selectos. Compromiso medioambiental certificado La composición en lana natural y los procesos de fabricación sostenibles hacen de Zenidis la elección perfecta para proyectos con certificaciones LEED y BREEAM. Su contribución incluye: Material renovable y biodegradable Baja huella de carbono en producción Mejora de la calidad del aire interior Durabilidad excepcional que reduce el consumo Reciclabilidad completa al final de su vida útil Aplicaciones y mantenimiento Ideal para: Residencias de lujo que valoran la sostenibilidad Hoteles boutique con compromiso ecológico Oficinas ejecutivas con certificación verde Espacios wellness y centros de salud premium El tratamiento antipolillas garantiza la protección permanente de las fibras sin necesidad de productos químicos adicionales. Su mantenimiento es sencillo gracias a las propiedades naturales autolimpiantes de la lana. La moqueta Zenidis no es solo un revestimiento premium, es una declaración de principios donde el lujo, la sostenibilidad y el bienestar convergen en perfecta armonía.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
