INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b16d3202-9931-47e5-828c-a03099696d4f',
  'Moqueta Lunadis',
  'moqueta-lunadis',
  'La moqueta Lunadis representa la definición de elegancia natural y confort sostenible en revestimientos de alta gama. Confeccionada en 100% lana virgen de primera calidad, su textura suave y uniforme de pelo cortado brinda una experiencia sensorial excepcional, combinando calidez natural, absorci...',
  'La moqueta Lunadis representa la definición de elegancia natural y confort sostenible en revestimientos de alta gama. Confeccionada en 100% lana virgen de primera calidad, su textura suave y uniforme de pelo cortado brinda una experiencia sensorial excepcional, combinando calidez natural, absorción acústica superior y un acabado visual impecable. Tecnología de fabricación avanzada La exclusiva técnica de fabricación Wilton face-to-face garantiza una estructura extraordinariamente estable y duradera. Este método tradicional perfeccionado produce: Densidad uniforme que mantiene su forma durante décadas Resistencia superior al desgaste y aplastamiento Precisión dimensional perfecta en cada rollo Durabilidad excepcional incluso en zonas de alto tránsito Acabado premium con bordes perfectamente definidos Beneficios naturales de la lana virgen La composición en lana virgen 100% proporciona ventajas incomparables: Regulación térmica natural que adapta la temperatura ambiente Absorción acústica que reduce el ruido hasta un 30% Resistencia natural a manchas y suciedad Propiedades ignífugas inherentes sin tratamientos químicos Purificación del aire mediante absorción de contaminantes Sostenibilidad certificada Lunadis es la elección perfecta para proyectos con certificación LEED® gracias a: Material completamente renovable y biodegradable Proceso de producción con mínimo impacto ambiental Contribución a la calidad del aire interior Longevidad que reduce el consumo de recursos Reciclabilidad total al final de su ciclo de vida Aplicaciones ideales Perfecta para: Viviendas de alto nivel que buscan lujo sostenible Espacios comerciales con estilo como boutiques y showrooms Hoteles premium con compromiso medioambiental Oficinas ejecutivas que priorizan el bienestar Residencias privadas donde el confort es esencial Mantenimiento y cuidados La lana virgen facilita un mantenimiento sencillo gracias a sus propiedades autolimpiantes naturales. El aspirado regular y la limpieza puntual de manchas son suficientes para mantener su aspecto pristino durante años. La moqueta Lunadis no es simplemente un revestimiento, es una inversión en bienestar, sostenibilidad y elegancia atemporal que transforma cualquier espacio en un santuario de confort natural.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
