INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '60f38cdb-83be-4ab9-8e49-b1006ddd8db4',
  'Sisal Lasdis',
  'moqueta-lasdis-inspiracion-sisal',
  'Moqueta sisal sintética Lasdis: apariencia natural con prestaciones técnicas superiores La moqueta sisal sintética Lasdis combina la estética orgánica del sisal natural con altas prestaciones técnicas de fibras avanzadas. Esta moqueta sisal sintética Lasdis ha sido diseñada para quienes buscan la...',
  'Moqueta sisal sintética Lasdis: apariencia natural con prestaciones técnicas superiores La moqueta sisal sintética Lasdis combina la estética orgánica del sisal natural con altas prestaciones técnicas de fibras avanzadas. Esta moqueta sisal sintética Lasdis ha sido diseñada para quienes buscan la belleza natural del sisal con los beneficios técnicos modernos, ofreciendo durabilidad excepcional sin sacrificar el aspecto auténtico. Perfecta para exteriores e interiores, se adapta a cualquier proyecto residencial o comercial. Composición de fibras sintéticas de última generación Fabricada con fibras sintéticas de última generación (91% polipropileno y 9% poliéster), este pavimento destaca por su durabilidad extraordinaria, resistencia superior a las manchas y fácil mantenimiento. Asimismo, esta composición garantiza que la moqueta mantenga su aspecto original durante años, incluso en condiciones de uso intensivo tanto en interiores como en exteriores protegidos. Tres tipos de respaldo técnico de la moqueta sisal sintética Disponible con tres tipos de respaldo técnico —Vlies, ECO Grip y Látex—, la moqueta sisal sintética Lasdis se adapta perfectamente a todo tipo de entornos y necesidades específicas. Por consiguiente, puede instalarse desde viviendas residenciales hasta espacios comerciales de alto tránsito, oficinas corporativas, hoteles y áreas exteriores cubiertas. De esta manera, cada proyecto encuentra el respaldo ideal según sus requerimientos técnicos. Diseño natural con textura firme El diseño sobrio y textura firme la convierten en una elección ideal para quienes buscan estética natural con beneficios técnicos modernos. Su apariencia que imita fielmente el sisal natural aporta calidez orgánica a cualquier espacio. Por otro lado, su textura firme proporciona una pisada segura y confortable que transmite sensación de calidad premium. Propiedades técnicas avanzadas La moqueta sisal sintética Lasdis es antialérgica, protegiendo la salud de usuarios sensibles al no acumular ácaros ni alérgenos. Además, es antideslizante, garantizando seguridad en zonas de tránsito. También es apta para calefacción por suelo radiante, ofreciendo confort térmico adicional en los meses fríos sin comprometer sus propiedades ni su aspecto. Resistencia superior a manchas y fácil mantenimiento Gracias a su composición en polipropileno y poliéster, este pavimento ofrece resistencia excepcional a las manchas, facilitando enormemente las tareas de limpieza. El mantenimiento es mínimo: aspirado regular y limpieza puntual ocasional son suficientes para mantenerla impecable. Esto reduce significativamente los costes de mantenimiento a largo plazo. Versatilidad para interiores y exteriores de la moqueta sisal Lasdis La moqueta sisal sintética Lasdis es perfecta para salones, dormitorios, despachos, oficinas, hoteles, terrazas cubiertas, porches, balcones protegidos y cualquier espacio que requiera un pavimento textil de inspiración natural con rendimiento técnico superior y durabilidad garantizada. Disponibilidad inmediata Tenemos stock disponible de la referencia 3886, garantizando entrega rápida para tus proyectos. Características principales Composición: 91% polipropileno + 9% poliéster Estilo: Inspiración sisal natural Respaldos disponibles: Vlies, ECO Grip, Látex Uso: Interior y exterior protegido Propiedades: Antialérgica, antideslizante Mantenimiento: Fácil y reducido Resistencia: Manchas y tráfico intensivo Calefacción radiante: Compatible Referencia en stock: 3886 Elige la moqueta sisal sintética Lasdis para combinar belleza natural, durabilidad técnica y facilidad de mantenimiento en un único pavimento versátil.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  25.00,
  1,
  'm²',
  true,
  true,
