INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3580e860-b4a3-4cde-8d14-bdcfc9db9d7e',
  'Sisal Sintético Robusdis',
  'moqueta-polipropileno-resistente',
  'La moqueta polipropileno resistente Robusdis combina estética natural con alta durabilidad. Además, su textura envolvente y agradable al tacto, junto con los tonos tierra, aporta calidez y confort a cualquier espacio. Gracias a su estructura en bucle, garantiza resistencia excepcional, siendo la ...',
  'La moqueta polipropileno resistente Robusdis combina estética natural con alta durabilidad. Además, su textura envolvente y agradable al tacto, junto con los tonos tierra, aporta calidez y confort a cualquier espacio. Gracias a su estructura en bucle, garantiza resistencia excepcional, siendo la elección ideal para hogares, oficinas y espacios comerciales exigentes. Incluso en zonas de tránsito constante, mantiene su calidad y elegancia. Composición y resistencia de la moqueta polipropileno resistenteRobusdis está fabricada en polipropileno de alta calidad, un material que ofrece resistencia superior al desgaste y facilidad de mantenimiento. Soporta perfectamente el tránsito diario y, por lo tanto, mantiene su aspecto original durante años. Esto la hace adecuada tanto para interiores residenciales como comerciales. Diseño natural y estética de RobusdisLos tonos tierra crean ambientes acogedores y se integran en decoraciones naturales o modernas. Su diseño elegante y atemporal, además, añade profundidad visual y uniformidad cromática en cada rollo. La moqueta también combina con muebles de madera, metal o textiles, por ejemplo, adaptándose a múltiples estilos de interiorismo. Fácil mantenimiento de la moqueta polipropileno resistenteEl polipropileno resistente repele la suciedad de forma natural. Las manchas se eliminan fácilmente con productos domésticos comunes. Por lo tanto, la limpieza regular con aspiradora es suficiente, lo que reduce costes y esfuerzo, haciendo de Robusdis una opción práctica para familias, oficinas y comercios. Aplicaciones recomendadasIdeal para viviendas familiares, oficinas con tráfico moderado, comercios pequeños y medianos, espacios de coworking y salas de espera. Además, asegura durabilidad y confort en cualquier entorno, ofreciendo una sensación de calidad profesional. Instalación versátil y confort bajo tus piesSu instalación es rápida y eficiente sobre distintos tipos de superficie, adaptándose incluso a suelos existentes. Además, la textura en bucle proporciona confort bajo los pies, aislamiento térmico y reducción del ruido ambiental, mejorando la calidad de vida diaria. Durabilidad garantizada y excelente relación calidad-precioRobusdis mantiene colores vivos y estructura firme durante años, soportando uso intensivo. Por lo tanto, su durabilidad y bajo mantenimiento ofrecen una excelente relación calidad-precio, convirtiéndola en una inversión inteligente. Además, su estética atemporal asegura que el espacio siempre luzca moderno y acogedor.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
