INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '2b1fbced-ccb1-49cc-879b-1f78d6e2a0ac',
  'Sisal Okawitdis Tela',
  'moqueta-efecto-sisal-okawitdis',
  'Moqueta Efecto Sisal Okawitdis: Elegancia Natural La moqueta efecto sisal Okawitdis Tela aporta calidez, textura y resistencia a cualquier espacio. Además, esta moqueta efecto sisal es ideal para oficinas, showrooms, hoteles o viviendas que buscan un suelo textil duradero y elegante. Está fabrica...',
  'Moqueta Efecto Sisal Okawitdis: Elegancia Natural La moqueta efecto sisal Okawitdis Tela aporta calidez, textura y resistencia a cualquier espacio. Además, esta moqueta efecto sisal es ideal para oficinas, showrooms, hoteles o viviendas que buscan un suelo textil duradero y elegante. Está fabricada en polipropileno 100%, lo que la hace fácil de limpiar y resistente al uso intensivo. Asimismo, presenta excelente comportamiento ante el fuego. Su base de fieltro permite una instalación rápida y sin adhesivos, revolucionando los procesos tradicionales. Textura Natural de la Moqueta Efecto Sisal La textura característica de la moqueta efecto sisal Okawitdis emula perfectamente el aspecto artesanal del sisal natural. Por tanto, presenta una trama visible y superficie ligeramente irregular que aporta carácter orgánico. Sin embargo, al estar fabricada en polipropileno, supera ampliamente las limitaciones del sisal tradicional. En consecuencia, no absorbe humedad, no se pudre, no alberga ácaros ni moho. Además, mantiene su integridad estructural incluso en ambientes con fluctuaciones. Aplicaciones Versátiles de Okawitdis Tela Esta moqueta con acabado sisal combina estética natural y tecnología moderna, convirtiéndose en la elección predilecta para proyectos exigentes. En oficinas corporativas, crea ambientes cálidos que mejoran el bienestar laboral sin comprometer durabilidad. Posteriormente, en showrooms y espacios comerciales, su textura añade profundidad visual mientras resiste el desgaste constante. Los hoteles la prefieren por mantener un aspecto impecable con mantenimiento mínimo. Finalmente, en viviendas particulares ofrece calidez sin inconvenientes. Instalación Rápida sin Adhesivos El sistema de instalación sin adhesivos mediante base de fieltro acelera significativamente los tiempos de colocación. Asimismo, permite su retirada o reemplazo sin dañar el suelo base. Por tanto, resulta ideal para espacios en alquiler o instalaciones temporales. Además, mejora el aislamiento acústico y térmico del espacio. En consecuencia, contribuye notablemente al confort general del ambiente. La Evolución del Revestimiento Tipo Sisal Okawitdis representa la evolución inteligente de los revestimientos textiles contemporáneos. Mantiene la belleza atemporal de las fibras naturales tradicionales. Además, ofrece las prestaciones técnicas que demanda el siglo XXI. Finalmente, combina diseño sofisticado con funcionalidad profesional sin compromisos.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
