INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ca71ae9f-1eb5-495d-8909-70ceab0379ab',
  'Sisal Natural Pequeño Bucle',
  'moqueta-sisal-natural-bucle',
  'Moqueta sisal natural bucle: elegancia ecológica y sostenibilidad para tu hogar Descubre la elegancia natural del modelo Sisal Pequeño Bucle, una moqueta sisal natural bucle ecológica y sofisticada fabricada con fibras 100% sisal auténtico. Este pavimento combina la belleza orgánica de las fibras...',
  'Moqueta sisal natural bucle: elegancia ecológica y sostenibilidad para tu hogar Descubre la elegancia natural del modelo Sisal Pequeño Bucle, una moqueta sisal natural bucle ecológica y sofisticada fabricada con fibras 100% sisal auténtico. Este pavimento combina la belleza orgánica de las fibras naturales con un diseño contemporáneo que transforma cualquier espacio en un ambiente acogedor y refinado. Textura y diseño excepcionales La textura de bucle fino aporta un acabado uniforme y orgánico, creando una superficie visualmente atractiva que se integra perfectamente en interiores modernos y clásicos. El pequeño bucle proporciona una sensación táctil agradable bajo los pies, mientras que su apariencia natural añade calidez y personalidad a cualquier estancia. Este pavimento es perfecto para espacios que buscan un equilibrio entre diseño natural, durabilidad excepcional y compromiso con la sostenibilidad ambiental. Durabilidad y resistencia natural del sisal Gracias a su estructura resistente fabricada con fibras de sisal de alta calidad y su reverso en látex natural, esta moqueta sisal natural bucle se convierte en una excelente alternativa tanto para espacios residenciales como comerciales con tráfico moderado. El sisal es reconocido mundialmente por su extraordinaria resistencia al desgaste, su capacidad para mantener su aspecto original durante años y su comportamiento antiestático natural que repele el polvo. Beneficios ecológicos y saludables Este pavimento textil es una opción 100% natural y biodegradable que contribuye a crear ambientes más saludables. El sisal es una fibra renovable que no contiene químicos sintéticos, regula naturalmente la humedad del ambiente y mejora la calidad del aire interior. Su reverso en látex natural refuerza el compromiso ecológico del producto, ofreciendo estabilidad sin comprometer los valores sostenibles. Aplicaciones versátiles La moqueta sisal natural bucle es ideal para salones, dormitorios, despachos, oficinas boutique, espacios comerciales con tráfico moderado, hoteles boutique y cualquier ambiente que valore la estética natural y la responsabilidad ambiental. Su versatilidad la convierte en la elección perfecta para proyectos de interiorismo que buscan materiales auténticos y de calidad superior. Características principales Composición: 100% fibra de sisal natural Textura: Bucle pequeño y uniforme Reverso: Látex natural Uso recomendado: Residencial y comercial moderado Mantenimiento: Sencillo con aspirado regular Elige la moqueta sisal natural bucle y apuesta por la elegancia natural, la durabilidad probada y el respeto por el medio ambiente en tus proyectos de interiorismo.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
