INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7a532614-aad3-401e-8215-0c52dd9ba70f',
  'Losetas Elemendis',
  'losetas-modulares-elemendis',
  'Las losetas modulares Elemendis han sido diseñadas para rendir en los entornos más exigentes, combinando pura tranquilidad con una base perfecta para cualquier proyecto de diseño interior. Fabricadas con materiales duraderos y sostenibles, estas moquetas modulares fusionan estética contemporánea ...',
  'Las losetas modulares Elemendis han sido diseñadas para rendir en los entornos más exigentes, combinando pura tranquilidad con una base perfecta para cualquier proyecto de diseño interior. Fabricadas con materiales duraderos y sostenibles, estas moquetas modulares fusionan estética contemporánea y tecnología avanzada. Por tanto, ofrecen confort superior, acústica mejorada y una instalación eficiente que optimiza tiempos y recursos en cada proyecto. Tecnología Solution Dyed y Resistencia Superior La colección Elemendis presenta una cuidada selección de colores lisos y depurados, creados específicamente para aportar equilibrio, simplicidad y armonía a cualquier concepto de diseño. Construida con hilo de nylon solution dyed, garantiza sostenibilidad real, solidez del color excepcional y resistencia al uso comercial más intensivo. Además, el empleo de hilo catiónico confiere a la colección una notable resistencia a la suciedad. En consecuencia, facilita el mantenimiento diario y reduce significativamente los costes operativos a largo plazo. Versatilidad de Diseño y Combinaciones Elemendis destaca por su excepcional versatilidad de diseño y facilidad de combinación. Asimismo, gracias a su altura de pelo uniforme, permite integrar sin esfuerzo diferentes tonalidades en una misma estancia, creando composiciones armoniosas y dinámicas. Así se genera dinamismo visual mediante transiciones suaves y elegantes superposiciones cromáticas que enriquecen cualquier espacio comercial. La modularidad del sistema facilita diseños personalizados adaptados a las necesidades específicas de cada proyecto. Sostenibilidad y Certificaciones La colección ofrece catorce opciones cromáticas cuidadosamente seleccionadas: nueve tonos básicos atemporales y cinco colores de acento expresivos. Posteriormente, estas opciones permiten infinitas posibilidades creativas adaptadas a cada proyecto. Su respaldo ecológico GREENBASE y certificación de resistencia al fuego Bfl-s1 las convierten en la opción ideal para oficinas modernas, espacios públicos, lobbies, pasillos corporativos y áreas de alto tránsito donde la paz y la concentración son fundamentales. Disponible en formato estándar de 50x50 cm en losetas modulares y también en moqueta wall-to-wall. Formatos adicionales de 25x100 cm están disponibles desde 100 m², mientras que las medidas de 100x100 cm y 100x200 cm pueden solicitarse a partir de 200 m².',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
