INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '45f2ede8-3db5-41b0-8775-d9664a13b7c0',
  'Losetas Esendis',
  'moqueta-modular-sostenible',
  'Moqueta modular sostenible: rendimiento técnico y compromiso ambiental La moqueta modular sostenible Esendis es una solución de pavimento textil en loseta que combina rendimiento técnico superior con auténtico compromiso ambiental. Esta loseta textil representa la elección profesional para espaci...',
  'Moqueta modular sostenible: rendimiento técnico y compromiso ambiental La moqueta modular sostenible Esendis es una solución de pavimento textil en loseta que combina rendimiento técnico superior con auténtico compromiso ambiental. Esta loseta textil representa la elección profesional para espacios que exigen calidad, durabilidad y responsabilidad ecológica sin compromisos. Tecnología de color duradera El sistema de teñido en masa garantiza colores duraderos que mantienen su intensidad original durante años. A diferencia de los sistemas de teñido superficial, esta tecnología penetra completamente en la fibra. Por consiguiente, ofrece gran resistencia a la decoloración causada por la luz solar y el tráfico intenso. Propiedades técnicas de la moqueta sostenible Este pavimento modular incorpora propiedades acústicas que reducen significativamente el ruido ambiental, creando espacios más confortables. Asimismo, su característica antiestática previene las descargas eléctricas y protege equipos electrónicos sensibles. Además, cuenta con clasificación de resistencia al fuego clase Bfl-s1, cumpliendo con las normativas más exigentes de seguridad. Versatilidad de diseño Disponible en 31 estilos diferentes, ofrece una paleta extraordinaria para crear ambientes únicos. Permite diseñar desde espacios corporativos elegantes hasta entornos creativos vibrantes. Por otro lado, es totalmente compatible con sillas de ruedas, garantizando accesibilidad universal. También funciona perfectamente con sistemas de calefacción radiante. Aplicaciones comerciales del pavimento modular Esta loseta textil está diseñada específicamente para espacios exigentes. Es ideal para oficinas corporativas, hospitales, centros educativos, hoteles y edificios institucionales. Su formato en loseta facilita la instalación rápida y permite reemplazos puntuales sin necesidad de cambiar toda la superficie. Sostenibilidad real Representa una elección responsable con el medio ambiente. Su durabilidad excepcional reduce la necesidad de reemplazos frecuentes. De esta manera, minimiza el impacto ambiental a largo plazo y optimiza los recursos invertidos. Características principales Formato: Loseta modular Teñido: Sistema en masa Estilos: 31 opciones de diseño Clasificación fuego: Bfl-s1 Propiedades: Antiestático y acústico Compatibilidad: Sillas de ruedas y calefacción radiante Elige la moqueta modular sostenible Esendis para unir rendimiento técnico, diseño versátil y responsabilidad ambiental en tu proyecto.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
