INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '5263bdef-a720-415b-86ca-509980311c17',
  'Losetas L480',
  'moqueta-loseta-econyl-ecologica-l480',
  'Moqueta en Loseta Sostenible L480: Rendimiento y Ecología La moqueta en loseta sostenible L480 combina elegancia y rendimiento técnico para espacios comerciales de alto tránsito. Fabricada con fibras ECONYL® recicladas, esta moqueta en loseta sostenible ofrece una solución respetuosa con el medio...',
  'Moqueta en Loseta Sostenible L480: Rendimiento y Ecología La moqueta en loseta sostenible L480 combina elegancia y rendimiento técnico para espacios comerciales de alto tránsito. Fabricada con fibras ECONYL® recicladas, esta moqueta en loseta sostenible ofrece una solución respetuosa con el medio ambiente sin comprometer durabilidad ni estética. Además, su diseño tipo buclé y su excelente absorción acústica la convierten en una opción ideal para oficinas, hoteles y espacios públicos. Tecnología ECONYL®: La Moqueta Sostenible del Futuro El hilo ECONYL® utilizado en esta loseta sostenible L480 proviene de redes de pesca recuperadas del océano y otros residuos de nylon. Posteriormente, estos materiales se transforman en una fibra de primera calidad mediante un proceso de regeneración innovador. Como resultado, obtenemos un producto totalmente reciclable que reduce significativamente la huella de carbono. Descubre más sobre moquetas sostenibles en nuestro catálogo. Formato Modular: Instalación Simplificada Por otro lado, la estructura en losetas facilita enormemente la instalación y el mantenimiento. A diferencia de las moquetas tradicionales en rollo, el formato modular permite sustituir piezas individuales. Así, se prolonga la vida útil del pavimento y se reducen los costes a largo plazo. Además, su sistema de instalación flexible se adapta a espacios irregulares y permite crear diseños creativos. Certificación Ignífuga Bfl-s1 Con certificación ignífuga Bfl-s1 según normativa europea, la L480 sostenible cumple los requisitos más estrictos de seguridad. Por tanto, es perfecta para edificios públicos y comerciales. Asimismo, su alta resistencia a la abrasión garantiza un aspecto impecable durante años, incluso en recepciones y pasillos de alto tránsito. Confort Acústico para Espacios Profesionales Finalmente, la capacidad de absorción acústica de esta moqueta en loseta contribuye a crear ambientes más silenciosos. En consecuencia, reduce la reverberación y mejora la calidad sonora. Esta característica es especialmente valorada en oficinas modernas, salas de conferencias y entornos donde el bienestar impacta en la productividad. Para más información sobre nuestras moquetas modulares o solicitar muestras, contacta con nuestro equipo.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
