INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'bb93c631-6602-4c02-872c-2236df8267c3',
  'Goma Sportdis - Uni Versa',
  'pavimento-deportivo-epdm-ignifugo-sportdis',
  'El pavimento deportivo EPDM ignífugo Sportdis es la solución ideal para instalaciones interiores que exigen máxima seguridad, durabilidad y confort. Este suelo en rollo de caucho técnico está fabricado con EPDM 100% coloreado, garantizando una estética homogénea y duradera sin pérdida de color co...',
  'El pavimento deportivo EPDM ignífugo Sportdis es la solución ideal para instalaciones interiores que exigen máxima seguridad, durabilidad y confort. Este suelo en rollo de caucho técnico está fabricado con EPDM 100% coloreado, garantizando una estética homogénea y duradera sin pérdida de color con el uso intensivo. Características Técnicas del Pavimento EPDM Este pavimento deportivo EPDM ignífugo destaca por su alta resistencia al tráfico intenso y su excelente confort de uso. Además, ofrece una reducción acústica de 14 dB, lo que lo convierte en una opción perfecta para gimnasios, instalaciones deportivas, oficinas y zonas comerciales donde el control del ruido es esencial. Ventajas principales: EPDM 100% coloreado en masa para durabilidad cromática Certificación ignífuga Cfl-s1 según normativa europea Reducción acústica de 14 dB Alta resistencia al desgaste y tráfico intenso Excelente confort y capacidad de amortiguación Emisiones certificadas A+ para calidad del aire interior Formato en rollo para instalación rápida y eficiente Aplicaciones del Pavimento Deportivo EPDM Ignífugo El pavimento deportivo EPDM ignífugo Sportdis es versátil y se adapta perfectamente a múltiples espacios interiores con alta exigencia de rendimiento. Por ejemplo, es ideal para gimnasios profesionales, salas de fitness, crossfit y entrenamiento funcional, instalaciones deportivas cubiertas y zonas de pesas. Asimismo, también funciona perfectamente en oficinas modernas, zonas comerciales de alto tráfico y espacios corporativos que requieren aislamiento acústico efectivo. Si necesitas otro tipo de pavimento, también ofrecemos pavimento de caucho alveolar para exteriores y moquetas feriales para eventos y exposiciones. Certificaciones de Seguridad y Sostenibilidad Este pavimento cumple con las normativas internacionales más exigentes en materia de seguridad contra incendios. En consecuencia, la certificación ignífuga Cfl-s1 garantiza su uso seguro en cualquier edificio público o privado, cumpliendo con el Código Técnico de la Edificación español. Además, cuenta con emisiones certificadas A+, lo que asegura la mejor calidad del aire interior para proteger la salud de los usuarios. Durabilidad y Mantenimiento Gracias a su composición de EPDM 100% coloreado en masa, el color permanece uniforme incluso después de años de uso intensivo. Por lo tanto, no necesitarás preocuparte por decoloraciones, manchas superficiales o pérdida de propiedades estéticas que afecten la apariencia de tu instalación deportiva. El mantenimiento es mínimo, requiriendo únicamente limpieza regular con productos neutros. Instalación Profesional En Disstands contamos con más de 20 años de experiencia en la instalación de pavimentos deportivos. Nuestro equipo de instaladores profesionales garantiza un montaje perfecto que maximiza la vida útil del pavimento deportivo EPDM ignífugo. Además, ofrecemos asesoramiento técnico personalizado para ayudarte a elegir el grosor y color más adecuado para tu proyecto específico. También disponemos de otros productos complementarios como moquetas para gimnasios y suelos técnicos para completar tu instalación. Colores y Grosores Disponibles El pavimento deportivo EPDM ignífugo Sportdis está disponible en diversos colores y grosores para adaptarse a las necesidades específicas de cada proyecto. Desde tonos neutros hasta colores vibrantes, podemos ofrecerte la solución perfecta que combine funcionalidad con el diseño de tu espacio. ¿Necesitas un pavimento deportivo EPDM ignífugo para tu proyecto? Solicita tu presupuesto personalizado sin compromiso. Te respondemos en menos de 24 horas con toda la información técnica y precios ajustados. Teléfono: 934 85 00 85 Email: ventas@disstands.com Servicio en toda España Descubre más sobre nuestros pavimentos deportivos y técnicos en nuestro catálogo completo.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
