INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'd6b124a0-ea5d-4239-8522-f1c8b147ff9d',
  'Loseta de Caucho 50x50',
  'loseta-caucho-50x50-exterior-parques',
  'Losetas de caucho reciclado 50x50cm certificadas EN1177 para seguridad en parques infantiles y zonas deportivas exteriores. Pavimento de seguridad fabricado con caucho 100% reciclado, diseñado específicamente para absorber impactos de caídas hasta 3 metros de altura. Su estructura porosa garantiz...',
  'Losetas de caucho reciclado 50x50cm certificadas EN1177 para seguridad en parques infantiles y zonas deportivas exteriores. Pavimento de seguridad fabricado con caucho 100% reciclado, diseñado específicamente para absorber impactos de caídas hasta 3 metros de altura. Su estructura porosa garantiza drenaje total del agua de lluvia, evitando charcos y manteniendo la superficie antideslizante incluso mojada (clasificación R10). Características principales: Dimensiones: 50x50cm con espesores disponibles de 20, 30 y 45mm Absorción de impactos según altura crítica de caída (HIC) Sistema de instalación machihembrado sin adhesivos ni obras Resistente a rayos UV y temperaturas extremas (-40°C a +80°C) Vida útil superior a 10 años en exteriores Mantenimiento mínimo: solo agua a presión Disponible en colores: rojo, verde, negro y gris Aplicaciones: Parques infantiles públicos y privados, guarderías, colegios, áreas de juego, gimnasios exteriores, zonas CrossFit, bordes de piscina, terrazas transitables y caminos peatonales.',
