INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '57f6df03-ce81-4113-8931-35790e960451',
  'Espuma Puzzle Tatami',
  'espuma-puzzle-tatami',
  'Nuestro tatami tipo puzzle está fabricado con espuma EVA (Etileno-Vinil-Acetato) de alta densidad, un material técnico especialmente diseñado por sus excepcionales propiedades de absorción de impactos, durabilidad y versatilidad. Este producto representa la solución ideal para crear espacios segu...',
  'Nuestro tatami tipo puzzle está fabricado con espuma EVA (Etileno-Vinil-Acetato) de alta densidad, un material técnico especialmente diseñado por sus excepcionales propiedades de absorción de impactos, durabilidad y versatilidad. Este producto representa la solución ideal para crear espacios seguros, confortables y funcionales en entornos deportivos, recreativos y profesionales. Sistema de Instalación Inteligente El innovador sistema de encaje dentado tipo puzzle permite una instalación rápida y sencilla sin necesidad de adhesivos, pegamentos ni herramientas. Las piezas se ensamblan perfectamente creando una superficie uniforme y estable, sin juntas visibles. Este diseño modular facilita la sustitución de piezas individuales en caso de desgaste, optimizando el mantenimiento y reduciendo costes. La instalación puede realizarse sobre cualquier superficie plana, adaptándose a espacios de diferentes dimensiones. Material de Alta Calidad La espuma EVA de alta densidad ofrece una excelente absorción de impactos, protegiendo articulaciones y músculos durante la práctica deportiva o el juego infantil. Su estructura celular proporciona el equilibrio perfecto entre firmeza y amortiguación. Además, presenta propiedades naturales de resistencia al deslizamiento, con superficie texturizada que mejora la tracción incluso descalzo, aspecto fundamental en artes marciales, yoga y actividades infantiles. Aplicaciones Versátiles Ideal para gimnasios, dojos, estudios de yoga y pilates, centros de artes marciales, así como guarderías, habitaciones infantiles, ludotecas y colegios. También perfecto para espacios profesionales como stands feriales y áreas de eventos. Beneficios Clave Ofrece confort excepcional bajo pisada prolongada, fácil limpieza con paño húmedo, superficie higiénica no porosa, aislamiento térmico y diseño ligero para transporte sencillo. Apto exclusivamente para uso interior, garantizando máxima durabilidad en ambientes protegidos.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
