INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3f6a9b4e-60f5-44e7-8b60-60f953a3be26',
  'Moqueta Zerbodis',
  'moqueta-agujereada-trafico-intenso',
  'La moqueta agujereada tráfico intenso Zerbodis representa la solución ideal para espacios con gran afluencia de personas que requieren resistencia excepcional sin renunciar al confort. Fabricada en 100% polipropileno con tecnología agujereada avanzada, esta moqueta está específicamente diseñada p...',
  'La moqueta agujereada tráfico intenso Zerbodis representa la solución ideal para espacios con gran afluencia de personas que requieren resistencia excepcional sin renunciar al confort. Fabricada en 100% polipropileno con tecnología agujereada avanzada, esta moqueta está específicamente diseñada para soportar el uso intensivo diario manteniendo su aspecto impecable durante años. Tecnología Agujereada de Alta Resistencia Esta moqueta agujereada tráfico intenso utiliza un proceso de fabricación especializado que entrelaza las fibras mediante agujas, creando una estructura compacta y extraordinariamente resistente. A diferencia de otros tipos de moqueta, el sistema agujereado garantiza que las fibras permanezcan firmemente ancladas, evitando el desprendimiento incluso en zonas de paso continuo. Por esta razón, es la elección preferida para espacios comerciales exigentes. Dos Versiones para Diferentes Necesidades Zerbodis ofrece flexibilidad con dos opciones de soporte adaptadas a distintos requisitos. Por un lado, la versión con soporte de poliuretano proporciona mayor amortiguación y confort acústico, ideal para oficinas y hoteles donde el bienestar es prioritario. Por otro lado, la versión con soporte de látex ofrece una adherencia superior y mayor estabilidad dimensional, perfecta para ferias, centros comerciales y espacios públicos con tráfico intenso constante. Acabado Velours de Alta Calidad El acabado tipo velours de esta moqueta agujereada tráfico intenso combina estética profesional con funcionalidad práctica. Además, su textura suave y uniforme crea una superficie agradable al tacto que mejora la experiencia de los usuarios. Asimismo, este acabado facilita el mantenimiento diario al ocultar eficazmente las marcas de pisadas y la suciedad superficial entre limpiezas. Material Polipropileno de Alto Rendimiento Gracias a su composición 100% polipropileno, Zerbodis ofrece ventajas significativas frente a otras fibras. En efecto, el polipropileno es naturalmente resistente a la humedad, no absorbe líquidos y se seca rápidamente, lo que previene la formación de moho y malos olores. De esta manera, resulta especialmente adecuado para zonas propensas a derrames o limpieza frecuente con agua. Aplicaciones Profesionales Versátiles Ideal para oficinas corporativas con alto tráfico de empleados y visitantes, hoteles que buscan combinar elegancia con durabilidad extrema, ferias comerciales y eventos donde se requiere instalación temporal pero resistente, escuelas y universidades con miles de estudiantes circulando diariamente, locales comerciales que necesitan mantener una imagen impecable, así como espacios públicos como centros culturales, bibliotecas y edificios gubernamentales. En definitiva, la moqueta agujereada tráfico intenso Zerbodis se adapta perfectamente a cualquier entorno exigente. Durabilidad y Vida Útil Extendida La construcción agujereada garantiza una vida útil significativamente superior a las moquetas convencionales. En consecuencia, su estructura permite soportar el tráfico intenso sin mostrar signos prematuros de desgaste, conservando su aspecto original durante años. Por lo tanto, representa una inversión rentable que reduce los costes de reemplazo a largo plazo. Mantenimiento Simplificado El polipropileno facilita extraordinariamente las tareas de limpieza y conservación. De hecho, su resistencia natural a las manchas y su capacidad para repeler líquidos simplifican el mantenimiento diario. Finalmente, una aspiración regular y limpieza ocasional con agua son suficientes para mantener la moqueta en condiciones óptimas, reduciendo significativamente los costes operativos de mantenimiento.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
