INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '4358fe89-fb28-45a3-856d-1815e9c747d5',
  'Felpudo Coco 17MM',
  'felpudo-coco-17-mm',
  'Felpudo coco 17 mm: la solución funcional y estética para tus entradas Este felpudo coco 17 mm está fabricado con fibra de coco 100% natural y una base de PVC resistente. Ha sido pensado específicamente para entradas que requieren una solución estética y funcional sin compromisos. El felpudo coco...',
  'Felpudo coco 17 mm: la solución funcional y estética para tus entradas Este felpudo coco 17 mm está fabricado con fibra de coco 100% natural y una base de PVC resistente. Ha sido pensado específicamente para entradas que requieren una solución estética y funcional sin compromisos. El felpudo coco 17 mm combina la belleza orgánica de las fibras naturales con la durabilidad necesaria para soportar el uso diario intensivo en cualquier tipo de acceso. Fibra de coco natural del felpudo 17 mm La fibra de coco utilizada en este felpudo coco 17 mm es completamente natural, renovable y biodegradable. Esta fibra posee una textura rígida perfecta para raspar eficazmente la suciedad de las suelas del calzado. Asimismo, retiene eficazmente tierra, polvo y humedad, evitando que entren en el interior de tu hogar o negocio. Por consiguiente, mantiene los espacios interiores considerablemente más limpios. Base de PVC resistente y antideslizante La base de PVC proporciona estabilidad excepcional y evita deslizamientos no deseados. Además, esta base resistente protege el suelo subyacente de arañazos y marcas. Por otro lado, garantiza que el felpudo permanezca firmemente en su lugar incluso con tráfico intenso de personas. Grosor de 17 mm para máximo rendimiento Con un grosor de 17 mm, el felpudo coco 17 mm ofrece una capacidad superior para raspar y retener la suciedad. Su altura proporciona el equilibrio perfecto entre eficacia de limpieza y comodidad al pisar. De esta manera, cada persona que entra realiza una limpieza profunda del calzado automáticamente sin esfuerzo adicional. Versatilidad de instalación del felpudo coco El formato se adapta perfectamente tanto a superficies planas como a fosos empotrados. Está disponible en rollos de varios tamaños que permiten ajustarse a cualquier medida de entrada. Esta versatilidad lo convierte en la solución ideal para puertas estándar, entradas amplias o accesos comerciales de gran formato. Acabado natural que aporta calidez El acabado natural del felpudo coco 17 mm aporta calidez y elegancia orgánica a cualquier entrada. Su apariencia rústica y acogedora complementa tanto estilos decorativos clásicos como contemporáneos. Sin embargo, no sacrifica resistencia ni funcionalidad por la estética natural. Aplicaciones ideales Este felpudo coco 17 mm es perfecto para entradas residenciales, portales de edificios, accesos comerciales, oficinas, hoteles, restaurantes y cualquier espacio que valore la combinación de funcionalidad, sostenibilidad y diseño natural con grosor equilibrado. Características principales Material: Fibra de coco 100% natural Base: PVC resistente antideslizante Grosor: 17 mm Formato: Rollos en varios tamaños Uso: Interior y exterior protegido Instalación: Superficie plana o foso empotrado Elige el felpudo coco 17 mm para combinar eficacia de limpieza, sostenibilidad y estética natural en tu entrada.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
