INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '977883a2-4ba9-4765-8f7f-3f4383efcf4b',
  'Sisal Sintético Lasdis',
  'sisal-lasdis-domestico',
  'La moqueta sisal sintética Lasdis combina la estética natural del sisal tradicional con las prestaciones técnicas de las fibras sintéticas modernas. Esta moqueta tipo sisal es la solución perfecta para quienes buscan durabilidad y diseño en un solo producto. Características de la moqueta sisal si...',
  'La moqueta sisal sintética Lasdis combina la estética natural del sisal tradicional con las prestaciones técnicas de las fibras sintéticas modernas. Esta moqueta tipo sisal es la solución perfecta para quienes buscan durabilidad y diseño en un solo producto. Características de la moqueta sisal sintética Lasdis Fabricada con fibras de última generación (91% polipropileno y 9% poliéster), esta moqueta tipo sisal destaca por su extraordinaria resistencia al desgaste y a las manchas. Su textura firme y apariencia natural aportan calidez y elegancia a cualquier espacio, tanto residencial como comercial. Composición técnica de alto rendimiento La moqueta sisal sintética Lasdis está diseñada para soportar tráfico intenso sin perder su aspecto original. Su estructura de fibras sintéticas garantiza una durabilidad superior frente a las moquetas naturales tradicionales, eliminando problemas como la decoloración o el deterioro por humedad. Opciones de respaldo técnico Este pavimento textil está disponible con tres tipos de respaldo profesional: Vlies: Base técnica ligera y versátil ECO Grip: Opción ecológica con adherencia natural Látex: Máxima estabilidad y resistencia Cada opción se adapta a diferentes necesidades de instalación y uso, garantizando el mejor resultado en cada proyecto. Ventajas para tu hogar o negocio La moqueta tipo sisal Lasdis ofrece múltiples beneficios prácticos. Es antialérgica, ideal para personas sensibles. Su superficie antideslizante proporciona seguridad en zonas de paso. Además, es compatible con sistemas de calefacción por suelo radiante, sin emisiones de formaldehído. Aplicaciones versátiles Esta solución textil es perfecta para viviendas, oficinas, hoteles, tiendas, espacios comerciales de alto tránsito y cualquier ambiente que requiera resistencia y estilo. Su diseño sobrio se integra armoniosamente con cualquier decoración. Fácil mantenimiento A diferencia del sisal natural, esta alternativa sintética requiere mínimo mantenimiento. Resistente a manchas y fácil de limpiar con aspirado regular y limpieza puntual cuando sea necesario. Disponibilidad inmediata Tenemos stock de la referencia 3886 lista para entrega. Para consultas sobre otras referencias, medidas personalizadas o asesoramiento técnico, contáctanos en ventas@disstands.com o visita nuestra sección de moquetas para más opciones. Invierte en una moqueta sisal sintética Lasdis y disfruta de la belleza natural con la tranquilidad de un producto técnico de máxima calidad y durabilidad.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  25.00,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
