INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a697704a-8794-4c18-8c7c-c35414b97019',
  'Suelo Abotonado',
  'suelo-abotonado-antideslizante-por-metros',
  'Suelo abotonado antideslizante por metros: seguridad versátil para todos los espacios El suelo abotonado antideslizante por metros es una solución práctica, segura y versátil para recubrir superficies en interiores y exteriores. Este pavimento destaca por su capacidad de adaptarse a múltiples ent...',
  'Suelo abotonado antideslizante por metros: seguridad versátil para todos los espacios El suelo abotonado antideslizante por metros es una solución práctica, segura y versátil para recubrir superficies en interiores y exteriores. Este pavimento destaca por su capacidad de adaptarse a múltiples entornos, ofreciendo seguridad y durabilidad sin comprometer la estética funcional. El formato de venta por metros permite adquirir exactamente la cantidad necesaria para tu proyecto. Diseño antideslizante del suelo abotonado por metros El diseño característico incorpora una textura en relieve tipo "botón" que proporciona propiedades antideslizantes excepcionales. Esta superficie texturizada garantiza agarre óptimo incluso en condiciones húmedas. Por consiguiente, reduce significativamente el riesgo de resbalones y caídas en zonas de alto tránsito. Resistencia y durabilidad superior Este pavimento de caucho ofrece alta resistencia al desgaste que soporta el tráfico intenso sin perder sus propiedades. Su composición robusta resiste condiciones climáticas adversas en exteriores. Asimismo, mantiene su funcionalidad y apariencia durante años sin necesidad de reemplazos frecuentes. Versatilidad del suelo antideslizante por metros El suelo abotonado antideslizante por metros encaja tanto en entornos profesionales como domésticos gracias a su diseño funcional. Es ideal para múltiples espacios y usos. Por ejemplo, funciona perfectamente en establecimientos de hostelería como bares, restaurantes y cafeterías. También es excelente para proyectos de decoración interior que buscan texturas originales y seguras. Además, resulta perfecto para eventos temporales que requieren pavimentos seguros y rápidos de instalar. En jardines y terrazas aporta seguridad y confort. Por otro lado, en zonas de paso frecuente como vestíbulos y accesos garantiza protección antideslizante constante. Formato práctico: venta por metros Este pavimento textil se adapta a diferentes necesidades gracias a su formato flexible. De esta manera, puedes adquirir exactamente la cantidad que necesitas sin desperdicios. La instalación es sencilla y permite cubrir superficies de cualquier dimensión con facilidad. Aplicaciones específicas El suelo abotonado antideslizante por metros es la elección perfecta para cocinas industriales, vestuarios deportivos, gimnasios, áreas de piscinas, rampas de acceso, talleres mecánicos, terrazas residenciales y stands feriales. Su capacidad para resistir humedad y tráfico pesado lo convierte en una solución integral. Características principales Textura: Relieve tipo botón antideslizante Material: Caucho de alta densidad Uso: Interior y exterior Resistencia: Alta al desgaste Formato: Venta por metros continuos Aplicaciones: Hostelería, eventos, jardines Elige el suelo abotonado antideslizante por metros para combinar seguridad, durabilidad y versatilidad.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
