INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'c3a6402d-2879-4862-8530-81feb498d5ef',
  'Moqueta Impresa Vanidis | Punzonada 1000-1400gr | Disstands',
  'suelo-vinilico-estampado-vanidis',
  'Vanidis - Revestimiento de Suelo de Alto Rendimiento con Acabado de Juta Sintética Vanidis es un suelo vinílico estampado Vanidis de alto rendimiento técnico. Está especialmente diseñado para satisfacer exigencias rigurosas. Es perfecto para entornos profesionales donde la durabilidad es fundamen...',
  'Vanidis - Revestimiento de Suelo de Alto Rendimiento con Acabado de Juta Sintética Vanidis es un suelo vinílico estampado Vanidis de alto rendimiento técnico. Está especialmente diseñado para satisfacer exigencias rigurosas. Es perfecto para entornos profesionales donde la durabilidad es fundamental. El diseño sofisticado marca la diferencia. El confort es un aspecto clave. Este pavimento representa la perfecta simbiosis entre funcionalidad avanzada y estética contemporánea. Ofrece soluciones integrales para espacios exigentes. Demandan lo mejor en prestaciones. La apariencia visual es excepcional. Acabado de Juta Sintética: Elegancia Natural con Tecnología Avanzada El característico acabado de juta sintética de Vanidis aporta una dimensión estética única que combina la calidez y textura natural de las fibras vegetales con las ventajas técnicas de los materiales sintéticos modernos. Esta superficie proporciona una apariencia elegante y acogedora que eleva instantáneamente cualquier espacio, creando ambientes profesionales que transmiten calidad, confort y sofisticación sin igual. La textura visual enriquece los interiores con un toque distintivo que resulta atemporal y versátil, adaptándose perfectamente a diferentes estilos de diseño arquitectónico y decorativo contemporáneo o clásico. Funcionalidad Técnica Superior Vanidis destaca por su excepcional aislamiento acústico, contribuyendo significativamente a la reducción del ruido de impacto y la reverberación sonora en espacios de trabajo, comerciales e institucionales de todo tipo. Esta propiedad mejora sustancialmente el confort ambiental, creando entornos más silenciosos y agradables que favorecen la concentración, la productividad y el bienestar general de usuarios y trabajadores en cualquier contexto. Además, ofrece resistencia térmica que proporciona aislamiento adicional efectivo, ayudando a mantener temperaturas confortables en el interior y contribuyendo a la eficiencia energética del edificio de manera notable. Esta característica resulta especialmente valiosa en proyectos comprometidos con la sostenibilidad y el ahorro energético a largo plazo. Compromiso con la Sostenibilidad Un aspecto fundamental de Vanidis es su condición de material totalmente reciclable, alineándose con los principios de economía circular y construcción sostenible, minimizando significativamente el impacto ambiental al finalizar su ciclo de vida útil completo.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
