INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ceeeb403-4681-41f9-8ffe-2e7ec8d4c6b5',
  'Moqueta Impresa Decodis - Pelo Punzonado - 900gr',
  'moqueta-impresa-decodis-pelo-punzonado-900gr',
  'La moqueta Decodis ofrece una combinación perfecta de estilo, comodidad y funcionalidad para espacios que demandan personalización y calidad. Con su superficie de terciopelo estampado y soporte de juta sintética, proporciona un acabado elegante y una resistencia excepcional al uso diario, convirt...',
  'La moqueta Decodis ofrece una combinación perfecta de estilo, comodidad y funcionalidad para espacios que demandan personalización y calidad. Con su superficie de terciopelo estampado y soporte de juta sintética, proporciona un acabado elegante y una resistencia excepcional al uso diario, convirtiéndola en la solución ideal para interiores donde el diseño y la durabilidad son prioridad. Características técnicas distintivas La tecnología de impresión digital avanzada permite crear diseños personalizados ilimitados con una resolución excepcional. Su construcción incluye: Pelo punzonado de 900 gr/m² que garantiza densidad y confort 100% poliamida en la superficie para máxima resistencia Base de juta sintética que proporciona estabilidad dimensional Terciopelo estampado con colores vibrantes y duraderos Tratamiento antideslizante para mayor seguridad Versatilidad en diseño y aplicaciones Decodis transforma cualquier espacio mediante la personalización completa del diseño. Perfecta para: Hoteles boutique que buscan diferenciación visual Tiendas y showrooms con identidad de marca específica Oficinas corporativas que requieren diseños exclusivos Espacios residenciales con decoración personalizada Eventos temáticos y montajes temporales especiales La capacidad de impresión personalizada permite reproducir logotipos corporativos, patrones geométricos, diseños artísticos o cualquier imagen con fidelidad fotográfica, creando ambientes únicos e irrepetibles. Rendimiento y mantenimiento El acabado Room Decor combina estética premium con funcionalidad práctica: Alto rendimiento acústico que reduce el ruido ambiental Confort térmico mejorado para mayor bienestar Resistencia a la decoloración y al desgaste Facilidad de limpieza con productos convencionales Durabilidad garantizada en espacios de tráfico moderado Instalación profesional Su base de juta sintética facilita la instalación mediante adhesivos específicos para moquetas, garantizando una fijación perfecta y duradera. El formato en rollos permite cubrir grandes superficies con mínimas juntas, optimizando el resultado visual. La moqueta Decodis no es solo un revestimiento, es una herramienta de diseño que permite expresar la identidad única de cada espacio, combinando tecnología de impresión avanzada con la calidad y confort de una moqueta premium.',
