INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '9bf00cdb-e2e8-491b-821b-3ead38cdf73b',
  'Moqueta Impresa Hi-Decodis - Pelo Punzonado - 900gr',
  'moqueta-terciopelo-estampado-hi-decodis',
  'Hi-Decodis es una moqueta de terciopelo estampado de alta calidad, especialmente diseñada para espacios que demandan una combinación perfecta entre estilo sofisticado y durabilidad excepcional. Fabricada con fibras de poliamida de última generación y un respaldo robusto de yute sintético, esta mo...',
  'Hi-Decodis es una moqueta de terciopelo estampado de alta calidad, especialmente diseñada para espacios que demandan una combinación perfecta entre estilo sofisticado y durabilidad excepcional. Fabricada con fibras de poliamida de última generación y un respaldo robusto de yute sintético, esta moqueta representa la excelencia en revestimientos textiles para suelos. Su composición garantiza no solo una estética refinada, sino también un rendimiento técnico superior en entornos de uso intensivo. La textura aterciopelada de Hi-Decodis proporciona un confort notable al tacto y al pisado, creando ambientes acogedores y elegantes. Sus propiedades de absorción acústica son excepcionales, contribuyendo significativamente a la reducción del ruido ambiental y mejorando el confort acústico de cualquier espacio. Además, su resistencia al desgaste diario está especialmente optimizada para soportar el tránsito constante sin perder su apariencia original. El estampado de esta moqueta añade un valor estético diferencial, permitiendo crear espacios con personalidad propia mientras mantiene su funcionalidad. La poliamida utilizada en su fabricación aporta resistencia a las manchas y facilita las tareas de mantenimiento, características esenciales en entornos profesionales. Hi-Decodis es la solución ideal para una amplia variedad de aplicaciones: desde oficinas corporativas que buscan proyectar una imagen profesional y acogedora, hasta hoteles boutique y establecimientos de hostelería que requieren productos de alta gama. También resulta perfecta para zonas residenciales de alto tránsito como pasillos, escaleras y áreas comunes en edificios premium, donde la combinación de estética y resistencia es fundamental.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
