INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '2208a607-8ce5-47f9-8cc2-d937633f6ba9',
  'PVC Acousdis',
  'pvc-acousdis-suelo-vinilico-acustico',
  'PVC Acousdis: suelo vinílico acústico de alto rendimiento para espacios exigentes El PVC Acousdis es un suelo vinílico acústico de alta resistencia diseñado específicamente para entornos exigentes que requieren confort, aislamiento acústico superior y estética moderna. Este PVC Acousdis combina t...',
  'PVC Acousdis: suelo vinílico acústico de alto rendimiento para espacios exigentes El PVC Acousdis es un suelo vinílico acústico de alta resistencia diseñado específicamente para entornos exigentes que requieren confort, aislamiento acústico superior y estética moderna. Este PVC Acousdis combina tecnología avanzada de absorción acústica con durabilidad excepcional, convirtiéndose en la solución perfecta para espacios comerciales, residenciales y profesionales donde el control del ruido es prioritario. Construcción técnica de 3,2 mm de grosor Con 3,2 mm de grosor total, el PVC Acousdis proporciona una estructura robusta que garantiza estabilidad dimensional y confort al caminar. Su capa de uso de 0,7 mm asegura durabilidad excepcional frente al tráfico intensivo, resistencia al desgaste y facilidad de limpieza. Por consiguiente, mantiene su aspecto original durante años incluso en condiciones de uso comercial exigente. Excelente aislamiento acústico La característica diferenciadora del PVC Acousdis es su capacidad de aislamiento acústico superior. Reduce significativamente el ruido de impacto y la transmisión sonora entre plantas, creando ambientes más silenciosos y confortables. Asimismo, mejora la calidad acústica de espacios abiertos, oficinas, hoteles, centros educativos y viviendas donde el control del ruido es esencial. Resistencia y facilidad de mantenimiento Este suelo vinílico garantiza un excelente comportamiento frente al uso intensivo gracias a su construcción técnica avanzada. La superficie es resistente a manchas, rayados y productos químicos de limpieza habituales. Además, su facilidad de limpieza permite mantenerlo impecable con aspirado regular y fregado ocasional, reduciendo drásticamente los costes de mantenimiento. Estética moderna y versátil del suelo vinílico acústico El PVC Acousdis ofrece una estética moderna que se adapta perfectamente a cualquier estilo decorativo contemporáneo. Su acabado sofisticado aporta elegancia profesional a espacios comerciales. Por otro lado, su diseño versátil se integra armoniosamente en ambientes residenciales que buscan combinar funcionalidad técnica con belleza visual. Instalación rápida y eficiente La instalación del PVC Acousdis es rápida y eficiente, minimizando las interrupciones en espacios operativos. De esta manera, permite poner en funcionamiento las instalaciones en el menor tiempo posible. Compatible con múltiples sistemas de instalación, se adapta a las necesidades específicas de cada proyecto. Aplicaciones ideales El PVC Acousdis es perfecto para oficinas corporativas, hoteles, hospitales, centros educativos, viviendas residenciales, espacios comerciales, salas de reuniones, estudios de grabación y cualquier entorno que requiera aislamiento acústico superior combinado con resistencia al tráfico intensivo y estética profesional moderna. Características principales Grosor total: 3,2 mm Capa de uso: 0,7 mm Propiedad principal: Aislamiento acústico superior Resistencia: Alta al tráfico intensivo Limpieza: Fácil mantenimiento Estética: Moderna y versátil Uso: Comercial y residencial Instalación: Rápida y eficiente Elige el PVC Acousdis para combinar confort acústico, durabilidad técnica y estética moderna en tu proyecto.',
