INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'eac6ebbd-d988-407b-8020-322caf61c3bc',
  'PVC Muradis',
  'revestimiento-mural-vinilico-muradis',
  'PVC Muradis es un revestimiento mural flexible de 1,5 mm de espesor, diseñado para aplicaciones verticales y horizontales en entornos públicos exigentes. Su composición multicapa con refuerzo de fibra de vidrio garantiza una alta estabilidad dimensional, mientras que su superficie lisa facilita e...',
  'PVC Muradis es un revestimiento mural flexible de 1,5 mm de espesor, diseñado para aplicaciones verticales y horizontales en entornos públicos exigentes. Su composición multicapa con refuerzo de fibra de vidrio garantiza una alta estabilidad dimensional, mientras que su superficie lisa facilita el mantenimiento. Puede instalarse mediante soldadura en frío o en caliente. Cuenta con propiedades antibacterianas y clasificación al fuego Bs2-d0, lo que lo convierte en una solución ideal para hospitales, centros educativos, oficinas y espacios de uso intensivo.',
