INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '484f6082-dc0a-4891-8aca-414da08eae80',
  'PVC Luxidis',
  'suelo-vinilico-modular-antibacteriano',
  'Suelo Vinílico Modular Antibacteriano: Luxidis iGUARD El suelo vinílico modular antibacteriano Luxidis es una solución de pavimento técnico de diseño realista, especialmente desarrollada para espacios donde la durabilidad, la higiene avanzada y la estética impecable son factores absolutamente crí...',
  'Suelo Vinílico Modular Antibacteriano: Luxidis iGUARD El suelo vinílico modular antibacteriano Luxidis es una solución de pavimento técnico de diseño realista, especialmente desarrollada para espacios donde la durabilidad, la higiene avanzada y la estética impecable son factores absolutamente críticos. Este suelo vinílico modular combina tecnología antibacteriana de vanguardia con formato modular de fácil instalación, creando la solución ideal para entornos comerciales exigentes, espacios de hostelería de alta rotación y proyectos residenciales contemporáneos que priorizan la salud. Sistema iGUARD Silver Knight: Protección Antibacteriana El innovador sistema iGUARD Silver Knight integrado en este suelo modular antibacteriano ofrece protección activa continua contra bacterias, virus y microorganismos patógenos durante las 24 horas del día. Por tanto, crea ambientes más seguros e higiénicos sin necesidad de tratamientos adicionales posteriores. Además, esta protección antibacteriana permanece activa durante toda la vida útil del pavimento instalado. Asimismo, resulta especialmente importante en hoteles, restaurantes, tiendas, clínicas y espacios de alta afluencia de público donde la higiene es prioritaria. Características Técnicas del Suelo Vinílico Con 2,5 mm de espesor total y 0,55 mm de capa de uso reforzada, este suelo vinílico antibacteriano ofrece resistencia excepcional al tráfico intensivo, arañazos superficiales y desgaste diario continuado. Además, su superficie es completamente impermeable, protegiendo contra derrames accidentales, humedad ambiental y facilitando enormemente las tareas de limpieza e higienización frecuente. En consecuencia, resulta ideal para cocinas comerciales profesionales, baños públicos, áreas húmedas y zonas donde la limpieza frecuente con productos químicos desinfectantes es obligatoria. Instalación y Diseño Realista El diseño realista de alta definición imita perfectamente texturas naturales de madera noble, piedra o diseños contemporáneos abstractos. Posteriormente, el formato modular facilita una instalación rápida mediante sistema click o adhesivo, reduciendo tiempos de obra significativamente. Además, está completamente libre de ftalatos nocivos para la salud. Finalmente, perfecto para hoteles boutique, cadenas de restauración, tiendas retail, oficinas corporativas, clínicas médicas y viviendas residenciales que priorizan higiene certificada, durabilidad garantizada y diseño contemporáneo excepcional.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
