INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a4257a9f-c2e1-41f3-896d-0b65ef42c1bc',
  'Loseta Medudis',
  'loseta-moqueta-modular-intensivo',
  'Loseta Modular Medudis - Diseño Estructurado y Rendimiento Profesional La Loseta Medudis es una loseta moqueta modular intensivo de alto rendimiento. Su diseño estructurado y acabado profesional la convierten en la elección perfecta. Es ideal para espacios comerciales que demandan estética sofist...',
  'Loseta Modular Medudis - Diseño Estructurado y Rendimiento Profesional La Loseta Medudis es una loseta moqueta modular intensivo de alto rendimiento. Su diseño estructurado y acabado profesional la convierten en la elección perfecta. Es ideal para espacios comerciales que demandan estética sofisticada. También para zonas residenciales que requieren máxima durabilidad. Este producto ha sido específicamente desarrollado para uso intensivo. Soporta las exigencias de zonas de alto tránsito. No compromete su apariencia elegante. Mantiene sus prestaciones técnicas a lo largo del tiempo. Materiales de Máxima Calidad Fabricada en nylon teñido en masa (SDN - Solution Dyed Nylon), la Loseta Medudis incorpora una de las tecnologías más avanzadas en fibras textiles para pavimentos. Este sistema de teñido garantiza que el color penetra completamente en cada fibra durante el proceso de fabricación, no solo en su superficie. El resultado es una resistencia excepcional a la decoloración causada por la luz solar, el tránsito intenso y el uso de productos de limpieza, manteniendo colores vivos e intensos durante años. El soporte de bitumen proporciona estabilidad dimensional superior, evitando deformaciones, ondulaciones o desplazamientos de las losetas incluso en condiciones de uso exigente. Esta base robusta asegura una instalación firme y duradera que mantiene su integridad estructural a lo largo de toda su vida útil. Formato Modular Versátil Con un formato cuadrado de 50x50 cm, estas losetas permiten una instalación flexible y creativa. Puedes crear patrones personalizados, combinar diferentes diseños o colores, y reemplazar piezas individuales en caso de desgaste localizado sin necesidad de cambiar todo el pavimento. Esta modularidad optimiza el mantenimiento y reduce significativamente los costes de conservación. Presentación práctica: Cada caja contiene 20 losetas, cubriendo 5 m² de superficie, facilitando el cálculo de materiales necesarios para tu proyecto. Diseño Estructurado y Elegante El diseño estructurado de Medudis aporta profundidad visual y textura sofisticada, creando ambientes elegantes y contemporáneos en oficinas, hoteles, comercios, salas de reuniones y espacios residenciales premium donde la primera impresión cuenta.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
