INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '455498b6-e7a2-4b6f-8163-324ae57a9932',
  'Loseta Maximudis',
  'loseta-maximidis',
  'La loseta moqueta modular Maximudis es la solución perfecta para espacios de alto tráfico que requieren resistencia y estética. Esta loseta de moqueta modular de 50×50 cm combina textura loop pile con nylon teñido en masa (SDN), ofreciendo durabilidad excepcional y mantenimiento del color en proy...',
  'La loseta moqueta modular Maximudis es la solución perfecta para espacios de alto tráfico que requieren resistencia y estética. Esta loseta de moqueta modular de 50×50 cm combina textura loop pile con nylon teñido en masa (SDN), ofreciendo durabilidad excepcional y mantenimiento del color en proyectos residenciales y comerciales exigentes. Características técnicas de la loseta Maximudis Maximudis destaca por su composición en nylon SDN (teñido en masa), que proporciona una resistencia superior al desgaste y garantiza que el color permanezca inalterado incluso en zonas de tráfico intensivo. Su textura loop pile ofrece un aspecto liso o jaspeado elegante, adaptándose a diferentes estilos decorativos. El soporte de bitumen asegura una excelente estabilidad dimensional, evitando deformaciones y facilitando una instalación rápida y precisa. Las dimensiones modulares de 50×50 cm permiten crear diseños personalizados y facilitan el reemplazo de losetas individuales en caso de daño localizado. Aplicaciones ideales para loseta moqueta modular Oficinas corporativas: Resistencia al tráfico continuo y absorción acústica que mejora el ambiente laboral Hoteles y establecimientos turísticos: Durabilidad y facilidad de mantenimiento en pasillos y habitaciones Tiendas y espacios comerciales: Aspecto profesional que soporta el paso constante de clientes Viviendas modernas: Confort térmico y acústico para dormitorios y salones Centros educativos: Solución práctica y resistente para aulas y zonas comunes Ventajas de instalar Maximudis Instalación sencilla y rápida: El formato modular permite colocar las losetas sin necesidad de mano de obra especializada Mantenimiento económico: Posibilidad de sustituir losetas individuales sin renovar todo el pavimento Versatilidad decorativa: Disponible en acabados liso y jaspeado para diferentes estilos Durabilidad garantizada: El nylon SDN asegura años de uso sin pérdida de color ni textura Absorción acústica: Reduce el ruido ambiental, creando espacios más confortables Especificaciones técnicas Dimensiones: 50 × 50 cm Composición: Nylon SDN (teñido en masa) Textura: Loop pile Soporte: Bitumen para estabilidad dimensional Uso recomendado: Tráfico intensivo (clase 33 comercial) Opciones de acabado: Liso y jaspeado La loseta moqueta modular Maximudis representa la combinación perfecta entre funcionalidad, estética y durabilidad. Su diseño modular y materiales de alta calidad la convierten en la elección inteligente para proyectos que buscan un pavimento resistente, fácil de mantener y visualmente atractivo.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
