INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f109907a-fedf-4de5-8f18-90482325c9a0',
  'Loseta Macdis',
  'loseta-macdis',
  'La loseta de moqueta estructurada para alto tránsito Macdis es la solución perfecta para entornos que demandan máxima resistencia y diseño técnico avanzado. Esta loseta de moqueta estructurada de 50×50 cm combina textura loop pile con acabado estructurado que añade profundidad visual, creando sup...',
  'La loseta de moqueta estructurada para alto tránsito Macdis es la solución perfecta para entornos que demandan máxima resistencia y diseño técnico avanzado. Esta loseta de moqueta estructurada de 50×50 cm combina textura loop pile con acabado estructurado que añade profundidad visual, creando superficies elegantes preparadas para soportar el tránsito más exigente. Características técnicas de la loseta Macdis Macdis destaca por su fabricación en Solution Dyed Nylon (SDN), un material de alta tecnología que garantiza resistencia excepcional al desgaste y permanencia del color incluso en zonas de alto tránsito. El nylon SDN teñido en masa evita que el color se desgaste superficialmente, ya que cada fibra está impregnada del pigmento desde su núcleo. El respaldo de bitumen proporciona estabilidad dimensional superior, evitando deformaciones y ondulaciones durante toda la vida útil del producto. Su textura loop pile estructurada no solo aporta un diseño técnico sofisticado, sino que también mejora la resistencia mecánica y facilita el mantenimiento diario. Las dimensiones modulares de 50×50 cm ofrecen flexibilidad de instalación, permitiendo crear patrones personalizados, combinar colores y sustituir losetas individuales sin necesidad de renovar todo el pavimento. Aplicaciones ideales para loseta de moqueta estructurada Esta loseta de moqueta estructurada para alto tránsito está especialmente diseñada para: Oficinas corporativas: Zonas de recepción, pasillos y áreas de trabajo con tráfico continuo donde se requiere durabilidad sin sacrificar estética Hoteles y establecimientos turísticos: Pasillos, habitaciones y zonas comunes que necesitan resistencia al uso intensivo con mantenimiento sencillo Tiendas y espacios comerciales: Superficies que soportan el flujo constante de clientes manteniendo un aspecto profesional impecable Centros educativos: Aulas, bibliotecas y zonas de circulación que requieren pavimentos duraderos y de fácil limpieza Espacios residenciales de alto tránsito: Entradas, salones y pasillos en viviendas modernas que buscan confort y resistencia Ventajas de instalar la loseta Macdis Resistencia extrema al desgaste: El nylon SDN garantiza años de uso intensivo sin deterioro visible Diseño técnico estructurado: La textura aporta profundidad visual y oculta mejor la suciedad entre limpiezas Instalación modular flexible: Permite crear diseños personalizados y facilita reparaciones puntuales Mantenimiento simplificado: La superficie estructurada disimula huellas y manchas menores Absorción acústica eficiente: Reduce el ruido de pasos y mejora el confort acústico del espacio Estabilidad dimensional garantizada: El respaldo de bitumen evita movimientos y burbujas Especificaciones técnicas Dimensiones: 50 × 50 cm Composición: Solution Dyed Nylon (SDN) Textura: Loop pile estructurada Respaldo: Bitumen de alta estabilidad Clasificación de uso: Tránsito intensivo (clase 33 comercial) Acabado: Estructurado técnico con profundidad visual Instalación: Sistema modular de colocación libre o adhesiva La loseta de moqueta estructurada para alto tránsito Macdis representa la elección inteligente para proyectos que no aceptan compromisos. Su combinación de tecnología SDN, diseño estructurado y formato modular la convierte en el pavimento ideal para espacios que exigen lo máximo en resistencia, funcionalidad y estética profesional.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
