INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '5a76a280-47b6-4ce5-8f4b-58f829ecc5f6',
  'Loseta Canopdis',
  'moqueta-modular-sostenible-econyl',
  'La moqueta modular sostenible ECONYL Canopdis representa la máxima expresión de diseño técnico, sostenibilidad ambiental y rendimiento profesional en revestimientos modulares. Esta moqueta modular sostenible de alta precisión está fabricada con hilo ECONYL® 100% regenerado, un nylon sostenible ob...',
  'La moqueta modular sostenible ECONYL Canopdis representa la máxima expresión de diseño técnico, sostenibilidad ambiental y rendimiento profesional en revestimientos modulares. Esta moqueta modular sostenible de alta precisión está fabricada con hilo ECONYL® 100% regenerado, un nylon sostenible obtenido de redes de pesca recuperadas del océano, desechos de alfombras y otros residuos plásticos. Además, está desarrollada con innovadora tecnología MBrodery® que aporta un diseño estructurado elegante, detallado y visualmente impactante. Tecnología ECONYL® Regenerada El hilo ECONYL® utilizado en esta moqueta sostenible es completamente regenerado, contribuyendo activamente a la economía circular y la reducción de residuos plásticos en océanos. Por tanto, cada metro cuadrado instalado representa un impacto positivo en el medio ambiente. Asimismo, mantiene las mismas propiedades técnicas y de calidad que el nylon virgen tradicional, sin comprometer rendimiento ni durabilidad. Características Técnicas Superiores Con un grosor total de 9,7 mm y una textura rica en relieve creada mediante tecnología MBrodery®, esta moqueta modular ECONYL ofrece confort excepcional al caminar, absorción acústica superior y alto rendimiento técnico en entornos de uso intensivo. Además, cuenta con certificación Bfl-s1 de reacción al fuego, cumpliendo con las normativas más exigentes de seguridad. Asimismo, dispone de certificación Green Label Plus que garantiza bajas emisiones de VOC para ambientes saludables. Aplicaciones Premium y Diseño Estructurado Perfecta para oficinas corporativas premium, salas de reuniones ejecutivas, hoteles de categoría superior, showrooms de marca y espacios representativos donde se prioriza el diseño sofisticado sin renunciar a la sostenibilidad ambiental. En consecuencia, la estructura loop pile combinada con la tecnología MBrodery® crea un patrón visual distintivo que aporta elegancia y personalidad. Posteriormente, su formato modular en losetas facilita la instalación rápida, permite reemplazos puntuales de zonas desgastadas y ofrece máxima flexibilidad en diseño de espacios corporativos contemporáneos. Finalmente, reduce el impacto ambiental contribuyendo a la economía circular global sostenible.',
  '35b2fe5e-cfd5-4fd1-85b1-b5108ff7adae',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'c91c9035-e587-48ca-8487-40ff73cfbf36',
  'Moqueta Le Besdis',
  'moqueta-saxony-bfl-s1-poliamida',
  'Moquetas Saxony: confort superior y durabilidad excepcional Las moquetas de textura Saxony con fibras 100% poliamida representan lo mejor en pavimentos textiles. De hecho, están diseñadas específicamente para espacios que necesitan confort, absorción acústica y larga duración. Tecnología de fabri...',
  'Moquetas Saxony: confort superior y durabilidad excepcional Las moquetas de textura Saxony con fibras 100% poliamida representan lo mejor en pavimentos textiles. De hecho, están diseñadas específicamente para espacios que necesitan confort, absorción acústica y larga duración. Tecnología de fabricación avanzada El distintivo pelo alto y denso del Saxony es el resultado de un proceso de manufactura preciso. En primer lugar, cada fibra de poliamida se corta, tuerce y fija térmicamente. Como resultado, esto crea una superficie con sensación lujosa al caminar. Además, la construcción vertical del pelo tiene alturas entre 12 y 20 mm. Por lo tanto, esto crea millones de puntos de apoyo. Así, el peso se distribuye uniformemente y se reduce la fatiga al caminar. De hecho, los usuarios describen la sensación como "caminar sobre nubes". Resistencia sin comprometer suavidad Sin embargo, esta suavidad no compromete la resistencia. Por el contrario, la poliamida empleada mantiene su estructura incluso con uso intensivo. Además, la moqueta recupera su forma original después de cada pisada. Absorción acústica excepcional Por otro lado, estas moquetas pueden reducir el ruido ambiental hasta 30 decibelios. En consecuencia, crean espacios más tranquilos y productivos. Por ejemplo, en oficinas open-plan, esto significa menor estrés laboral y mayor concentración. Certificaciones y seguridad Asimismo, la clasificación al fuego Bfl-s1 garantiza cumplimiento con las normativas europeas más estrictas. Igualmente, la certificación UPEC U3P3E1C0 valida su resistencia: U3: Resistencia al desgaste P3: Resistencia al punzonamiento E1: Resistencia al agua C0: Resistencia a productos químicos Aplicaciones ideales En definitiva, el Saxony es la elección perfecta para: Oficinas corporativas: La imagen profesional es crucial y por ello esta moqueta transmite calidad. Zonas comunes de edificios: Requieren elegancia duradera y también gran resistencia al tráfico. Espacios residenciales premium: El lujo debe ser tangible y por tanto el confort, evidente. Hoteles boutique: Cada detalle cuenta para la experiencia del huésped y precisamente esta moqueta marca la diferencia. Una inversión que se amortiza Finalmente, la inversión en moqueta Saxony se amortiza rápidamente. No solo por su durabilidad, sino también por crear ambientes que comunican calidad. En conclusión, cada detalle cuenta para transmitir profesionalidad y atención al detalle.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7f8e6a7f-4175-46bc-8ea8-727134868eea',
  'Moqueta Ultrasoftdis',
  'moqueta-saxony-resistente',
  'La moqueta Saxony resistente representa el equilibrio perfecto entre elegancia atemporal y durabilidad excepcional. Además, está diseñada específicamente para espacios interiores exigentes. Por esta razón, este revestimiento textil de poliamida premium combina prestaciones técnicas superiores con...',
  'La moqueta Saxony resistente representa el equilibrio perfecto entre elegancia atemporal y durabilidad excepcional. Además, está diseñada específicamente para espacios interiores exigentes. Por esta razón, este revestimiento textil de poliamida premium combina prestaciones técnicas superiores con una estética sofisticada. Tecnología y Calidad Premium en Revestimientos Saxony En primer lugar, está fabricada con 100% poliamida de primera calidad. Por lo tanto, garantiza un rendimiento excepcional durante años. Asimismo, su característica superficie densa de pelo cortado tipo terciopelo crea un aspecto lujoso. De hecho, invita al tacto y proporciona calidez inmediata en cualquier entorno interior. Construcción de Pelo Cortado: Durabilidad Garantizada La tecnología Saxony se distingue por su construcción de pelo cortado vertical. Posteriormente, tras un proceso de torsión y fijación térmica, genera una superficie extraordinariamente suave y mullida. Como resultado, mantiene su forma y belleza incluso después de años de uso continuado en espacios de alto tránsito. Características Técnicas del Revestimiento de Poliamida Con un grosor de 6,8mm, esta moqueta Saxony resistente ofrece múltiples ventajas: Aislamiento acústico de 25dB: Absorbe eficazmente el ruido ambiental. Por consiguiente, crea espacios más tranquilos y confortables. Aislamiento térmico adicional: Además del confort acústico, mejora la eficiencia térmica de tus espacios. Clasificación Bfl-s1: Cumple con la máxima seguridad contra incendios. En efecto, sigue la normativa europea más exigente. Certificación UPEC U2SP2E1C0: Por otro lado, cuenta con validación profesional de resistencia internacional. Certificaciones de Seguridad y Normativa Europea La clasificación Bfl-s1 frente al fuego garantiza el cumplimiento de los estándares europeos más estrictos. En consecuencia, es apropiada para instalaciones comerciales y residenciales. Especialmente, para aquellas que requieren máximas garantías de seguridad. Aplicaciones Versátiles para Espacios Interiores Este revestimiento textil elegante es perfecto para múltiples espacios. A continuación, te mostramos las aplicaciones principales: Habitaciones principales: Ideal para dormitorios de alto standing donde el confort es prioritario. Zonas comunes: Perfecta para áreas residenciales y comerciales que requieren elegancia duradera. Despachos profesionales: Excelente para oficinas ejecutivas que buscan distinción. Comercios selectos: Especialmente adecuada para boutiques y tiendas de tráfico moderado. Espacios contract: Igualmente, perfecta para hoteles y establecimientos de prestigio. Áreas de recepción: Por último, ideal para espacios que necesitan causar una primera impresión impecable. Validación Profesional UPEC para Uso Comercial La prestigiosa certificación UPEC U2SP2E1C0 confirma su validación para uso profesional. Específicamente, demuestra resistencia comprobada al desgaste y punzonamiento. Además, resiste eficazmente el agua y los agentes químicos. Todo esto según normativas francesas reconocidas internacionalmente. Mantenimiento Sencillo y Limpieza Práctica La poliamida de alta calidad empleada ofrece ventajas excepcionales: Resistencia a las manchas: En primer lugar, repele eficazmente la suciedad y los líquidos. Limpieza simple: Asimismo, permite una limpieza regular sencilla y rápida sin productos especiales. Aspecto duradero: Por consiguiente, mantiene su aspecto prístino durante toda su vida útil. Durabilidad superior: Finalmente, resiste condiciones de uso intensivo sin perder sus cualidades. Inversión Inteligente en Revestimientos de Alta Gama La combinación de belleza clásica y prestaciones técnicas superiores hace de esta moqueta Saxony resistente una opción excepcional. Además, sus certificaciones profesionales garantizan seguridad y calidad. Por todo ello, es una inversión inteligente. En definitiva, equilibra perfectamente lujo, funcionalidad y seguridad. De este modo, crea ambientes sofisticados que perduran en el tiempo. Elige este revestimiento textil premium para garantizar elegancia duradera. Asimismo, asegura un rendimiento excepcional en tus espacios interiores más exigentes.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
