  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '46344838-c014-43ea-8408-9ce70128f44e',
  'Moqueta Sydnedis',
  'moqueta-fibra-cortada-confortable',
  'La moqueta fibra cortada confortable Sydnedis representa la solución ideal para espacios de alto uso que requieren suavidad, resistencia y una estética contemporánea. Fabricada en 100% poliamida con fibra cortada de calidad superior, esta moqueta fibra cortada confortable ofrece una textura lisa ...',
  'La moqueta fibra cortada confortable Sydnedis representa la solución ideal para espacios de alto uso que requieren suavidad, resistencia y una estética contemporánea. Fabricada en 100% poliamida con fibra cortada de calidad superior, esta moqueta fibra cortada confortable ofrece una textura lisa y homogénea que crea ambientes limpios y profesionales. Su diseño técnico combina confort excepcional con durabilidad probada, perfecta para proyectos donde el rendimiento y la estabilidad son prioritarios. Textura Lisa y Homogénea La moqueta fibra cortada confortable Sydnedis destaca por su superficie uniforme que proporciona una estética limpia y moderna. Además, la fibra cortada crea una textura suave al tacto que resulta extraordinariamente agradable y acogedora. De esta manera, cada paso sobre esta moqueta ofrece una sensación de confort inmediato. Por esta razón, es la elección preferida para oficinas contemporáneas, habitaciones de hotel y salas de espera donde la imagen profesional es fundamental. Grosor de 7 mm para Uso Intensivo Con 7 mm de grosor, esta moqueta fibra cortada confortable proporciona la pisada perfecta entre confort y resistencia para espacios de alto tráfico. Asimismo, este grosor optimizado garantiza estabilidad dimensional y facilita la instalación en grandes superficies. Gracias a su estructura equilibrada, mantiene su aspecto original incluso en zonas de paso continuo durante años. Material Poliamida 100% de Alta Calidad La composición 100% poliamida garantiza resistencia excepcional al desgaste y al tráfico intensivo. En efecto, la fibra poliamida es conocida por su capacidad de recuperación elástica y su resistencia a la abrasión, lo que significa que la moqueta mantiene su aspecto uniforme y texturizado incluso después de años de uso intenso. De esta manera, conserva su belleza original y su confort durante mucho más tiempo que otros materiales. Clasificación Ignífuga Cfl-s1 Esta moqueta fibra cortada confortable cuenta con clasificación de reacción al fuego Cfl-s1, garantizando máxima seguridad en espacios públicos y privados. Por lo tanto, cumple con las normativas europeas más exigentes para edificios comerciales, hoteles y espacios públicos, ofreciendo tranquilidad adicional sin comprometer el confort ni la estética. Certificación UPEC U3P3E1C0 La certificación UPEC U3P3E1C0 verifica el rendimiento profesional de Sydnedis en cuatro aspectos clave. En efecto, U3 indica resistencia al desgaste por tráfico intensivo, P3 certifica excelente comportamiento frente al punzonamiento, E1 garantiza resistencia adecuada al agua, y C0 especifica resistencia a agentes químicos. En consecuencia, esta certificación asegura un rendimiento técnico superior y duradero en condiciones exigentes. Suavidad y Confort al Tacto El tacto suave y aterciopelado de esta moqueta fibra cortada confortable mejora significativamente la experiencia sensorial de los usuarios. Por un lado, reduce la fatiga al caminar en zonas de larga permanencia. Por otro lado, crea ambientes más acogedores y confortables que mejoran el bienestar general. Gracias a estas cualidades, es perfecta para espacios donde el confort es prioritario. Aplicaciones Versátiles para Alto Uso Ideal para oficinas corporativas con alto tráfico de empleados y visitantes, habitaciones de hotel que buscan combinar elegancia con durabilidad extrema, salas de espera donde el confort y la imagen profesional son esenciales, zonas comunes en edificios comerciales que requieren resistencia sin renunciar a la estética, espacios educativos con uso intensivo diario, y áreas de recepción que necesitan mantener una apariencia impecable. En definitiva, la moqueta fibra cortada confortable Sydnedis se adapta perfectamente a cualquier entorno exigente manteniendo su aspecto contemporáneo. Estabilidad Dimensional Superior La estructura técnica de Sydnedis garantiza excelente estabilidad dimensional que previene deformaciones y ondulaciones durante toda su vida útil. Finalmente, esta estabilidad facilita la instalación, reduce costes de mantenimiento y asegura un acabado profesional duradero que mantiene su aspecto original durante años.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
