INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e2fe4c10-155c-4ee4-85e1-25d18ab4834a',
  'Moqueta Les Greedis',
  'moqueta-cortada-premium-acustica',
  'La moqueta cortada premium acústica Les Greedis representa la máxima expresión de elegancia, confort y rendimiento acústico para espacios exigentes. Fabricada en 100% poliamida con fibra cortada de alta densidad, esta moqueta cortada premium acústica ofrece un tacto extraordinariamente suave y un...',
  'La moqueta cortada premium acústica Les Greedis representa la máxima expresión de elegancia, confort y rendimiento acústico para espacios exigentes. Fabricada en 100% poliamida con fibra cortada de alta densidad, esta moqueta cortada premium acústica ofrece un tacto extraordinariamente suave y una estética sofisticada que transforma cualquier ambiente en un espacio premium. Su diseño técnico combina belleza visual con funcionalidad superior, ideal para proyectos donde el confort y la calidad son prioritarios. Alta Densidad y Tacto Superior La moqueta cortada premium acústica Les Greedis destaca por su excepcional densidad que garantiza durabilidad y resistencia al uso intensivo. Además, la fibra cortada proporciona una superficie suave y aterciopelada que resulta extraordinariamente agradable al tacto. De esta manera, cada paso sobre esta moqueta ofrece una sensación de lujo y confort incomparable. Por esta razón, es la elección preferida para habitaciones premium, suites de hotel y despachos ejecutivos donde la experiencia sensorial es fundamental. Grosor Premium de 9,2 mm Con 9,2 mm de altura de pelo, esta moqueta cortada premium acústica proporciona una pisada excepcionalmente mullida y confortable. Asimismo, este grosor superior contribuye significativamente al aislamiento térmico, creando ambientes más cálidos y acogedores. Gracias a su estructura generosa, reduce la fatiga al caminar y mejora notablemente el bienestar de los usuarios en espacios de larga permanencia. Confort Acústico Excepcional El rendimiento acústico es uno de los puntos fuertes de esta moqueta cortada premium acústica. En efecto, su alta densidad y grosor generoso absorben eficazmente el ruido ambiental y reducen significativamente la transmisión de sonido entre plantas. Por un lado, mejora la privacidad en habitaciones y despachos. Por otro lado, crea ambientes más tranquilos y relajantes en zonas comunes. En consecuencia, es perfecta para hoteles boutique, residencias de lujo y oficinas ejecutivas donde el confort sonoro es esencial. Material Poliamida de Primera Calidad La composición 100% poliamida garantiza resistencia excepcional y durabilidad profesional. En efecto, la fibra poliamida es conocida por su capacidad de recuperación elástica superior, lo que significa que la moqueta mantiene su aspecto mullido y texturizado incluso después de años de uso. De esta manera, conserva su belleza original y su confort durante mucho más tiempo que otros materiales. Clasificación Cfl-s1 Esta moqueta cortada premium acústica cuenta con clasificación de reacción al fuego Cfl-s1, garantizando seguridad en espacios residenciales y comerciales. Por lo tanto, cumple con las normativas europeas para interiores, ofreciendo tranquilidad adicional sin comprometer el confort ni la estética. Clasificación UPEC La clasificación UPEC certifica el rendimiento de la moqueta en cuatro aspectos fundamentales: resistencia al desgaste por pisadas (U), comportamiento frente al punzonamiento (P), resistencia al agua (E) y resistencia a agentes químicos (C). Gracias a esta certificación, Les Greedis garantiza un rendimiento profesional verificado y duradero. Aplicaciones Premium Ideal para habitaciones principales y suites de hotel que buscan máximo confort, despachos ejecutivos donde la imagen profesional es crucial, espacios premium residenciales de alto standing, zonas comunes exclusivas que requieren elegancia y durabilidad, salas de estar sofisticadas, vestidores y áreas privadas donde el confort es prioritario. En definitiva, la moqueta cortada premium acústica Les Greedis transforma cualquier espacio en un ambiente de lujo y distinción. Estética Sofisticada La fibra cortada proporciona un acabado visual elegante y atemporal que se integra perfectamente en diseños contemporáneos y clásicos. Finalmente, su textura uniforme y su tacto suave crean una atmósfera de refinamiento que eleva el nivel de cualquier interior, convirtiéndola en una inversión en calidad y belleza duradera.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
