INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '5f947f38-b0e6-448e-8860-015dfb3a197f',
  'Moqueta Scenadis',
  'moqueta-saxony-rizada-bfl-s1',
  'La moqueta Saxony rizada Bfl-s1 Scenadis representa la combinación perfecta entre confort, resistencia y seguridad para interiores exigentes. Fabricada en 100% poliamida con fibra Saxony rizada, esta moqueta Saxony rizada Bfl-s1 ofrece una textura elegante y suave que transforma cualquier espacio...',
  'La moqueta Saxony rizada Bfl-s1 Scenadis representa la combinación perfecta entre confort, resistencia y seguridad para interiores exigentes. Fabricada en 100% poliamida con fibra Saxony rizada, esta moqueta Saxony rizada Bfl-s1 ofrece una textura elegante y suave que transforma cualquier espacio en un ambiente acogedor y profesional. Su diseño texturizado no solo aporta belleza estética, sino también funcionalidad superior en zonas de alto tránsito. Textura Saxony Rizada de Alta Calidad La fibra Saxony rizada de esta moqueta Saxony rizada Bfl-s1 proporciona un acabado visual distintivo que añade profundidad y carácter a cualquier estancia. Además, la estructura rizada mejora significativamente el rendimiento frente al desgaste diario sin comprometer la suavidad al tacto. De esta manera, las marcas de pisadas se disimulan eficazmente, manteniendo un aspecto impecable durante más tiempo. Por esta razón, es la elección ideal para espacios donde la imagen profesional es fundamental. Clasificación Ignífuga Bfl-s1 Esta moqueta Saxony rizada Bfl-s1 cuenta con clasificación de reacción al fuego Bfl-s1, garantizando máxima seguridad en espacios públicos y privados. En efecto, esta certificación europea asegura que el material tiene baja combustibilidad y produce mínima emisión de humos en caso de incendio. Por lo tanto, cumple con las normativas más exigentes para edificios comerciales, hoteles y espacios públicos. Grosor y Confort Excepcional Con 7,6 mm de grosor, Scenadis proporciona una pisada excepcionalmente cómoda que mejora la experiencia de los usuarios. Asimismo, este grosor contribuye a un excelente aislamiento térmico que aumenta la sensación de bienestar en cualquier estación. Gracias a su estructura, cada paso resulta suave y confortable, reduciendo la fatiga en zonas de paso continuo. Aislamiento Acústico Superior El rendimiento acústico de 28 dB de esta moqueta Saxony rizada Bfl-s1 la convierte en una solución integral para el confort sonoro. Por un lado, reduce significativamente el ruido de impacto entre plantas, mejorando la privacidad y tranquilidad. Por otro lado, absorbe eficazmente el ruido ambiental, creando espacios más silenciosos y productivos. En consecuencia, es perfecta para oficinas, hoteles y salas de reuniones donde el control acústico es prioritario. Resistencia y Durabilidad Profesional La composición 100% poliamida garantiza una resistencia extraordinaria al desgaste y al tráfico intenso. En efecto, la fibra poliamida es conocida por su capacidad de recuperación elástica, lo que significa que la moqueta recupera su forma original después de ser pisada. De esta manera, mantiene su aspecto texturizado y elegante incluso en zonas de alto tránsito durante años. Aplicaciones Versátiles Ideal para oficinas corporativas que requieren confort y profesionalidad, hoteles y alojamientos que buscan crear ambientes acogedores, salas de espera donde la comodidad es esencial, habitaciones residenciales de alto standing, zonas comunes en edificios comerciales, y espacios públicos que necesitan combinar estética con durabilidad. En definitiva, la moqueta Saxony rizada Bfl-s1 Scenadis se adapta perfectamente a múltiples usos manteniendo su elegancia característica. Mantenimiento Simplificado La textura rizada facilita extraordinariamente el mantenimiento diario al camuflar la suciedad entre limpiezas. Finalmente, la fibra de poliamida resiste eficazmente las manchas y permite una limpieza profunda sencilla. Un aspirado regular y limpieza ocasional garantizan que la moqueta conserve su belleza durante años.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
