INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '32c79620-da12-47ca-8701-7f9d2880a6e4',
  'Moqueta Sweedis',
  'moqueta-sweedis-saxony-poliamida',
  'La moqueta Sweedis de fibra Saxony en 100% poliamida representa la elección perfecta para interiores que demandan máxima suavidad, aislamiento y elegancia. Su exclusiva estructura de pelo alto de 7,7mm con acabado aterciopelado proporciona una sensación acogedora y lujosa incomparable, transforma...',
  'La moqueta Sweedis de fibra Saxony en 100% poliamida representa la elección perfecta para interiores que demandan máxima suavidad, aislamiento y elegancia. Su exclusiva estructura de pelo alto de 7,7mm con acabado aterciopelado proporciona una sensación acogedora y lujosa incomparable, transformando cualquier espacio en un ambiente de confort superior. Características técnicas destacadas Esta moqueta premium combina un grosor total de 9,7mm con fibras de poliamida de alta gama, creando una superficie extraordinariamente suave al tacto. El acabado tipo Saxony garantiza uniformidad visual y una textura aterciopelada que mantiene su aspecto impecable con el paso del tiempo. Su certificación ignífuga Cfl-s1 asegura el cumplimiento de las normativas europeas más exigentes en seguridad contra incendios, permitiendo su instalación en espacios públicos y privados sin restricciones. Confort y funcionalidad superior La fibra 100% poliamida ofrece ventajas excepcionales que la distinguen de otras moquetas: Aislamiento acústico superior que reduce significativamente el ruido ambiental Aislamiento térmico que mejora el confort en cualquier estación del año Resistencia excepcional al desgaste para mantener su aspecto lujoso durante años Facilidad de mantenimiento y limpieza diaria sin productos especiales Durabilidad garantizada incluso en zonas de tránsito moderado Resistencia natural a las manchas gracias a su composición premium Aplicaciones ideales La Sweedis Saxony es especialmente recomendada para: Dormitorios principales donde el confort y la calidez son prioritarios Suites de hotel de categoría superior que buscan distinción Salas de reuniones ejecutivas que requieren elegancia y confort acústico Despachos y oficinas de alta dirección con imagen corporativa premium Espacios residenciales de alto nivel que valoran la calidad Zonas corporativas donde el confort visual y táctil es esencial para el bienestar Instalación profesional y mantenimiento Con su clasificación al fuego Cfl-s1, esta moqueta cumple todos los requisitos legales para instalación en espacios públicos y privados. Su formato permite una instalación profesional eficiente, adaptándose perfectamente a espacios de cualquier dimensión. El mantenimiento es sencillo mediante aspirado regular, mientras que su composición en poliamida de alta calidad facilita la eliminación de manchas ocasionales sin deteriorar las fibras. La moqueta Sweedis no solo decora, sino que transforma cualquier espacio interior en un ambiente sofisticado donde el confort visual y táctil se convierten en protagonistas absolutos, convirtiéndola en una opción confiable y duradera para proyectos residenciales o corporativos de alto nivel.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
