INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '5a384976-64fc-448c-8dd4-9545c08aa02b',
  'Acero Inoxidable E30 - R/E30 RECTO - CURVO',
  'perfil-acero-inoxidable-e30',
  'El perfil curvable aluminio anodizado R/AE30 representa la solución ideal para proyectos que requieren remates profesionales en superficies curvas e irregulares. Diseñado específicamente con base ranurada, este perfil curvable aluminio anodizado permite adaptarse manualmente a cualquier forma arq...',
  'El perfil curvable aluminio anodizado R/AE30 representa la solución ideal para proyectos que requieren remates profesionales en superficies curvas e irregulares. Diseñado específicamente con base ranurada, este perfil curvable aluminio anodizado permite adaptarse manualmente a cualquier forma arquitectónica sin necesidad de herramientas especiales. Además, su construcción ligera facilita enormemente la instalación en diseños complejos y creativos. Tecnología de Base Ranurada La base ranurada es la característica distintiva de este perfil curvable aluminio anodizado que permite el curvado manual preciso. En efecto, esta tecnología innovadora facilita la adaptación a columnas circulares, esquinas redondeadas y formas orgánicas complejas. De esta manera, los instaladores profesionales trabajan con total flexibilidad sin comprometer la calidad del acabado. Por esta razón, resulta indispensable en proyectos arquitectónicos que requieren soluciones personalizadas. Aluminio Anodizado Mate Superior El tratamiento anodizado mate de este perfil curvable aluminio anodizado proporciona una superficie elegante y extremadamente resistente al desgaste. Asimismo, este acabado ofrece protección superior contra la oxidación, arañazos y deterioro en zonas de alto tránsito. Gracias al proceso de anodizado, la capa protectora se integra molecularmente con el aluminio, garantizando durabilidad excepcional durante años. Altura de 3 mm para Pavimentos Finos Con una altura de 3 mm, este perfil curvable aluminio anodizado está optimizado para trabajar con moquetas, vinílicos y tarimas técnicas. En consecuencia, proporciona una transición discreta y profesional que no interfiere visualmente en el diseño del espacio. Por lo tanto, mantiene su estabilidad estructural incluso en curvas pronunciadas y formas irregulares complejas. Aplicaciones Versátiles en Diseño Este perfil curvable aluminio anodizado es perfecto para stands de ferias y eventos con diseños creativos diferenciadores. Por un lado, resulta ideal para espacios comerciales con arquitectura contemporánea y elementos curvos innovadores. Por otro lado, funciona excepcionalmente en showrooms de diseño, tiendas retail premium, oficinas corporativas con elementos arquitectónicos orgánicos, hoteles boutique y espacios culturales. Asimismo, es la elección preferida para proyectos que priorizan la personalidad y la estética distintiva. Ligereza y Facilidad de Instalación La composición en aluminio garantiza ligereza excepcional que simplifica el transporte y la manipulación durante toda la instalación. Finalmente, su diseño optimizado reduce significativamente los tiempos de montaje y costes operativos, convirtiéndolo en una solución profesional eficiente para proyectos arquitectónicos exigentes.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
