INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '2c904bb3-15c0-4aac-8ce2-16210cdc717c',
  'Aluminio Adonizado Mate Recto/Curvo AE30-3MM',
  'perfil-aluminio-ae30-recto-curvo',
  'El perfil AE30 está fabricado en aluminio anodizado mate natural, diseñado específicamente para ofrecer remates limpios y profesionales en pavimentos de interior. Con una altura de 3 mm, resulta compatible con revestimientos finos como vinílicos y moquetas, proporcionando una transición elegante ...',
  'El perfil AE30 está fabricado en aluminio anodizado mate natural, diseñado específicamente para ofrecer remates limpios y profesionales en pavimentos de interior. Con una altura de 3 mm, resulta compatible con revestimientos finos como vinílicos y moquetas, proporcionando una transición elegante entre diferentes tipos de suelo. Además, su acabado anodizado mate aporta una estética sobria y contemporánea que se integra perfectamente en cualquier proyecto. Altura Optimizada de 3 mm La altura de 3 mm del perfil AE30 está especialmente diseñada para pavimentos finos y delicados. En efecto, esta medida permite una transición suave y discreta que no interfiere visualmente en el espacio. De esta manera, protege eficazmente los bordes del revestimiento mientras mantiene un acabado profesional impecable. Por esta razón, es la elección ideal para instalaciones donde la estética minimalista es prioritaria. Aluminio Anodizado Mate Natural El tratamiento anodizado mate natural proporciona una superficie resistente al desgaste y la oxidación. Asimismo, este acabado ofrece una apariencia elegante y neutra que combina con cualquier estilo decorativo. Gracias a su composición en aluminio, el perfil garantiza ligereza excepcional que facilita enormemente el transporte y la instalación. Por lo tanto, reduce tiempos de montaje y costes operativos. Protección y Durabilidad Este perfil proporciona una transición elegante y duradera entre diferentes superficies de suelo. En consecuencia, protege los bordes del pavimento contra impactos y desgaste prematuro. Además, reduce significativamente el deterioro en zonas de unión, prolongando la vida útil de la instalación completa. Versatilidad en Aplicaciones El perfil AE30 es perfecto tanto para instalaciones temporales como permanentes. Por un lado, resulta ideal para ferias y eventos donde se requiere montaje rápido y desmontaje limpio. Por otro lado, ofrece durabilidad excepcional en tiendas retail, oficinas corporativas y espacios comerciales con tránsito medio. En definitiva, su combinación de ligereza, resistencia y estética lo convierte en una solución versátil para múltiples proyectos profesionales.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
