INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '930dbd67-6bdf-463f-8554-e31f87bd4a76',
  'Aluminio Adonizado Brillo Recto A30 - 3MM',
  'perfil-aluminio-a30-recto',
  'El perfil A30 recto en aluminio anodizado brillo representa una solución ligera, funcional y estética para el remate profesional de suelos vinílicos, moquetas y tarimas finas. Diseñado específicamente para instalaciones rectas, este perfil combina rendimiento técnico con una estética limpia que s...',
  'El perfil A30 recto en aluminio anodizado brillo representa una solución ligera, funcional y estética para el remate profesional de suelos vinílicos, moquetas y tarimas finas. Diseñado específicamente para instalaciones rectas, este perfil combina rendimiento técnico con una estética limpia que se integra perfectamente en cualquier proyecto. Además, su acabado brillante aporta un toque de elegancia contemporánea que realza la calidad del pavimento. Diseño Recto y Funcional Este perfil recto destaca por su simplicidad y eficacia en aplicaciones lineales. En efecto, está especialmente diseñado para transiciones rectas en puertas, pasillos y uniones entre diferentes tipos de suelo. Gracias a su geometría optimizada, proporciona un remate limpio que protege los bordes del pavimento mientras mantiene una apariencia profesional impecable. Aluminio Anodizado de Alta Calidad La composición en aluminio garantiza ligereza excepcional sin comprometer la resistencia. Asimismo, el proceso de anodizado crea una capa protectora que aumenta significativamente la durabilidad del perfil. De esta manera, resiste el desgaste diario, la corrosión y mantiene su acabado brillante durante años. Por esta razón, resulta ideal para zonas de tránsito medio y alto. Acabado Brillo Elegante El acabado anodizado brillo proporciona una superficie reflectante que añade luminosidad y modernidad a cualquier espacio. En consecuencia, se integra perfectamente en proyectos comerciales contemporáneos, tiendas retail que buscan imagen premium, y espacios residenciales de alto standing. Además, este acabado facilita extraordinariamente la limpieza y el mantenimiento diario. Instalación Rápida y Sencilla El diseño del perfil A30 permite una instalación ágil que reduce tiempos y costes de mano de obra. Por lo tanto, los instaladores profesionales aprecian su facilidad de montaje. Gracias a su sistema de fijación eficiente, se adapta rápidamente a diferentes espesores de pavimento sin necesidad de ajustes complejos. Aplicaciones Versátiles Ideal para oficinas modernas, comercios retail, viviendas residenciales, hoteles boutique y espacios corporativos donde se requiere un acabado profesional con estética contemporánea. En definitiva, el perfil A30 ofrece la combinación perfecta entre funcionalidad, diseño y facilidad de instalación.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
