INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a7be9dac-e61b-48af-8b7c-03b65fe9021a',
  'Aluminio Adonizado Mate Curvo R/AE30-3MM',
  'perfil-moqueta-r-ae30',
  'El perfil curvable R/AE30 en aluminio anodizado mate representa la solución perfecta para rematar suelos con formas curvas o irregulares en proyectos arquitectónicos exigentes. Diseñado específicamente para adaptarse a perímetros no rectos, este perfil ofrece versatilidad excepcional sin comprome...',
  'El perfil curvable R/AE30 en aluminio anodizado mate representa la solución perfecta para rematar suelos con formas curvas o irregulares en proyectos arquitectónicos exigentes. Diseñado específicamente para adaptarse a perímetros no rectos, este perfil ofrece versatilidad excepcional sin comprometer el acabado profesional. Además, su construcción en aluminio anodizado mate garantiza durabilidad y resistencia en cualquier entorno interior. Base Ranurada para Curvado Manual La característica distintiva del perfil curvable R/AE30 es su base ranurada que permite el curvado manual sin necesidad de herramientas especiales. Gracias a esta tecnología, se adapta fácilmente a columnas circulares, esquinas redondeadas y formas arquitectónicas orgánicas. De esta manera, los instaladores pueden trabajar con total flexibilidad en diseños complejos. Por esta razón, resulta indispensable en proyectos que requieren soluciones personalizadas y creativas. Aluminio Anodizado Mate de Primera Calidad El tratamiento anodizado mate proporciona una superficie elegante y resistente al desgaste diario. Asimismo, este acabado ofrece protección superior contra la oxidación y los arañazos en zonas de alto tránsito. En efecto, el aluminio garantiza ligereza excepcional que facilita enormemente el transporte y la manipulación durante la instalación. Por lo tanto, reduce significativamente los tiempos de montaje y los costes operativos del proyecto. Altura de 3 mm Optimizada Con una altura de 3 mm, el perfil curvable R/AE30 está diseñado para trabajar con pavimentos finos como moquetas, vinílicos y tarimas técnicas. En consecuencia, proporciona una transición discreta y profesional que no interfiere visualmente en el diseño del espacio. Gracias a estas dimensiones equilibradas, mantiene su estabilidad incluso en curvas pronunciadas. Aplicaciones en Espacios con Personalidad Este perfil curvable es perfecto para stands ferias y eventos que requieren diseños creativos y diferenciadores. Por un lado, resulta ideal para espacios comerciales con arquitectura contemporánea y formas innovadoras. Por otro lado, funciona excepcionalmente en showrooms, tiendas retail de diseño, oficinas corporativas con elementos arquitectónicos curvos, y hoteles boutique que buscan acabados únicos. Asimismo, es la elección preferida para museos, galerías y espacios culturales donde la estética es fundamental. Acabado Profesional Garantizado El perfil curvable R/AE30 mantiene un acabado limpio y profesional incluso en las curvas más exigentes. Finalmente, su resistencia a la oxidación garantiza que conserve su apariencia original durante años, convirtiéndolo en una inversión inteligente para proyectos que priorizan la durabilidad y el diseño arquitectónico distintivo.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
