INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f28b04c6-8571-4efd-865d-2e0455918bf6',
  'Aluminio Anodizado Mate Recto AE45 - 4,5MM',
  'perfil-adonizado-ae45-aluminio-anodizado-mate-recto',
  'El perfil AE45 representa una solución de remate recto fabricada en aluminio anodizado mate, especialmente diseñada para ofrecer un acabado limpio, resistente y estéticamente sobrio en pavimentos ligeros. Ideal para moquetas, vinílicos y tarimas técnicas, este perfil combina funcionalidad profesi...',
  'El perfil AE45 representa una solución de remate recto fabricada en aluminio anodizado mate, especialmente diseñada para ofrecer un acabado limpio, resistente y estéticamente sobrio en pavimentos ligeros. Ideal para moquetas, vinílicos y tarimas técnicas, este perfil combina funcionalidad profesional con una estética contemporánea que se adapta a múltiples entornos. Además, su diseño técnico garantiza durabilidad excepcional sin comprometer la imagen del espacio. Acabado Anodizado Mate de Alta Calidad El tratamiento anodizado mate del perfil AE45 aporta un aspecto elegante y moderno que se integra perfectamente en diseños contemporáneos. En efecto, este acabado proporciona una alta resistencia al desgaste, la oxidación y los arañazos. De esta manera, mantiene su apariencia original durante años incluso en zonas de tránsito medio. Por esta razón, resulta una opción fiable para proyectos que requieren durabilidad y diseño cuidado. Especificaciones Técnicas Optimizadas Con una altura de 4,5 mm, el perfil AE45 ofrece un remate discreto que no interfiere visualmente en el espacio. Asimismo, la longitud estándar de 2,5 metros facilita la instalación en pasillos y transiciones lineales. Gracias a estas dimensiones equilibradas, proporciona un acabado profesional tanto en instalaciones permanentes como temporales. Material Aluminio Ligero y Resistente La composición en aluminio garantiza ligereza excepcional que facilita el transporte y la instalación. Por otro lado, este material ofrece resistencia mecánica superior que protege eficazmente los bordes del pavimento. En consecuencia, previene deterioros prematuros y mantiene la integridad de la instalación durante toda su vida útil. Aplicaciones Profesionales Versátiles Este perfil es ideal para espacios comerciales que requieren imagen profesional, oficinas corporativas con tránsito medio, tiendas retail que buscan acabados cuidados, zonas comunes en edificios residenciales, instalaciones temporales como ferias y eventos, y cualquier entorno interior donde se priorice la durabilidad y el diseño. En definitiva, el perfil AE45 ofrece la combinación perfecta entre resistencia, estética sobria y facilidad de instalación para proyectos profesionales exigentes.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
