INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '11b59f8e-42c4-467e-8a63-9d7237640154',
  'Acero Inoxidable Recto R/E45 - 4,5MM',
  'perfil-acero-inoxidable-curvo',
  'El perfil R/E45 es una solución de remate plano fabricada en acero inoxidable. Diseñado específicamente para entornos que requieren alta resistencia mecánica, ofrece un acabado técnico impecable. Además, su base permite instalación directa sobre superficies planas, lo que lo hace ideal para remat...',
  'El perfil R/E45 es una solución de remate plano fabricada en acero inoxidable. Diseñado específicamente para entornos que requieren alta resistencia mecánica, ofrece un acabado técnico impecable. Además, su base permite instalación directa sobre superficies planas, lo que lo hace ideal para remates lineales rectos. Por esta razón, funciona perfectamente en perímetros regulares y se ajusta a formas arquitectónicas lineales. Especificaciones Técnicas Con una altura de 4,5 mm, ofrece un perfil discreto que no interfiere visualmente. Asimismo, la longitud de 2,5 metros facilita la instalación y proporciona un remate duradero y preciso. En efecto, resulta tanto funcional como estético, mientras que el acero inoxidable garantiza resistencia a la corrosión. De esta manera, no se oxida con humedad ni productos químicos. Versatilidad de Aplicación Este perfil es la opción preferida para proyectos técnicos de alto nivel. Por un lado, los centros sanitarios lo eligen por su higiene excepcional. Por otro lado, las cocinas profesionales valoran su resistencia superior. Además, las tiendas aprecian su acabado impecable, mientras que las zonas de tránsito requieren su durabilidad probada. Finalmente, las instalaciones corporativas buscan su estética profesional. Facilidad de Instalación La base plana es su característica más destacada y práctica. En consecuencia, permite la instalación directa sin necesidad de curvado o herramientas especiales. Gracias a esto, se adapta a pasillos rectos fácilmente y funciona en transiciones lineales. Asimismo, se ajusta perfectamente a diseños rectos y regulares. Por esta razón, los instaladores aprecian enormemente su simplicidad de montaje. Acabado Profesional El acero inoxidable proporciona un acabado brillante de alta calidad. Además, la superficie es lisa y fácil de limpiar, sin acumular suciedad en las uniones. De esta manera, el aspecto es moderno y técnico. En efecto, se integra perfectamente con cerámicas y combina con pavimentos vinílicos. Por lo tanto, funciona con cualquier revestimiento profesional. Durabilidad Excepcional La resistencia mecánica del perfil R/E45 es superior a alternativas convencionales. En consecuencia, soporta golpes e impactos sin deformarse ni deteriorarse con el paso del tiempo. Gracias a su composición, mantiene su aspecto original durante años. Por esta razón, la inversión se amortiza rápidamente con su larga vida útil. Aplicaciones Específicas En hospitales, cumple rigurosamente con las normativas higiénicas más exigentes. Asimismo, en cocinas resiste productos de limpieza agresivos sin deteriorarse. Por otro lado, en comercios soporta el tránsito intenso diario manteniendo su apariencia. Además, en oficinas aporta distinción y profesionalidad. Finalmente, en hoteles ofrece elegancia duradera que mejora la experiencia de los huéspedes. Precio indicado por unidad de 2,5 metros lineales.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
