INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '9ee337e2-09ed-48c3-8bfd-73e8a64efb96',
  'PVC Taralidis Liber',
  'suelo-vinilico-taralidis-liber-trafico-intenso',
  'Suelo Vinílico Tráfico Intenso: Taralidis Liber Taralidis Liber es un suelo vinílico tráfico intenso de altas prestaciones técnicas, especialmente desarrollado para entornos profesionales que exigen máxima durabilidad y rendimiento constante bajo uso continuado. Este suelo vinílico para tráfico i...',
  'Suelo Vinílico Tráfico Intenso: Taralidis Liber Taralidis Liber es un suelo vinílico tráfico intenso de altas prestaciones técnicas, especialmente desarrollado para entornos profesionales que exigen máxima durabilidad y rendimiento constante bajo uso continuado. Este suelo vinílico para tráfico intenso incorpora una capa de desgaste de 0,70 mm, diseñada específicamente para soportar el tráfico diario intensivo sin comprometer su apariencia ni sus propiedades funcionales a largo plazo. Acabado Protecsol®: Protección Avanzada Su composición técnica avanzada incorpora el innovador acabado Protecsol®, un tratamiento superficial que facilita extraordinariamente las tareas de limpieza y mantenimiento. Por tanto, reduce tanto el tiempo como los costes asociados a la conservación del suelo. Además, este acabado crea una barrera protectora que repele la suciedad y las manchas, manteniendo el pavimento en condiciones óptimas con un esfuerzo mínimo. Seguridad Antideslizante R10 En términos de seguridad, el suelo vinílico tráfico intenso Taralidis Liber cuenta con una clasificación antideslizante R10. Asimismo, proporciona un agarre fiable que minimiza el riesgo de caídas y resbalones, aspecto fundamental en espacios de uso público y colectivo. En consecuencia, esta característica lo convierte en una opción especialmente indicada para áreas donde la seguridad de los usuarios es prioritaria. Propiedades Acústicas Superiores Las propiedades acústicas de este suelo vinílico son igualmente destacables, con una absorción acústica de 19 dB que contribuye significativamente a la reducción del ruido de impacto y la reverberación sonora. Posteriormente, esta capacidad de aislamiento acústico mejora sustancialmente el confort ambiental, creando espacios más silenciosos y agradables tanto para trabajadores como para visitantes. Aplicaciones Profesionales Versátiles La versatilidad del Taralidis Liber lo convierte en la solución ideal para una amplia gama de aplicaciones profesionales: Oficinas que buscan un pavimento duradero y de fácil mantenimiento Centros educativos donde la resistencia al tráfico intenso y la seguridad son esenciales Hospitales y centros sanitarios que requieren pavimentos higiénicos, de fácil limpieza y con propiedades acústicas Espacios Comerciales como tiendas, centros comerciales y establecimientos retail donde la estética debe combinarse con máxima resistencia Su rendimiento técnico superior, unido a su facilidad de instalación y mantenimiento, posiciona al Taralidis Liber como una inversión inteligente y rentable a largo plazo para cualquier proyecto que demande calidad, funcionalidad y durabilidad comprobadas. Para más información o solicitar presupuesto, contacta: ventas@disstands.com o llama al 934 850 085.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
