INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e20bf561-e49d-4773-8e39-ccd6fe90dd9c',
  'PVC Mipoldis Plandis',
  'mipoldis-plandis',
  'Mipoldis Plandis es un suelo vinílico homogéneo de 2 mm de espesor, especialmente diseñado para entornos sanitarios, educativos y de alto tránsito. Ofrece un excelente comportamiento frente a agentes químicos, una superficie fácil de mantener gracias a su acabado Evercare®, y una acción antibacte...',
  'Mipoldis Plandis es un suelo vinílico homogéneo de 2 mm de espesor, especialmente diseñado para entornos sanitarios, educativos y de alto tránsito. Ofrece un excelente comportamiento frente a agentes químicos, una superficie fácil de mantener gracias a su acabado Evercare®, y una acción antibacteriana y antivírica superior, con eficacia probada contra bacterias comunes y coronavirus humano. Con clasificación al fuego Bfl-s1, resistencia al deslizamiento R9 y emisiones muy bajas de COV, es una solución segura, higiénica y sostenible.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
