INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'c522fedf-9757-4e27-8c74-db1b4a9d9aab',
  'PVC Mipoldis Tropdis',
  'mipolam-troplan-homogeneo',
  'Mipoldis Tropdis es un suelo vinílico homogéneo de 2 mm que establece nuevos estándares en durabilidad, seguridad e higiene para espacios profesionales exigentes. Su composición homogénea garantiza un desgaste uniforme y una vida útil prolongada, manteniendo su aspecto y propiedades incluso en zo...',
  'Mipoldis Tropdis es un suelo vinílico homogéneo de 2 mm que establece nuevos estándares en durabilidad, seguridad e higiene para espacios profesionales exigentes. Su composición homogénea garantiza un desgaste uniforme y una vida útil prolongada, manteniendo su aspecto y propiedades incluso en zonas de tráfico extremo. Tecnología Evercare® para máxima higiene El tratamiento exclusivo Evercare® facilita significativamente la limpieza diaria, reduciendo costes de mantenimiento y tiempo de trabajo. Esta tecnología avanzada proporciona: Protección antibacteriana permanente contra microorganismos Eficacia antivírica del 99,7% frente al coronavirus humano Resistencia química excepcional a desinfectantes y productos de limpieza Superficie no porosa que impide la acumulación de suciedad Mantenimiento simplificado sin necesidad de encerados Resistencia y durabilidad superiores La estructura homogénea de 2 mm ofrece ventajas incomparables: Resistencia mecánica extraordinaria al desgaste y punzonado Clasificación uso comercial muy intenso (34) e industrial (43) Estabilidad dimensional que previene deformaciones Durabilidad garantizada con mínimo mantenimiento Reparabilidad mediante termosoldado en caso de daños Versatilidad de formato e instalación Disponible en rollo y losetas, Mipoldis Tropdis se adapta a cualquier proyecto: Rollos: ideales para grandes superficies con mínimas juntas Losetas: perfectas para diseños creativos y reposiciones parciales Instalación profesional con adhesivos específicos Juntas termosoldadas que garantizan higiene total Aplicaciones especializadas Especialmente recomendado para: Hospitales y clínicas: quirófanos, UCI, salas blancas Centros educativos: aulas, laboratorios, comedores Oficinas corporativas de alto tráfico Espacios públicos con normativas sanitarias estrictas Industria farmacéutica y alimentaria Certificaciones y normativas Cumple con las regulaciones más exigentes del sector sanitario y comercial, incluyendo resistencia al fuego Bfl-s1, emisiones COV controladas y certificaciones específicas para entornos hospitalarios. Mipoldis Tropdis no es solo un pavimento, es una inversión en salud, seguridad y eficiencia operativa para espacios que no pueden comprometer en higiene ni durabilidad.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
