INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '62da622c-11c6-4e1d-8ffd-4cac31a2dd88',
  'PVC Mipoldis Afinidis',
  'suelo-vinilico-homogeneo-antibacteriano-mipoldis-afinidis',
  'Suelo Vinílico Homogéneo Antibacteriano Mipoldis Afinidis Mipoldis Afinidis es un suelo vinílico homogéneo antibacteriano de alta calidad con tratamiento Evercare™, diseñado específicamente para entornos que requieren máxima higiene y resistencia al tránsito intenso. Este pavimento vinílico combi...',
  'Suelo Vinílico Homogéneo Antibacteriano Mipoldis Afinidis Mipoldis Afinidis es un suelo vinílico homogéneo antibacteriano de alta calidad con tratamiento Evercare™, diseñado específicamente para entornos que requieren máxima higiene y resistencia al tránsito intenso. Este pavimento vinílico combina propiedades antibacterianas, antivirales y una extraordinaria durabilidad, convirtiéndolo en la solución ideal para hospitales, centros educativos, industria alimentaria y cualquier espacio donde la limpieza sea prioritaria. Características Principales del Suelo Vinílico Homogéneo Antibacteriano El suelo vinílico homogéneo Mipoldis Afinidis destaca por sus excepcionales prestaciones técnicas: Tratamiento Evercare™ Protección antibacteriana y antiviral permanente integrada en toda la composición del material. Este tratamiento reduce hasta el 99,9% de bacterias y virus en la superficie, creando entornos más seguros e higiénicos sin necesidad de tratamientos adicionales. Composición Homogénea El diseño y el color atraviesan todo el espesor del pavimento, lo que garantiza que incluso con el desgaste por uso intensivo, el suelo mantenga su aspecto original durante años. Esta característica es fundamental en zonas de alto tránsito donde la durabilidad es esencial. Resistencia Química Superior Soporta perfectamente el uso de productos de limpieza agresivos, desinfectantes hospitalarios, alcoholes y soluciones químicas comunes en entornos sanitarios e industriales, sin deteriorarse ni perder sus propiedades. Acabado Mate Antideslizante La superficie mate proporciona seguridad adicional al reducir el riesgo de resbalones, cumpliendo con las normativas de seguridad más exigentes. Además, el acabado mate disimula mejor pequeñas marcas y el desgaste diario. Fácil Mantenimiento Su superficie no porosa facilita enormemente las tareas de limpieza diaria. Se limpia eficazmente con productos convencionales, reduciendo costes y tiempo de mantenimiento. Aplicaciones Ideales Este suelo vinílico homogéneo antibacteriano es la elección profesional para: Centros Sanitarios Hospitales, clínicas, consultorios médicos, quirófanos, laboratorios de análisis, centros de salud, residencias geriátricas y centros de rehabilitación. Cumple con todas las normativas sanitarias vigentes. Centros Educativos Escuelas, colegios, guarderías, universidades, comedores escolares, aulas y zonas comunes donde se requiere higiene y resistencia al uso intensivo por parte de muchos usuarios diariamente. Industria Alimentaria y Farmacéutica Fábricas de procesamiento de alimentos, cocinas industriales, laboratorios farmacéuticos, salas blancas y áreas de producción donde la higiene es crítica y está sujeta a inspecciones rigurosas. Espacios Públicos de Alto Tránsito Centros deportivos, gimnasios, piscinas cubiertas, aeropuertos, estaciones, centros comerciales y cualquier espacio público con circulación intensa de personas. Comercios Especializados Supermercados, tiendas de alimentación, carnicerías, pescaderías, panaderías y establecimientos donde se manipulan alimentos y se requieren condiciones higiénicas óptimas. Ventajas del Pavimento Vinílico Mipoldis Afinidis Higiene Garantizada El tratamiento Evercare™ proporciona protección antibacteriana continua las 24 horas del día, reduciendo significativamente la proliferación de microorganismos patógenos en la superficie. Durabilidad Excepcional Su clasificación para tráfico intenso (34-43) garantiza años de vida útil incluso en las condiciones más exigentes. La inversión se amortiza rápidamente gracias a su longevidad. Ahorro en Mantenimiento La facilidad de limpieza y la resistencia a productos químicos reducen drásticamente los costes de mantenimiento a largo plazo. No requiere tratamientos especiales ni decapados periódicos. Seguridad para Usuarios El acabado antideslizante minimiza accidentes por caídas, proporcionando tranquilidad en entornos donde transitan personas mayores, niños o personas con movilidad reducida. Confort Acústico Reduce la transmisión de ruidos de impacto, creando ambientes más confortables y menos ruidosos, especialmente importante en hospitales y centros educativos. Instalación Profesional Su sistema de instalación permite acabados perfectos sin juntas visibles, creando superficies continuas de fácil limpieza donde no se acumula suciedad. Especificaciones Técnicas Tipo de producto: Suelo vinílico homogéneo Tratamiento superficial: Evercare™ antibacteriano y antiviral Acabado: Mate antideslizante Clasificación de uso: 34-43 (Tráfico comercial intenso e industrial) Resistencia a productos químicos: Excelente Resistencia a la abrasión: Muy alta Espesor: Consultar según modelo Mantenimiento: Bajo Garantía: Según condiciones del fabricante ¿Por Qué Elegir Disstands para la Instalación? En Disstands somos especialistas en la instalación de pavimentos vinílicos antibacterianos con más de 20 años de experiencia. Nuestro equipo técnico garantiza: Asesoramiento profesional para elegir la solución más adecuada a tu proyecto Instalación experta que maximiza la durabilidad del pavimento Cumplimiento de plazos estricto para no interferir con tu actividad Presupuesto detallado sin sorpresas ni costes ocultos Servicio completo que incluye medición, suministro e instalación Solicita tu Presupuesto Gratuito ¿Necesitas un suelo vinílico homogéneo antibacteriano para tu hospital, centro educativo o industria? Contacta con nosotros y te prepararemos un presupuesto personalizado sin compromiso. 📞 Teléfono: 934 850 085 📧 Email: ventas@disstands.com ⏰ Horario: Lunes a Viernes de 9:00h a 14:00h y de 15:00h a 18:00h El suelo vinílico Mipoldis Afinidis es la inversión inteligente para espacios que no pueden comprometer en higiene, durabilidad y seguridad. Su tratamiento Evercare™ y su composición homogénea garantizan años de servicio con mínimo mantenimiento y máxima tranquilidad.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
