INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '760735a6-2405-4555-8bf2-e0ce0d022dff',
  'PVC Taraladis Initial',
  'suelo-vinilico-acustico-alto-confort',
  'Talaradis Initial es un pavimento vinílico de alto rendimiento. Está diseñado para entornos que exigen confort bajo los pies. Ofrece absorción acústica superior. La resistencia al desgaste es excepcional. Su tratamiento Protecsol™ facilita la limpieza diaria. Las propiedades antibacterianas son c...',
  'Talaradis Initial es un pavimento vinílico de alto rendimiento. Está diseñado para entornos que exigen confort bajo los pies. Ofrece absorción acústica superior. La resistencia al desgaste es excepcional. Su tratamiento Protecsol™ facilita la limpieza diaria. Las propiedades antibacterianas son certificadas. La resistencia química es notable. Es ideal para centros educativos exigentes. Los hospitales valoran su higiene. Las oficinas aprecian su confort. Los espacios públicos confían en su durabilidad. Confort y Bienestar El confort bajo los pies es inmediato. La pisada es suave y agradable. Reduce la fatiga en jornadas largas. Las personas que trabajan de pie lo notan. La sensación es más acogedora que suelos duros. Los usuarios aprecian esta diferencia cada día. Absorción Acústica Efectiva La absorción acústica reduce el ruido ambiental. Los pasos se escuchan menos. El eco disminuye significativamente. Los espacios son más tranquilos. La concentración mejora en oficinas. Las aulas escolares son más silenciosas. Los pacientes en hospitales descansan mejor. Tratamiento Protecsol™ El tratamiento superficial Protecsol™ es avanzado. Protege contra manchas y suciedad. La limpieza diaria es muy sencilla. No requiere productos especializados costosos. Una mopa húmeda es suficiente. El mantenimiento ahorra tiempo y dinero. El aspecto se mantiene impecable. Propiedades Antibacterianas Las propiedades antibacterianas están certificadas. Inhibe el crecimiento de bacterias. Es crucial en entornos sanitarios. Los centros educativos reducen contagios. Los espacios públicos son más higiénicos. La salud de los usuarios se protege. Resistencia Química Superior La resistencia química es excepcional. Soporta productos de limpieza agresivos. No se deteriora con desinfectantes. Los hospitales pueden usar protocolos estrictos. Las cocinas industriales lo resisten. Los laboratorios confían en él. Aplicaciones Profesionales Talaradis Initial funciona en múltiples sectores. Los centros educativos lo eligen frecuentemente. Los hospitales y clínicas lo instalan. Las oficinas corporativas lo prefieren. Los comercios con tráfico lo seleccionan. Los edificios públicos cumplen normativas con él. Instalación y Formato La instalación es rápida y eficiente. El formato optimiza el trabajo. Las uniones quedan imperceptibles. El resultado final es profesional. Precio indicado por metro cuadrado.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
