INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '0d7e48fb-a540-48fa-8d2e-429ad68d39b4',
  'PVC Taraladis Impression',
  'pavimento-vinilico-trafico-intenso',
  'Pavimento Vinílico Tráfico Intenso: Taraldis Impression Taraldis Impression es un pavimento vinílico tráfico intenso heterogéneo de última generación, especialmente desarrollado para satisfacer las exigencias más rigurosas de espacios profesionales con alto tránsito continuo. Este pavimento viníl...',
  'Pavimento Vinílico Tráfico Intenso: Taraldis Impression Taraldis Impression es un pavimento vinílico tráfico intenso heterogéneo de última generación, especialmente desarrollado para satisfacer las exigencias más rigurosas de espacios profesionales con alto tránsito continuo. Este pavimento vinílico para tráfico intenso representa la combinación perfecta entre durabilidad excepcional, máxima higiene y una estética cuidada que se mantiene impecable a lo largo del tiempo. Estructura Heterogénea Resistente Su estructura heterogénea garantiza que el diseño atraviesa todo el espesor del pavimento, lo que se traduce en una resistencia al desgaste superior y una apariencia uniforme que perdura incluso en las zonas de mayor uso. Esta característica técnica es fundamental en entornos donde el pavimento vinílico está sometido a un tráfico constante e intensivo. Tratamiento Protecsol® 2: Protección Avanzada El tratamiento Protecsol® 2 es uno de los elementos diferenciadores clave de Taraldis Impression. Este innovador acabado de protección superficial proporciona una resistencia química excepcional frente a productos de limpieza, desinfectantes y agentes agresivos. Por tanto, es fundamental en entornos sanitarios y educativos donde la higienización frecuente es obligatoria. Además, este tratamiento facilita extraordinariamente las tareas de limpieza y mantenimiento, creando una superficie que repele la suciedad y permite una conservación óptima con mínimo esfuerzo y coste. Propiedades Higiénicas y Antibacterianas Las propiedades higiénicas de este pavimento vinílico tráfico intenso son especialmente destacables. Asimismo, su superficie no porosa impide la acumulación de bacterias, ácaros y microorganismos, contribuyendo a crear entornos más saludables y seguros. En consecuencia, esta característica lo convierte en la opción preferente para espacios donde la higiene es prioritaria. Diseño Compacto Versátil El diseño compacto de Taraldis Impression ofrece versatilidad estética sin comprometer las prestaciones técnicas. Posteriormente, permite crear espacios profesionales con personalidad propia mientras se mantienen los más altos estándares de funcionalidad. Aplicaciones Profesionales La versatilidad de Taraldis Impression lo posiciona como la solución ideal para múltiples aplicaciones profesionales: Centros educativos (colegios, institutos y universidades) donde la resistencia al tráfico intenso de estudiantes y la facilidad de mantenimiento son esenciales Centros sanitarios (hospitales, clínicas y centros de salud) que demandan pavimentos higiénicos, resistentes a productos químicos y de fácil desinfección Espacios comerciales (tiendas, centros comerciales y áreas retail) donde la estética debe combinarse con durabilidad Edificios institucionales (oficinas públicas, administraciones) que requieren pavimentos de largo recorrido con mínimo mantenimiento Su instalación profesional y su rendimiento técnico probado hacen de Taraldis Impression una inversión inteligente y rentable para cualquier proyecto que demande calidad, funcionalidad y durabilidad a largo plazo. Para más información o solicitar presupuesto, contacta: ventas@disstands.com o llama al 934 850 085.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
