INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'c372340c-b9b7-4394-8179-e7d59d6bbcc2',
  'PVC Muraldis Ultradis',
  'revestimiento-vinilico-tecnico-higienico',
  'Revestimiento Vinílico Técnico Higiénico: Muraldis Ultradis Muraldis Ultradis es un revestimiento vinílico técnico higiénico de alta prestación con acabado decorativo profesional, especialmente diseñado para ambientes donde la higiene, la resistencia y la durabilidad son absolutamente prioritaria...',
  'Revestimiento Vinílico Técnico Higiénico: Muraldis Ultradis Muraldis Ultradis es un revestimiento vinílico técnico higiénico de alta prestación con acabado decorativo profesional, especialmente diseñado para ambientes donde la higiene, la resistencia y la durabilidad son absolutamente prioritarias. Este revestimiento vinílico técnico representa la solución ideal para espacios sanitarios, clínicos y entornos que demandan estrictos protocolos de higienización y mantenimiento continuo. Tecnología PROTECSOL® en Revestimiento Higiénico Gracias a su innovadora capa de protección PROTECSOL®, este revestimiento técnico higiénico ofrece máxima protección superficial contra el desgaste diario y los productos químicos de limpieza agresivos. Además, proporciona resistencia excepcional al rayado, a la abrasión y al impacto, manteniendo su integridad estructural incluso en zonas de alto tránsito y uso intensivo. Asimismo, la formulación antibacteriana integrada impide la proliferación de bacterias, hongos y microorganismos patógenos sobre la superficie. Higiene y Mantenimiento del Revestimiento Vinílico La superficie no porosa del revestimiento vinílico permite una limpieza rápida, eficaz y profunda con productos desinfectantes habituales en entornos sanitarios. Por tanto, facilita enormemente las tareas de higienización rutinaria y desinfección de alto nivel. Además, resiste perfectamente la limpieza frecuente e intensiva sin deteriorarse ni perder sus propiedades estéticas ni funcionales. En consecuencia, reduce significativamente los costes de mantenimiento a largo plazo. Aplicaciones en Entornos Sanitarios Muraldis Ultradis es la elección preferida para hospitales de cualquier especialidad, quirófanos que requieren máxima asepsia, clínicas dentales y médicas, centros de salud, laboratorios de análisis clínicos, salas blancas farmacéuticas y cualquier espacio que requiera cumplimiento estricto de protocolos sanitarios y normativas de higiene. Asimismo, su acabado decorativo permite crear ambientes profesionales agradables visualmente sin comprometer las prestaciones técnicas necesarias. Características Técnicas Con 1,5 mm de espesor, tratamiento PROTECSOL®, propiedades antibacterianas certificadas, superficie 100% lavable y material completamente reciclable, este revestimiento cumple con las normativas más exigentes. Posteriormente, ofrece una estética cuidada que permite personalizar espacios sanitarios manteniendo siempre las máximas garantías higiénicas y de durabilidad.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
