INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b3bcd895-4cd5-4497-8082-65eb70e86299',
  'Telas Impresa Twisdis',
  'telas-impresas-ignifugas-personalizables',
  'Las telas impresas Twisdis y Okawitdis representan la solución perfecta para proyectos que demandan personalización visual total. Estas telas combinan seguridad y creatividad sin límites. Fabricadas mediante impresión digital de alta resolución, ofrecen posibilidades decorativas ilimitadas. Segur...',
  'Las telas impresas Twisdis y Okawitdis representan la solución perfecta para proyectos que demandan personalización visual total. Estas telas combinan seguridad y creatividad sin límites. Fabricadas mediante impresión digital de alta resolución, ofrecen posibilidades decorativas ilimitadas. Seguridad Certificada La clasificación ignífuga B-s1 es permanente. El tratamiento permanent fire-proof garantiza protección durante toda la vida útil. Cumple con la normativa europea EN 13501-1. Es apta para espacios públicos y eventos de cualquier escala. La seguridad está garantizada sin comprometer la estética. Impresión Digital de Alta Calidad La tecnología de impresión digital reproduce cualquier diseño. Los colores corporativos se replican con fidelidad exacta. Las imágenes fotográficas mantienen alta resolución. No hay límite de colores en cada impresión. El acabado profesional está garantizado. Elasticidad y Versatilidad Los elastic fabrics facilitan instalaciones complejas. Se adaptan a superficies curvas sin problemas. Funcionan en columnas cilíndricas perfectamente. Las formas arquitectónicas irregulares no son obstáculo. La instalación es rápida y eficiente. Aplicaciones Profesionales Son perfectas para stands feriales personalizados. Las escenografías teatrales ganan impacto visual. Los espacios comerciales temporales se transforman. Los fondos fotográficos son espectaculares. Las ambientaciones corporativas transmiten marca. Los eventos de lanzamiento destacan. Formato Práctico El formato en rollos facilita el transporte. El almacenamiento es simple y compacto. El despliegue es rápido en el montaje. Son reutilizables en múltiples eventos. La inversión se amortiza. Personalización Total Twisdis y Okawitdis admiten cualquier diseño gráfico. Los logotipos se reproducen perfectamente. Las fotografías mantienen calidad. Los patrones complejos son viables. La creatividad no tiene límites. Precio indicado por metro cuadrado o por proyecto.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
