INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'cd38c5f3-8ff0-46f9-893c-5449ad68b56f',
  'Twisdis Litos',
  'twisdis-litos',
  'La Twisdis Litos es una moqueta decorativa de alta calidad que reproduce fielmente el aspecto de un pavimento de piedra natural, ofreciendo la combinación perfecta entre estética realista y funcionalidad práctica. Este innovador revestimiento destaca por su diseño en elegantes tonos grises que ap...',
  'La Twisdis Litos es una moqueta decorativa de alta calidad que reproduce fielmente el aspecto de un pavimento de piedra natural, ofreciendo la combinación perfecta entre estética realista y funcionalidad práctica. Este innovador revestimiento destaca por su diseño en elegantes tonos grises que aportan sofisticación a cualquier espacio, mientras que su textura con ligero relieve proporciona un acabado visual tridimensional que simula con gran realismo la superficie de piedras naturales. Características y ventajas de la Twisdis Litos: Esta moqueta decorativa está especialmente diseñada para resistir el tránsito intenso y las condiciones más exigentes, lo que la convierte en una solución ideal para múltiples aplicaciones. Su durabilidad excepcional garantiza una larga vida útil incluso en zonas de alto tráfico, manteniendo su aspecto impecable con el paso del tiempo. Aplicaciones versátiles: La Twisdis Litos es perfecta para una amplia variedad de espacios tanto residenciales como comerciales. Destaca especialmente en: Entradas y recibidores: donde su resistencia y elegancia causan una excelente primera impresión Terrazas cubiertas: aportando un toque decorativo con aspecto de piedra sin las complicaciones de instalación de pavimentos tradicionales Ferias y eventos: gracias a su fácil instalación y desmontaje, además de su resistente superficie Entornos comerciales: como tiendas, showrooms y espacios públicos que requieren un suelo atractivo y duradero Presentación y opciones de personalización: Este producto se presenta en cómodos rollos de 2 metros de ancho, facilitando su instalación y reduciendo el número de juntas visibles. Además, para proyectos específicos que requieran una personalización mayor, la Twisdis Litos está disponible en colores especiales bajo pedido, permitiéndote adaptar completamente el revestimiento a tu proyecto decorativo o corporativo. La moqueta Twisdis Litos representa la solución perfecta para quienes buscan la belleza de la piedra con la practicidad de un revestimiento textil.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
