INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '71ae71ef-c166-44a7-83b4-77ae1247743e',
  'PVC Pixeldis',
  'suelo-vinilico-pvc-pixeldis',
  'Pixeldis es un pavimento vinílico profesional que combina diseño contemporáneo con prestaciones técnicas superiores. Su distintivo patrón pixelado aporta dinamismo visual y modernidad a cualquier espacio, rompiendo con la monotonía de los revestimientos tradicionales. Fabricado con 97% vinilo ref...',
  'Pixeldis es un pavimento vinílico profesional que combina diseño contemporáneo con prestaciones técnicas superiores. Su distintivo patrón pixelado aporta dinamismo visual y modernidad a cualquier espacio, rompiendo con la monotonía de los revestimientos tradicionales. Fabricado con 97% vinilo reforzado, 2% poliéster y 1% fibra de vidrio, ofrece una resistencia excepcional certificada Clase 33 para uso comercial intenso. Su superficie con tratamiento PUR garantiza fácil mantenimiento y protección duradera contra manchas y arañazos, mientras que sus propiedades antiestáticas y aislamiento acústico de 15 dB lo convierten en la solución ideal para oficinas, centros educativos y espacios sanitarios. Disponible en rollos de 2 metros y losetas modulares 50x50 cm, Pixel permite máxima flexibilidad de instalación adaptándose a cualquier proyecto arquitectónico. Con certificación ignífuga Bfls1, baja emisión de COV y compatibilidad con suelo radiante, representa el equilibrio perfecto entre diseño vanguardista, funcionalidad y sostenibilidad para los proyectos más exigentes del mercado profesional.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
