INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '66aa130a-4f58-42c5-86dd-b1bfe8ec9112',
  'PVC Klasidis',
  'pvc-klasidis',
  'Klasidis representa la nueva generación de revestimientos textiles profesionales, diseñado para satisfacer las demandas más exigentes del sector contract, retail y residencial de alta gama. Este innovador producto combina tecnología avanzada con versatilidad excepcional, permitiendo su instalació...',
  'Klasidis representa la nueva generación de revestimientos textiles profesionales, diseñado para satisfacer las demandas más exigentes del sector contract, retail y residencial de alta gama. Este innovador producto combina tecnología avanzada con versatilidad excepcional, permitiendo su instalación en tres formatos diferentes: alfombra, moqueta o loseta, adaptándose perfectamente a las necesidades específicas de cada proyecto arquitectónico o de interiorismo. Composición y Tecnología Superior La formulación única de Klasidis, compuesta por 97% vinilo de alta calidad, 2% poliéster reforzado y 1% fibra de vidrio, garantiza una durabilidad excepcional y un rendimiento óptimo incluso en espacios de tránsito intenso. Esta composición ha sido específicamente desarrollada para ofrecer la máxima resistencia al desgaste, manteniendo su aspecto impecable durante años de uso continuado. Salud y Bienestar Garantizados El compromiso con la salud y el bienestar se refleja en cada aspecto de Klasidis. Sus materiales completamente lavables y superficies hipoalergénicas certificadas lo convierten en la elección preferida para entornos sensibles como hospitales, clínicas, centros educativos y oficinas modernas. La ausencia de componentes alergénicos y su fácil mantenimiento contribuyen a crear espacios más saludables y seguros para todos los usuarios. Rendimiento Certificado para Uso Intensivo Con una clasificación Clase 33 para uso comercial pesado según normativa EN 685/1307, Klasidis está preparado para soportar las condiciones más exigentes. Su resistencia anti-deslizante R10, certificación antiestática y excelente estabilidad dimensional garantizan seguridad y durabilidad en aeropuertos, centros comerciales, hoteles, oficinas corporativas y espacios públicos de alto tránsito. Confort Acústico y Térmico El aislamiento acústico de 15 dB contribuye significativamente a la reducción del ruido ambiental, creando espacios más confortables y productivos. Su total compatibilidad con sistemas de suelo radiante optimiza la eficiencia energética de los edificios, mientras que sus propiedades térmicas mejoran el confort general del espacio. Seguridad y Sostenibilidad Klasidis cumple con las normativas más estrictas de seguridad contra incendios (clasificación Bfls1), con baja emisión de humos y gases tóxicos. Sus bajas emisiones de COV (<48) contribuyen a la calidad del aire interior, fundamental para obtener certificaciones de construcción sostenible como LEED o BREEAM. Diseño y Personalización La amplia gama de colecciones disponibles permite combinaciones ilimitadas, facilitando la creación de ambientes únicos y diferenciados. Desde espacios corporativos minimalistas hasta entornos creativos y dinámicos, Klasidis ofrece soluciones estéticas que se adaptan a cualquier concepto de diseño, manteniendo siempre los más altos estándares de calidad y funcionalidad que caracterizan a los productos profesionales de nueva generación.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
