INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a9021015-9e99-4ec5-8aac-d2b24b069c19',
  'PVC Zedis',
  'zedis-revestimiento-textil-vinilico-clase-33',
  'Zedis representa la evolución en revestimientos textiles profesionales, diseñado para satisfacer las demandas más exigentes del sector contract, retail y residencial. Este innovador producto combina tecnología avanzada con versatilidad excepcional, permitiendo su instalación en tres formatos dife...',
  'Zedis representa la evolución en revestimientos textiles profesionales, diseñado para satisfacer las demandas más exigentes del sector contract, retail y residencial. Este innovador producto combina tecnología avanzada con versatilidad excepcional, permitiendo su instalación en tres formatos diferentes: alfombra, moqueta o loseta, adaptándose perfectamente a las necesidades específicas de cada proyecto arquitectónico. La formulación única de Zedis, compuesta por 97% vinilo de alta calidad, 2% poliéster reforzado y 1% fibra de vidrio, garantiza una durabilidad excepcional y un rendimiento óptimo incluso en espacios de tránsito intenso. Esta composición ha sido desarrollada para ofrecer la máxima resistencia al desgaste, manteniendo su aspecto impecable durante años de uso continuado. Sus materiales completamente lavables y superficies hipoalergénicas certificadas lo convierten en la elección preferida para entornos sensibles como hospitales, clínicas, centros educativos y oficinas modernas. Con una clasificación Clase 33 para uso comercial pesado, Zedis está preparado para soportar las condiciones más exigentes, mientras que su resistencia anti-deslizante R10 y certificación antiestática garantizan seguridad y durabilidad. El aislamiento acústico de 15 dB contribuye significativamente a la reducción del ruido ambiental, creando espacios más confortables. Su compatibilidad con sistemas de suelo radiante optimiza la eficiencia energética, cumpliendo con las normativas más estrictas de seguridad contra incendios (Bfls1) y bajas emisiones de COV (<48), fundamental para certificaciones de construcción sostenible como LEED o BREEAM.',
