INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '48d6ca27-6e19-4d88-877d-d98bb1594a24',
  'PVC Lindis',
  'pvc-vinilico-textura-tejida',
  'PVC Vinílico Textura Tejida – Lindis Profesional Lindis Profesional es un revestimiento vinílico con textura tejida que combina la estética de un textil natural con las ventajas técnicas del vinilo de alta calidad. Su diseño innovador y apariencia sofisticada lo hacen ideal para espacios que requ...',
  'PVC Vinílico Textura Tejida – Lindis Profesional Lindis Profesional es un revestimiento vinílico con textura tejida que combina la estética de un textil natural con las ventajas técnicas del vinilo de alta calidad. Su diseño innovador y apariencia sofisticada lo hacen ideal para espacios que requieren tanto resistencia como estilo contemporáneo. Composición Técnica Este revestimiento está compuesto por: 97% vinilo 2% poliéster 1% fibra de vidrio Esta fórmula garantiza una estructura sólida, excelente estabilidad dimensional y alta resistencia al desgaste. Su superficie presenta un patrón entrelazado que imita tejidos naturales artesanales. Este diseño no solo aporta valor estético, sino que también mejora la resistencia al tránsito intenso y disimula imperfecciones del subsuelo. Uso Comercial e Industrial Gracias a su certificación Clase 33 para uso intensivo (según normativa europea), este PVC vinílico es perfecto para: Oficinas corporativas Espacios comerciales de alto tráfico Centros educativos Instalaciones sanitarias Proyectos arquitectónicos exigentes Además, sus propiedades antiestáticas certificadas lo hacen apto para entornos con equipamiento electrónico sensible. Aislamiento Acústico y Diseño Ofrece un aislamiento acústico de 15 dB, lo que mejora el confort reduciendo el ruido entre plantas. Está disponible en una amplia gama de colores neutros y combinaciones bicolor, ideales para crear ambientes modernos y profesionales. Mantenimiento y Compatibilidad El mantenimiento es sencillo gracias a su superficie lavable e hipoalergénica. También es compatible con sistemas de suelo radiante, lo que lo convierte en una opción ideal para proyectos sostenibles o de rehabilitación energética. Aporta eficiencia térmica durante todo el año.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
