INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b63bd672-002c-49b9-86a5-e8b8084fe828',
  'Imitación Alfresdis Exterior',
  'moquetas-exterior-resistentes-agua',
  'Moqueta Alfresdis Nueva Colección es una solución versátil diseñada para uso interior y exterior. Revoluciona el concepto tradicional de revestimientos textiles. Con un aspecto que imita fielmente las fibras naturales tipo sisal, ofrece todas las ventajas técnicas. El polipropileno de última gene...',
  'Moqueta Alfresdis Nueva Colección es una solución versátil diseñada para uso interior y exterior. Revoluciona el concepto tradicional de revestimientos textiles. Con un aspecto que imita fielmente las fibras naturales tipo sisal, ofrece todas las ventajas técnicas. El polipropileno de última generación elimina las limitaciones de los materiales naturales. Tecnología StainSafe® Patentada Su mayor innovación radica en el tratamiento StainSafe®. Es un sistema patentado de protección antimanchas. Impide que la suciedad penetre en las fibras. Los líquidos no se absorben. La limpieza resulta extraordinariamente sencilla. Esta tecnología permite incluso el uso de solución de lejía diluida (máx. 10%) para desinfección. Esto es impensable en moquetas convencionales. Resistencia Excepcional para Exteriores La resistencia al agua dulce y salada es total. Soporta la exposición continua sin deteriorarse. Su inmunidad a los efectos de la luz solar UV es completa. Los colores no se desvanecen con el sol. La estructura no se degrada con rayos ultravioleta. Es perfecta para terrazas soleadas y porches expuestos. Ideal para zonas de piscina con cloro y agua. Excelente para embarcaciones marinas y fluviales. Versatilidad de Aplicaciones Alfresdis funciona en cualquier espacio exterior. También es perfecta para interiores exigentes. Jardines de invierno mantienen confort todo el año. Balcones urbanos ganan elegancia. Áticos con terraza mejoran su estética. Restaurantes con terraza ofrecen mejor experiencia. Hoteles en playa resisten el ambiente salino. Nueva Colección Ampliada La colección incluye diseños actualizados. Los colores siguen las tendencias modernas. Se adaptan a decoración contemporánea. Tonos naturales predominan en la gama. También hay opciones más atrevidas. Cada color mantiene las mismas propiedades técnicas. La variedad permite personalizar cada proyecto. Mantenimiento Simplificado El mantenimiento es extremadamente sencillo. Una manguera con agua limpia la mayoría de suciedades. Las manchas difíciles se tratan con lejía diluida. No requiere productos especializados costosos. Ahorra tiempo y dinero en limpieza. El aspecto se mantiene impecable con mínimo esfuerzo. Fibra Natural, Ventajas Sintéticas El aspecto de sisal es completamente natural. Pero las ventajas son superiores. No se pudre con humedad. No atrae insectos ni ácaros. No se decolora con el sol. No requiere tratamientos periódicos. Combina lo mejor de ambos mundos. Precio indicado por metro cuadrado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
