INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3540ebd0-7aaf-4262-8b52-de00a62585d6',
  'Moquetas Koidis',
  'moquetas-koidis-lujo-poliamida-antron',
  'Las moquetas KOIDIS representan la excelencia en revestimientos textiles de lujo. Establecen nuevos estándares en el mercado premium. Fabricadas con Poliamida 6.6 Antron® de última generación, ofrecen la apariencia brillante característica de la viscosa. Sin embargo, su durabilidad es muy superio...',
  'Las moquetas KOIDIS representan la excelencia en revestimientos textiles de lujo. Establecen nuevos estándares en el mercado premium. Fabricadas con Poliamida 6.6 Antron® de última generación, ofrecen la apariencia brillante característica de la viscosa. Sin embargo, su durabilidad es muy superior. Por esta razón, se posicionan como una inversión inteligente a largo plazo. Textura Ultra Suave de Alta Densidad Su textura ULTRA SUAVE se consigue mediante una construcción de alta densidad. Cuenta con 1.666 g/m² de pelo y una altura de 7,8 mm. De esta manera, se convierte en la elección perfecta para espacios residenciales premium. Asimismo, resulta ideal para oficinas elegantes y zonas infantiles donde el confort es prioritario. Esta suavidad excepcional no es solo una característica táctil. En efecto, representa una experiencia sensorial completa que transforma cualquier estancia en un refugio de bienestar. Tecnología y Certificaciones Profesionales La tecnología Ceneva® Actionbac® en su base garantiza estabilidad dimensional. Además, facilita la instalación profesional sin complicaciones. Por otro lado, la certificación CflS1 en resistencia al fuego cumple con las normativas más exigentes. Gracias a esto, es apta para espacios comerciales y residenciales. Con un peso total de 2.500 g/m², KOIDIS ofrece la robustez necesaria. En consecuencia, soporta el tráfico intenso sin perder su aspecto lujoso. Paleta de Colores Contemporáneos Disponible en una amplia gama de colores cálidos contemporáneos, cada tono ha sido cuidadosamente seleccionado. Por lo tanto, complementa perfectamente las tendencias actuales en diseño de interiores. Desde neutros sofisticados hasta tonalidades más atrevidas, la paleta KOIDIS permite crear ambientes únicos. De esta manera, cada proyecto puede personalizarse completamente según las necesidades del cliente. Opciones de Acabado Versátiles Las opciones de acabado son prácticamente ilimitadas para proyectos personalizados. Sin embargo, destacan especialmente THE END y ANTELOOK en sus versiones BANDA y BLIND. Estos acabados son reconocidos por su elegancia y funcionalidad excepcionales. En definitiva, esta versatilidad convierte a KOIDIS en la solución ideal. Funciona tanto para proyectos residenciales exclusivos como para espacios corporativos que buscan transmitir prestigio. Durabilidad y Garantía de Calidad El mantenimiento profesional recomendado preserva las cualidades premium del producto durante años. Asimismo, las certificaciones CE EN 14041:2004 y EN 1307 garantizan el cumplimiento de los estándares europeos más estrictos. Finalmente, KOIDIS no es simplemente una moqueta. Es una declaración de estilo y calidad que eleva cualquier espacio al máximo nivel de sofisticación.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
