INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '46a43636-6ae5-4129-8ed5-4c2fa7627e0a',
  'Moqueta Kontradis',
  'moquetas-ecologicas-eco-kontradis-poliamida-regenerada',
  'ECO KONTRADIS representa la evolución sostenible de la icónica colección KONTRADIS. Combina resistencia excepcional con un compromiso medioambiental sin precedentes. Esta innovadora moqueta está fabricada con 100% poliamida regenerada. Se trata de un material revolucionario que transforma redes d...',
  'ECO KONTRADIS representa la evolución sostenible de la icónica colección KONTRADIS. Combina resistencia excepcional con un compromiso medioambiental sin precedentes. Esta innovadora moqueta está fabricada con 100% poliamida regenerada. Se trata de un material revolucionario que transforma redes de pesca abandonadas y otros desechos marinos en revestimientos textiles de alta calidad. De esta manera, da una segunda vida a materiales que de otro modo contaminarían nuestros océanos. Durabilidad y Compromiso Ambiental Con una clasificación de uso comercial intenso, ECO KONTRADIS mantiene la durabilidad legendaria que caracteriza a la marca. Además, contribuye activamente a la limpieza de los océanos y la reducción de residuos plásticos. Su perfil ultrafino de apenas 4 mm de altura total incorpora un peso del pelo de 785 g/m². Por esta razón, se convierte en la solución perfecta para espacios públicos de alto tránsito. Asimismo, resulta ideal para oficinas corporativas, centros comerciales, hospitales y proyectos institucionales. En estos entornos, la sostenibilidad es tan importante como el rendimiento técnico. Certificaciones y Seguridad La certificación Cfl-s1 en resistencia al fuego garantiza la máxima seguridad en instalaciones públicas y comerciales. En efecto, cumple con las normativas más estrictas del sector profesional. Por otro lado, su resistencia térmica (TOG) de 0,7 proporciona confort térmico adicional. Gracias a esto, mejora la eficiencia energética de los espacios. En consecuencia, contribuye significativamente al bienestar de los usuarios. Formatos y Facilidad de Instalación Disponible en rollos de 2 y 4 metros, ECO KONTRADIS facilita la instalación en proyectos de cualquier envergadura. La versatilidad del producto se extiende a sus opciones de personalización múltiples. Por un lado, funciona perfectamente como alfombras a medida personalizadas. Por otro lado, admite diversos acabados premium como SUPER & MINI FEST, PREMIUM o THE END. De esta manera, permite adaptación total a las necesidades estéticas y funcionales de cada proyecto específico. Estilo, Funcionalidad y Sostenibilidad ECO KONTRADIS demuestra que estilo, funcionalidad y sostenibilidad pueden coexistir perfectamente en un solo producto. Cada metro cuadrado instalado representa un paso hacia un futuro más limpio y responsable. En efecto, convierte los desechos marinos en superficies elegantes y duraderas que mejoran cualquier espacio. Compromiso con el Planeta ECO KONTRADIS no es solo una moqueta técnica de alto rendimiento. Es una declaración de principios medioambientales que transforma espacios mientras protege activamente el planeta. Finalmente, porque cuidar el medio ambiente nunca se sintió ni se pisó tan bien como con esta innovadora solución sostenible.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
