INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '8eac0a4c-b723-4855-8b6a-1a3bde2a1873',
  'Moquetas Alpadis',
  'moquetas-alpadis-interior-exterior-stainsafe',
  'Las moquetas ALPADIS están pensadas para quienes disfrutan tanto de los espacios interiores como de los exteriores, representando la evolución natural de la exitosa colección ALPATIO. Esta nueva generación de alfombras a medida y moquetas se adapta a cualquier entorno, ofreciendo estilo y resiste...',
  'Las moquetas ALPADIS están pensadas para quienes disfrutan tanto de los espacios interiores como de los exteriores, representando la evolución natural de la exitosa colección ALPATIO. Esta nueva generación de alfombras a medida y moquetas se adapta a cualquier entorno, ofreciendo estilo y resistencia sin importar el lugar, invitando a llevar el confort y el diseño de calidad también al aire libre, para crear espacios acogedores tanto dentro como fuera de casa. Fabricadas con 100% polipropileno Stainsafe®, ALPADIS ofrece características excepcionales que la distinguen en el mercado. Su fácil limpieza es revolucionaria: diseñada para soportar el uso diario sin complicaciones de mantenimiento, incluso permite limpieza con lejía, algo impensable en moquetas convencionales. La tecnología antimanchas permanente repele líquidos y suciedad, mientras que su resistencia al agua dulce y salada garantiza durabilidad en cualquier ambiente. Con alta resistencia para espacios con mucho tránsito y clasificación al fuego Cfl-s1 cuando se instala como moqueta, ALPADIS es ideal para proyectos de contrata más exigentes. Su certificación hipoalergénica y resistencia UV nivel 5-6 la convierten en la opción perfecta para hogares, oficinas, hoteles y espacios comerciales que buscan combinar funcionalidad y elegancia. La variedad de diseños y colores en tonos cálidos contemporáneos permite encontrar la combinación perfecta para cada espacio, creando ambientes únicos que reflejan personalidad y estilo. Como alfombra a medida, es necesario rematarla con acabados profesionales: para uso exterior, recomendamos BANDA STRONG o BANDA NATUR por su resistencia extrema; para interiores, las posibilidades incluyen BANDA MICROFIBRA, PELLE, KUERO y el exclusivo BANDA THE END. ALPADIS no es solo una alfombra a medida; es una solución de diseño integral que lleva la calidez y el estilo a patios, terrazas o cualquier espacio que desees personalizar. Con ALPADIS, el confort se extiende al aire libre, permitiendo disfrutar de ambientes acogedores, en interiores o exteriores, durante todo el año.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ae5ae92e-b715-429a-8e28-48cd61a4ba20',
  'Moqueta Ekilibridis',
  'moquetas-ekilibridis-poliester-halcyon-residencial',
  'Las moquetas EKILIBRIDIS son moquetas poliester Halcyon residencial que representan la perfecta armonía entre estética y funcionalidad. Están diseñadas para quienes comprenden que el verdadero lujo reside en el equilibrio. Esta sofisticada colección trasciende la mera decoración. Se convierte en ...',
  'Las moquetas EKILIBRIDIS son moquetas poliester Halcyon residencial que representan la perfecta armonía entre estética y funcionalidad. Están diseñadas para quienes comprenden que el verdadero lujo reside en el equilibrio. Esta sofisticada colección trasciende la mera decoración. Se convierte en una declaración de estilo de vida consciente y duradero. El poliéster Halcyon ofrece resistencia excepcional para uso residencial intenso. Fabricadas con 100% PES Halcyon®, una fibra de poliéster de última generación reconocida por su excepcional resistencia y suavidad, EKILIBRIDIS ofrece una experiencia sensorial única. Con una generosa altura de pelo de 7,5 mm y un peso de 1.330 g/m², cada pisada se convierte en un momento de confort absoluto, mientras que su estructura de 2.300 g/m² de peso total garantiza durabilidad excepcional para uso residencial intenso. La paleta diversa de colores ha sido cuidadosamente curada para satisfacer todas las sensibilidades estéticas. Desde tonos apacibles que crean atmósferas de serenidad y contemplación, hasta tonalidades vibrantes que energizan y revitalizan los espacios, cada opción cromática permite expresar personalidad única mientras se mantiene la coherencia visual del ambiente. La certificación Cfl-s1 en resistencia al fuego y la resistencia térmica de 0,11 m² K/W convierten a EKILIBRIDIS en una inversión inteligente que combina seguridad, eficiencia energética y confort. Estas características técnicas superiores aseguran que cada pieza mantenga su belleza y funcionalidad durante años de uso intensivo. Como alfombras a medida, EKILIBRIDIS ofrece infinitas posibilidades de personalización. Los acabados PREMIUM aportan grosor adicional y máximo confort, mientras que el ribete FEST permite jugar con contrastes y añadir calidez visual. La versatilidad de opciones garantiza que cada proyecto encuentre su expresión perfecta. EKILIBRIDIS no es simplemente una moqueta; es un recordatorio tangible de que la verdadera belleza emerge cuando forma y función convergen en perfecta armonía. Para aquellos que buscan no solo adornar sus hogares sino también equilibrar sus vidas con estilo y gracia, EKILIBRIDIS se presenta como la elección natural e indiscutible.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
