INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '8be4e042-42ce-4c29-87c2-fc134abaf4cd',
  'PVC Taraladis Impression',
  'suelo-vinilico-heterogeneo-taraladis-impression',
  'Taraladis Impression: La Solución Profesional en Suelos Vinílicos de Alto Rendimiento El suelo vinílico heterogéneo Taraladis Impression representa la evolución definitiva en pavimentos PVC. Es ideal para espacios comerciales e industriales de alta exigencia. Desarrollado con tecnología de vangua...',
  'Taraladis Impression: La Solución Profesional en Suelos Vinílicos de Alto Rendimiento El suelo vinílico heterogéneo Taraladis Impression representa la evolución definitiva en pavimentos PVC. Es ideal para espacios comerciales e industriales de alta exigencia. Desarrollado con tecnología de vanguardia, este revolucionario revestimiento combina resistencia excepcional. Las propiedades higiénicas son superiores. Se ha convertido en la elección preferida de arquitectos. Los profesionales del sector confían en él. Especificaciones Técnicas Superiores Con un espesor total de 2,00 mm ofrece gran robustez. La capa de desgaste de 0,70 mm es muy resistente. Taraladis Impression está específicamente diseñado para tráfico intenso. Soporta las condiciones más exigentes. Su avanzado tratamiento superficial Protecsol® 2 garantiza protección duradera. Facilita extraordinariamente las labores de mantenimiento. Los costes operativos se reducen significativamente a largo plazo. Certificación de Uso Máximo Este innovador pavimento vinílico destaca por su certificación de uso 34/43. Se posiciona en la categoría más alta. Es perfecto para aplicaciones comerciales intensas. También para instalaciones industriales exigentes. Hoteles de alto tráfico lo eligen. Hospitales valoran sus propiedades. Centros comerciales confían en su resistencia. Protección Antibacteriana Certificada La incorporación de propiedades antibacterianas y antivirales es crucial. Ofrece protección adicional en entornos públicos. Elimina más del 99% de bacterias comunes. Destruye E. coli y S. aureus efectivamente. Incluye eficacia contra MRSA. Presenta 99,7% de eficacia contra coronavirus humano 229E. Todo esto en apenas 2 horas de exposición. Confort Acústico Excepcional La versatilidad de Taraladis Impression es notable. Su comportamiento acústico es excepcional. Proporciona aislamiento de impacto de 8 dB. Contribuye significativamente al confort ambiental. Los espacios son más silenciosos. El ruido de pasos se reduce notablemente. Seguridad Certificada Su clasificación al fuego es Bfl-s1. Cumple con las normativas más exigentes. La resistencia al deslizamiento R10 garantiza máxima seguridad. Previene caídas y accidentes. Es seguro incluso en zonas húmedas. Calidad del Aire Interior La certificación Floorscore® avala su calidad. Los niveles de emisiones TVOC son bajísimos (< 10 µg/m³). Aseguran una calidad del aire interior óptima. No contamina espacios cerrados. Es seguro para personas sensibles. Precio indicado por metro cuadrado.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
