INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7cd78aa8-9173-47ef-8815-7b37d5311c6a',
  'Moqueta Sunridis',
  'moquetas-iridiscentes-sunridis',
  'La colección SUNRIDIS redefine el concepto de moquetas decorativas con su distintivo acabado iridiscente que captura y refleja la luz de manera única. Esta innovadora propuesta textil ofrece un efecto visual dinámico que transforma cualquier espacio en una experiencia sensorial, donde los colores...',
  'La colección SUNRIDIS redefine el concepto de moquetas decorativas con su distintivo acabado iridiscente que captura y refleja la luz de manera única. Esta innovadora propuesta textil ofrece un efecto visual dinámico que transforma cualquier espacio en una experiencia sensorial, donde los colores evolucionan sutilmente según el ángulo de visión y las condiciones lumínicas del ambiente. Disponible en 35 variantes cromáticas cuidadosamente seleccionadas, SUNRIDIS permite crear desde ambientes sutiles y elegantes hasta espacios de alto impacto visual. Su superficie brillante no es solo una característica estética; representa un avance en la tecnología de acabados textiles que combina belleza y funcionalidad de manera excepcional. El proceso de fabricación especializado garantiza que cada metro cuadrado mantenga uniformidad en el efecto tornasolado, mientras que la durabilidad del acabado asegura que el brillo característico perdure a lo largo del tiempo. Esta tecnología permite que la moqueta no solo sea un elemento decorativo, sino una herramienta de diseño activa que interactúa con la iluminación natural y artificial del espacio. La amplia paleta de 35 opciones responde a las necesidades más diversas del diseño contemporáneo. Desde tonos neutros con destellos sutiles para ambientes corporativos sofisticados, hasta combinaciones vibrantes que crean puntos focales dramáticos en espacios comerciales. Cada variante ha sido desarrollada considerando las tendencias actuales en interiorismo y la psicología del color. SUNRIDIS encuentra su aplicación ideal en proyectos donde la diferenciación es fundamental: boutiques de lujo, showrooms de automóviles, lobbies de hoteles, espacios de eventos y residencias de alto standing. Su capacidad para transformar la percepción espacial mediante efectos lumínicos la convierte en una solución preferida por arquitectos y diseñadores que buscan crear experiencias memorables más allá de la simple decoración. El mantenimiento de estas moquetas, pese a su acabado especial, sigue protocolos estándar con consideraciones específicas para preservar el brillo, garantizando así que la inversión mantenga su impacto visual durante años.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1e429fe0-f25c-47a5-8ec1-be7f4680ad6f',
  'Moqueta Boradis',
  'moquetas-ignifugas-sin-goma-boradis',
  'Las moquetas BORADIS son moquetas ignifugas sin goma reciclables que establecen un nuevo estándar en revestimientos textiles técnicos. La innovación se manifiesta en cada aspecto de su construcción. Su característica más distintiva es el efecto de brillos moteados. Este efecto transforma superfic...',
  'Las moquetas BORADIS son moquetas ignifugas sin goma reciclables que establecen un nuevo estándar en revestimientos textiles técnicos. La innovación se manifiesta en cada aspecto de su construcción. Su característica más distintiva es el efecto de brillos moteados. Este efecto transforma superficies ordinarias en espacios con profundidad visual. Pequeñas partículas reflectantes capturan y devuelven la luz. Crean un dinamismo sutil pero constante. La verdadera revolución de BORADIS radica en su construcción sin base de goma, una decisión técnica que elimina los problemas tradicionales de las moquetas convencionales. Esta innovación no solo facilita el reciclaje completo del producto, sino que también previene la emisión de compuestos volátiles, mejora la estabilidad dimensional y reduce significativamente el peso para transporte e instalación. La certificación ignífuga garantiza cumplimiento con las normativas más estrictas del sector público y comercial. Con más de 43 variantes cromáticas, la colección abarca todo el espectro desde rojos intensos y azules profundos hasta grises neutros y negros elegantes. Cada color incorpora el mismo efecto de brillos, creando coherencia visual en proyectos de gran escala mientras permite zonificación y diferenciación de espacios. Esta amplitud de opciones convierte a BORADIS en solución versátil para hoteles, hospitales, oficinas corporativas y centros educativos. El mantenimiento simplificado es otra ventaja clave. Los brillos, al estar integrados en las propias fibras durante la fabricación, mantienen su luminosidad sin tratamientos adicionales. La superficie resiste manchas comunes y permite limpieza con productos estándar, mientras que la ausencia de base gomosa elimina problemas de delaminación o degradación por humedad. BORADIS representa el futuro de los revestimientos contract: segura, sostenible y estéticamente versátil. Es la respuesta a las demandas de arquitectos y diseñadores que buscan productos que cumplan certificaciones ambientales sin comprometer la creatividad del diseño, demostrando que la responsabilidad medioambiental y la excelencia técnica pueden coexistir perfectamente en un único producto.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
