INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e491ce3e-ab08-42b3-8c71-d4c624735ee2',
  'Moqueta Melandis',
  'moqueta-melandis-ignifuga-reciclable',
  'La moqueta Melandis es una moqueta ignífuga reciclable que representa la solución perfecta para proyectos exigentes. Combina seguridad, sostenibilidad y diseño en un solo producto. Con tecnología NO FLAME certificada, este revestimiento textil ofrece protección ignífuga de máxima calidad. Cumple ...',
  'La moqueta Melandis es una moqueta ignífuga reciclable que representa la solución perfecta para proyectos exigentes. Combina seguridad, sostenibilidad y diseño en un solo producto. Con tecnología NO FLAME certificada, este revestimiento textil ofrece protección ignífuga de máxima calidad. Cumple con las normativas más exigentes de seguridad contra incendios. Compromiso Ambiental Fabricada con un compromiso firme hacia el medio ambiente. La moqueta Melandis es 100% reciclable. Permite que los espacios profesionales reduzcan su huella ecológica. No es necesario renunciar a la calidad. Tampoco se compromete la durabilidad. Al finalizar su vida útil, el material puede reciclarse completamente. Contribuye activamente a la economía circular. Resistencia y Durabilidad Su textura de bucle resistente garantiza excelente rendimiento. Es ideal para zonas de alto tránsito. Mantiene su aspecto impecable durante años. La construcción técnica resiste el desgaste diario. No se aplasta fácilmente con el uso intensivo. Recupera su forma original tras el paso constante de personas. Versatilidad Cromática Disponible en una amplia paleta de 25 colores. Melandis se adapta a cualquier proyecto de interiorismo. Es perfecta para oficinas corporativas modernas. Ideal para hoteles de alta categoría. Excelente para centros comerciales con alto tránsito. Apropiada para espacios educativos seguros. Cada color mantiene las mismas propiedades técnicas. La variedad permite personalizar cada proyecto. Instalación Optimizada Su presentación en rollos de 200 cm de ancho facilita la instalación. Optimiza el aprovechamiento del material significativamente. Reduce desperdicios y costes de instalación. Los profesionales aprecian este formato práctico. La colocación es rápida y eficiente. Innovación Patentada Como producto patentado con sello "BREVETTATO PRODOTTO". Melandis ofrece garantías de calidad superiores. La innovación tecnológica marca la diferencia. Es un referente en pavimentos textiles profesionales. La certificación NO FLAME es exclusiva. Proporciona tranquilidad en proyectos críticos. Aplicaciones Profesionales Melandis es especialmente valorada en sectores exigentes. Hoteles con normativa estricta la eligen. Oficinas comprometidas con sostenibilidad la instalan. Centros comerciales con alto tráfico confían en ella. Espacios educativos priorizan su seguridad ignífuga. Edificios públicos cumplen normativas con facilidad. Precio indicado por metro cuadrado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
