INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f4075442-12f5-43ed-86c4-b843a4e87458',
  'Moqueta Tipo Pelo Twisdis Ignífuga',
  'moqueta-tipo-pelo-twisdis-ignifuga',
  'La moqueta tipo pelo Twidis representa la combinación perfecta entre lujo, seguridad y sostenibilidad en pavimentos textiles. Con su característica textura de fibras largas y densas, este revestimiento ofrece una experiencia táctil excepcional que aporta calidez y sofisticación a cualquier ambien...',
  'La moqueta tipo pelo Twidis representa la combinación perfecta entre lujo, seguridad y sostenibilidad en pavimentos textiles. Con su característica textura de fibras largas y densas, este revestimiento ofrece una experiencia táctil excepcional que aporta calidez y sofisticación a cualquier ambiente. Certificada con tecnología NO FLAME, esta moqueta tipo pelo proporciona protección ignífuga de máxima calidad, cumpliendo rigurosamente con las normativas de seguridad contra incendios más exigentes del mercado. Esta característica la convierte en la opción ideal para proyectos que requieren altos estándares de seguridad sin renunciar al confort y la elegancia visual. El compromiso con la sostenibilidad es fundamental en la moqueta Twisdis. Su composición 100% reciclable permite una gestión responsable del producto al final de su ciclo de vida, contribuyendo activamente a reducir el impacto ambiental de los espacios comerciales y residenciales. Esta característica ecológica no compromete en absoluto su durabilidad ni su rendimiento, ofreciendo una solución que beneficia tanto al planeta como a los usuarios. La textura tipo pelo de esta moqueta proporciona un acabado excepcionalmente suave y acogedor, creando ambientes que invitan al bienestar y la comodidad. Su construcción de fibras de alta densidad garantiza una pisada confortable mientras mantiene una resistencia excepcional al desgaste y al tráfico continuado. Esta combinación de suavidad y durabilidad la hace perfecta para hoteles boutique, oficinas ejecutivas, espacios residenciales de alto standing y cualquier proyecto que busque transmitir una sensación de lujo y distinción. Disponible en más de 24 modelos y colores, la moqueta tipo pelo Twisdis ofrece una versatilidad cromática y de diseño sin precedentes. Desde tonos neutros y elegantes hasta colores más vibrantes y contemporáneos, esta amplia paleta permite crear ambientes personalizados que se adaptan perfectamente a cualquier concepto de interiorismo. Ya sea para crear espacios cálidos y acogedores o ambientes modernos y sofisticados, la variedad disponible garantiza la solución perfecta para cada proyecto. La presentación en rollos de 195 cm de ancho facilita enormemente la instalación, especialmente en espacios amplios donde se busca minimizar las juntas visibles y crear una superficie continua y uniforme. Este formato optimiza el aprovechamiento del material, reduce desperdicios y agiliza el proceso de instalación, traduciendo en ahorros de tiempo y costes para el proyecto. Como producto patentado con el sello "BREVETTATO PRODOTTO", la moqueta Twisdis ofrece garantías de calidad, innovación tecnológica y exclusividad que marcan la diferencia en el competitivo sector de los pavimentos textiles profesionales. Esta certificación respalda años de investigación y desarrollo orientados a crear un producto superior que satisface las demandas más exigentes del mercado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
