INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'd47d6b67-f969-41fb-8ae8-62c94dc1cb06',
  'Moqueta Pigalldis',
  'moqueta-pigalldis-tipo-rizo-ignifuga-sin-goma',
  'La moqueta Pigalldis tipo rizo representa una solución integral para proyectos que demandan máxima resistencia, seguridad y versatilidad en la instalación. Con su característica textura de rizo compacto, este pavimento textil ofrece una superficie uniforme y extraordinariamente duradera, perfecta...',
  'La moqueta Pigalldis tipo rizo representa una solución integral para proyectos que demandan máxima resistencia, seguridad y versatilidad en la instalación. Con su característica textura de rizo compacto, este pavimento textil ofrece una superficie uniforme y extraordinariamente duradera, perfecta para soportar el tráfico intenso de espacios comerciales y profesionales. Certificada con tecnología NO FLAME, esta moqueta proporciona protección ignífuga de máxima calidad, cumpliendo rigurosamente con las normativas de seguridad contra incendios más exigentes del mercado europeo. Esta certificación la convierte en la opción preferida para proyectos que requieren cumplir con estrictos estándares de seguridad, desde edificios corporativos hasta instalaciones educativas y espacios públicos. Una característica distintiva de la moqueta Pigalldis es su base sin goma, lo que proporciona una flexibilidad excepcional en los métodos de instalación. Esta particularidad permite adaptar la colocación a las necesidades específicas de cada proyecto, ya sea mediante adhesivos, sistemas de doble cara o instalaciones flotantes, ofreciendo a los profesionales la libertad de elegir el método más adecuado para cada situación particular. El compromiso con la sostenibilidad está presente en cada aspecto de Pigalldis. Su composición 100% reciclable permite una gestión responsable al final de su ciclo de vida, contribuyendo activamente a la economía circular y reduciendo el impacto ambiental de los proyectos de construcción y renovación. Esta característica ecológica no compromete en absoluto su excepcional durabilidad ni su rendimiento en condiciones de uso intensivo. La textura tipo rizo de esta moqueta crea una superficie extraordinariamente compacta y resistente al desgaste. Las fibras cortas entrelazadas forman una estructura densa que soporta el tráfico pesado mientras mantiene su apariencia impecable durante años. Esta construcción robusta también facilita significativamente las tareas de limpieza y mantenimiento, ya que la superficie compacta previene la acumulación de suciedad en profundidad, permitiendo una higienización eficiente que mantiene los espacios en condiciones óptimas con mínimo esfuerzo. Disponible en una impresionante paleta de 33 colores, la moqueta Pigalldis ofrece opciones cromáticas para satisfacer cualquier visión de diseño. Desde tonos neutros y profesionales perfectos para entornos corporativos, hasta colores más vibrantes y contemporáneos ideales para espacios creativos o educativos, esta amplia variedad garantiza que cada proyecto encuentre la solución cromática perfecta. La diversidad de colores permite crear desde ambientes sobrios y elegantes hasta espacios dinámicos y energizantes, adaptándose perfectamente a la identidad visual de cada organización o concepto de diseño. La presentación en rollos de 200 cm de ancho optimiza significativamente el proceso de instalación, especialmente en espacios amplios donde se busca crear superficies continuas con el mínimo número de juntas visibles. Este formato de rollo ancho reduce el tiempo de instalación, minimiza los desperdicios de material y proporciona un acabado más limpio y profesional, traduciendo directamente en ahorros de costes y mayor eficiencia en la ejecución del proyecto. Como producto patentado con el prestigioso sello "BREVETTATO PRODOTTO", la moqueta Pigalldis respalda su calidad con años de investigación, desarrollo e innovación tecnológica. Esta certificación no solo garantiza un producto superior, sino que también ofrece la tranquilidad de contar con un pavimento textil que ha sido rigurosamente testado y que cumple con los más altos estándares de la industria europea de revestimientos profesionales.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
