INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'eaf56d60-8c03-4de3-8afd-960133e7ff9b',
  'Moqueta Timelediss',
  'moqueta-timelediss-tipo-rizo-ignifuga',
  'La moqueta Timelediss es una moqueta tipo rizo ignífuga que representa la máxima expresión de versatilidad y seguridad. Con una impresionante selección de más de 70 modelos y colores, este revestimiento ofrece posibilidades de diseño prácticamente ilimitadas. Permite crear espacios únicos que ref...',
  'La moqueta Timelediss es una moqueta tipo rizo ignífuga que representa la máxima expresión de versatilidad y seguridad. Con una impresionante selección de más de 70 modelos y colores, este revestimiento ofrece posibilidades de diseño prácticamente ilimitadas. Permite crear espacios únicos que reflejan perfectamente la identidad visual de cada proyecto. La certificación ignífuga garantiza seguridad en cualquier ambiente profesional. Certificada con tecnología NO FLAME, esta moqueta proporciona protección ignífuga de máxima calidad, cumpliendo rigurosamente con las normativas de seguridad contra incendios más exigentes del mercado europeo. Esta certificación la convierte en la solución ideal para proyectos que deben cumplir con estrictos estándares de seguridad, desde edificios corporativos y centros educativos hasta instalaciones comerciales y espacios públicos de gran afluencia. Una característica distintiva de la moqueta Timelediss es su innovadora base textil sin goma. A diferencia de otros pavimentos textiles que incorporan una base de goma, Timelediss utiliza un soporte fabricado con el mismo tipo de material textil que la superficie, proporcionando una homogeneidad estructural única. Esta particularidad ofrece una flexibilidad excepcional en los métodos de instalación, permitiendo adaptar la colocación a las necesidades específicas de cada proyecto, ya sea mediante adhesivos especializados, sistemas de fijación mecánica o instalaciones flotantes. El compromiso con la sostenibilidad es un pilar fundamental de Timeledis. Su composición 100% reciclable permite una gestión completamente responsable al final de su ciclo de vida útil, contribuyendo activamente a la economía circular y reduciendo significativamente el impacto ambiental de los proyectos de construcción y renovación. Esta característica ecológica no compromete en absoluto su excepcional durabilidad ni su rendimiento bajo condiciones de uso intensivo, ofreciendo una solución que beneficia tanto al planeta como a los usuarios finales. La textura tipo rizo de esta moqueta crea una superficie compacta, uniforme y extraordinariamente resistente al desgaste. Los bucles entrelazados forman una estructura densa que soporta el tráfico pesado y el uso continuado mientras mantiene su apariencia impecable durante años. Esta construcción robusta también facilita significativamente las tareas de limpieza y mantenimiento, ya que la superficie compacta previene la acumulación profunda de suciedad y permite una higienización eficiente que mantiene los espacios en condiciones óptimas con mínimo esfuerzo y recursos. Disponible en una extraordinaria paleta de más de 70 modelos y colores, la moqueta Timelediss ofrece la mayor versatilidad cromática del mercado. Desde tonos neutros y sobrios perfectos para entornos corporativos tradicionales, pasando por colores intermedios que aportan calidez y profesionalidad, hasta opciones vibrantes y audaces ideales para espacios creativos, educativos o comerciales que buscan impacto visual y diferenciación. Esta amplísima variedad garantiza que cada proyecto, sin importar cuán específicas sean sus necesidades de diseño, encuentre la solución cromática perfecta que se integre armoniosamente con el concepto arquitectónico y la identidad visual del espacio. La presentación en rollos de 200 cm de ancho optimiza significativamente el proceso de instalación, especialmente en espacios amplios donde se busca crear superficies continuas y uniformes con el mínimo número de juntas visibles. Este generoso formato de rollo reduce drásticamente el tiempo de instalación, minimiza los desperdicios de material y proporciona un acabado más limpio, profesional y estéticamente superior, traduciendo directamente en ahorros sustanciales de costes de mano de obra y mayor eficiencia en la ejecución del proyecto. Como producto patentado con el prestigioso sello "BREVETTATO PRODOTTO", la moqueta Timelediss respalda su calidad superior con años de investigación, desarrollo tecnológico e innovación continua. Esta certificación no solo garantiza un producto de rendimiento excepcional, sino que también ofrece la tranquilidad y seguridad de contar con un pavimento textil que ha sido rigurosamente testado y que cumple y supera los más altos estándares de calidad de la industria europea de revestimientos profesionales.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
