INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '2b72b533-85cb-42b2-83b6-08118d5f32f0',
  'Firedis Block and Tagdis',
  'barreras-ignifugas-contra-fuego-firedis-block-tagdis-50',
  'Las barreras ignífugas contra fuego Firedis Block y Tagdis 50 son soluciones técnicas esenciales para la protección contra incendios en espacios donde se combinan soportes combustibles con revestimientos textiles. Estas barreras ignífugas contra fuego actúan interponiéndose estratégicamente entre...',
  'Las barreras ignífugas contra fuego Firedis Block y Tagdis 50 son soluciones técnicas esenciales para la protección contra incendios en espacios donde se combinan soportes combustibles con revestimientos textiles. Estas barreras ignífugas contra fuego actúan interponiéndose estratégicamente entre soportes combustibles como paredes, suelos de madera, paneles o escenarios, y revestimientos textiles como moquetas, telas o cortinas. Los rigurosos tests de laboratorio demuestran que estas barreras impiden eficazmente la propagación de las llamas hacia los tejidos subyacentes y las estructuras portantes. Esta protección resulta crucial durante los primeros minutos de un incendio, proporcionando tiempo valioso para la evacuación segura de las personas y permitiendo la intervención de los servicios de emergencia antes de que el fuego alcance elementos estructurales críticos. Cumplimiento Normativo y Certificación Ambas soluciones cumplen escrupulosamente con la normativa italiana D.M. del 14 de enero de 1985, manteniendo inalterada la clase de reacción al fuego del revestimiento final. Esta característica técnica es fundamental, ya que permite cumplir con todas las condiciones primarias de certificación para su uso e instalación sin comprometer las propiedades ignífugas del sistema completo. Fire Block: Flexibilidad y Adaptabilidad Fire Block se presenta como una barrera textil no tejida fabricada en fibra acrílica preoxidada, ofreciendo una solución elástica y moldeable especialmente adecuada para superficies irregulares o aplicaciones que requieren adaptabilidad. Su textura tipo fieltro facilita la instalación sobre diversos tipos de superficies, proporcionando una capa de protección flexible pero efectiva. Tago 50: Instalación Rápida y Aislamiento Múltiple Por su parte, Tagdis 50 consiste en una lámina de aluminio aislante con sistema adhesivo incorporado, diseñada para ofrecer no solo protección contra el fuego, sino también aislamiento térmico y acústico adicional. Su sistema autoadhesivo simplifica significativamente el proceso de instalación, eliminando la necesidad de adhesivos externos y reduciendo los tiempos de montaje. Aplicaciones y Espacios Recomendados Estas barreras ignífugas encuentran aplicación en teatros, auditorios, hoteles, centros comerciales, edificios públicos y cualquier espacio donde la normativa de protección contra incendios exija medidas de seguridad adicionales. Son especialmente relevantes en la protección de escenarios, telones, cortinas divisorias y revestimientos murales textiles en espacios de concurrencia pública. Criterios de Selección La elección entre Firedis Block y Tagdis 50 dependerá de los requisitos específicos de cada proyecto: mientras Fire Block ofrece máxima flexibilidad y moldeabilidad, Tago 50 proporciona instalación más rápida y prestaciones adicionales de aislamiento térmico y acústico.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '6e5c3de6-1a4f-4ea3-8654-c3d731456717',
  'Moqueta Velvedis',
  'moqueta-velvedis-aterciopelada',
  'Velvedis representa la máxima expresión de lujo y sofisticación en moquetas aterciopeladas de alta gama. Fabricada íntegramente en poliéster al cien por cien, tanto en su tejido vista como en su soporte, esta moqueta ofrece un acabado homogéneo y resistente que garantiza durabilidad excepcional s...',
  'Velvedis representa la máxima expresión de lujo y sofisticación en moquetas aterciopeladas de alta gama. Fabricada íntegramente en poliéster al cien por cien, tanto en su tejido vista como en su soporte, esta moqueta ofrece un acabado homogéneo y resistente que garantiza durabilidad excepcional sin comprometer el confort. Su característica textura aterciopelada tipo velour proporciona una experiencia táctil premium que eleva inmediatamente la percepción de calidad de cualquier espacio. La superficie suave y sedosa al tacto crea ambientes acogedores y distinguidos, perfectos para proyectos que buscan transmitir prestigio y exclusividad. Esta textura no solo aporta valor estético, sino que también contribuye a la absorción acústica del espacio, mejorando el confort general. Con un peso de 650 gramos por metro cuadrado, Velvedis ofrece una densidad superior que se traduce en mayor resistencia al tráfico y al desgaste. Esta construcción robusta garantiza que la moqueta mantenga su aspecto impecable durante años, incluso en espacios de uso frecuente, haciendo de ella una inversión inteligente para proyectos de alto nivel. La seguridad contra incendios es una prioridad fundamental en Velvedis. El producto cuenta con certificación NO FLAME como Fire Resistant y cumple con la normativa británica BS EN ISO 9239-1, disponible bajo solicitud para aquellos proyectos que requieran documentación específica de cumplimiento normativo. Esta certificación garantiza que la moqueta cumple con los estándares más exigentes de protección contra incendios en el ámbito internacional. Una característica distintiva de Velvedis es su disponibilidad en colores especiales personalizados. A diferencia de las moquetas estándar con paletas cromáticas limitadas, Velvedis permite la producción de colores específicos bajo solicitud del cliente. Esta capacidad de personalización resulta especialmente valiosa para proyectos corporativos que necesitan integrar colores de marca, hoteles boutique que buscan identidad visual única, o diseñadores de interiores que requieren tonalidades específicas para sus conceptos creativos. La moqueta se presenta en rollos de 200 centímetros de ancho y 40 metros de longitud, formato que optimiza la instalación en espacios amplios minimizando las juntas visibles. Este ancho generoso resulta ideal para habitaciones de hotel, salas de juntas, despachos ejecutivos y salones residenciales de alto standing. Como producto patentado con el sello BREVETTATO PRODOTTO, Velvedis respalda su calidad con años de investigación y desarrollo. Esta certificación no solo garantiza un producto superior, sino que también ofrece la tranquilidad de contar con una moqueta que ha sido rigurosamente testada y que cumple con los más altos estándares de la industria europea. Velvedis encuentra su aplicación ideal en hoteles boutique de cinco estrellas, despachos de dirección, salas VIP corporativas, showrooms de lujo, espacios residenciales premium y cualquier ambiente que requiera transmitir distinción y exclusividad. Su combinación de estética refinada, seguridad certificada y posibilidad de personalización cromática la convierten en la elección preferida de arquitectos e interioristas que trabajan en proyectos de alto nivel. Es importante señalar que, como ocurre con todos los productos textiles de alta calidad, los colores pueden variar ligeramente de partida a partida debido al proceso natural de fabricación. Esta característica debe considerarse al planificar proyectos que requieran múltiples suministros en diferentes momentos.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
