INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7a14531e-282b-4f4f-858a-f657399e62ba',
  'Cuero Leathdis C',
  'leathdis-revestimiento-efecto-cuero',
  'LEATHDIS C es un revestimiento textil de alta gama. Reproduce fielmente el aspecto del cuero natural. Ofrece una solución profesional para decoración temporal y permanente. Este material combina elegancia visual con ventajas prácticas. Es la opción perfecta para eventos de lujo. Está fabricado co...',
  'LEATHDIS C es un revestimiento textil de alta gama. Reproduce fielmente el aspecto del cuero natural. Ofrece una solución profesional para decoración temporal y permanente. Este material combina elegancia visual con ventajas prácticas. Es la opción perfecta para eventos de lujo. Está fabricado con algodón, PVC y poliuretano. LEATHDIS C proporciona un acabado sofisticado. Aporta distinción y calidez a cualquier espacio. Su gramaje de 1150 gr/m² garantiza excelente caída. El cuerpo es consistente y duradero. La certificación ignífuga cumple normativas exigentes. Esto asegura máxima seguridad en espacios públicos. LEATHDIS C es ideal para diseñadores y decoradores. También para organizadores de eventos profesionales. Es un material premium de fácil instalación. No requiere herramientas especializadas. Disponible en nueve colores seleccionados. Incluye tonos neutros elegantes. También colores intensos para proyectos atrevidos. Permite crear ambientes personalizados de lujo. Cada color ha sido probado en múltiples aplicaciones. Su estructura textil es de poliéster. Proporciona estabilidad dimensional excepcional. Facilita la manipulación durante la instalación. Funciona perfectamente en superficies verticales. Se adapta a paneles curvos sin problemas. No necesita equipamiento especializado. El acabado reproduce las características del cuero auténtico. Incluye textura suave y brillo natural. Crea un efecto realista sorprendente. Incluso de cerca resulta convincente. Aplicaciones Principales LEATHDIS C destaca en el sector ferial. Transforma stands convencionales en espacios distintivos. Capta la atención del público visitante. Transmite valores de calidad y exclusividad. Las marcas premium lo eligen constantemente. También se usa en espacios comerciales. Perfecto para tiendas de lujo y boutiques. Ideal para showrooms de automóviles. Excelente para escenografías teatrales. Funciona muy bien en fondos fotográficos. Es perfecto para proyectos de interiorismo. Hoteles y restaurantes lo utilizan frecuentemente. Ventajas del Producto El revestimiento efecto cuero para eventos LEATHDIS C ofrece múltiples beneficios. Es más ligero que el cuero natural. Su instalación es significativamente más rápida. El mantenimiento resulta mucho más sencillo. El coste es más competitivo. La flexibilidad permite usos creativos. Se puede instalar sobre diversas superficies. La limpieza es simple y rápida. Resiste el uso intensivo en eventos. Mantiene su aspecto durante todo el montaje. Personalización Puede solicitar colores especiales bajo pedido. Esto amplía enormemente las opciones creativas. Se adapta a identidades corporativas específicas. Cumple requerimientos de diseño particulares. Los tiempos de producción son razonables. Cada rollo mide 130 cm de ancho. La longitud estándar es de 25 metros lineales. Esto facilita el cálculo de necesidades. Optimiza la logística de cualquier proyecto. Reduce desperdicios en la instalación.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
