INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '6c755eb2-19f6-4540-81c4-06747fc4ccae',
  'Moqueta Saxonydis Confort Premium',
  'moqueta-pelo-profundo-confort-saxonydis',
  'La moqueta Saxonydis es una moqueta pelo profundo confort diseñada para ofrecer máxima suavidad. Su diseño de pelo profundo crea una superficie excepcionalmente suave. La textura lujosa transforma cualquier habitación en un espacio acogedor. Es la elección perfecta para hogares que valoran la cal...',
  'La moqueta Saxonydis es una moqueta pelo profundo confort diseñada para ofrecer máxima suavidad. Su diseño de pelo profundo crea una superficie excepcionalmente suave. La textura lujosa transforma cualquier habitación en un espacio acogedor. Es la elección perfecta para hogares que valoran la calidad. El confort bajo los pies es incomparable. Fabricada mediante tecnología tufted cut pile de última generación. Este proceso garantiza uniformidad perfecta en toda la superficie. Cada fibra está cortada a la altura exacta. El resultado es una apariencia elegante y sofisticada. La densidad del pelo aporta cuerpo y consistencia. El material es 100% polipropileno extra suave. Esta fibra sintética ofrece múltiples ventajas prácticas. Es naturalmente resistente a las manchas. Repele la suciedad de forma efectiva. El mantenimiento resulta extraordinariamente sencillo. Incluso puede limpiarse con lejía diluida. Características Destacadas El gramaje de 3.200 g/m² es excepcionalmente alto. Este peso garantiza durabilidad superior a largo plazo. La moqueta mantiene su aspecto original durante años. No se aplasta fácilmente con el uso diario. Recupera su forma tras el tránsito. El respaldo Comfy back es tecnología avanzada. Proporciona estabilidad dimensional excepcional. Facilita enormemente el proceso de instalación. Ofrece aislamiento térmico con rating TOG 2.0. Este valor reduce la pérdida de calor significativamente. Los costes de calefacción disminuyen. Disponible en anchos de 4 y 5 metros. Esta versatilidad permite cubrir habitaciones amplias. Se reducen las uniones visibles en el pavimento. La instalación es más rápida y eficiente. El resultado final es más estético. Versatilidad de Uso Clasificada para uso doméstico intensivo (Heavy Domestic Use). Soporta perfectamente el tránsito de familias numerosas. Es ideal para dormitorios principales y de invitados. Los salones ganan en elegancia y confort. Las salas de estar se vuelven más acogedoras. Apta para instalación en escaleras. La densidad del pelo proporciona agarre seguro. Reduce el riesgo de resbalones accidentalmente. Es perfectamente compatible con calefacción por suelo radiante. Esta característica amplía sus posibilidades de instalación. Garantías y Tranquilidad Cuenta con garantía de desgaste de 12 años. Esta cobertura demuestra la confianza del fabricante. Incluye garantía antimanchas para mayor tranquilidad. Las manchas accidentales no son un problema. El producto se puede limpiar sin preocupaciones. La clasificación al fuego Efl-s1 garantiza seguridad. Cumple con las normativas europeas más exigentes. Es segura para uso en viviendas. Proporciona tranquilidad a las familias. Precio indicado por metro cuadrado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
