INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'caac2538-1552-41a9-8d9e-122e9924f1f2',
  'Moqueta Resordis',
  'moqueta-resordis',
  'La moqueta Resordis está fabricada 100% en poliamida de alta calidad. Este material ofrece resistencia excepcional al desgaste. Es ideal para espacios con alto tránsito de personas. La durabilidad es su característica más destacada. Mantiene su aspecto original durante años. Construcción y Acabad...',
  'La moqueta Resordis está fabricada 100% en poliamida de alta calidad. Este material ofrece resistencia excepcional al desgaste. Es ideal para espacios con alto tránsito de personas. La durabilidad es su característica más destacada. Mantiene su aspecto original durante años. Construcción y Acabado La construcción cut pile proporciona un acabado uniforme. La superficie es suave y agradable al tacto. El aspecto profesional realza cualquier ambiente. La textura cortada crea una apariencia elegante. Es perfecta para entornos comerciales y residenciales exigentes. El respaldo de yute sintético aporta estabilidad superior. Este sistema action backing facilita la instalación. Garantiza que la moqueta permanezca en su lugar. No se desplaza ni se arruga con el uso. La base es resistente y duradera. Especificaciones de Peso y Altura El peso de fibra es de 1.200 g/m². Esta densidad garantiza cuerpo y consistencia. El peso total alcanza los 2.200 g/m². Estos valores aseguran alta calidad del producto. La moqueta no es endeble ni frágil. La altura de pelo es de 6,2 mm. Proporciona confort sin ser excesivamente alta. La altura total incluyendo el respaldo es 8,5 mm. Estas medidas son ideales para uso intensivo. Facilitan la limpieza y el mantenimiento. Seguridad y Normativas La clasificación ignífuga es Bfl-s1. Cumple con las normativas europeas de seguridad. Es adecuada para espacios públicos y comerciales. Hoteles, oficinas y comercios pueden instalarla con tranquilidad. La seguridad ante el fuego está garantizada. Versatilidad de Instalación Disponible en anchos de 200 o 400 cm. Los rollos tienen aproximadamente 25 metros lineales. Esta versatilidad facilita la instalación en espacios diversos. Se puede instalar con o sin cinta de unión. La opción sin overlocking agiliza el montaje. Gama de Colores Resordis está disponible en más de 16 colores diferentes. Esta amplia paleta permite personalizar cualquier proyecto. Desde tonos neutros hasta colores vibrantes. Se adapta a cualquier diseño de interiores. La elección cromática es extraordinariamente amplia. Aplicaciones Recomendadas Es perfecta para hoteles y espacios de hospitalidad. Oficinas corporativas la eligen por su resistencia. Comercios de alto tránsito se benefician de su durabilidad. Espacios residenciales premium aprecian su calidad. Salas de conferencias lucen más profesionales con ella.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
