INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '23734593-fc15-4cb8-828f-51e68b59f4b5',
  'Moqueta Blodis Back',
  'moqueta-sostenible-reciclada-econyl',
  'La moqueta Blodis Back es una moqueta ECONYL reciclada sostenible de nueva generación. Representa la evolución de los pavimentos ecológicos. Está fabricada en 100% poliamida 6 ECONYL reciclada. Este material proviene de redes de pesca y residuos plásticos recuperados. Se transforma en fibra texti...',
  'La moqueta Blodis Back es una moqueta ECONYL reciclada sostenible de nueva generación. Representa la evolución de los pavimentos ecológicos. Está fabricada en 100% poliamida 6 ECONYL reciclada. Este material proviene de redes de pesca y residuos plásticos recuperados. Se transforma en fibra textil de alta calidad. El resultado es un producto completamente reciclable. Contribuye activamente a la economía circular. Sostenibilidad y Certificaciones El compromiso ambiental de Blodis Back está certificado. Cuenta con el sello R2R (Regenerated to Regenerated). Este certificado garantiza que el producto es reciclable. Al finalizar su vida útil, puede regenerarse nuevamente. La calificación A+ en emisiones de sustancias volátiles es excepcional. Garantiza aire interior saludable y libre de contaminantes. Es perfecta para espacios sensibles como escuelas y hospitales. Construcción y Acabado La construcción tufted cut pile 1/10" ofrece acabado velluto. La superficie es uniforme y elegante. El tacto es suave y agradable. La densidad de 181.700 puntos por metro cuadrado es excepcional. Esta alta densidad garantiza durabilidad superior. El acabado se mantiene impecable durante años. El respaldo needlefelt aporta estabilidad dimensional. Está fabricado en poliamida con peso de 350 g/m². Garantiza que la moqueta permanezca perfectamente plana. No se desplaza ni se arruga con el uso. La instalación es segura y duradera. Características Técnicas Destacadas El peso de fibra alcanza los 1.100 g/m². Este gramaje proporciona cuerpo y consistencia. El peso total es de 2.150 g/m². Estas cifras aseguran calidad profesional. La moqueta no es endeble ni frágil. La altura de pelo de 6 mm ofrece confort óptimo. No es excesivamente alta ni demasiado baja. Proporciona pisada agradable sin dificultar el tránsito. La altura total incluyendo respaldo es de 10 mm. Estas dimensiones son ideales para uso mixto. Aislamiento Acústico Superior Blodis Back ofrece excelente aislamiento acústico. El valor ΔLw es de 34 dB. Reduce significativamente el ruido de impacto. Los pasos se escuchan mucho menos. La absorción acústica αw es de 0,30. Mejora la calidad sonora del ambiente. Los espacios son más tranquilos y confortables. Resistencia y Durabilidad La clasificación de uso muestra versatilidad. Tres estrellas para uso comercial moderado. Tres estrellas para uso doméstico intensivo. Cuatro estrellas en confort bajo los pies. Es perfecta para oficinas, hoteles y viviendas. La resistencia a la luz es superior a 5. Los colores no se decoloran con exposición solar. Mantienen su intensidad original durante años. La tecnología antimanchas STAINADVERSE protege la fibra. Las manchas se eliminan fácilmente. El mantenimiento es extraordinariamente sencillo. Aplicaciones Recomendadas Blodis Back es ideal para proyectos sostenibles. Hoteles con certificación ambiental la eligen. Oficinas comprometidas con la sostenibilidad la instalan. Espacios educativos valoran su calidad de aire A+. Viviendas ecológicas aprecian su reciclabilidad. El ancho de rollo de 400 cm facilita instalaciones amplias. Reduce el número de uniones visibles. La instalación es más rápida y eficiente. El resultado final es más estético. Precio indicado por metro cuadrado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
