INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e94fe857-3c5a-4605-8bdd-0145dbdb5425',
  'Césped Monkdis Green 25MM',
  'cesped-artificial-monkdis-green',
  'El césped artificial Monkdis Green representa la elección perfecta para quienes buscan un equilibrio ideal entre estética natural y durabilidad excepcional. Este césped artificial de 25mm está fabricado con tecnología holandesa de última generación, garantizando un producto de máxima calidad que ...',
  'El césped artificial Monkdis Green representa la elección perfecta para quienes buscan un equilibrio ideal entre estética natural y durabilidad excepcional. Este césped artificial de 25mm está fabricado con tecnología holandesa de última generación, garantizando un producto de máxima calidad que transforma cualquier espacio. Tecnología y Calidad Superior El césped artificial Monkdis Green incorpora un hilo fuerte con tecnología de máxima recuperación que asegura que cada fibra vuelva a su posición original después de cada pisada. Esta característica hace que tu césped artificial mantenga su aspecto impecable durante años, sin importar el tráfico que reciba. Una de las innovaciones más destacadas del césped artificial Monkdis Green es su propiedad antiestática, que elimina por completo las molestas descargas eléctricas. Esto lo convierte en una opción segura y cómoda para toda la familia, especialmente en áreas de juego infantil. Versatilidad en Aplicaciones El césped artificial Monkdis Green es perfecto tanto para instalaciones interiores como exteriores. Su alta densidad de fibras crea un aspecto tupido y realista que imita la belleza del césped natural sin el mantenimiento constante. Además, cuenta con protección UV que previene la decoloración solar, manteniendo su color vibrante bajo cualquier condición climática. Amplia Gama de Colores Disponible en verde natural y opciones decorativas como naranja, azul, amarillo, morado, rosa y blanco, el césped artificial Monkdis Green permite crear espacios personalizados únicos que reflejan tu estilo personal. Aplicaciones Ideales El césped artificial Monkdis Green es ideal para jardines residenciales donde puedes transformar tu espacio en un área verde permanente. También es perfecto para terrazas y balcones, creando un oasis urbano con mínimo mantenimiento. En áreas de juego infantil proporciona una superficie segura y suave para los más pequeños, mientras que en zonas de piscina ofrece una superficie antideslizante que drena perfectamente. Los espacios comerciales se benefician de su acabado profesional que resiste alto tráfico. El sistema de drenaje integrado del césped artificial Monkdis Green garantiza que el agua fluya eficientemente, evitando charcos y manteniendo la superficie seca y lista para usar en todo momento. Con el césped artificial Monkdis Green, disfrutarás de un espacio verde perfecto los 365 días del año, sin riego, sin corte y con un mantenimiento mínimo que solo requiere un cepillado ocasional. Es la solución inteligente para quienes valoran su tiempo y desean un resultado impecable. Este césped artificial combina innovación con calidad excepcional, asegurando una inversión duradera para tu hogar o negocio.',
  '066160b7-eb53-4b03-835f-73978abab4d7',
  13.73,
  1,
  'm²',
  true,
  true,
  NULL
