INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '323be914-7749-449f-861e-bb65d06777bb',
  'Moquetas Impresas Ignífugas - Diseño Personalizado para Eventos y Producciones',
  'moquetas-impresas-ignifugas',
  'Nuestras moquetas impresas ignífugas con certificación Bfl-S1 son la solución perfecta para quienes buscan combinar seguridad, personalización y calidad profesional. Diseñadas específicamente para eventos, producciones televisivas, ferias y espacios comerciales que requieren cumplir con las norma...',
  'Nuestras moquetas impresas ignífugas con certificación Bfl-S1 son la solución perfecta para quienes buscan combinar seguridad, personalización y calidad profesional. Diseñadas específicamente para eventos, producciones televisivas, ferias y espacios comerciales que requieren cumplir con las normativas más exigentes de seguridad contra incendios. Cada moqueta cuenta con un revestimiento textil de alta calidad sobre el que se realiza la impresión digital, garantizando colores vivos, diseños nítidos y un acabado profesional excepcional. Esta tecnología permite reproducir cualquier diseño, logotipo, patrón o imagen con precisión, creando alfombras totalmente personalizadas que reflejan la identidad de tu marca o evento. Ideales para alfombras rojas, sets de grabación, stands feriales, pasarelas de moda, eventos corporativos y cualquier espacio que requiera una solución segura, duradera y visualmente impactante. La certificación ignífuga Bfl-S1 asegura el cumplimiento normativo en espacios públicos y eventos de gran afluencia.',
