INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '742d35e4-3efc-4a03-8c25-00172a72ac4e',
  'Cúter Moqueta',
  'cuter-profesional-moqueta',
  'Cúter profesional de seguridad diseñado específicamente para el corte preciso de moquetas, alfombras y pavimentos textiles. Su construcción robusta en aleación metálica garantiza durabilidad y resistencia en trabajos de instalación intensivos. Este cúter de seguridad permite realizar cortes limpi...',
  'Cúter profesional de seguridad diseñado específicamente para el corte preciso de moquetas, alfombras y pavimentos textiles. Su construcción robusta en aleación metálica garantiza durabilidad y resistencia en trabajos de instalación intensivos. Este cúter de seguridad permite realizar cortes limpios y profesionales sin deshilachar los bordes de la moqueta. El diseño ergonómico del mango proporciona un agarre cómodo y seguro durante su uso prolongado, mientras que el mecanismo de bloqueo de la cuchilla asegura la máxima protección durante el trabajo. Ideal para instaladores profesionales de moquetas, montadores de stands, decoradores y técnicos especializados en pavimentos textiles. Su sistema de cambio rápido de cuchilla facilita el mantenimiento y optimiza los tiempos de trabajo en proyectos de instalación de moqueta modular, moqueta en rollo o alfombras comerciales. Herramienta imprescindible para conseguir acabados impecables en la instalación de cualquier tipo de revestimiento textil para suelos. Perfecto para trabajos en ferias, eventos, oficinas y espacios comerciales que requieren precisión y profesionalidad en cada corte.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
