INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '21831e4a-d9e2-43e8-8514-c7d0f72e9f17',
  'Tubos de Cartón para Moqueta',
  'tubos-carton-sostenible-envio',
  'Los tubos de cartón para moqueta son la solución profesional ideal para fabricantes, distribuidores e instaladores que necesitan enrollar, transportar y almacenar moquetas, alfombras y pavimentos textiles de forma segura y sostenible. Fabricados con cartón industrial resistente de alta calidad y ...',
  'Los tubos de cartón para moqueta son la solución profesional ideal para fabricantes, distribuidores e instaladores que necesitan enrollar, transportar y almacenar moquetas, alfombras y pavimentos textiles de forma segura y sostenible. Fabricados con cartón industrial resistente de alta calidad y materiales 100% reciclables, estos tubos cilíndricos ofrecen la robustez necesaria para soportar el peso completo de rollos de moqueta sin deformarse ni colapsar. Su construcción reforzada garantiza protección total durante el transporte y almacenaje, evitando deformaciones, arrugas o daños en las fibras del tejido. Disponibles en múltiples diámetros y longitudes, nuestros tubos se adaptan perfectamente a cualquier tipo de moqueta: desde losetas modulares enrolladas hasta moquetas comerciales en rollo de gran anchura. Esta versatilidad permite encontrar el formato exacto para cada necesidad específica del sector textil. El diseño cilíndrico mantiene la forma óptima del rollo y facilita el enrollado uniforme y profesional del material. Además, los tubos pueden suministrarse con o sin tapa según los requerimientos de cada proyecto, ofreciendo máxima flexibilidad en su uso. Como solución 100% reciclable y biodegradable, estos tubos demuestran un compromiso real con la sostenibilidad ambiental sin comprometer la calidad ni la funcionalidad. Representan la alternativa más responsable y profesional para las empresas del sector que buscan combinar eficiencia logística con respeto por el medio ambiente. Perfectos para fabricantes de moquetas, distribuidores mayoristas, empresas de instalación profesional, almacenes especializados y cualquier negocio del sector de pavimentos textiles que requiera soluciones de transporte y almacenamiento fiables, duraderas y ecológicas.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
