INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '2ca29811-d625-48af-84b6-b1228c523a5a',
  'Cinta Adhesiva de Doble Cara Amarilla',
  'cinta-adhesiva-doble-cara-moqueta',
  'La cinta adhesiva doble cara es la solución profesional más eficaz para la fijación de moquetas en recintos feriales, stands comerciales y espacios de eventos temporales. Fabricada con soporte de tejido de algodón resistente y adhesivo de caucho de alta adherencia, esta cinta biadhesiva ofrece un...',
  'La cinta adhesiva doble cara es la solución profesional más eficaz para la fijación de moquetas en recintos feriales, stands comerciales y espacios de eventos temporales. Fabricada con soporte de tejido de algodón resistente y adhesivo de caucho de alta adherencia, esta cinta biadhesiva ofrece un tack inicial excepcional que garantiza una fijación inmediata y segura. Además, su excelente adaptabilidad permite su aplicación sobre todo tipo de superficies, convirtiéndola en la opción preferida por instaladores profesionales y montadores de stands. Características de la Cinta Adhesiva para Moqueta Esta cinta adhesiva doble cara destaca por su practicidad y facilidad de uso. Asimismo, puede cortarse manualmente sin necesidad de herramientas especiales, lo que agiliza considerablemente el proceso de instalación en proyectos con plazos ajustados. Por tanto, resulta ideal para el montaje rápido de stands feriales donde el tiempo es un factor crítico. En consecuencia, los profesionales del sector ferial la eligen como su primera opción para la fijación temporal de moquetas. El adhesivo de caucho proporciona una adherencia potente en ambas caras, garantizando que la moqueta permanezca firmemente fijada durante todo el evento. Posteriormente, cuando finaliza la feria o congreso, la cinta permite un despegado limpio en la mayoría de superficies, facilitando el desmontaje y la recuperación de los materiales. No obstante, no se recomienda su aplicación sobre parqué, ya que puede dejar residuos. Aplicaciones Versátiles Más allá de su uso principal en recintos feriales y stands comerciales, esta cinta adhesiva es perfecta para uso general en montaje y decoración, confección de muestrarios textiles y aplicaciones específicas de flexografía. Su protector de papel siliconado marrón facilita la manipulación y conservación del producto. Medidas: 50m x 45mm 50ml x 30mm 50m x 17mm Para pedidos, consultas técnicas o asesoramiento sobre la aplicación adecuada, contacta con nuestro equipo en moquetas@disstands.com o llama al 934 850 085.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
