INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f23a4999-455e-4194-8b05-9849e357b013',
  'Cinta Unión',
  'cinta-union-cesped-artificial',
  'La cinta de unión para césped artificial es la solución profesional esencial para conseguir instalaciones perfectas e invisibles en proyectos de césped sintético. Fabricada con polipropileno de alta resistencia y adhesivo de rendimiento superior, esta cinta garantiza uniones duraderas, seguras y ...',
  'La cinta de unión para césped artificial es la solución profesional esencial para conseguir instalaciones perfectas e invisibles en proyectos de césped sintético. Fabricada con polipropileno de alta resistencia y adhesivo de rendimiento superior, esta cinta garantiza uniones duraderas, seguras y completamente imperceptibles entre rollos de césped artificial. Características de la Cinta de Unión para Césped Con un ancho óptimo de 15 cm, esta cinta adhesiva para césped proporciona la superficie de contacto ideal para asegurar uniones firmes y estables. Además, su composición en polipropileno garantiza resistencia excepcional al desgarro, tracción y deformaciones. Por tanto, resulta perfecta para instalaciones que deben soportar tráfico intensivo, condiciones climáticas adversas y uso continuado durante años. El adhesivo especialmente formulado ofrece adherencia inmediata y permanente. Asimismo, resiste perfectamente la radiación UV, humedad, cambios de temperatura y todos los factores ambientales que pueden comprometer instalaciones de césped artificial. En consecuencia, las uniones se mantienen intactas sin necesidad de mantenimiento adicional ni revisiones periódicas. Formatos Disponibles Disponible en dos formatos profesionales que se adaptan a diferentes necesidades de proyecto. Posteriormente, puedes elegir entre rollo de 5 metros (380 g) en cajas de 40 unidades, o rollo de 10 metros (750 g) en cajas de 32 unidades. Así, optimizas tu inversión según el volumen de trabajo. Aplicaciones Profesionales Esta cinta para unión de césped artificial es ideal para instaladores profesionales que trabajan en jardines residenciales, terrazas, campos deportivos, áreas recreativas, espacios comerciales y proyectos paisajísticos de cualquier envergadura. Su aplicación profesional requiere cola específica para césped artificial que garantiza el sellado perfecto de las juntas. La combinación de polipropileno resistente y adhesivo permanente convierte esta cinta en la elección preferida de instaladores profesionales que buscan resultados impecables, durabilidad garantizada y acabados invisibles en cada proyecto de césped sintético. Su formato en rollo optimiza notablemente el trabajo profesional.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
