INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '89be9ccc-629a-4e22-886f-cd0fabb9b471',
  'Cinta Carrocero',
  'cinta-enmascarar-profesional',
  'La cinta de enmascarar profesional es la herramienta esencial para cualquier trabajo de pintura y decoración que requiera precisión y acabados impecables. Fabricada con soporte de papel crepado flexible y adhesivo de caucho natural en base disolvente, esta cinta de carrocero ofrece la combinación...',
  'La cinta de enmascarar profesional es la herramienta esencial para cualquier trabajo de pintura y decoración que requiera precisión y acabados impecables. Fabricada con soporte de papel crepado flexible y adhesivo de caucho natural en base disolvente, esta cinta de carrocero ofrece la combinación perfecta entre adherencia firme y retirada limpia sin residuos. Además, su diseño profesional la convierte en la elección preferida de pintores, decoradores y profesionales de la construcción. Características de la Cinta de Enmascarar Esta cinta adhesiva de papel crepado destaca por su excepcional resistencia térmica de hasta 60ºC durante una hora. Por tanto, mantiene su integridad y adherencia incluso durante procesos de secado acelerado con calor o aplicaciones en exteriores bajo radiación solar directa. Asimismo, su fácil desbobinado agiliza significativamente el trabajo profesional, permitiendo aplicaciones rápidas y precisas sin frustraciones. El soporte de papel crepado proporciona la flexibilidad necesaria para adaptarse perfectamente a superficies irregulares, esquinas complejas y contornos difíciles. En consecuencia, conseguirás líneas de enmascarado perfectas incluso en las geometrías más complicadas. Posteriormente, cuando finalices el trabajo de pintura, la cinta se retira limpiamente sin romperse con frecuencia, ahorrando tiempo valioso en el acabado final. Ventajas Profesionales Una característica especialmente práctica es su superficie escribible que permite anotar referencias, números de color o indicaciones directamente sobre la cinta de enmascarar. Además, esta funcionalidad facilita enormemente la organización en proyectos complejos con múltiples zonas de trabajo o diferentes colores. Aplicaciones Versátiles Perfecta para enmascarado de precisión en trabajos de pintura interior y exterior, protección de marcos de puertas y ventanas, delimitación de áreas en proyectos de decoración, trabajos de lacado y barnizado, y cualquier aplicación donde se requiera protección temporal durante procesos de acabado. Su compatibilidad con todo tipo de pinturas, esmaltes y revestimientos la convierte en la herramienta universal del profesional. Medida: 45ml x 30mm',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
