INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '260e01d9-a6fd-416a-855c-3a6c736f0294',
  'Cinta Americana',
  'cinta-americana-multiuso',
  'La cinta americana es la solución universal más versátil y resistente para todo tipo de proyectos, reparaciones y aplicaciones tanto en interior como en exterior. Desde arreglos temporales domésticos hasta aplicaciones profesionales de mantenimiento y construcción, esta cinta multiuso hace que cu...',
  'La cinta americana es la solución universal más versátil y resistente para todo tipo de proyectos, reparaciones y aplicaciones tanto en interior como en exterior. Desde arreglos temporales domésticos hasta aplicaciones profesionales de mantenimiento y construcción, esta cinta multiuso hace que cualquier trabajo sea rápido, efectivo y duradero. Construcción Robusta y Resistente Fabricada con un soporte ultragrueso de gasa de tejido tupido resistente al agua, esta cinta americana profesional ofrece una resistencia excepcional al desgaste y la abrasión. Además, su construcción reforzada proporciona una elevada resistencia a la tracción, haciéndola ideal para aplicaciones de agrupamiento, empaquetado y sujeción de objetos pesados. Por tanto, soporta condiciones exigentes sin romperse ni deteriorarse. El resistente adhesivo de caucho natural se adhiere instantáneamente a una gran variedad de superficies. Asimismo, funciona perfectamente sobre metal, vidrio, plástico, madera, hormigón sellado y muchos otros materiales, proporcionando una fijación firme y segura. En consecuencia, resulta ideal para múltiples situaciones y necesidades. Versatilidad y Facilidad de Uso Una de las mayores ventajas de esta cinta de reparación universal es que se puede rasgar fácilmente con la mano, sin necesidad de tijeras ni dispensadores. Posteriormente, se fija firmemente y se despega del rollo sin complicaciones, agilizando cualquier trabajo de reparación o instalación. Resistencia a la Intemperie Algunas versiones incorporan resistencia específica a la intemperie para soportar los efectos nocivos de la luz solar directa, humedad constante y cambios de temperatura. Además, esta característica garantiza un rendimiento fiable en aplicaciones exteriores como reparaciones de tuberías, sellado temporal, sujeción de lonas y protección de elementos expuestos. Aplicaciones Infinitas Perfecta para fontaneros, electricistas, instaladores, profesionales del mantenimiento, talleres, industria y usuarios domésticos. Desde reparaciones rápidas hasta proyectos de bricolaje más elaborados, la cinta americana es la herramienta indispensable que no puede faltar en ninguna caja de herramientas. Su versatilidad y resistencia la convierten en la solución preferida por profesionales.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
