INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'bf62ae35-25a3-4bd5-880e-49ce5d13760e',
  'Piquetas Césped',
  'piquetas-fijacion-cesped-artificial',
  'Piquetas de Fijación para Césped Artificial Las piquetas de fijación son accesorios esenciales para cualquier instalación profesional de césped artificial. Fabricadas en metal galvanizado de alta resistencia con forma de U, proporcionan la sujeción óptima del césped sintético. Además, evitan desp...',
  'Piquetas de Fijación para Césped Artificial Las piquetas de fijación son accesorios esenciales para cualquier instalación profesional de césped artificial. Fabricadas en metal galvanizado de alta resistencia con forma de U, proporcionan la sujeción óptima del césped sintético. Además, evitan desplazamientos, levantamientos o deformaciones causados por el viento, el tránsito intensivo o las condiciones climáticas adversas. Dimensiones y Construcción Resistente Estas piquetas tienen dimensiones específicas de 17 cm de longitud, 3,5 cm de ancho y 3 mm de grosor de varilla. Por tanto, ofrecen el equilibrio perfecto entre resistencia estructural y facilidad de instalación manual. Además, su construcción en metal galvanizado garantiza protección completa contra la corrosión y oxidación. Asimismo, resisten el deterioro causado por la humedad y las condiciones de intemperie durante años de exposición exterior. Instalación Sencilla y Rápida La aplicación es extraordinariamente sencilla e intuitiva. Primero, coloca el césped artificial sobre la superficie previamente preparada y nivelada. Posteriormente, distribuye las piquetas estratégicamente en todo el perímetro exterior. También debes colocarlas a lo largo de las uniones entre diferentes rollos de césped. Luego, clávalas fácilmente en el suelo mediante golpes firmes con martillo convencional. Finalmente, quedan completamente enterradas y niveladas con la base del césped. En consecuencia, resultan invisibles una vez finalizada la instalación. Diseño Inteligente y Distribución Uniforme El diseño en forma de grapa U asegura una distribución uniforme de la presión mecánica sobre el material sintético. Por tanto, evita eficazmente daños en las fibras delicadas del césped. Además, mantiene el césped firmemente anclado al terreno durante toda su vida útil sin moverse. Aplicaciones Versátiles Son ideales para jardines residenciales privados, terrazas urbanas, instalaciones deportivas municipales y zonas infantiles de juegos. Asimismo, funcionan perfectamente en áreas recreativas y proyectos paisajísticos comerciales. Finalmente, garantizan máxima estabilidad permanente y acabados profesionales impecables que perduran décadas sin mantenimiento adicional necesario.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
