INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '0d121a36-cbf6-4aae-8f6e-03bd9d2f1bab',
  'Moqueta Purpurina',
  'moqueta-purpurina',
  'La moqueta Purpurina está diseñada para captar todas las miradas. Su acabado brillante con efecto glitter la convierte en la opción perfecta para destacar en eventos únicos, decoraciones especiales, producciones escénicas y espacios donde la estética visual impactante es clave. Además de su apari...',
  'La moqueta Purpurina está diseñada para captar todas las miradas. Su acabado brillante con efecto glitter la convierte en la opción perfecta para destacar en eventos únicos, decoraciones especiales, producciones escénicas y espacios donde la estética visual impactante es clave. Además de su apariencia sofisticada, ofrece una base resistente y retardante al fuego, garantizando seguridad sin renunciar al estilo. Características Técnicas y Diseño Espectacular Esta moqueta con glitter incorpora partículas brillantes integradas en su superficie que crean efectos luminosos únicos bajo diferentes ángulos de luz. Disponible en una amplia gama de colores desde el elegante negro galaxia con purpurina plateada hasta vibrantes tonos como rojo coral, azul eléctrico o dorado oro, cada opción está diseñada para crear atmósferas memorables. El efecto glitter no es superficial, sino que está perfectamente integrado en la fibra, garantizando durabilidad y evitando desprendimientos durante el uso. Aplicaciones Versátiles y Creativas Ideal para ferias, pasarelas y presentaciones que buscan dejar huella, la moqueta Purpurina transforma cualquier espacio en un escenario espectacular. Perfecta para photocalls brillantes, alfombras rojas glamurosas, stands feriales que buscan diferenciación, zonas VIP en discotecas y eventos nocturnos, escenografías teatrales y televisivas, y eventos temáticos como galas, premiaciones y celebraciones especiales. Su capacidad para reflejar y jugar con la luz la convierte en la aliada perfecta de fotógrafos y videógrafos profesionales. Seguridad Certificada A pesar de su acabado lujoso, la seguridad no se compromete. Su tratamiento ignífugo certificado cumple con las normativas europeas para espacios públicos, permitiendo su uso en cualquier tipo de evento sin restricciones. Información de Compra Precio: 10,83 €/m² Cálculo ejemplo: 1 metro lineal x 2 metros de ancho = 2 m² × 10,83 €/m² = 21,66 € Los cortes personalizados no admiten devoluciones, garantizando precios ajustados. Para medidas específicas, contacta con ventas@disstands.com.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  12.95,
  1,
  'm²',
  true,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
