INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '4edcbd50-69a8-4c0b-8833-b6cf2b924822',
  'Loseta Crossdis',
  'moqueta-bucle-crossdis',
  'Loseta Crossdis: rendimiento profesional para espacios comerciales exigentes La loseta Crossdis es un pavimento textil de alto rendimiento diseñado específicamente para entornos comerciales que requieren máxima durabilidad y propiedades técnicas superiores. Esta loseta Crossdis combina construcci...',
  'Loseta Crossdis: rendimiento profesional para espacios comerciales exigentes La loseta Crossdis es un pavimento textil de alto rendimiento diseñado específicamente para entornos comerciales que requieren máxima durabilidad y propiedades técnicas superiores. Esta loseta Crossdis combina construcción de bucle estructurado en poliamida 6 con tecnologías avanzadas para ofrecer resistencia excepcional, confort acústico y seguridad antiestática en un único producto profesional. Homologación para uso comercial intensivo Certificada según EN 1307 para uso comercial general intensivo, este pavimento es la solución perfecta para oficinas corporativas, hoteles, centros educativos, espacios comerciales, salas de reuniones y áreas de recepción que soportan tráfico diario elevado. Por consiguiente, garantiza un rendimiento óptimo durante años sin perder sus propiedades. Descubre más opciones en nuestra gama de moquetas comerciales. Construcción de bucle estructurado duradera Fabricada mediante tecnología de tufting 1/10", la loseta Crossdis presenta una construcción de bucle estructurado en 100% poliamida 6 teñida en masa. Esta técnica de teñido garantiza colores permanentes que no se decoloran con el paso del tiempo ni la exposición solar. Asimismo, alcanza una densidad de 191.000 puntos por metro cuadrado, asegurando resistencia excepcional al desgaste incluso en zonas de alto tráfico. Propiedades antiestáticas permanentes Este pavimento textil incorpora propiedades antiestáticas permanentes con valores ≤ 2,0 kV según ISO 6356. De esta manera, protege equipos electrónicos sensibles y evita descargas eléctricas molestas en entornos de trabajo. Además, cuenta con clasificación de resistencia al fuego Bfl-S1 cuando se instala adherida, cumpliendo con EN 13501-1 para máxima seguridad contra incendios. Excelente comportamiento acústico de la moqueta Crossdis Con una absorción acústica αw de 0,20 y reducción del ruido de impacto de 25 dB según ISO 10140, la loseta Crossdis crea ambientes más silenciosos y productivos. Por otro lado, su reducción de 44 dB a 1000 Hz la convierte en una barrera acústica efectiva para espacios abiertos tipo open space donde el control del ruido es prioritario. Consulta nuestras soluciones acústicas comerciales. Resistencia intensiva para mobiliario con ruedas Clasificada como uso intensivo según EN 985, este pavimento soporta perfectamente el uso diario con sillas de ruedas de oficina sin deformarse ni desgastarse prematuramente. También es apta para instalación en escaleras con clasificación de uso intensivo según EN 1963, ofreciendo versatilidad total en proyectos comerciales completos de múltiples plantas. Formato profesional de 400 cm Disponible en rollos de 400 cm de ancho, la loseta Crossdis permite cubrir grandes superficies con mínimas juntas visibles. Su patrón repetitivo de 206 x 172 cm facilita la continuidad visual perfecta en instalaciones extensas. Además, es compatible con sistemas de calefacción radiante y alcanza una resistencia térmica de 0,086 m²K/W. Conoce más sobre instalación profesional de moquetas. Aplicaciones comerciales ideales La loseta Crossdis es perfecta para oficinas corporativas, despachos profesionales, hoteles y establecimientos hoteleros, centros educativos universitarios, salas de conferencias, espacios de coworking, showrooms comerciales, áreas de recepción y cualquier entorno comercial que requiera un pavimento técnico certificado con estética profesional y durabilidad garantizada. Características técnicas principales Construcción: Bucle estructurado tufted 1/10" Material: 100% Poliamida 6 teñida en masa Peso total: 1.950 g/m² Altura total: 6,5 mm Densidad: 191.000 puntos/m² Ancho: 400 cm Resistencia al fuego: Bfl-S1 adherida (EN 13501-1) Antiestático: ≤ 2,0 kV permanente Absorción acústica: αw 0,20 Solidez a la luz: Nivel 8 Elige la loseta Crossdis para combinar rendimiento técnico certificado, durabilidad excepcional y estética profesional en tus proyectos comerciales más exigentes.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
