INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '4255d693-9f53-49bf-8525-a680a3522084',
  'Loseta Ingrodis',
  'loseta-ingrodis-minituft',
  'Loseta Ingrodis: tecnología de captura de suciedad para zonas de alto tráfico La loseta Ingrodis minituft es una solución innovadora diseñada específicamente para atrapar y bloquear la suciedad en zonas de entrada y alto tráfico. Esta loseta Ingrodis minituft incorpora un sistema único de captura...',
  'Loseta Ingrodis: tecnología de captura de suciedad para zonas de alto tráfico La loseta Ingrodis minituft es una solución innovadora diseñada específicamente para atrapar y bloquear la suciedad en zonas de entrada y alto tráfico. Esta loseta Ingrodis minituft incorpora un sistema único de captura que evita que las partículas se esparzan por el entorno, manteniendo los espacios interiores notablemente más limpios y reduciendo las tareas de mantenimiento diario. Construcción minituft con fibra especialmente gruesa La loseta Ingrodis está fabricada mediante construcción minituft con una fibra especialmente gruesa que proporciona densidad superior y resistencia excepcional. Esta técnica de fabricación crea una superficie densa y compacta capaz de soportar el tráfico intensivo diario sin deformarse ni perder sus propiedades. Asimismo, la fibra gruesa garantiza mayor durabilidad en condiciones de uso comercial exigente. Estructura de rejilla única para captura de suciedad La característica diferenciadora de esta loseta Ingrodis es su estructura de rejilla diseñada científicamente para capturar y retener la suciedad en su interior. Este sistema actúa como una trampa eficaz que atrapa partículas, polvo y suciedad antes de que puedan dispersarse por áreas adyacentes. Por consiguiente, mejora significativamente la calidad del aire interior y reduce la propagación de contaminantes. Ideal para vestíbulos y pasillos de alto tráfico La loseta Ingrodis se convierte en la solución perfecta para vestíbulos de entrada, pasillos comerciales, recepciones de hoteles, accesos a edificios de oficinas y zonas de transición donde el control de la suciedad es crítico. De esta manera, protege las áreas interiores principales al capturar la suciedad en la primera línea de defensa. Formato modular para instalación flexible El formato en loseta modular facilita enormemente la instalación rápida y eficiente sin necesidad de herramientas especializadas. Además, permite reemplazos puntuales de piezas individuales en caso de desgaste localizado, optimizando costes de mantenimiento a largo plazo. Por otro lado, ofrece versatilidad creativa para diseñar patrones personalizados que se adapten a la identidad visual de cada proyecto. Reducción significativa del mantenimiento Al retener la suciedad en su estructura de rejilla, la loseta Ingrodis reduce drásticamente la necesidad de limpieza frecuente en espacios adyacentes. Esto se traduce en ahorro de tiempo, costes de limpieza profesional y productos químicos. Asimismo, mejora la imagen corporativa al mantener las instalaciones visiblemente más limpias durante más tiempo entre limpiezas. Aplicaciones comerciales ideales Esta loseta modular es perfecta para edificios corporativos, centros comerciales, hoteles, hospitales, centros educativos, aeropuertos, estaciones de transporte y cualquier instalación comercial donde se requiera controlar eficazmente la entrada de suciedad desde el exterior hacia los espacios interiores principales. Características principales Construcción: Minituft de alta densidad Fibra: Especialmente gruesa para máxima resistencia Estructura: Rejilla de captura de suciedad Formato: Loseta modular Aplicación: Zonas de alto tráfico Zonas ideales: Vestíbulos, pasillos, entradas Beneficio principal: Atrapa y bloquea suciedad Mantenimiento: Reducido significativamente Instalación: Rápida y flexible Durabilidad: Resistencia al tráfico intensivo Elige la loseta moqueta Ingrodis para proteger tus espacios interiores con la tecnología más avanzada de captura de suciedad del mercado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
