INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'bcedf367-247c-4522-8c8c-4df2bcdf29c5',
  'Césped Bredis 30MM - Oferta',
  'cesped-bredis-30mm-oferta',
  'Césped artificial Bredis 30 mm: naturalidad y durabilidad para tu jardín El césped artificial Bredis 30 mm es una solución decorativa de alta calidad. Está diseñado específicamente para transformar tus espacios exteriores en áreas verdes impecables durante todo el año. Este césped artificial Bred...',
  'Césped artificial Bredis 30 mm: naturalidad y durabilidad para tu jardín El césped artificial Bredis 30 mm es una solución decorativa de alta calidad. Está diseñado específicamente para transformar tus espacios exteriores en áreas verdes impecables durante todo el año. Este césped artificial Bredis 30 mm destaca por su aspecto extraordinariamente natural. Imita a la perfección un césped recién cortado. Por ello, se convierte en la elección ideal para jardines residenciales, terrazas, áticos, zonas de piscina y proyectos de paisajismo profesional. Características técnicas superiores Con una altura de fibra de 30 mm, el césped artificial Bredis 30 mm ofrece una textura mullida y confortable. Proporciona gran suavidad al tacto. Además, es perfecta para que niños y mascotas disfruten sin preocupaciones. Su composición combina polietileno y polipropileno de primera calidad. Está completamente libre de plomo y cadmio. De esta manera, garantiza un producto seguro, no tóxico y respetuoso con el medio ambiente y la salud de tu familia. Resistencia y durabilidad excepcional El césped artificial Bredis 30 mm incorpora protección avanzada contra rayos UV. Esta protección previene la decoloración y el deterioro prematuro causado por la exposición solar constante. Asimismo, su resistencia al desgaste asegura que mantenga su aspecto verde y fresco incluso en áreas de tránsito frecuente. Por otro lado, el sistema de drenaje perforado permite la evacuación rápida del agua de lluvia. Evita encharcamientos y garantiza que tu jardín esté seco y listo para usar en cuestión de minutos. Ventajas del césped artificial de 30 mm Este césped artificial Bredis 30 mm elimina por completo el mantenimiento tradicional. Olvídate de cortar, regar, fertilizar o resembrar. Ahorra tiempo, dinero y recursos hídricos mientras disfrutas de un jardín perfecto los 365 días del año. Además, su rendimiento duradero garantiza años de belleza sin esfuerzo. Soporta incluso condiciones climáticas exigentes como altas temperaturas, heladas o lluvias intensas. Aplicaciones versátiles El césped artificial Bredis 30 mm es perfecto para múltiples espacios. Por ejemplo, jardines privados, terrazas urbanas y áreas de recreo infantil. También es ideal para zonas perimetrales de piscinas, espacios comerciales y hoteles. Igualmente, funciona muy bien en restaurantes con terrazas, centros educativos y cualquier proyecto de paisajismo. En definitiva, es la solución perfecta cuando se requiere estética, practicidad y bajo mantenimiento. Especificaciones técnicas Altura de fibra: 30 mm Composición: Polietileno y polipropileno sin plomo ni cadmio Rollo: 30 ml x 2 m de ancho Solicita tu presupuesto personalizado ¿Necesitas medidas personalizadas? Escríbenos a: ventas@disstands.com Transforma tu espacio exterior con césped artificial Bredis 30 mm y disfruta de un jardín perfecto sin esfuerzo.',
