INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'cec6a2b0-cd9b-4d5c-8145-840a7f4ac386',
  'Retales de Moqueta Variada | Diferentes Medidas y Calidades',
  'retales-revestimiento-textil-alta-calidad',
  '¡Aprovecha nuestros retales moqueta de alta calidad al mejor precio! Los retales moqueta de alta calidad de Disstands son la solución perfecta para proyectos profesionales que requieren revestimiento textil económico sin renunciar a la calidad. Ideales para stands feriales, showrooms, reformas co...',
  '¡Aprovecha nuestros retales moqueta de alta calidad al mejor precio! Los retales moqueta de alta calidad de Disstands son la solución perfecta para proyectos profesionales que requieren revestimiento textil económico sin renunciar a la calidad. Ideales para stands feriales, showrooms, reformas comerciales y espacios corporativos temporales. Ofrecemos retales en múltiples variedades: moqueta ferial, eco-friendly, velour premium, Las Vegas, y más opciones especializadas. Con amplia gama de colores y texturas profesionales adaptadas a cualquier proyecto. Precio excepcional: 2,10 € por metro cuadrado – calidad profesional al alcance de tu presupuesto. Características principales de nuestros retales Múltiples medidas disponibles para optimizar tu proyecto Diferentes calidades y grosores según aplicación Amplia variedad de colores y texturas profesionales Tipos especializados: ferial, eco, velour, Las Vegas Precio competitivo: 2,10 €/m² Excelente relación calidad-precio garantizada Aplicaciones ideales para retales moqueta de alta calidad Perfectos para: Stands en ferias y eventos profesionales Showrooms y espacios de exposición comercial Oficinas temporales y áreas de coworking Reformas parciales en comercios y boutiques Proyectos de interiorismo con presupuesto ajustado Áreas de presentación y zonas VIP en eventos Ofrecen acabado profesional incluso en proyectos con limitaciones presupuestarias. Ventajas de nuestros retales de moqueta Solución sostenible y económica: aprovechamos material de primera calidad que de otro modo se desperdiciaría, contribuyendo a la economía circular. Cada retal mantiene los estándares de nuestros rollos completos. Flexibilidad de proyecto: pagas solo por lo que necesitas, perfecto para espacios irregulares o proyectos específicos donde el rollo completo resultaría excesivo. Asesoramiento experto incluido: nuestro equipo técnico te ayuda a seleccionar el tipo, grosor, color y medida más adecuados para tu aplicación específica. Disponibilidad y consulta profesional Stock limitado – Nuestros retales moqueta de alta calidad se agotan rápidamente debido a su excelente precio. Consulta disponibilidad actual de medidas, colores y tipos específicos. Ofrecemos asesoramiento profesional sin compromiso sobre: Selección de tipo de moqueta según tráfico esperado Recomendaciones de instalación para cada superficie Mantenimiento adecuado para prolongar la vida útil Combinaciones de color para proyectos corporativos Contacta ahora para reservar tus retales y asegurar el revestimiento perfecto para tu proyecto al mejor precio del mercado.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
