INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1178f013-4808-4517-829a-74a9daa3d92a',
  'Moqueta Canutillo',
  'moqueta-canutillo-clase-33-bfl-s1',
  'La moqueta canutillo es un revestimiento textil profesional diseñado específicamente para espacios que requieren máxima resistencia y seguridad contra incendios. Con su característica estructura de canutillo vertical y clasificación Bfl-s1, este producto se posiciona como la solución ideal para i...',
  'La moqueta canutillo es un revestimiento textil profesional diseñado específicamente para espacios que requieren máxima resistencia y seguridad contra incendios. Con su característica estructura de canutillo vertical y clasificación Bfl-s1, este producto se posiciona como la solución ideal para instalaciones comerciales, hoteles, oficinas y cualquier área de alto tránsito que demande prestaciones técnicas superiores. ¿Qué hace especial a la moqueta canutillo? Este tipo de moqueta canutillo se distingue por su proceso de fabricación mediante punzonado mecánico, que crea una superficie vertical única. A diferencia de otros revestimientos textiles, la estructura de canutillo proporciona mayor durabilidad frente al desgaste continuo, manteniendo su aspecto profesional incluso después de años de uso intensivo. La composición 100% polipropileno reforzada con resina ligante garantiza resistencia excepcional a la humedad, manchas y agentes químicos. Esto significa que tu moqueta canutillo mantendrá su apariencia impecable con mínimos cuidados, reduciendo significativamente los costes de mantenimiento a largo plazo. Seguridad certificada: Clasificación Bfl-s1 Una de las ventajas más importantes de nuestra moqueta canutillo es su clasificación de reacción al fuego Bfl-s1 según normativa europea EN 13501-1. Esta certificación indica baja contribución al fuego y producción muy limitada de humos, cumpliendo con los requisitos más exigentes de seguridad en edificación pública y comercial. Especificaciones técnicas destacadas Nuestra moqueta canutillo presenta un espesor de 4 mm que combina confort al caminar con excelente absorción acústica. Los rollos de 50 metros lineales por 2 metros de ancho (100 m² por rollo) facilitan la instalación en grandes superficies con mínimas juntas visibles, logrando un acabado profesional y uniforme. La clasificación Clase 33 certifica que este producto está diseñado para soportar tráfico intenso en entornos comerciales, garantizando una vida útil prolongada incluso en las condiciones más exigentes. Aplicaciones ideales La moqueta canutillo es perfecta para hoteles y áreas de recepción, oficinas corporativas, centros educativos y sanitarios, salas polivalentes y auditorios, así como stands de ferias y eventos. Su versatilidad la convierte en la elección preferida de arquitectos y diseñadores para proyectos que requieren combinar estética, funcionalidad y seguridad. Ventajas del canutillo para limpieza La estructura vertical de la moqueta canutillo no solo aporta un aspecto visual distintivo, sino que facilita enormemente las tareas de limpieza y mantenimiento. Las partículas de suciedad no se adhieren tan fácilmente a las fibras verticales, permitiendo una aspiración más eficiente y resultados superiores con menos esfuerzo. En Disstands somos especialistas en revestimientos textiles para espacios comerciales y ofrecemos asesoramiento personalizado para tu proyecto. ¿Necesitas calcular la cantidad exacta o resolver dudas técnicas? Contacta con nuestro equipo en ventas@disstands.com o visita nuestra guía de instalación de moquetas. Nota: Los cortes personalizados no admiten devoluciones. Para medidas específicas, consúltanos antes de realizar tu pedido.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
