INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'd462f9af-a5c4-44dc-8114-73adb6b811ad',
  'Moqueta Las Vegas - Impresa',
  'moqueta-las-vegas-impresa-personalizada',
  'La Moqueta Las Vegas Impresa lleva la funcionalidad y elegancia de la versión clásica a un nuevo nivel, incorporando impresión digital personalizada de alta calidad. Diseñada específicamente para empresas y profesionales que buscan destacar en ferias, eventos corporativos y espacios comerciales, ...',
  'La Moqueta Las Vegas Impresa lleva la funcionalidad y elegancia de la versión clásica a un nuevo nivel, incorporando impresión digital personalizada de alta calidad. Diseñada específicamente para empresas y profesionales que buscan destacar en ferias, eventos corporativos y espacios comerciales, esta moqueta transforma cualquier superficie en una poderosa herramienta de branding y comunicación visual. Características y Ventajas de la Personalización Esta moqueta profesional combina la resistencia excepcional de la poliamida con tecnología de impresión digital de última generación, permitiendo reproducir logotipos corporativos, diseños personalizados, mensajes promocionales y elementos gráficos con precisión fotográfica. Su superficie lisa de alta calidad garantiza colores vibrantes y definición impecable, mientras que el reverso Action Back proporciona la estabilidad necesaria para instalaciones seguras y duraderas. La personalización convierte cada metro cuadrado en un elemento estratégico de comunicación, reforzando la identidad de marca y creando experiencias memorables para visitantes y clientes. Ideal para empresas que participan regularmente en ferias comerciales, eventos corporativos, inauguraciones, presentaciones de producto y activaciones de marca. Aplicaciones Estratégicas La Moqueta Las Vegas Impresa es la solución perfecta para múltiples aplicaciones profesionales: Ferias y Exposiciones: Stands personalizados que captan la atención desde el primer momento, diferenciándote de la competencia con un diseño único que comunica profesionalidad y atención al detalle. Eventos Corporativos: Alfombras de bienvenida con logotipo empresarial, zonas de networking personalizadas, áreas VIP diferenciadas y espacios de presentación que refuerzan la imagen corporativa en congresos, convenciones y conferencias. Retail y Showrooms: Suelos personalizados para lanzamientos de producto, tiendas temporales (pop-up stores), espacios de demostración y puntos de venta que crean ambientes inmersivos alineados con la identidad de marca. Activaciones de Marca: Instalaciones promocionales, eventos de marketing experiencial, inauguraciones y presentaciones donde cada detalle cuenta para transmitir el mensaje de marca de forma impactante. Proceso de Personalización y Especificaciones El proceso de impresión digital permite reproducir desde diseños corporativos simples hasta composiciones gráficas complejas, degradados y fotografías de alta resolución. Los colores se mantienen vibrantes y resistentes al tránsito, garantizando que tu inversión en branding permanezca impecable durante todo el evento. La estructura resistente de poliamida soporta el tránsito intenso característico de ferias y eventos sin comprometer la calidad visual de la impresión. El mantenimiento es sencillo mediante aspirado regular, y su diseño permite reutilización en múltiples eventos, maximizando el retorno de inversión. Compatible con sistemas de instalación profesional mediante cintas adhesivas especiales para ferias, permite montajes rápidos y seguros sin arrugas, esencial cuando los tiempos de preparación son limitados. Información de Pedido y Asesoramiento Precio personalizado según diseño y cantidad El precio final depende de las dimensiones del pedido, complejidad del diseño y cantidad de unidades. Los proyectos de mayor volumen se benefician de tarifas más competitivas, ideal para empresas con múltiples eventos programados. Proceso de pedido: Envía tu diseño o concepto a ventas@disstands.com Nuestro equipo técnico revisará las especificaciones y preparará un presupuesto detallado Aprobación del diseño y muestra digital antes de producción Fabricación e impresión con controles de calidad rigurosos Entrega en los plazos acordados para tu evento Por Qué Elegir la Moqueta Las Vegas Impresa La Moqueta Las Vegas Impresa representa mucho más que un simple revestimiento: es una inversión estratégica en comunicación visual y branding profesional. Cada instalación se convierte en una declaración de identidad corporativa, transmitiendo valores de innovación, profesionalidad y atención al detalle. Para empresas de organización de eventos, agencias de publicidad, departamentos de marketing y empresas expositoras que buscan diferenciación real en un mercado competitivo, esta moqueta ofrece la combinación perfecta de funcionalidad técnica, calidad visual y personalización sin límites. Contacta con nuestro equipo especializado en ventas@disstands.com para recibir asesoramiento personalizado, muestras de calidad de impresión y presupuestos adaptados a tus necesidades específicas. Transforma tus eventos en experiencias de marca inolvidables con la Moqueta Las Vegas Impresa.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
