INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '919d2772-a743-4cba-8cfc-ecf6dcc4afe0',
  'Rollo Caucho Sportdis Oscuro',
  'suelo-caucho-negro-rollo-gimnasios',
  'Pavimento profesional para instalaciones deportivas El suelo de caucho negro en rollo es la solución perfecta para gimnasios y centros deportivos. Este pavimento de alto rendimiento está fabricado con caucho granulado aglomerado de alta tecnología. Su densidad de 950 kg/m³ garantiza una resistenc...',
  'Pavimento profesional para instalaciones deportivas El suelo de caucho negro en rollo es la solución perfecta para gimnasios y centros deportivos. Este pavimento de alto rendimiento está fabricado con caucho granulado aglomerado de alta tecnología. Su densidad de 950 kg/m³ garantiza una resistencia excepcional al uso intensivo. La composición antideslizante proporciona máxima seguridad durante los entrenamientos. Sus propiedades antifatiga ofrecen confort incluso en sesiones prolongadas. Además, reduce el ruido entre 15 y 23 dB, creando un ambiente más agradable. La amortiguación de impactos protege tanto a usuarios como al suelo base de la instalación. Resistencia y durabilidad garantizadas Este pavimento deportivo soporta las demandas más exigentes del entorno fitness profesional. Su estructura de caucho reciclado de primera calidad garantiza estabilidad y seguridad. La alta densidad del material asegura una durabilidad excepcional. Mantiene sus propiedades intactas tras años de uso con equipamiento pesado y máquinas. El suelo es completamente resistente a la humedad e imputrescible. Funciona perfectamente en temperaturas extremas, desde -30°C hasta +80°C. Esta característica lo hace ideal para cualquier tipo de instalación deportiva. Su resistencia permite su uso en zonas con alta sudoración sin deteriorarse. Mantenimiento sencillo y eficaz La baja porosidad del material facilita enormemente la limpieza diaria. Permite una desinfección rápida con productos de limpieza convencionales. Este aspecto es fundamental para mantener los estándares de higiene deportiva. La superficie no absorbe líquidos ni olores, manteniéndose siempre en óptimas condiciones. Formatos adaptados a cada necesidad Disponible en rollos de 1,25 x 10 metros (12,5 m²) con tres espesores diferentes. El modelo de 4 mm es perfecto para zonas de tránsito y recepción. El espesor de 6 mm se recomienda para salas de entrenamiento funcional y cardio. Para áreas de peso libre y crossfit, el grosor de 8 mm ofrece máxima protección. Instalación rápida y profesional La instalación es sencilla y no requiere conocimientos especializados. Se coloca directamente sobre superficies lisas y niveladas. En muchos casos no necesita adhesivos, lo que agiliza el proceso. El formato en rollo permite cubrir grandes superficies con mínimas juntas. Su excelente estabilidad dimensional previene deformaciones y ondulaciones. La superficie permanece uniforme y segura durante toda su vida útil. Es ideal para zonas de peso libre, crossfit, musculación y clases colectivas. También perfecto para áreas de cardio, pasillos y zonas funcionales.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
