INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '09e02b7f-48cb-4833-8ea5-efb7fc013c9f',
  'Suelo de Caucho Sportdis Optimus EPDM',
  'suelo-caucho-sportdis-optimus-epdm',
  'El pavimento de máximo rendimiento para instalaciones deportivas El suelo de caucho Sportdis Optimus representa la evolución en pavimentos deportivos profesionales. Este innovador suelo combina caucho reciclado con partículas EPDM en colores naranja y blanco. El resultado es un pavimento distinti...',
  'El pavimento de máximo rendimiento para instalaciones deportivas El suelo de caucho Sportdis Optimus representa la evolución en pavimentos deportivos profesionales. Este innovador suelo combina caucho reciclado con partículas EPDM en colores naranja y blanco. El resultado es un pavimento distintivo que ofrece el más alto rendimiento para cada actividad. Su densidad de 850 kg/m³ proporciona el equilibrio perfecto entre resistencia y confort. Las partículas EPDM mejoran las propiedades elásticas y la durabilidad del material. El diseño con motas de color sobre base negra crea un aspecto moderno y profesional. Características técnicas superiores Este pavimento destaca por su excepcional resistencia al uso intensivo. Soporta cargas de hasta 200 t/m² en espesores de 8 y 10 mm. La resistencia a la tracción mínima de 0.7 N/mm² garantiza su integridad estructural. El alargamiento de rotura del 42% proporciona flexibilidad sin comprometer la durabilidad. El coeficiente de fricción de 0.81 asegura máxima seguridad antideslizante. Esta característica previene accidentes durante entrenamientos intensos. Funciona perfectamente en temperaturas desde -30°C hasta +80°C. Además, cumple con la normativa de resistencia al fuego Efl B2 EN 13501. Ventajas para el usuario y la instalación El efecto antifatiga protege articulaciones y reduce el cansancio muscular. Las propiedades amortiguadoras absorben impactos y protegen el suelo base. La reducción acústica crea un ambiente más agradable para entrenar. Una de sus principales ventajas es la ausencia total de olores. La superficie no porosa facilita enormemente la limpieza diaria. El mantenimiento es mínimo, reduciendo costes operativos a largo plazo. La instalación es rápida y sencilla, sin necesidad de adhesivos especiales. Formatos versátiles para cada necesidad Disponible en cuatro espesores para adaptarse a diferentes zonas. El modelo de 4 mm (1,25 x 15 m) es ideal para áreas de tránsito. La versión de 6 mm (1,25 x 10 m) funciona perfectamente en zonas de cardio. Para áreas de peso libre, los espesores de 8 mm (1,25 x 8 m) y 10 mm (1,25 x 6 m) ofrecen máxima protección. Aplicaciones profesionales Sportdis Optimus es perfecto para centros deportivos y gimnasios de alto rendimiento. Ideal para boxes de crossfit y áreas de peso libre. Excelente para salas de musculación, cardio y clases colectivas. También recomendado para zonas de recepción, pasillos y áreas funcionales. Su versatilidad lo convierte en la elección preferida de instalaciones fitness profesionales.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
