INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'c1074ec2-d25d-4e24-8eb2-88b276504490',
  'Suelo Sportdis UNI Classic EPDM 100% - Pavimento Deportivo Premium',
  'suelo-sportdis-uni-classic-epdm',
  'Pavimento deportivo premium de EPDM puro El suelo Sportdis UNI Classic representa la máxima calidad en pavimentos deportivos de interior. Fabricado con 100% gránulos EPDM comprimidos y unidos con elastómero de poliuretano. Este material premium ofrece una coloración uniforme perfecta para aplicar...',
  'Pavimento deportivo premium de EPDM puro El suelo Sportdis UNI Classic representa la máxima calidad en pavimentos deportivos de interior. Fabricado con 100% gránulos EPDM comprimidos y unidos con elastómero de poliuretano. Este material premium ofrece una coloración uniforme perfecta para aplicar líneas de demarcación deportiva de alto contraste. Con una densidad excepcional de 1.310 kg/m³, proporciona estabilidad y durabilidad superiores. Su superficie de granulado fino crea una textura homogénea y profesional. Disponible en cinco colores elegantes: rojo, azul, gris claro, beige y gris oscuro. Rendimiento técnico certificado Este pavimento cuenta con certificación de resistencia al fuego Cfl-s1 (B1). Su resistencia a la tracción mínima de 0,7 N/mm² garantiza durabilidad excepcional. El alargamiento de rotura del 70% proporciona flexibilidad óptima sin comprometer la integridad estructural. El coeficiente de fricción de 0,88 μ y clasificación antideslizante R10 aseguran máxima seguridad. Con sellado especial RZ turbo protect zero + RZ grip alcanza clasificación R11. La dureza de 60 Shore A ofrece el equilibrio perfecto entre confort y resistencia. Confort acústico y térmico superior Sportdis UNI Classic proporciona una reducción acústica de 14 dB. Esta característica lo hace ideal tanto para instalaciones deportivas como para oficinas comerciales. Su deformación remanente de solo 0,32 mm garantiza una superficie siempre uniforme. El material funciona perfectamente en rangos de temperatura de -30°C a 80°C. Su resistencia térmica de 0,0139 m²K/W lo hace compatible con sistemas de calefacción por suelo radiante. La conductividad térmica optimizada mantiene temperaturas agradables en cualquier estación. Sostenibilidad y certificaciones ambientales Este pavimento cuenta con múltiples certificaciones ambientales de prestigio. Clasificación A+ en regulación francesa de emisiones VOC. Certificaciones Indoor Air Comfort Gold y Blue Angel (DE-UZ 120). Cumple con los estándares BREEAM International y BREEAM-NOR (Nivel Ejemplar). Compatible con EU Taxonomy y LEED v4.1 BETA. Estas certificaciones garantizan un producto seguro y respetuoso con el medio ambiente. Instalación y mantenimiento simplificados La instalación es rápida y sencilla siguiendo las recomendaciones del fabricante. Se presenta en rollos de 1,25 x 15 metros, cubriendo 18,75 m² por rollo. El espesor uniforme de 4 mm facilita la instalación sin desniveles. Se recomienda el sellado con sistema RZ turbo protect zero de 2 componentes. Los pequeños daños pueden repararse con RZ Refresher Set. Su superficie no porosa facilita la limpieza diaria con productos convencionales.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
