INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '9e439452-08d6-4960-8538-147714d4b1ca',
  'Suelo Sportdis FR Pigmento Azul/Gris',
  'suelo-sportdis-color-fr-ignifugo',
  'Pavimento ignífugo de alto rendimiento El suelo Sportdis Color FR es la solución definitiva para instalaciones que requieren máxima seguridad contra incendios. Fabricado con caucho reciclado de neumáticos y gránulos EPDM coloreados unidos con aglomerante de poliuretano. Incorpora tratamiento reta...',
  'Pavimento ignífugo de alto rendimiento El suelo Sportdis Color FR es la solución definitiva para instalaciones que requieren máxima seguridad contra incendios. Fabricado con caucho reciclado de neumáticos y gránulos EPDM coloreados unidos con aglomerante de poliuretano. Incorpora tratamiento retardante de llama que garantiza certificación Cfl-s1. Este pavimento robusto y versátil está disponible en dos elegantes colores: gris y azul. La combinación de materiales crea un diseño atractivo y funcional. Su composición especial lo hace completamente repelente al agua. Resistencia y durabilidad excepcionales Sportdis Color FR destaca por su extraordinaria durabilidad ante el desgaste mecánico. Su estructura de caucho reciclado con EPDM garantiza años de uso intensivo sin deterioro. La superficie resiste impactos, abrasión y cargas pesadas sin deformarse. El tratamiento ignífugo no compromete las propiedades físicas del material. Mantiene su flexibilidad y resistencia en todas las condiciones. La repelencia al agua protege el pavimento de manchas y facilita su mantenimiento. Confort y reducción acústica Este pavimento ofrece un excelente confort de pisada para usuarios y trabajadores. Sus propiedades amortiguadoras reducen la fatiga durante largas jornadas. La absorción de impactos protege articulaciones y reduce lesiones. Las características acústicas minimizan el ruido ambiental y de impacto. Crea espacios más agradables para entrenar y trabajar. La superficie antideslizante garantiza seguridad en todas las actividades. Versatilidad de aplicaciones Sportdis Color FR es ideal para múltiples instalaciones deportivas y comerciales. Perfecto para gimnasios y centros fitness de alto tráfico. Excelente para tiendas, salas de exposición y pabellones feriales. También recomendado para almacenes de equipamiento y estadios de deportes de hielo. Su resistencia al agua lo hace apto para zonas húmedas. La facilidad de limpieza reduce costes de mantenimiento. Formatos adaptados a cada proyecto Disponible en rollos de 1,50 metros de ancho para cubrir grandes superficies. Cuatro espesores diferentes para adaptarse a cada necesidad específica. El formato de 4 mm (30 m de longitud) ideal para zonas de tránsito moderado. Los espesores de 6 mm (20 m) y 8 mm (15 m) para áreas de entrenamiento. El modelo de 10 mm (12 m) ofrece máxima protección en zonas de alto impacto. Todos los formatos mantienen tolerancias precisas de ±1,5% en dimensiones. Instalación y mantenimiento simplificados La instalación es rápida gracias al formato en rollos de gran anchura. No requiere adhesivos especiales en muchas aplicaciones. La estabilidad dimensional previene deformaciones post-instalación. El mantenimiento es extremadamente sencillo gracias a su superficie repelente al agua. La limpieza se realiza con productos convencionales no agresivos. Su resistencia química permite desinfección frecuente sin deterioro.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
