INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'b534b887-7d7c-4e54-8e5e-1e66fb23eabb',
  'Rampas de Borde y Esquina Sportdis FR Ignífugas',
  'rampas-borde-esquina-sportdis-fr',
  'Solución profesional de transición para pavimentos deportivos Las rampas de borde y esquina Sportdis FR son el complemento perfecto para pavimentos deportivos ignífugos. Cumplen con los requisitos de protección contra incendios clase Cfl-s1 (retardante de llama). Diseñadas específicamente para co...',
  'Solución profesional de transición para pavimentos deportivos Las rampas de borde y esquina Sportdis FR son el complemento perfecto para pavimentos deportivos ignífugos. Cumplen con los requisitos de protección contra incendios clase Cfl-s1 (retardante de llama). Diseñadas específicamente para complementar los pavimentos Sportdis base FR y style purcolor. Fabricadas con mezcla seleccionada de gránulos de caucho EPDM unidos con elastómero de poliuretano. Su color negro uniforme combina perfectamente con cualquier instalación. La superficie porosa abierta garantiza adherencia y seguridad óptimas. Seguridad y prevención de accidentes Los bordes biselados reducen significativamente el riesgo de tropiezos. Proporcionan una transición suave y segura entre diferentes niveles de pavimento. Especialmente importantes al entrar y salir de áreas de peso libre. La inclinación progresiva de 30 a 10 mm facilita el paso de equipamiento rodante. Ideal para el tránsito de carros de limpieza y material deportivo. La superficie antideslizante mantiene la seguridad en todas las condiciones. Resistencia y durabilidad certificadas Estas rampas cuentan con certificación ignífuga Cfl-s1 según DIN EN 13501-1. La resistencia a la tracción mínima de 0,5 N/mm² garantiza durabilidad. El alargamiento de rotura del 40% proporciona flexibilidad adecuada. Con dureza de 60 ± 5 Shore A, ofrecen estabilidad dimensional óptima. Funcionan perfectamente en rangos de temperatura de -30°C a 80°C. Resisten fracturas en frío hasta -40°C durante 24 horas sin deterioro. Dos modelos para soluciones completas Las rampas de borde miden 1000 x 250 mm para transiciones rectas. Peso aproximado de 4,9 kg por pieza para fácil manipulación. Ideales para perímetros y pasillos de instalaciones deportivas. Las rampas de esquina tienen dimensiones específicas para ángulos de 90 grados. Borde exterior de 1000 x 250 mm y borde interior de 750 x 250 mm. Peso de 4,3 kg para instalación cómoda y precisa. Sostenibilidad y certificaciones ambientales Clasificación A+ en la regulación francesa de emisiones VOC. El valor de reflectancia lumínica (LRV) del 3% en color negro. Cumple con los estándares ambientales más exigentes del sector. Los materiales reciclados en su composición reducen el impacto ambiental. La durabilidad excepcional minimiza la necesidad de reemplazos. Contribuye a proyectos de construcción sostenible y certificaciones verdes. Instalación profesional y sencilla Se recomienda la instalación con adhesivo PU OTTOCOLL P83 color gris. Un tubo de adhesivo es suficiente para aproximadamente 3 metros de pegado. La instalación debe seguir las recomendaciones técnicas del fabricante. La superficie lisa de apoyo garantiza contacto completo con el suelo base. Las tolerancias precisas de ±0,8% aseguran ajustes perfectos. El mantenimiento es mínimo gracias a la calidad de los materiales.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
