INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3b2064bc-d061-482e-8840-e7b1272d645f',
  'PVC Estándar - Impresión',
  'pvc-estandar-impreso',
  'PVC Estándar Impreso es un revestimiento vinílico en rollo, versátil y económico, especialmente diseñado para cubrir suelos en ferias, exposiciones, stands y eventos temporales con impresión personalizada. Su composición de PVC y soporte resistente proporcionan una instalación rápida y sencilla, ...',
  'PVC Estándar Impreso es un revestimiento vinílico en rollo, versátil y económico, especialmente diseñado para cubrir suelos en ferias, exposiciones, stands y eventos temporales con impresión personalizada. Su composición de PVC y soporte resistente proporcionan una instalación rápida y sencilla, siendo una solución práctica para proyectos con presupuesto ajustado. Su superficie impresa permite personalizar completamente el diseño, ofreciendo una excelente relación calidad-precio para comunicación visual efectiva en espacios de tráfico moderado. Ideal para eventos de corta duración donde se busca impacto visual sin comprometer la funcionalidad. Los cortes no admiten devoluciones. Para medidas personalizadas y diseños de impresión, escríbenos a: ventas@disstands.com',
