INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '86d3c555-05c7-437b-8d41-24d1bbfbf91b',
  'PVC Las Vegas Brillo - Impresión',
  'pvc-las-vegas-brillo-impresion',
  'El suelo vinílico Las Vegas Brillo Lux Impreso es una solución de alta calidad con grosor de 2 mm, ideal para espacios interiores que necesitan un acabado elegante, extraordinariamente resistente y completamente personalizable. Este suelo vinílico Las Vegas está diseñado para durar años, soportar...',
  'El suelo vinílico Las Vegas Brillo Lux Impreso es una solución de alta calidad con grosor de 2 mm, ideal para espacios interiores que necesitan un acabado elegante, extraordinariamente resistente y completamente personalizable. Este suelo vinílico Las Vegas está diseñado para durar años, soportar el uso diario sin desgastarse y mantenerse estable con el tiempo, mientras ofrece la posibilidad de impresión digital a medida para crear diseños únicos y comunicación visual impactante. Construcción y Acabado Premium con Impresión Personalizada En primer lugar, este suelo vinílico Las Vegas destaca por su construcción robusta de 2 mm que garantiza resistencia excepcional. Además, su superficie permite impresión digital de alta resolución con acabado brillo que aporta luminosidad y amplitud visual a cualquier espacio. Como resultado, crea ambientes más elegantes y sofisticados con diseños completamente personalizados que causan excelente impresión. El acabado brillo lux refleja la luz natural de manera óptima, resaltando los colores y detalles de la impresión. Por consiguiente, los espacios parecen más amplios y acogedores. Asimismo, este efecto brillante se mantiene impecable durante años con el mantenimiento adecuado. Protección Higiénica Certificada Por otro lado, incluye protección antibacteriana y fungicida integrada en su composición. Este tratamiento inhibe activamente el crecimiento de bacterias dañinas. De este modo, garantiza un ambiente higiénico constante en tu comercio o vivienda. Además, incorpora un acabado especial que facilita enormemente su limpieza. En consecuencia, el mantenimiento diario se realiza de manera rápida y sencilla con productos convencionales. Especialmente útil en espacios comerciales donde la higiene es prioritaria. Compromiso Ecológico y Seguridad Este suelo vinílico Las Vegas es un producto ecológico certificado. En primer lugar, está fabricado sin disolventes nocivos que puedan emitir compuestos volátiles. Igualmente, no contiene metales pesados peligrosos como plomo o cadmio. Por lo tanto, cumple rigurosamente con los estándares europeos de seguridad y calidad. Asimismo, cuenta con certificaciones CE reconocidas internacionalmente. De este modo, protege la salud de usuarios, empleados y clientes. Aplicaciones Versátiles con Personalización Perfecto para tiendas y boutiques que buscan un pavimento elegante, duradero y con imagen corporativa personalizada. Igualmente ideal para oficinas modernas donde se requiere mínimo mantenimiento, máxima resistencia y branding visual. También excelente para espacios comerciales como consultas, farmacias, salones de belleza y showrooms que desean comunicar su identidad de marca desde el suelo. En entornos residenciales, este suelo vinílico Las Vegas transforma salones, cocinas y baños en espacios de alto standing con diseños únicos y personalizados. Su acabado brillo con impresión a medida aporta distinción premium a cualquier hogar.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
