INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '7ce417dd-75c8-469a-8e23-11610436ead1',
  'PVC Oro y Plata Brillo - Impresión',
  'pvc-metalizado-impreso-oro-plata-eventos',
  'El PVC Oro y Plata Impreso es un revestimiento vinílico flexible y ligero, especialmente diseñado para cubrir suelos en ferias, exposiciones, pasarelas y eventos temporales con impresión personalizada. Disponible en acabados mate, brillante, oro, plata y espejo con posibilidad de impresión digita...',
  'El PVC Oro y Plata Impreso es un revestimiento vinílico flexible y ligero, especialmente diseñado para cubrir suelos en ferias, exposiciones, pasarelas y eventos temporales con impresión personalizada. Disponible en acabados mate, brillante, oro, plata y espejo con posibilidad de impresión digital, este producto ofrece una solución estética llamativa, completamente personalizable y funcional para entornos efímeros. Su clasificación al fuego Bfl-s1 lo convierte en una opción segura y su instalación es rápida gracias a su formato en rollo. Ideal para decoraciones impactantes, modernas y de alto nivel visual con diseños exclusivos que comunican marca y crean experiencias memorables. Precio indicado por metro cuadrado. Ejemplo de corte: 1 metro lineal x 2 metros de ancho = 2 m² 2 m² x 13,90 €/m² = 27,80 € Los cortes no admiten devoluciones. Para medidas personalizadas y diseños de impresión, escríbenos a: ventas@disstands.com',
