INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'dcdf8267-72ab-4b54-8519-ea76db87fd1a',
  'Jardin Vertical Pradis',
  'jardin-vertical-pradis-50x50',
  'Jardín vertical Pradis 50x50: naturaleza decorativa con certificación ignífuga El jardín vertical Pradis 50x50 es un panel artificial decorativo que simula vegetación natural para colocación en vertical, recreando a la perfección paredes vegetales realistas. Este jardín vertical Pradis 50x50 ha s...',
  'Jardín vertical Pradis 50x50: naturaleza decorativa con certificación ignífuga El jardín vertical Pradis 50x50 es un panel artificial decorativo que simula vegetación natural para colocación en vertical, recreando a la perfección paredes vegetales realistas. Este jardín vertical Pradis 50x50 ha sido diseñado específicamente para transformar espacios con elegancia y sin las complicaciones del mantenimiento tradicional de plantas naturales. Diseño versátil del jardín vertical Pradis Nuestro jardín vertical Pradis 50x50 ha sido creado para decorar terrazas, balcones, techos, columnas, fachadas, cercas, vallas publicitarias y escaparates con estilo. Convierte un muro o pared aburrida en un hermoso jardín vertical artificial lleno de vida y color. Asimismo, estos paneles transforman instantáneamente cualquier ambiente en un espacio acogedor y natural que impresiona a visitantes y clientes. Certificación de fuego clase E El jardín vertical Pradis 50x50 cuenta con certificado de clasificación de fuego E, lo que garantiza un nivel de seguridad adecuado para su instalación en diversos entornos. Esta certificación lo convierte en una opción fiable para espacios comerciales, hoteles y zonas donde la normativa de seguridad contra incendios es prioritaria. Materiales de alta calidad con garantía UV El jardín vertical Pradis 50x50 está fabricado con materiales de alta calidad y cuenta con garantía de protección UV. Esto consigue por tanto una resistencia perfecta al paso del tiempo, tanto en interiores como en exteriores. Además, esta protección UV garantiza que los colores permanezcan vivos y brillantes durante años sin decoloración ni deterioro visible. Formato compacto de 50x50 cm Cada pieza del jardín vertical Pradis 50x50 mide exactamente 50 cm x 50 cm, un formato compacto y manejable que permite crear instalaciones modulares de cualquier tamaño. Por otro lado, este formato facilita enormemente la instalación y permite combinar varios paneles para cubrir grandes superficies con total flexibilidad. De esta forma, puedes diseñar muros vegetales completos adaptados a tus necesidades específicas de proyecto. Cero mantenimiento garantizado El jardín vertical Pradis 50x50 no requiere mantenimiento alguno, eliminando completamente la necesidad de riego, poda, fertilización o luz natural específica. No requiere sistemas de drenaje complicados ni genera problemas de humedad en las paredes. Asimismo, es perfecto para espacios sin luz natural donde las plantas reales no sobrevivirían. Aplicaciones ideales del jardín Pradis Este panel artificial decorativo es perfecto para recibidores de hoteles, paredes de restaurantes, oficinas corporativas, espacios comerciales, terrazas cubiertas, salones residenciales y cualquier ambiente que busque incorporar naturaleza decorativa con seguridad ignífuga. Características principales Modelo: Pradis Código de referencia: 8436593443931 / 10402 Dimensiones: 50 cm x 50 cm por panel Clasificación de fuego: Clase E Protección UV: Garantizada Mantenimiento: Cero Uso: Interior y exterior Elige el jardín vertical Pradis 50x50 para disfrutar de paredes vegetales espectaculares con certificación ignífuga y sin preocupaciones.',
