INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e77d12a6-3dd0-4c45-858b-a4622c809e5c',
  'Jardín Vertical Bobodis',
  'jardin-vertical-bobodis-100x100',
  'Jardín Vertical Bobodis 100x100: elegancia italiana con seguridad ignífuga El jardín vertical Bobodis 100x100 es un panel artificial decorativo que simula vegetación exuberante de estilo mediterráneo. Está diseñado para colocación en vertical, recreando paredes vegetales con la elegancia de los j...',
  'Jardín Vertical Bobodis 100x100: elegancia italiana con seguridad ignífuga El jardín vertical Bobodis 100x100 es un panel artificial decorativo que simula vegetación exuberante de estilo mediterráneo. Está diseñado para colocación en vertical, recreando paredes vegetales con la elegancia de los jardines renacentistas. Este modelo cuenta con certificación de fuego clase E. Por tanto, ofrece seguridad adecuada para múltiples tipos de instalaciones. En Disstands ofrecemos el modelo Bobodis como solución decorativa inspirada en los célebres jardines florentinos. Su diseño ha sido cuidadosamente seleccionado para aportar sofisticación y naturalidad. Combina estética clásica con prestaciones técnicas de calidad. Diseño Versátil del Jardín Vertical Bobodis Nuestro jardín vertical Bobodis 100x100 ha sido creado para decorar paredes con refinamiento. Es perfecto para viviendas, comercios, hoteles y empresas que buscan un ambiente distinguido. Convierte cualquier muro aburrido en un hermoso jardín vertical lleno de carácter. Asimismo, estos paneles transforman instantáneamente cualquier espacio. Crean ambientes que evocan la majestuosidad de los jardines italianos. Además, su instalación modular permite cubrir superficies de cualquier tamaño. Certificación de Fuego Clase E El jardín vertical Bobodis 100x100 cuenta con certificado de clasificación de fuego E. Esta certificación garantiza un nivel de seguridad apropiado para instalaciones decorativas. Por consiguiente, cumple con los requisitos normativos para espacios residenciales y comerciales. Esta certificación lo convierte en una opción fiable para diversos entornos. Viviendas, oficinas, restaurantes y comercios pueden instalarlo con tranquilidad. También es adecuado para proyectos de interiorismo y decoración profesional. Composiciones Basadas en Vegetación Auténtica El modelo Bobodis ha sido seleccionado basándose en composiciones de vegetación real. De esta manera, logramos un aspecto natural que imita perfectamente jardines ornamentales clásicos. Cada panel presenta una estética mediterránea y armoniosa. El realismo excepcional engaña incluso al ojo más crítico. Sin embargo, no requiere ningún tipo de mantenimiento ni cuidados especiales. Por consiguiente, disfrutas de naturaleza decorativa sin las complicaciones de las plantas vivas. Materiales de Alta Calidad con Garantía UV El jardín vertical Bobodis 100x100 está fabricado con materiales de primera calidad. Son totalmente resistentes a los rayos UV gracias a su tratamiento especial. Esta protección garantiza estabilidad del color durante años. Por tanto, los paneles mantienen su aspecto original sin decoloración ni deterioro. Funcionan perfectamente tanto en interiores como en exteriores protegidos. Además, resisten las condiciones climáticas sin perder sus propiedades. Formato Estándar de 100x100 cm Cada pieza del jardín vertical Bobodis mide exactamente 100 x 100 cm. Este formato estándar facilita enormemente la planificación de instalaciones. Permite calcular fácilmente el número de paneles necesarios para cada proyecto. El sistema modular posibilita crear muros vegetales de cualquier dimensión. Los paneles se conectan entre sí de forma sencilla y discreta. De este modo, las juntas resultan prácticamente invisibles en la instalación final. Cero Mantenimiento Garantizado El jardín vertical Bobodis elimina completamente las tareas de mantenimiento tradicionales. No requiere riego, poda, fertilización ni luz natural específica. Tampoco necesita sistemas de drenaje ni genera problemas de humedad. Solo precisa una limpieza ocasional para eliminar el polvo acumulado. Un simple cepillado o aspirado mantiene los paneles en perfecto estado. Por consiguiente, el coste de mantenimiento es prácticamente nulo. Aplicaciones Ideales del Jardín Bobodis Este panel artificial es perfecto para múltiples aplicaciones profesionales y residenciales: Viviendas: Salones, terrazas cubiertas y patios interiores con estilo mediterráneo. Restaurantes y bares: Ambientes sofisticados que evocan la Toscana italiana. Oficinas: Espacios de trabajo elegantes y acogedores. Comercios: Decoración de escaparates y zonas de atención al cliente. Hoteles: Vestíbulos, pasillos y zonas comunes con aire distinguido. Eventos: Photocalls, stands y decoraciones temporales con impacto visual.',
