INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '47ffc9ce-fcae-4d7d-8e97-75d695aca06b',
  'Jardín Vertical Rodis',
  'jardin-vertical-artificial-rodas',
  'Transforma cualquier espacio con el jardín vertical artificial Rodis, una solución decorativa diseñada para recrear la belleza natural de las paredes vegetales sin ningún tipo de mantenimiento. Cada panel ha sido cuidadosamente elaborado con composiciones inspiradas en plantas auténticas, combina...',
  'Transforma cualquier espacio con el jardín vertical artificial Rodis, una solución decorativa diseñada para recrear la belleza natural de las paredes vegetales sin ningún tipo de mantenimiento. Cada panel ha sido cuidadosamente elaborado con composiciones inspiradas en plantas auténticas, combinando diferentes tonalidades de verde y texturas vegetales para lograr un acabado extraordinariamente realista que aporta frescura y elegancia a cualquier entorno. El modelo Rodis es perfecto para viviendas, comercios, hoteles, restaurantes, oficinas y espacios corporativos, convirtiendo muros y paredes en elementos decorativos de alto impacto visual. Ya sea para crear un punto focal en un salón, dar vida a la recepción de un negocio o transformar una terraza en un oasis verde, este jardín vertical ofrece infinitas posibilidades decorativas sin las complicaciones del mantenimiento de plantas naturales. Fabricado con materiales de alta calidad y tratamiento anti-UV, el jardín vertical Rodis mantiene su aspecto impecable año tras año, resistiendo la exposición solar sin decoloración ni deterioro. Esto lo convierte en una opción ideal tanto para interiores como para exteriores protegidos, garantizando una inversión duradera que conservará su belleza con el paso del tiempo. La instalación es sencilla y rápida gracias a su diseño modular de 50 x 50 cm, que permite cubrir superficies de cualquier tamaño combinando varios paneles. Olvídate del riego, la poda, los fertilizantes y las plagas: el jardín vertical Rodas te ofrece toda la estética de un muro vegetal natural con cero preocupaciones. Además, cuenta con certificación de clasificación al fuego Euroclase E, cumpliendo con las normativas de seguridad para su uso en espacios comerciales y públicos.',
  '4c07f655-21b5-40bc-89df-73e5d3f6fbb5',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
