INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '4e79ce0e-4b6e-46f6-8ba1-1fe345be00a4',
  'Linóleo Etrusdis',
  'suelo-linoleo-natural-etrusdis',
  'Descubre el suelo de linóleo Etrusdis, una solución de pavimentación que combina la belleza natural con la máxima sostenibilidad. Fabricado con un 94% de materias primas naturales, este suelo pertenece a la prestigiosa colección Etrusco Silencio xf²™ de Tarkett, una marca con más de 150 años de e...',
  'Descubre el suelo de linóleo Etrusdis, una solución de pavimentación que combina la belleza natural con la máxima sostenibilidad. Fabricado con un 94% de materias primas naturales, este suelo pertenece a la prestigiosa colección Etrusco Silencio xf²™ de Tarkett, una marca con más de 150 años de experiencia en el sector. El linóleo Etrusdis representa la perfecta fusión entre tradición e innovación, ofreciendo un producto respetuoso con el medio ambiente sin renunciar a las más altas prestaciones técnicas. El tratamiento de protección exclusivo xf²™ confiere al suelo Etrusdis una resistencia superior frente al desgaste, las manchas y los productos químicos. Esta tecnología avanzada facilita enormemente la limpieza diaria y reduce significativamente los costes de mantenimiento, eliminando la necesidad de pulido o encerado periódico. Gracias a estas propiedades, el linóleo Etrusdis mantiene su aspecto impecable durante años con un mínimo esfuerzo. Disponible en una amplia gama de colores sólidos contemporáneos, el suelo Etrusdis se adapta a cualquier proyecto de diseño interior. Su versatilidad lo convierte en la opción ideal para espacios residenciales de uso intenso, entornos comerciales con alto tráfico y aplicaciones industriales exigentes. Además, sus propiedades naturalmente antibacterianas y su excelente aislamiento acústico crean ambientes más saludables y confortables. El linóleo Etrusdis refleja un compromiso firme con la economía circular y la sostenibilidad. Este producto contribuye a la creación de espacios más saludables mientras minimiza el impacto ambiental, cumpliendo con las certificaciones medioambientales más exigentes como la ISO 14001. Una elección responsable para proyectos que valoran tanto la estética como el respeto por el planeta.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
