INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '01c1fcd7-4409-42a5-8cbd-7093acd352a2',
  'Linóleo Marmoredis 2,00mm',
  'suelo-linoleo-marmol-marmorette',
  'Descubre el suelo de linóleo Marmoredis 2,00 mm, una solución de pavimentación de alto rendimiento que destaca por su icónico diseño de mármol veteado. Fabricado con un 98% de componentes naturales, este suelo combina la elegancia atemporal del mármol con las ventajas técnicas del linóleo, ofreci...',
  'Descubre el suelo de linóleo Marmoredis 2,00 mm, una solución de pavimentación de alto rendimiento que destaca por su icónico diseño de mármol veteado. Fabricado con un 98% de componentes naturales, este suelo combina la elegancia atemporal del mármol con las ventajas técnicas del linóleo, ofreciendo un producto sostenible y de excepcional calidad. Su aspecto natural y brillante aporta sofisticación a cualquier espacio, convirtiéndolo en una opción ideal para proyectos que buscan distinción sin renunciar a la durabilidad. El tratamiento de superficie NeoCare confiere al suelo Marmoredis una excelente resistencia a las manchas y facilita enormemente su limpieza y mantenimiento diario. Su construcción multicapa, compuesta por una capa de diseño de linóleo sobre soporte de yute natural, garantiza una alta resistencia al tránsito y una durabilidad excepcional. Estas propiedades lo convierten en la elección perfecta para entornos con alto nivel de exigencia. Con una clasificación 23/32/41, el linóleo Marmoredis 2,00 mm es apto para uso residencial intenso, comercial general e industrial moderado. Su resistencia al deslizamiento R9 proporciona seguridad en zonas de paso, mientras que su reacción al fuego Cfl-s1 cumple con las normativas más exigentes para espacios públicos y comerciales. Además, ofrece una reducción acústica de 3 dB que contribuye a crear ambientes más confortables y silenciosos. Disponible en formato de rollo de 2 metros de ancho por 31 metros de largo, el suelo Marmoredis permite cubrir grandes superficies de forma eficiente y con un resultado estético uniforme. Su instalación mediante encolado garantiza una fijación segura y duradera. Una solución completa para quienes buscan la belleza del mármol con las prestaciones y sostenibilidad del linóleo natural.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
