INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '947f31ef-024a-4eba-83a2-1899243039fa',
  'GRIP A500 MULTI',
  'imprimacion-multiusos-grip-a500-multi',
  'Descubre la imprimación Grip A500 Multi, una solución versátil y multiusos diseñada para aumentar la adhesión de compuestos autonivelantes y adhesivos para baldosas en superficies tanto absorbentes como no absorbentes. Especialmente indicada para obra nueva y rehabilitación, esta imprimación base...',
  'Descubre la imprimación Grip A500 Multi, una solución versátil y multiusos diseñada para aumentar la adhesión de compuestos autonivelantes y adhesivos para baldosas en superficies tanto absorbentes como no absorbentes. Especialmente indicada para obra nueva y rehabilitación, esta imprimación base agua facilita enormemente la aplicación de autonivelantes, garantizando resultados profesionales en todo tipo de proyectos de pavimentación. Formulada con una mezcla de resina acrílica modificada base agua, la imprimación Grip A500 Multi es completamente inodora y está lista para usar sin necesidad de preparación adicional. Cuando se usa diluida, controla y reduce la porosidad de los sustratos absorbentes en base de cemento, optimizando la adherencia de los materiales de acabado. Su color azul translúcido permite visualizar fácilmente las zonas ya tratadas durante la aplicación. Apta para suelos y paredes interiores así como para suelos exteriores, la Grip A500 Multi ofrece una extraordinaria versatilidad de aplicación. En pavimentos, es compatible con losas de hormigón, soleras de cemento, superficies de hormigón pulido, soleras de anhidrita, placas de yeso, azulejos antiguos, terracota, tableros de partículas y madera contrachapada. En paredes, funciona perfectamente sobre placas de yeso, mamparas de escayola, revoques y hormigón celular. Certificada con las más exigentes normativas medioambientales y de calidad interior, la imprimación Grip A500 Multi cuenta con clasificación A+ en emisiones al aire interior, certificación EC1 Plus de muy bajas emisiones, está libre de disolventes y verificada FDES. Una elección responsable y profesional para proyectos que exigen máxima calidad y respeto por el medio ambiente.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
