INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f77bbe3c-29c3-43cc-8a31-4ecca92181c7',
  'SL C990 SPRINTER',
  'pasta-autonivelante-secado-rapido-bostik-sl-c990-sprinter',
  'El SL C990 Sprinter es un compuesto autonivelante de fraguado ultrarrápido. Representa la solución más avanzada para profesionales que necesitan alisar y nivelar subsuelos en tiempos mínimos. Además, su innovadora formulación a base de cemento permite una recuperación excepcionalmente rápida. Ape...',
  'El SL C990 Sprinter es un compuesto autonivelante de fraguado ultrarrápido. Representa la solución más avanzada para profesionales que necesitan alisar y nivelar subsuelos en tiempos mínimos. Además, su innovadora formulación a base de cemento permite una recuperación excepcionalmente rápida. Apertura al tráfico: 45 min. Recubrimiento a partir de 90 min. Resistencia mecánica muy alta Gracias a estas características, es posible aplicar el adhesivo y colocar el pavimento final en el mismo día de trabajo. Por lo tanto, se reducen significativamente los plazos de ejecución en cualquier proyecto. Tiempos de Trabajo Optimizados Este producto ha sido desarrollado para responder a las exigencias más estrictas del sector. En primer lugar, los plazos ajustados y la eficiencia son factores determinantes en construcción y rehabilitación. Por esta razón, el SL C990 Sprinter ofrece tiempos de recuperación excepcionales. Con tan solo 45 minutos de espera, el suelo ya admite tráfico peatonal. Esto permite continuar con otras tareas de obra sin interrupciones prolongadas. Además, a partir de los 90 minutos ya es posible instalar el revestimiento definitivo en muchos casos. Alta Resistencia Mecánica La resistencia mecánica de este autonivelante garantiza un soporte sólido y duradero. En concreto, cuenta con clasificación C40 en resistencia a compresión. Asimismo, alcanza F10 en resistencia a flexión. Como resultado, supera ampliamente los requisitos técnicos de la mayoría de proyectos. Por consiguiente, es apto tanto para obra nueva como para rehabilitación y reforma. Versatilidad de Aplicación Otro de sus puntos fuertes es la versatilidad de aplicación. Por un lado, puede mezclarse y aplicarse de forma manual con batidor eléctrico. Por otro lado, también es compatible con bomba mezcladora continua para grandes superficies. En ambos casos, el tiempo de trabajo es de 20 minutos. Esto permite una aplicación cómoda y controlada antes del fraguado. Además, el rango de espesores va desde 1 hasta 10 mm en una sola capa. Certificaciones de Calidad El SL C990 Sprinter cuenta con importantes certificaciones. En primer lugar, dispone de EC1 Plus de muy bajas emisiones. También tiene clasificación A+ en emisiones al aire interior. Finalmente, incluye marcado CE europeo. Por lo tanto, es idóneo para todo tipo de espacios interiores. Esto incluye hospitales, centros educativos, residencias y espacios públicos con requisitos especiales.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
