INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '1be4ac87-b975-464f-8860-be70315bf449',
  'SL C340 LEVEL PLUS',
  'autonivelante-pavimentos-interiores-sl-c340-level-plus',
  'El SL C340 Level Plus es un compuesto autonivelante de altas prestaciones diseñado específicamente para uso en pavimentos interiores. Este producto destaca por su dureza reforzada y su capacidad de auto alisado. Además, es ideal para áreas de servicio pesado y ubicaciones con puntos de carga elev...',
  'El SL C340 Level Plus es un compuesto autonivelante de altas prestaciones diseñado específicamente para uso en pavimentos interiores. Este producto destaca por su dureza reforzada y su capacidad de auto alisado. Además, es ideal para áreas de servicio pesado y ubicaciones con puntos de carga elevados. Fácil de preparar Secado más rápido Dureza reforzada Pasta autonivelante adecuada para áreas de servicio pesado y ubicaciones con puntos de carga elevados como áreas comerciales, hospitales, hoteles... Aplicación en Capa Fina Una de las principales ventajas del SL C340 Level Plus es su capacidad de aplicación en capa fina. El rango de espesores va desde 1 hasta 10 mm en una sola aplicación. Como resultado, se adapta perfectamente a diferentes necesidades de nivelación. Además, genera menos polvo al lijar que otros productos del mercado. Esto facilita el trabajo en espacios ocupados o con requisitos de limpieza estrictos. Por consiguiente, es especialmente útil en rehabilitaciones de locales en funcionamiento. Versatilidad de Aplicación El SL C340 Level Plus ofrece gran flexibilidad en cuanto a métodos de aplicación. Por un lado, puede mezclarse y aplicarse de forma manual con batidor eléctrico. Por otro lado, también es compatible con bomba mezcladora continua para proyectos de mayor envergadura. En ambos casos, el tiempo de trabajo es de 20 minutos. Esto permite una aplicación cómoda antes de que comience el fraguado. Además, su propiedad de auto alisado facilita conseguir superficies perfectamente planas. Compatibilidad con Suelo Radiante Este autonivelante es totalmente apto para sistemas de calefacción por suelo radiante. Sin embargo, es importante seguir algunas recomendaciones. En primer lugar, la calefacción debe apagarse al menos 48 horas antes de comenzar el trabajo. Posteriormente, después de colocar el revestimiento, la calefacción debe subirse gradualmente. Este proceso debe realizarse en etapas a lo largo de 48 horas. De esta manera, se garantiza un curado óptimo sin fisuras ni problemas. Certificaciones de Calidad El SL C340 Level Plus cuenta con importantes certificaciones de calidad. En concreto, dispone de certificación EC1 de bajas emisiones. También tiene clasificación A+ en emisiones al aire interior. Por lo tanto, es idóneo para espacios con requisitos especiales de calidad ambiental. Esto incluye hospitales, centros educativos, guarderías y residencias de mayores.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
