INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e5f610a7-3191-4f76-8a93-3272b7b3ec70',
  'SL C510 PRO',
  'pasta-autonivelante-alta-resistencia-sl-c510-pro',
  'La pasta autonivelante SL C510 Pro es un compuesto de alta resistencia mecánica diseñado para uso interior. Esta pasta autonivelante destaca por su formulación avanzada sin contracción y su excelente adherencia. Además, no requiere lijado tras su aplicación, lo que agiliza los tiempos de obra. Al...',
  'La pasta autonivelante SL C510 Pro es un compuesto de alta resistencia mecánica diseñado para uso interior. Esta pasta autonivelante destaca por su formulación avanzada sin contracción y su excelente adherencia. Además, no requiere lijado tras su aplicación, lo que agiliza los tiempos de obra. Alta resistencia mecánica Fácil de aplicar Secado rápido Gracias a estas características, esta pasta autonivelante es la solución ideal para áreas de servicio pesado y alto tráfico peatonal. Por lo tanto, resulta perfecta para supermercados, grandes superficies comerciales, cocinas colectivas, aeropuertos y estaciones de tren. Asimismo, es apta tanto para proyectos de nueva construcción como para trabajos de renovación. Para más información sobre normativas de construcción, puedes consultar el Código Técnico de la Edificación. Pasta Autonivelante con Alta Resistencia Mecánica Una de las principales ventajas del SL C510 Pro es su alta resistencia a la punción. Esta característica lo convierte en la solución ideal para zonas sometidas a cargas elevadas. Como resultado, soporta sin problemas el paso constante de carretillas, transpaletas y equipos pesados. Con una clasificación C30 en resistencia a compresión y F7 en resistencia a flexión, supera los requisitos de la mayoría de proyectos exigentes. Por consiguiente, garantiza un soporte sólido y duradero durante toda la vida útil del pavimento. Aplicación Versátil de la Pasta Autonivelante El producto ofrece gran flexibilidad en cuanto a métodos de aplicación. Por un lado, puede aplicarse de forma manual utilizando un batidor eléctrico con hélice mezcladora. Por otro lado, es totalmente bombeable, lo que permite cubrir grandes superficies de forma rápida y uniforme. El tiempo de trabajo es de 20 minutos, suficiente para una aplicación cómoda y controlada. Además, el rango de espesores es muy amplio, desde 1 hasta 20 mm en una sola capa continua. Como resultado, se adapta a diferentes necesidades de nivelación sin requerir múltiples aplicaciones. Consulta nuestra guía de preparación de suelos para más consejos de aplicación. Pasta Autonivelante Sin Lijado Posterior A diferencia de otros autonivelantes del mercado, el SL C510 Pro no requiere lijado después de su aplicación. Esta ventaja reduce significativamente los tiempos de obra y los costes de mano de obra. Además, elimina la generación de polvo asociada al lijado, mejorando las condiciones de trabajo. Por lo tanto, es especialmente útil en rehabilitaciones de locales comerciales en funcionamiento. También resulta ideal para proyectos con plazos ajustados donde cada hora cuenta. Compatibilidad con Suelo Radiante Esta pasta autonivelante es compatible con sistemas de calefacción por suelo radiante. Sin embargo, es importante seguir algunas recomendaciones para garantizar resultados óptimos. En primer lugar, la calefacción debe apagarse al menos 48 horas antes de comenzar el trabajo. Posteriormente, después de colocar el revestimiento final, la calefacción debe subirse gradualmente. Este proceso debe realizarse en etapas a lo largo de 48 horas. De esta manera, se garantiza un curado correcto sin fisuras ni problemas de adherencia. Certificaciones de Calidad El SL C510 Pro cuenta con importantes certificaciones que avalan su calidad. En concreto, dispone de clasificación A+ en emisiones al aire interior. También cuenta con certificación FDES, marcado CE y sello QB de calidad francesa. Por lo tanto, es idóneo para espacios con requisitos especiales de calidad ambiental. Esto incluye hospitales, centros educativos, guarderías, residencias y espacios públicos. Para más información sobre certificaciones, consulta la web del fabricante. Áreas de Aplicación de la Pasta Autonivelante Esta pasta autonivelante ha sido diseñada específicamente para áreas de servicio pesado. Entre sus aplicaciones más habituales encontramos: Supermercados y grandes superficies comerciales Cocinas industriales y colectivas Aeropuertos y estaciones de tren Hospitales y centros sanitarios Hoteles y espacios de hostelería Naves logísticas y almacenes Su alta resistencia a la punción y al tráfico intenso lo convierten en la elección preferida de profesionales. Además, su excelente adherencia garantiza resultados duraderos incluso en las condiciones más exigentes. Consulta también nuestros otros productos de pasta autonivelante para encontrar la solución perfecta para tu proyecto.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
