INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ad435d20-1a30-4e78-8f74-383a4c7148e6',
  'STIX A800 PREMIUM',
  'cola-acrilica-revestimientos-stix-a800-premium',
  'La cola acrílica Premium es un adhesivo de altas prestaciones diseñado para la instalación de revestimientos ligeros. Esta cola acrílica está especialmente formulada para suelos LVT y cauchos. Además, es apta para todo tipo de locales, desde uso doméstico hasta zonas de tráfico intenso. Gracias a...',
  'La cola acrílica Premium es un adhesivo de altas prestaciones diseñado para la instalación de revestimientos ligeros. Esta cola acrílica está especialmente formulada para suelos LVT y cauchos. Además, es apta para todo tipo de locales, desde uso doméstico hasta zonas de tráfico intenso. Gracias a su avanzada formulación, esta cola acrílica ofrece una alta resistencia a la cizalla. Por lo tanto, garantiza que el revestimiento permanezca perfectamente fijado incluso en condiciones de uso exigentes. Además, proporciona un total bloqueo del pavimento, evitando desplazamientos y levantamientos. Cola Acrílica Versátil para Múltiples Revestimientos Una de las principales ventajas de este producto es su extraordinaria versatilidad. Esta cola acrílica es compatible con una amplia gama de revestimientos ligeros. Por consiguiente, se convierte en la solución ideal para instaladores profesionales que trabajan con diferentes materiales. Entre los revestimientos compatibles encontramos suelos LVT en lamas y losetas, PVC homogéneo y heterogéneo, cauchos en losetas y rollos, moquetas de todo tipo, fibras naturales con reverso de látex y poliolefinas. Además, es apta para aplicaciones en suelos y paredes, incluyendo duchas de PVC y placas de protección mural. Cola Acrílica Sin Disolventes ni Ftalatos La formulación de este adhesivo está libre de disolventes y ftalatos. Por lo tanto, es una opción segura tanto para los instaladores como para los usuarios finales. Además, contribuye a mantener una buena calidad del aire interior en los espacios donde se instala. Esta característica la hace especialmente adecuada para proyectos donde la sostenibilidad y la salud son prioritarias. Por ejemplo, hospitales, centros educativos, guarderías y espacios públicos valoran cada vez más este tipo de productos respetuosos con el medio ambiente. Cola Acrílica Compatible con Suelo Radiante Este adhesivo es totalmente compatible con sistemas de calefacción por suelo radiante. Sin embargo, es importante seguir algunas recomendaciones para garantizar resultados óptimos. En primer lugar, la calefacción debe apagarse al menos 48 horas antes de comenzar la instalación. Una vez finalizado el trabajo, la calefacción debe subirse gradualmente. Este proceso garantiza un curado correcto del adhesivo sin problemas de adherencia. De esta manera, se consiguen instalaciones duraderas incluso con calefacción radiante. Alta Resistencia a la Cizalla La resistencia a la cizalla es una característica fundamental en adhesivos para pavimentos. Esta cola acrílica ofrece una resistencia excepcional que mantiene el revestimiento perfectamente fijado. Por consiguiente, soporta el tráfico intenso, el paso de carretillas y el movimiento de mobiliario sin problemas. El agarre definitivo se alcanza a las 24 horas de la instalación. Sin embargo, el tráfico peatonal puede abrirse a partir de las 12 horas. Estos tiempos permiten una rápida puesta en servicio de los espacios renovados. Aplicación Profesional El producto se aplica de forma sencilla con espátula dentada o rodillo. El rodillo está especialmente recomendado para aplicaciones verticales y revestimientos finos. Además, mejora el tiempo de gomaje del adhesivo en estas situaciones. El rendimiento varía entre 250 y 400 g/m² según el tipo de revestimiento y la espátula utilizada. Los revestimientos con reverso liso requieren menos adhesivo que aquellos con reverso rugoso o con grandes relieves. Para más información sobre técnicas de instalación de pavimentos, puedes consultar el Código Técnico de la Edificación. También puedes visitar la web del fabricante para más detalles técnicos.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '6e5dbefc-8a95-4fd5-8f50-094739920fe8',
  'STIX A340 LVT PROJECT',
  'stix-a340-lvt-project',
  'El adhesivo acrílico Stix A340 LVT Project es un producto de baja emisión especialmente diseñado para suelos LVT. Este adhesivo acrílico ofrece una solución profesional para el pegado de pavimentos flexibles en lamas, losetas y rollos. Además, está libre de disolventes, lo que garantiza seguridad...',
  'El adhesivo acrílico Stix A340 LVT Project es un producto de baja emisión especialmente diseñado para suelos LVT. Este adhesivo acrílico ofrece una solución profesional para el pegado de pavimentos flexibles en lamas, losetas y rollos. Además, está libre de disolventes, lo que garantiza seguridad durante la aplicación. Gracias a su formulación avanzada, este adhesivo acrílico proporciona alta adherencia inicial y excelente cohesión final. Por lo tanto, asegura que el revestimiento quede perfectamente fijado desde el primer momento. Además, es recomendado por los principales fabricantes de suelos LVT del mercado. Adhesivo Acrílico Ideal para Suelos LVT El Stix A340 LVT Project ha sido desarrollado específicamente para instalaciones de suelos vinílicos de lujo. Su formulación optimizada garantiza un pegado perfecto en lamas y losetas LVT. Además, también es compatible con pavimentos homogéneos y heterogéneos de PVC. Este adhesivo acrílico ofrece un tiempo abierto de 35 minutos, suficiente para trabajar cómodamente. Por consiguiente, permite realizar ajustes durante la instalación antes de que el adhesivo fije definitivamente. El tráfico peatonal puede abrirse a partir de las 12 horas. Adhesivo Acrílico de Baja Emisión La calidad del aire interior es cada vez más importante en proyectos de construcción y rehabilitación. Este adhesivo acrílico cuenta con certificación EC1 Plus de muy bajas emisiones. También dispone de clasificación A+ en emisiones al aire interior. Por lo tanto, es la elección ideal para espacios donde la calidad ambiental es prioritaria. Esto incluye hospitales, centros educativos, guarderías, oficinas y viviendas. Además, su formulación libre de disolventes protege la salud de los instaladores. Adhesivo Acrílico Compatible con Suelo Radiante El Stix A340 LVT Project es totalmente compatible con sistemas de calefacción por suelo radiante. Funciona tanto con sistemas de agua caliente como con suelo radiante eléctrico. Sin embargo, es importante seguir las recomendaciones de aplicación. La calefacción debe apagarse 48 horas antes de la instalación. Después de colocar el revestimiento, debe permanecer apagada 48 horas más. Finalmente, se sube gradualmente hasta alcanzar la temperatura de funcionamiento. Fácil Aplicación Este adhesivo acrílico destaca por su facilidad de aplicación. Se extiende uniformemente con espátula dentada sostenida en ángulo de 60°. El tiempo de espera antes de colocar el revestimiento es de 5 a 10 minutos. Para minimizar las estrías visibles a través del revestimiento, se puede usar un rodillo humedecido con adhesivo. Esto crea una apariencia uniforme y maximiza el contacto con el pavimento. Después de instalar, se pasa rodillo pesado para asegurar la adhesión.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
