INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'adbd9f90-ba95-4e6b-8c66-2f098ed6d59d',
  'STIX A300 MULTI FLOOR',
  'adhesivo-multiusos-suelos-a300-multi-floor',
  'El adhesivo multiusos Stix A300 Multi Floor es un producto de altas prestaciones para la instalación de pavimentos blandos. Este adhesivo multiusos destaca por su gran polivalencia, siendo capaz de instalar la mayoría de revestimientos de suelo flexibles. Además, es apto tanto para suelos como pa...',
  'El adhesivo multiusos Stix A300 Multi Floor es un producto de altas prestaciones para la instalación de pavimentos blandos. Este adhesivo multiusos destaca por su gran polivalencia, siendo capaz de instalar la mayoría de revestimientos de suelo flexibles. Además, es apto tanto para suelos como para paredes en aplicaciones interiores. Gracias a su formulación avanzada, este adhesivo multiusos ofrece alta adherencia inicial combinada con un largo tiempo abierto. Por lo tanto, proporciona flexibilidad durante la instalación permitiendo ajustes antes del curado definitivo. Además, es recomendado por la mayoría de fabricantes de pavimentos del mercado. Adhesivo Multiusos con Certificaciones Ambientales El Stix A300 Multi Floor es un adhesivo acrílico de bajas emisiones de COV. Cuenta con las certificaciones más exigentes del mercado: EC1, A+, LEED y BREEAM. Por consiguiente, es la elección perfecta para proyectos de construcción sostenible y edificios con requisitos de calidad ambiental. Esta formulación libre de disolventes y ftalatos garantiza seguridad para instaladores y usuarios finales. Además, contribuye a mantener una excelente calidad del aire interior. Por lo tanto, es ideal para hospitales, centros educativos, guarderías, oficinas y viviendas. Adhesivo Multiusos con Largo Tiempo Abierto Una de las principales ventajas del Stix A300 Multi Floor es su largo tiempo abierto de 50 a 60 minutos. Esta característica permite trabajar con comodidad en superficies amplias. Además, facilita realizar ajustes durante la instalación antes de que el adhesivo fije definitivamente. El curado es fuerte y rápido, alcanzando el agarre definitivo entre 24 y 48 horas. Sin embargo, el tráfico peatonal puede abrirse a partir de las 12 horas. Estos tiempos permiten una rápida puesta en servicio de los espacios renovados. Adhesivo Multiusos para Todos los Locales Este adhesivo multiusos es apto para todo tipo de pavimentos resilientes en edificios privados, públicos o colectivos. Su versatilidad lo convierte en la solución única para múltiples aplicaciones. Por consiguiente, simplifica la gestión de materiales en proyectos con diferentes tipos de revestimientos. Además, es totalmente compatible con sistemas de calefacción por suelo radiante. Siguiendo las recomendaciones de aplicación, garantiza instalaciones duraderas incluso con calefacción activa. Fácil Aplicación El Stix A300 Multi Floor destaca por su facilidad de uso. Se aplica uniformemente con llana dentada adecuada según la porosidad del soporte. Para revestimientos finos, se recomienda alisar con rodillo de espuma humedecido previamente con adhesivo. El tiempo de espera antes de colocar el revestimiento es de 10 a 15 minutos aproximadamente. En el caso de pegado de PVC sobre PVC o superficies impermeables, este tiempo puede variar de 30 a 90 minutos dependiendo de las condiciones ambientales. Para más información técnica, puedes consultar la documentación del fabricante. También puedes revisar el Código Técnico de la Edificación para normativas de construcción.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
