  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '860a9df6-c628-4e06-8256-250ebfc59414',
  'STIX A100 PROJECT',
  'adhesivo-suelos-flexibles-stix-a100-project',
  'El adhesivo para suelos flexibles Stix A100 Project es un producto de alta adherencia y agarre inmediato. Este adhesivo para suelos flexibles está especialmente recomendado para cubiertas rígidas y difíciles donde otros adhesivos fallan. Además, ofrece alta tolerancia frente a diferentes condicio...',
  'El adhesivo para suelos flexibles Stix A100 Project es un producto de alta adherencia y agarre inmediato. Este adhesivo para suelos flexibles está especialmente recomendado para cubiertas rígidas y difíciles donde otros adhesivos fallan. Además, ofrece alta tolerancia frente a diferentes condiciones ambientales. Gracias a su formulación como emulsión de resina sintética, este adhesivo para suelos flexibles proporciona un tiempo de trabajo prolongado de hasta 45 minutos. Por lo tanto, permite trabajar con comodidad en superficies amplias. Además, es recomendado por los principales fabricantes de pavimentos del mercado. Adhesivo para Suelos Flexibles con Alta Versatilidad El Stix A100 Project es compatible con una amplia gama de pavimentos vinílicos y textiles. Este adhesivo para suelos flexibles funciona perfectamente con láminas y baldosas de PVC homogéneas y heterogéneas, cubiertas aglomeradas de PVC-corcho, vinilo expandido y baldosas semiflexibles. Además, es apto para tejidos como fieltro de aguja, moquetas con refuerzo de espuma, pavimentaciones textiles no tejidas, polipropileno Action Bac y fibras naturales como coco, sisal y hierbas marinas. Por consiguiente, se convierte en una solución única para múltiples tipos de revestimientos. Adhesivo para Suelos Flexibles Apto para PVC sobre PVC Una característica destacada del Stix A100 Project es su capacidad para pegar PVC a PVC. Esta función lo hace ideal para proyectos de rehabilitación donde se instala nuevo vinilo sobre existente. Además, es apto incluso para zonas de ducha donde la impermeabilidad es crítica. El tiempo abierto para pegar PVC sobre PVC o superficies impermeables puede variar de 30 a 90 minutos. Por lo tanto, proporciona flexibilidad suficiente para ajustar el revestimiento correctamente. Esto depende de las condiciones ambientales y la cantidad de adhesivo aplicada. Adhesivo para Suelos Flexibles Resistente Este adhesivo para suelos flexibles ofrece resistencia excepcional a ruedas pivotantes. También es resistente al plastificante del revestimiento de PVC, evitando problemas de migración. Por consiguiente, garantiza instalaciones duraderas en zonas de alto tráfico con sillas de oficina y carros. El agarre definitivo se alcanza a las 24 horas de la instalación. Sin embargo, el tráfico peatonal puede abrirse a partir de las 12 horas aproximadamente. Estos tiempos permiten una rápida puesta en servicio de los espacios renovados. Adhesivo para Suelos Flexibles Compatible con Suelo Radiante El Stix A100 Project es totalmente compatible con sistemas de calefacción por losa radiante. Esta característica amplía sus posibilidades de uso en viviendas y edificios con este tipo de instalaciones. Siguiendo las recomendaciones de aplicación, garantiza resultados óptimos. Para más información técnica, puedes consultar la web del fabricante. También puedes revisar el Código Técnico de la Edificación para normativas de construcción.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
