INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '13f2498a-d1a2-4973-81a9-315921dd286d',
  'FIX A320 TACK',
  'adhesivo-moquetas-removibles-bostik-fix-a320-tack',
  'El adhesivo para moquetas removibles Fix A320 Tack es un producto tackifier especialmente diseñado para entornos de oficina. Este adhesivo para moquetas removibles proporciona una película pegajosa permanente que facilita la extracción y sustitución de losetas textiles. Además, su formulación sin...',
  'El adhesivo para moquetas removibles Fix A320 Tack es un producto tackifier especialmente diseñado para entornos de oficina. Este adhesivo para moquetas removibles proporciona una película pegajosa permanente que facilita la extracción y sustitución de losetas textiles. Además, su formulación sin disolventes garantiza que no manche el revestimiento. Gracias a sus características únicas, este adhesivo para moquetas removibles es la solución ideal para suelos técnicos elevados y sistemas de paneles de acceso. Por lo tanto, permite el mantenimiento y renovación de pavimentos sin necesidad de retirar todo el adhesivo existente. Adhesivo para Moquetas Removibles en Oficinas El Fix A320 Tack ha sido desarrollado específicamente para pavimentos de oficinas modernas. Este adhesivo para moquetas removibles permite instalar losetas textiles que pueden retirarse y sustituirse fácilmente. Por consiguiente, facilita el mantenimiento, la limpieza y el acceso a instalaciones bajo el suelo. Es compatible con moquetas en losetas con soporte de fieltro, betún o fibra no tejida. Además, su tiempo abierto permanentemente pegajoso significa que las baldosas pueden retirarse y recolocarse sin añadir producto adicional. Adhesivo para Moquetas Removibles de Bajo Consumo Una de las principales ventajas del Fix A320 Tack es su bajo consumo. El rendimiento oscila entre 60 y 100 g/m² dependiendo del tipo de sustrato. Por lo tanto, un bote de 15 kg puede cubrir entre 150 y 250 m² de superficie. La aplicación se realiza fácilmente con rodillo tipo anticaída de 12 mm. Esta técnica permite una distribución uniforme y rápida del producto. Además, reduce los tiempos de instalación en comparación con otros métodos de aplicación. Adhesivo para Moquetas Removibles con Certificaciones Este adhesivo para moquetas removibles cuenta con las certificaciones más exigentes del mercado. Dispone de clasificación A+ en emisiones al aire interior y certificación EC1 de muy bajas emisiones. También está verificado FDES y es libre de disolventes y ftalatos. Por lo tanto, es la elección perfecta para oficinas y espacios de trabajo donde la calidad del aire interior es prioritaria. Además, contribuye a la obtención de certificaciones de edificios sostenibles como LEED y BREEAM. Adhesivo para Moquetas Removibles Compatible con Suelo Radiante El Fix A320 Tack es compatible con sistemas de calefacción por suelo radiante. Sin embargo, es importante seguir las recomendaciones de aplicación. La calefacción debe apagarse 48 horas antes de la instalación. Después de instalar las losetas, se debe esperar 7 días antes de encender gradualmente la calefacción. Este tiempo permite que el adhesivo desarrolle completamente sus propiedades de agarre permanente.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
