INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e577364c-5a46-41fb-88e4-c78ba2d0d614',
  'CONTACT 1465',
  'cola-contacto-uso-general-bostik-contact-1465',
  'La cola de contacto Contact 1465 es un adhesivo de uso general ideal para trabajos de bricolaje y reparación. Esta cola de contacto destaca por su pegado inmediato y definitivo sobre una gran variedad de materiales. Además, ofrece excelente resistencia a la temperatura y a la humedad. Gracias a s...',
  'La cola de contacto Contact 1465 es un adhesivo de uso general ideal para trabajos de bricolaje y reparación. Esta cola de contacto destaca por su pegado inmediato y definitivo sobre una gran variedad de materiales. Además, ofrece excelente resistencia a la temperatura y a la humedad. Gracias a su formulación a base de caucho de policloropreno, esta cola de contacto proporciona uniones flexibles y duraderas. Por lo tanto, es perfecta para aplicaciones donde se requiere cierta elasticidad en la unión. Además, se aplica fácilmente a pincel, rodillo o espátula. Cola de Contacto Multiusos El Contact 1465 tiene una gran variedad de aplicaciones en diferentes sectores. Esta cola de contacto es adecuada para el pegado de madera y estratificados, cuero y similares, gomas, caucho, poliéster, lana de roca, cerámica y metales. Por consiguiente, se convierte en una solución única para múltiples necesidades. En la industria de la construcción, es ideal para pegar plásticos estratificados, paneles acústicos, madera, laminados y lana de roca. Además, en carpintería y tapicería funciona perfectamente con contraplacado, cantos, materiales de tapicería, piel, espumas y tejidos. Cola de Contacto con Pegado Inmediato Una de las principales ventajas de esta cola de contacto es su pegado inmediato y definitivo. Una vez que las superficies se unen, la adhesión es instantánea. Por lo tanto, no requiere tiempos de prensado prolongados ni sistemas de sujeción complejos. El tiempo de secado antes de unir las piezas es de 10 a 15 minutos aproximadamente. Después del secado, se dispone de 30 minutos para realizar la unión. Sin embargo, no conviene forzar la unión durante las primeras 24 horas para garantizar un curado completo. Cola de Contacto Resistente Esta cola de contacto ofrece excelente resistencia a condiciones adversas. Soporta temperaturas de entre 70 °C y 90 °C sin perder sus propiedades adhesivas. Además, es resistente a la humedad, lo que la hace apta para aplicaciones en zonas húmedas. El pegado flexible que proporciona permite absorber vibraciones y movimientos sin que la unión se rompa. Por consiguiente, es ideal para aplicaciones donde los materiales pueden expandirse o contraerse con los cambios de temperatura. Cola de Contacto en Múltiples Formatos El Contact 1465 está disponible en una amplia gama de formatos para adaptarse a cada necesidad. Desde tubos pequeños de 55 ml para reparaciones puntuales hasta botes de 25 litros para uso industrial. Por lo tanto, ofrece la cantidad justa para cada tipo de proyecto.',
  'e9fcbf03-df7f-4ec5-80fb-31e9ea8ce400',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
