INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '779b227a-6440-4f1e-87af-75bf8145c1a1',
  'NEOFIX SPRAY',
  'cola-contacto-spray-bostik-neofix',
  'La cola de contacto en spray Neofix Spray es un adhesivo de neopreno en aerosol diseñado para todos los soportes. Esta cola de contacto en spray ofrece adherencia inmediata y alta resistencia en una aplicación sencilla y uniforme. Además, está lista al uso sin necesidad de preparación previa. Gra...',
  'La cola de contacto en spray Neofix Spray es un adhesivo de neopreno en aerosol diseñado para todos los soportes. Esta cola de contacto en spray ofrece adherencia inmediata y alta resistencia en una aplicación sencilla y uniforme. Además, está lista al uso sin necesidad de preparación previa. Gracias a su formato en aerosol, esta cola de contacto en spray es perfecta para lugares inaccesibles donde otros adhesivos no llegan. Por lo tanto, facilita el trabajo en rincones, superficies irregulares y zonas de difícil acceso. Además, es apta tanto para interior como para exterior. Cola de Contacto en Spray Multiusos El Neofix Spray es compatible con una amplia variedad de materiales. Esta cola de contacto en spray funciona perfectamente con cartón, papel, textiles, fieltro, corcho, madera y productos de madera. También es adecuada para cuero, espuma, metal y materiales aislantes de poliestireno o poliuretano. Además, es compatible con la mayoría de plásticos del mercado. Sin embargo, no es apta para polietileno y polipropileno debido a sus características químicas. Por consiguiente, es importante verificar el material antes de aplicar. Cola de Contacto en Spray de Fácil Aplicación Una de las principales ventajas del Neofix Spray es su aplicación sencilla y uniforme. Esta cola de contacto en spray se vaporiza a unos 30 cm del material a pegar. Después, se espera aproximadamente 5 minutos para la evaporación del disolvente antes de unir las piezas. El formato en aerosol permite una distribución homogénea del adhesivo sin grumos ni excesos. Por lo tanto, se consiguen acabados profesionales con mínimo esfuerzo. Además, la boquilla permite controlar el caudal de aplicación con precisión. Cola de Contacto en Spray con Alta Resistencia El Neofix Spray proporciona uniones de alta resistencia una vez curado. Esta cola de contacto en spray ofrece adherencia inmediata que se fortalece con el tiempo. Por consiguiente, es ideal para trabajos que requieren resistencia mecánica y durabilidad. Para materiales muy porosos o aplicaciones que requieran máxima resistencia, se recomienda aplicar a dos caras. Después de los 5 minutos de evaporación en ambas superficies, se unen las piezas para conseguir una adhesión óptima. Cola de Contacto en Spray para Interior y Exterior A diferencia de otros adhesivos de contacto, el Neofix Spray es apto para uso en interior y exterior. Esta versatilidad amplía sus posibilidades de aplicación en múltiples proyectos. Por lo tanto, es ideal para trabajos de bricolaje, manualidades, tapicería y reparaciones diversas.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
