INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '26a88882-fc04-4853-8dca-759658914012',
  'MSP TURBO',
  'bostik-msp-turbo-adhesivo-agarre-inmediato',
  'Bostik MSP Turbo es un adhesivo elástico de agarre inicial inmediato y elevada resistencia, capaz de fijar elementos en tan solo 3 segundos. Es la solución ideal para pegados verticales pesados y posee excelentes propiedades adhesivas tanto en exteriores (paneles, tejas, cornisas) como en interio...',
  'Bostik MSP Turbo es un adhesivo elástico de agarre inicial inmediato y elevada resistencia, capaz de fijar elementos en tan solo 3 segundos. Es la solución ideal para pegados verticales pesados y posee excelentes propiedades adhesivas tanto en exteriores (paneles, tejas, cornisas) como en interiores (zócalos, espejos, revestimientos). Su fórmula avanzada permite la aplicación sobre superficies húmedas e incluso bajo el agua. Además, es altamente resistente a la intemperie, los rayos UV, el moho y las bacterias, garantizando una fijación duradera sin contener disolventes ni isocianatos.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
