INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'f5427696-b9f7-4b70-890f-93d3ffea5948',
  'Adhesivo DECO GREEN',
  'adhesivo-cesped-artificial-deco-green',
  'El Adhesivo DECO GREEN es la solución profesional definitiva para la instalación y reparación de césped artificial. Formulado con tecnología avanzada de Polímeros MS, este adhesivo destaca por su color verde, diseñado específicamente para integrarse visualmente y disimular las uniones en el céspe...',
  'El Adhesivo DECO GREEN es la solución profesional definitiva para la instalación y reparación de césped artificial. Formulado con tecnología avanzada de Polímeros MS, este adhesivo destaca por su color verde, diseñado específicamente para integrarse visualmente y disimular las uniones en el césped. Es un producto exento de disolventes, siliconas e isocianatos, lo que garantiza una aplicación prácticamente sin olor y sin la formación de burbujas. Su gran versatilidad permite una adhesión excelente incluso sobre superficies húmedas, siendo ideal para proyectos de jardinería, paisajismo y pistas deportivas (fútbol, tenis, pádel) . Además, ofrece una resistencia excepcional a la intemperie y estabilidad ante los rayos UV, asegurando la durabilidad de sus instalaciones al aire libre.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
