INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a12d45a7-540d-4a2f-8121-4e8a427654dc',
  'Cinta Adhesiva de Doble Cara Azul',
  'cinta-azul-doble-cara-removible-dd890',
  'La cinta azul doble cara DD-890 es una solución biadhesiva de alto rendimiento diseñada para profesionales que necesitan una fijación temporal pero segura en todo tipo de proyectos de instalación y decoración. Su característica más destacada es el sistema de doble adhesivo diferenciado: mientras ...',
  'La cinta azul doble cara DD-890 es una solución biadhesiva de alto rendimiento diseñada para profesionales que necesitan una fijación temporal pero segura en todo tipo de proyectos de instalación y decoración. Su característica más destacada es el sistema de doble adhesivo diferenciado: mientras una cara ofrece adhesión permanente para anclarse firmemente a la superficie base, la otra cara presenta un adhesivo removible que permite retirar el material adherido sin dejar ningún tipo de residuo. Esta tecnología la convierte en la opción ideal para trabajos donde la limpieza y la reversibilidad son requisitos fundamentales. Fabricada con un soporte de polietileno de baja densidad en color azul semitransparente, esta cinta doble cara combina flexibilidad y resistencia mecánica para adaptarse a superficies irregulares sin perder sus propiedades adhesivas. El adhesivo de caucho sintético proporciona un excelente tack inicial, lo que significa que la cinta agarra de forma inmediata al contacto, facilitando enormemente el trabajo de instalación y reduciendo los tiempos de ejecución en obra. Una de las principales ventajas de la cinta biadhesiva DD-890 es su versatilidad de aplicación. Resulta especialmente eficaz para el montaje de moquetas, suelos vinílicos, alfombras y otros pavimentos flexibles sobre superficies delicadas que no pueden dañarse durante la instalación ni al retirar el revestimiento. Pavimentos como el parqué de madera, las baldosas cerámicas, el mármol pulido o el terrazo requieren soluciones adhesivas que garanticen una sujeción firme durante el uso pero que permitan una remoción limpia cuando sea necesario realizar cambios o renovaciones. Esta cinta doble cara removible cumple perfectamente con ambos requisitos. Más allá del sector de la instalación de suelos, la cinta azul DD-890 encuentra numerosas aplicaciones en el ámbito de la decoración de interiores, la cartelería promocional y el montaje de eventos. Cualquier elemento decorativo, cartel publicitario, señalización temporal o protección de superficies que deba retirarse en un plazo relativamente corto puede fijarse con total seguridad utilizando esta cinta biadhesiva sin residuos. Los profesionales del visual merchandising, los escaparatistas y los organizadores de ferias y eventos valoran especialmente esta propiedad, ya que les permite trabajar con la tranquilidad de saber que no dejarán marcas ni daños en las superficies una vez finalizado el montaje. El protector de papel bisiliconado blanco de 80 gramos facilita la manipulación y el corte de la cinta, además de proteger el adhesivo hasta el momento de su aplicación. Este liner se retira con facilidad, permitiendo un trabajo ágil y preciso incluso cuando se manejan grandes longitudes de cinta. La semitransparencia del soporte azul también resulta práctica durante la instalación, ya que permite visualizar la posición exacta de la cinta sobre la superficie sin necesidad de realizar marcas adicionales. Para obtener el máximo rendimiento de la cinta doble cara DD-890, es importante seguir algunas recomendaciones de aplicación. Las superficies de contacto deben estar completamente secas y libres de polvo, aceites, grasas o cualquier otro contaminante que pueda interferir con la adhesión. El rango de temperatura óptimo para la aplicación se sitúa entre los 20 °C y los 40 °C, desaconsejándose su uso por debajo de los 10 °C ya que el frío puede afectar negativamente al desarrollo de las propiedades adhesivas. Cuando se almacena correctamente en sus cajas originales a una temperatura de 23 °C y una humedad relativa del 65%, el producto mantiene todas sus características durante un período de seis meses. La cinta biadhesiva azul DD-890 representa una solución profesional, fiable y limpia para todas aquellas aplicaciones donde la fijación temporal y la remoción sin residuos son prioritarias. Su combinación de adhesivo permanente y removible, junto con sus excelentes propiedades mecánicas, la convierten en una herramienta indispensable para instaladores de pavimentos, decoradores, escaparatistas y profesionales del montaje de eventos que buscan resultados impecables sin comprometer la integridad de las superficies. Medida: 50ml x 30mm',
  'e9fcbf03-df7f-4ec5-80fb-31e9ea8ce400',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
