INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'bae455fe-8191-4596-8e9c-45bd4d66c364',
  'Suelo Caucho Sportdis Puzzle 2.0',
  'suelo-caucho-sportdis-puzzle-2-0',
  'Sportdis® puzzle 2.0 ofrece un revestimiento de suelo de seguridad para interiores en formato modular tipo puzzle. Cada pieza mide 1030 x 1030 mm y cubre un área efectiva de 1000 x 1000 mm. Además, está disponible en espesores de 6, 8 y 10 mm con acabado de gránulo fino. El sistema combina las pr...',
  'Sportdis® puzzle 2.0 ofrece un revestimiento de suelo de seguridad para interiores en formato modular tipo puzzle. Cada pieza mide 1030 x 1030 mm y cubre un área efectiva de 1000 x 1000 mm. Además, está disponible en espesores de 6, 8 y 10 mm con acabado de gránulo fino. El sistema combina las propiedades de Sportdis® color y Sportdis® purcolor. Por ello, puedes elegir entre siete opciones de color: negro, gris, azul, rojo, purcolor gris claro, purcolor gris oscuro y amarillo neón brillante. Gracias a esta variedad, es posible crear combinaciones creativas de colores y patrones. Este suelo modular destaca por su versatilidad y facilidad de instalación. De hecho, permite montarse y desmontarse sin adhesivos. Asimismo, cumple con las normativas europeas más exigentes en emisiones VOC. En consecuencia, cuenta con la certificación Indoor Air Comfort Gold y Blue Angel. También es compatible con los sistemas BREEAM y LEED.',
  '2bb9639c-bec5-4bfd-8811-f7eb88a51944',
