INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '02afc0a2-b3f2-41c6-816f-32203b231826',
  'Film de Polietileno G300 (PEBD) - 100% Reciclado',
  'film-polietileno-g300-reciclado-300',
  'El Film de Polietileno de Baja Densidad (PEBD) G300 de Derplas es una solución profesional diseñada para ofrecer máxima resistencia, protección y sostenibilidad en aplicaciones industriales, de construcción, agrícolas y de embalaje. Se trata de una lámina plástica de alto rendimiento, ideal para ...',
  'El Film de Polietileno de Baja Densidad (PEBD) G300 de Derplas es una solución profesional diseñada para ofrecer máxima resistencia, protección y sostenibilidad en aplicaciones industriales, de construcción, agrícolas y de embalaje. Se trata de una lámina plástica de alto rendimiento, ideal para entornos exigentes donde se requiere una barrera eficaz frente a la humedad, el polvo y los agentes externos. Fabricado con material reciclado postconsumo al 100%, este film contribuye activamente a la economía circular, reduciendo el impacto ambiental sin comprometer sus propiedades técnicas. Su espesor de 300 galgas (75 micras) proporciona una excelente resistencia mecánica, permitiendo su uso tanto en protección de superficies como en el embalaje y paletizado de mercancías. Gracias a su formulación técnica avanzada, el Film G300 mantiene su estabilidad y durabilidad incluso en condiciones extremas de temperatura, conservando su flexibilidad y capacidad protectora tanto en ambientes de frío intenso como en exposiciones prolongadas al calor. Esto lo convierte en una opción fiable para aplicaciones exteriores y usos continuados en sectores profesionales. El Film PEBD G300 es ampliamente utilizado en construcción, para proteger suelos, paredes y materiales durante obras; en industria y logística, como funda o lámina retráctil para palets y mercancía; y en agricultura, como plástico para ensilaje y protección de cultivos, garantizando seguridad y conservación en cada aplicación.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
