INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'a7ac8a4f-9955-4431-8196-6ceb0fd0ca30',
  'Arena de Silice',
  'arena-de-silice',
  'La arena de sílice para filtración de piscinas es un componente esencial para mantener el agua limpia, cristalina y libre de impurezas durante toda la temporada de baño. Este saco de 25 kg contiene arena de sílice de alta pureza, especialmente seleccionada y tratada para su uso en sistemas de dep...',
  'La arena de sílice para filtración de piscinas es un componente esencial para mantener el agua limpia, cristalina y libre de impurezas durante toda la temporada de baño. Este saco de 25 kg contiene arena de sílice de alta pureza, especialmente seleccionada y tratada para su uso en sistemas de depuración de piscinas residenciales, comunitarias y semiprofesionales. Gracias a su granulometría controlada de 0,4 a 0,8 mm, este medio filtrante ofrece un equilibrio perfecto entre capacidad de retención de partículas y permeabilidad, lo que permite una circulación eficiente del agua sin obstrucciones ni pérdidas de presión. Compatible con filtros de arena de alto rendimiento, esta arena de sílice soporta caudales de filtración de hasta 250 m³/h, lo que la hace adecuada tanto para piscinas de uso doméstico como para instalaciones de mayor tamaño. El proceso de filtración a través de arena de sílice elimina eficazmente partículas en suspensión, sedimentos, residuos orgánicos y microimpurezas que el agua arrastra, contribuyendo a reducir el consumo de productos químicos y a prolongar la vida útil del sistema de depuración. La arena de sílice destaca por su elevada resistencia mecánica y química, lo que garantiza una larga durabilidad sin degradarse ni compactarse con el uso continuado. A diferencia de otros medios filtrantes, no libera sustancias al agua ni altera sus propiedades, asegurando un baño seguro y saludable para toda la familia. Su formato en saco de 25 kg facilita el transporte, almacenamiento y manipulación, permitiendo recargar el filtro de forma cómoda y sin desperdicios. Para obtener los mejores resultados, se recomienda realizar contralavados periódicos del filtro y renovar completamente la carga de arena cada 3 a 5 años, dependiendo del uso y las condiciones del agua. Mantener el medio filtrante en óptimas condiciones es fundamental para disfrutar de una piscina impecable y reducir el esfuerzo de mantenimiento a lo largo del tiempo. Todos los productos distribuidos por Disstands incluyen una garantía de tres años desde la fecha de compra, respaldando la calidad y fiabilidad de cada artículo.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
