INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '17e0a921-a26e-4928-86d3-1571c3b154c7',
  'Lámina Acústica de Polietileno Reticulado 5mm (50ml x 2m)',
  'lamina-acustica-polietileno-5mm-impacto',
  'Esta lámina acústica de polietileno reticulado es una solución de alto rendimiento diseñada específicamente para el aislamiento frente al ruido de impacto en suelos y forjados. Con un espesor de solo 5 mm, este material actúa como un amortiguador elástico eficiente dentro de sistemas de masa-reso...',
  'Esta lámina acústica de polietileno reticulado es una solución de alto rendimiento diseñada específicamente para el aislamiento frente al ruido de impacto en suelos y forjados. Con un espesor de solo 5 mm, este material actúa como un amortiguador elástico eficiente dentro de sistemas de masa-resorte-masa, siendo ideal para su aplicación en viviendas, hoteles y centros comerciales. Su diseño de celda cerrada permite obtener altos rendimientos acústicos sin sacrificar la altura útil de las estancias, lo que la convierte en una opción técnica superior para proyectos de edificación moderna. Gracias a sus propiedades físicas, esta lámina es altamente recomendada para sistemas de calefacción radiante, ayudando a atenuar frecuencias bajas, medias y altas en locales comerciales y residenciales. Además de su eficiencia térmica y acústica, destaca por su compromiso ambiental, ya que el 5% de su materia prima proviene de materiales reciclados. Su formato en rollo facilita una instalación rápida y continua, asegurando una reducción del ruido de impacto superior a los 20 dB cuando se combina con losas prefabricadas o morteros adecuados.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
