INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '19489d12-6bf7-441f-8883-aa7b5c27cd7f',
  'Lámina Acústica de Polietileno Reticulado 10mm (25ml x 2m)',
  'lamina-acustica-10mm-distands-suelos',
  'Esta lámina acústica de polietileno reticulado de Distands es una solución de aislamiento de nivel superior, diseñada específicamente para mitigar el ruido de impacto en suelos y forjados de edificios con altas exigencias acústicas. Con un espesor de 10 mm, este material proporciona una estructur...',
  'Esta lámina acústica de polietileno reticulado de Distands es una solución de aislamiento de nivel superior, diseñada específicamente para mitigar el ruido de impacto en suelos y forjados de edificios con altas exigencias acústicas. Con un espesor de 10 mm, este material proporciona una estructuración interna elástica que funciona como un amortiguador de alto rendimiento en sistemas de masa-resorte-masa. Es la opción ideal para proyectos en viviendas, hoteles y centros comerciales donde se busca la máxima eficiencia sin comprometer excesivamente la altura útil de las estancias. Datos Generales El producto de Distands destaca por ofrecer rendimientos acústicos excepcionales, logrando reducciones significativas tanto en ruido aéreo como de impacto en forjados. Es altamente recomendado para su integración en sistemas de calefacción radiante, ya que su excelente conductividad térmica permite atenuar frecuencias bajas, medias y altas de forma eficaz. Además, es un material comprometido con la sostenibilidad, fabricado con un 5% de materia prima reciclada y certificado con la clase A+ en emisiones al aire interior, lo que garantiza un ambiente saludable y seguro.',
