INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '098224c8-932a-42db-8f39-0212f94f467c',
  'Espuma Sundis 10MM',
  'espuma-sundis-20mm-2',
  'La espuma Sundis 10 mm es una base amortiguadora de alto rendimiento, diseñada para instalarse bajo superficies de césped artificial, especialmente en áreas deportivas, zonas infantiles y espacios que requieren mayor seguridad ante impactos. Fabricada con material europeo 100 % certificado, esta ...',
  'La espuma Sundis 10 mm es una base amortiguadora de alto rendimiento, diseñada para instalarse bajo superficies de césped artificial, especialmente en áreas deportivas, zonas infantiles y espacios que requieren mayor seguridad ante impactos. Fabricada con material europeo 100 % certificado, esta espuma garantiza excelente absorción de impactos, resistencia a la compresión y drenaje rápido del agua, lo que la convierte en una solución duradera, estable y segura para proyectos exteriores. Rollo: 25 ml x 2 m de ancho Precio indicado por metro cuadrado. Esta espuma se vende en rollos completos. Los cortes no admiten devoluciones. Para medidas personalizadas, escríbenos a: ventas@disstands.com',
