INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '0cbe3cd2-ada6-4f29-8a59-10e1c6abefc0',
  'Fieltro Sintético Disstands 200g/m²',
  'fieltro-sintetico-disstands-200g-m%c2%b2',
  'Este fieltro sintético de Disstands representa una solución de alto rendimiento en el sector de las telas sin tejer, diseñada específicamente para proyectos que demandan una durabilidad extrema y un acabado visual impecable. Gracias a nuestro avanzado proceso de tintura industrial, el material of...',
  'Este fieltro sintético de Disstands representa una solución de alto rendimiento en el sector de las telas sin tejer, diseñada específicamente para proyectos que demandan una durabilidad extrema y un acabado visual impecable. Gracias a nuestro avanzado proceso de tintura industrial, el material ofrece una resistencia superior y una fijación de color excepcional frente a la exposición lumínica, el frote mecánico, el lavado y el planchado intenso. Su versatilidad técnica lo convierte en el aliado perfecto para aplicaciones industriales, corporativas y decorativas. Además de nuestra amplia gama de colores vivos y brillantes en stock, ofrecemos la posibilidad de fabricar colores personalizados bajo demanda, permitiendo una integración total con la identidad corporativa o los requisitos estéticos de cualquier proyecto exclusivo. La estructura del material permite la aplicación de múltiples tratamientos de impregnación y resinados, transformando un fieltro estándar en un componente técnico avanzado capaz de repeler líquidos, resistir el fuego o adherirse mediante calor, adaptándose con precisión a las exigencias más estrictas de cada cliente.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
