INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ab0f00b4-46d2-4068-8210-04e310d95568',
  'Fieltro Sintético Disstands 500g/m2',
  'fieltro-sintetico-3mm-500g',
  'Este fieltro sintético de Disstands, perteneciente a nuestra gama premium de 500 g/m², representa la cumbre de la resistencia y el cuerpo en telas sin tejer. Diseñado específicamente para proyectos que exigen un material con presencia estructural y durabilidad extrema, este fieltro de 3,00 mm de ...',
  'Este fieltro sintético de Disstands, perteneciente a nuestra gama premium de 500 g/m², representa la cumbre de la resistencia y el cuerpo en telas sin tejer. Diseñado específicamente para proyectos que exigen un material con presencia estructural y durabilidad extrema, este fieltro de 3,00 mm de grosor ofrece una densidad superior que lo hace ideal para aplicaciones donde los materiales convencionales no son suficientes. Su fabricación en 100% poliéster (PES) garantiza una base sólida, firme y con un acabado estético impecable. La excelencia de este material reside en su comportamiento bajo condiciones de uso intensivo. Gracias a un avanzado proceso de tintura industrial, el fieltro mantiene una solidez del color excepcional; ha sido testado para resistir la exposición prolongada a la luz artificial sin perder viveza (Grado 6 Blue Scale), así como para soportar el frote, el lavado comercial y el planchado a altas temperaturas sin degradación cromática (Grados 4-5 Grey Scale). Además, su estabilidad dimensional es sobresaliente, con una variación máxima de apenas el 1% incluso sometido a 60°C, lo que asegura una instalación perfecta y duradera en cualquier entorno profesional. Es un producto extremadamente versátil, capaz de transformarse según las necesidades del cliente. Más allá de su uso en bordados de alta gama, decoración técnica y artesanía industrial, este fieltro puede ser potenciado mediante impregnaciones especiales. En Disstands podemos convertir este material en una herramienta técnica avanzada mediante tratamientos ignífugos para máxima seguridad, acabados hidrófugos o la aplicación de polvos termofusibles para un pegado industrial eficiente.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
