INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '662da7dd-dabe-4456-88e8-27470f442350',
  'Fieltro Sintético Disstands 800g/m2',
  'fieltro-sintetico-5mm-800g-disstands',
  'Este fieltro sintético de Disstands, con un gramaje de 800 g/m², es el exponente máximo de nuestra serie técnica en cuanto a densidad, grosor y resistencia mecánica. Con un espesor nominal de 5,00 mm, este material está diseñado para proyectos de ingeniería textil, arquitectura efímera y decoraci...',
  'Este fieltro sintético de Disstands, con un gramaje de 800 g/m², es el exponente máximo de nuestra serie técnica en cuanto a densidad, grosor y resistencia mecánica. Con un espesor nominal de 5,00 mm, este material está diseñado para proyectos de ingeniería textil, arquitectura efímera y decoración de alto impacto que requieren una estructura autoportante o una capacidad de absorción y protección superior. Fabricado íntegramente en 100% poliéster (PES), su robustez no compromete un acabado visual de lujo, ofreciendo una superficie de alta calidad y tacto firme. La tecnología de tintura aplicada a esta gama asegura una solidez del color excepcional, alcanzando un grado 6 en la escala de azules para luz artificial y grados 4-5 para frote, lavado y planchado, lo que garantiza que el material mantenga su apariencia original incluso en las condiciones de uso más severas. Además, su estabilidad dimensional es sobresaliente, manteniendo su forma con una variación máxima del 1% bajo estrés térmico de hasta 60°C. Este fieltro de 800 g/m² es una herramienta de personalización ilimitada para el profesional. En Disstands, podemos potenciar sus propiedades mediante la aplicación de polvos termofusibles (APP) para su adhesión por calor, tratamientos ignífugos para el cumplimiento de normativas de seguridad, o acabados hidrófugos y oleófugos que repelen agua y aceites. Es, sin duda, la opción más fiable para aplicaciones industriales de precisión y diseño contract de alta exigencia.',
  'c42678e9-5c77-43a2-893e-5d1814df247f',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
