INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '051d1902-4878-412c-8791-17c4262ad48d',
  'Suelo SPC Disstands Easy Invisible 5.5mm | Madera Real 100% Hidrófugo',
  'suelo-parquet-click',
  'El suelo EASY representa la evolución definitiva en pavimentos de interior, combinando la belleza atemporal de la madera natural con la ingeniería de materiales más avanzada del mercado. Este suelo de núcleo rígido (Stone Plastic Composite) ha sido diseñado para quienes buscan un acabado estético...',
  'El suelo EASY representa la evolución definitiva en pavimentos de interior, combinando la belleza atemporal de la madera natural con la ingeniería de materiales más avanzada del mercado. Este suelo de núcleo rígido (Stone Plastic Composite) ha sido diseñado para quienes buscan un acabado estético de lujo sin las complicaciones de mantenimiento de la madera real. Gracias a su tecnología de acabado sincronizado, la veta que ves es la que sientes al tacto, proporcionando una textura ultra mate que elimina reflejos artificiales y realza el realismo en cada lama. A diferencia de los laminados convencionales, el modelo es 100% resistente al agua e hidrófugo, lo que permite unificar el diseño de toda la vivienda, incluyendo estancias críticas como cocinas y baños, sin miedo a hinchamientos o filtraciones. Su estructura de alta densidad (2.000 kg/m3) y su espesor de 5,5 mm le confieren una estabilidad dimensional sin precedentes; esto permite instalar superficies de hasta 400 m2 sin necesidad de antiestéticas juntas de dilatación, logrando espacios diáfanos, continuos y visualmente más amplios. Pensado para una vida sin preocupaciones, este suelo SPC integra una capa de uso de alta resistencia que protege el diseño contra impactos de objetos caídos, arañazos de mascotas y manchas difíciles. Además, su compromiso con el confort es total: incorpora una base HD aislante de 1 mm que no solo facilita la pisada, sino que actúa como una barrera térmica y acústica eficiente, reduciendo significativamente el ruido ambiental y de impacto. Es la solución perfecta para proyectos de reforma rápida gracias a su sistema de instalación Click VILOX 2G, que garantiza un encaje hermético y duradero en tiempo récord.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
  price_per_m2 = EXCLUDED.price_per_m2,
  featured = EXCLUDED.featured,
  badge = EXCLUDED.badge;

INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'e3c3b6b9-c510-449f-87fa-cb1c3133f996',
  'Suelo SPC Disstands Easy Natural | Madera Real 5.5mm Hidrófugo',
  'suelo-spc-disstands-easy-natural-madera-real-5-5mm-hidrofugo',
  'El suelo Disstands SPC de la colección EASY (Referencia: Natural) es la solución definitiva para quienes buscan la calidez orgánica de la madera sin renunciar a las prestaciones de un pavimento de última generación. Este modelo destaca por su textura ultra mate y acabado sincronizado, una tecnolo...',
  'El suelo Disstands SPC de la colección EASY (Referencia: Natural) es la solución definitiva para quienes buscan la calidez orgánica de la madera sin renunciar a las prestaciones de un pavimento de última generación. Este modelo destaca por su textura ultra mate y acabado sincronizado, una tecnología que alinea la veta visual con el relieve táctil para ofrecer una experiencia de realismo absoluto. Su diseño está pensado para integrarse en cualquier espacio, aportando una estética natural que se mantiene inalterable con el paso del tiempo gracias a su alta resistencia al desgaste y a los impactos. Al ser un material 100 % resistente al agua e hidrófugo, el modelo Natural es apto para todas las estancias de la vivienda o local comercial, eliminando las barreras visuales entre salones, cocinas y baños. Su núcleo rígido mineral de alta densidad (2.000 kg/m³) le otorga una estabilidad dimensional excepcional, lo que permite realizar instalaciones de grandes dimensiones - hasta 400 m² sin juntas de dilatación, favoreciendo un diseño continuo y moderno. La experiencia de uso se ve potenciada por su base HD aislante de 1 mm incorporada, que garantiza un confort acústico superior y una pisada confortable. Además, su sistema de instalación Click VILOX 2G permite un montaje rápido, limpio y extremadamente resistente, asegurando que las lamas permanezcan perfectamente unidas ante el tránsito intenso.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
