INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '904f9b85-db77-4d3d-82ab-1e876b59e555',
  'Disstands SPC de la colección EASY (Referencia: MIEL)',
  'suelo-spc-disstands-easy-miel',
  'El suelo Disstands SPC de la colección EASY (Referencia: MIEL) es la máxima expresión de calidez y realismo en pavimentos de núcleo rígido. Diseñado para transformar cualquier ambiente en un espacio acogedor, este modelo captura la esencia cromática de la madera natural en tonos miel, aportando u...',
  'El suelo Disstands SPC de la colección EASY (Referencia: MIEL) es la máxima expresión de calidez y realismo en pavimentos de núcleo rígido. Diseñado para transformar cualquier ambiente en un espacio acogedor, este modelo captura la esencia cromática de la madera natural en tonos miel, aportando una luminosidad y elegancia incomparables. Su textura ultra mate y acabado sincronizado garantizan que el relieve del material coincida exactamente con el dibujo de la veta , ofreciendo una experiencia sensorial idéntica a la madera real pero con las ventajas técnicas de un material de vanguardia. Como solución 100% resistente al agua e hidrófuga, la referencia MIEL permite unificar el diseño de todo el proyecto, desde salones y dormitorios hasta zonas húmedas como cocinas y baños, sin riesgo de deterioro. Su estructura de alta densidad de 2.000 kg/m³ y su espesor de 5,5 mm proporcionan una estabilidad dimensional excepcional. Esto permite realizar instalaciones diáfanas de hasta 400 m² sin juntas de dilatación, creando superficies continuas y elegantes que amplían visualmente el espacio. El bienestar del usuario está garantizado gracias a la base HD aislante de 1 mm incorporada , que actúa como una barrera acústica y térmica eficiente, suavizando la pisada y reduciendo el ruido ambiental. Su sistema de instalación Click VILOX 2G asegura un montaje rápido, seguro y con una unión entre lamas extremadamente duradera.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
