INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '3106874a-73e5-4278-839c-a7cd7b3e97dd',
  'SPC Disstands Colección EASY (Ref. AVELLANA)',
  'suelo-spc-disstands-easy-avellana',
  'El suelo Disstands SPC de la colección EASY (Referencia: AVELLANA) es la solución definitiva para quienes buscan la calidez orgánica de la madera tradicional combinada con la tecnología más avanzada en pavimentos de núcleo rígido. Este modelo destaca por su tono equilibrado y acogedor, que junto ...',
  'El suelo Disstands SPC de la colección EASY (Referencia: AVELLANA) es la solución definitiva para quienes buscan la calidez orgánica de la madera tradicional combinada con la tecnología más avanzada en pavimentos de núcleo rígido. Este modelo destaca por su tono equilibrado y acogedor, que junto a su textura ultra mate y acabado sincronizado, logra una reproducción fiel de la madera real tanto a la vista como al tacto. Gracias a su tecnología de fabricación, la veta que se percibe visualmente coincide con el relieve de la superficie, eliminando los brillos artificiales y elevando el estándar estético de cualquier proyecto de interiorismo. Al ser un material 100% resistente al agua e hidrófugo, la referencia AVELLANA permite una continuidad decorativa total en todo el hogar o local comercial, eliminando las juntas de transición entre salones, cocinas y baños. Su núcleo rígido mineral de alta densidad (2.000 kg/m³) y un espesor de 5,5 mm garantizan una estabilidad dimensional superior, incluso ante variaciones térmicas extremas de hasta 80°C. Esta robustez técnica permite realizar instalaciones de grandes dimensiones, cubriendo superficies de hasta 400 m² (20x20 metros) sin necesidad de juntas de dilatación, lo que favorece un diseño fluido, moderno y visualmente más amplio. La experiencia de uso se ve potenciada por la base HD aislante de 1 mm integrada, que actúa como una barrera térmica y acústica eficiente, reduciendo el ruido de impacto y proporcionando una pisada confortable y silenciosa. Equipado con el sistema de instalación Click VILOX 2G, este suelo asegura un montaje rápido, limpio y un encaje hermético de alta resistencia (180N), ideal tanto para reformas rápidas como para obras nuevas de alta exigencia',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
