INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'fad64c12-3a13-4d62-8704-3f3c3e50efd1',
  'Suelo Laminado Disstands Plus 5 AC5 Clase 33 – Acabado Sky 8mm',
  'suelo-laminado-disstands-plus-5-ac5',
  'El suelo laminado Disstands Plus 5 representa la excelencia en durabilidad y diseño para proyectos que requieren el máximo rendimiento. Perteneciente a la Clase 33 y con una resistencia a la abrasión AC5, este pavimento está específicamente diseñado para soportar el tránsito intenso tanto en ento...',
  'El suelo laminado Disstands Plus 5 representa la excelencia en durabilidad y diseño para proyectos que requieren el máximo rendimiento. Perteneciente a la Clase 33 y con una resistencia a la abrasión AC5, este pavimento está específicamente diseñado para soportar el tránsito intenso tanto en entornos residenciales exigentes como en locales comerciales de alta actividad. Características Principales Estética Avanzada: Su superficie con acabado Sky ofrece una estética sofisticada y moderna, elevando el valor visual de cualquier estancia. Bienestar y Seguridad: Gracias a su avanzada tecnología, el Disstands Plus 5 es resistente al agua y cuenta con una protección + Hygiene, lo que garantiza un entorno más limpio y saludable para su hogar o negocio. Construcción Robusta: Su estructura de 8 mm de grosor y núcleo de HDF de alta densidad proporciona una estabilidad dimensional superior. Alta Resistencia: Capable de resistir impactos severos y el uso continuado de sillas de ruedas sin sufrir daños. Garantía de Calidad: Con una garantía de 25 años para uso doméstico, es la inversión definitiva en confort y longevidad.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
