INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  '46dbef0e-d321-4f67-8543-7563dc4cced3',
  'Rodapié Espumado Blanco',
  'rodapie-espumado-blanco-hidrofugo-12cm',
  'El Rodapié Espumado Blanco representa la nueva generación de acabados para suelos, diseñado específicamente para ofrecer una resistencia inigualable en las zonas más críticas del hogar. Fabricado con la avanzada tecnología Kerracore, este zócalo destaca por su estructura celular de alta densidad ...',
  'El Rodapié Espumado Blanco representa la nueva generación de acabados para suelos, diseñado específicamente para ofrecer una resistencia inigualable en las zonas más críticas del hogar. Fabricado con la avanzada tecnología Kerracore, este zócalo destaca por su estructura celular de alta densidad que lo convierte en el producto más resistente a los golpes según nuestros tests comparativos. Su acabado en blanco puro no solo aporta una estética minimalista y moderna que combina con cualquier tipo de pavimento, sino que además ofrece la versatilidad de ser un material totalmente pintable, permitiendo una personalización absoluta según el diseño de sus espacios. A diferencia de los rodapiés de madera tradicionales o MDF, este zócalo es 100% resistente al agua e hidrófugo, lo que lo hace ideal para estancias con presencia de humedad como cocinas y baños, garantizando que no se hinche ni se deteriore con el tiempo. Además de su durabilidad física, este producto destaca por su seguridad al ser ignífugo y no propagar las llamas, aportando una protección extra a su vivienda. Su compromiso con el medio ambiente es sólido, ya que está fabricado con un 80% de materiales reciclados, convirtiéndolo en una elección responsable y sostenible.',
  'f4ae9001-32d7-44cf-8ce5-c62c1826f3fc',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  description_long = EXCLUDED.description_long,
  category_id = EXCLUDED.category_id,
