INSERT INTO public.products (id, name, slug, description, description_long, category_id, price_per_m2, min_m2, unit, featured, active, badge)
VALUES (
  'ced50c08-8218-41cd-8ded-e81a47b6d0e0',
  'Moqueta Compredis',
  'compredis-moqueta-contract-monocromatica',
  'Compredis es un pavimento textil monocromático diseñado para espacios contract de alto tráfico, donde el confort y la durabilidad deben ir de la mano. Define los interiores con una elegancia sutil, aportando calidez y personalidad. Disponible en 19 tonalidades vibrantes, combina una estructura só...',
  'Compredis es un pavimento textil monocromático diseñado para espacios contract de alto tráfico, donde el confort y la durabilidad deben ir de la mano. Define los interiores con una elegancia sutil, aportando calidez y personalidad. Disponible en 19 tonalidades vibrantes, combina una estructura sólida con una superficie suave, ofreciendo un resultado que fusiona funcionalidad y estilo sin concesiones. Su construcción tufting de terciopelo cortado en galga 1/10" emplea fibra 100% poliamida 6, un material reconocido por su extraordinaria resistencia a la abrasión, su capacidad de recuperación ante el aplastamiento y su facilidad de mantenimiento. La poliamida 6 es una de las fibras más utilizadas en el sector contract precisamente por mantener su apariencia original durante años, incluso en zonas sometidas a tráfico intenso y continuado. Con una densidad de aproximadamente 197.500 puntos por m², Compredis presenta una superficie uniforme y compacta que distribuye el desgaste de forma homogénea. La altura de pelo de 5,2 mm ofrece una pisada agradable y acogedora sin comprometer la estabilidad del pavimento, mientras que su peso de fibra de 770 g/m² y un peso total de 1.800 g/m² reflejan la solidez de una moqueta pensada para el largo plazo. El respaldo de yute sintético aporta estabilidad dimensional y resistencia a la humedad, evitando deformaciones y garantizando una instalación firme sobre el sustrato. Este tipo de backing es especialmente adecuado para instalaciones encoladas en entornos comerciales donde se requiere una base fiable y duradera. Compredis incorpora el tratamiento antimanchas Stainadverse, una protección que facilita la limpieza de derrames y reduce la adherencia de la suciedad a las fibras. Este tratamiento no solo simplifica el mantenimiento diario, sino que prolonga la vida útil del pavimento al mantener las fibras libres de partículas abrasivas que aceleran el desgaste. En cuanto a prestaciones técnicas, Compredis alcanza una clasificación de reacción al fuego Bfl-s1, el estándar exigido en la mayoría de proyectos contract, hospitality y espacios públicos en Europa. Su aislamiento acústico de 28 dB (ΔLw) contribuye significativamente a la reducción del ruido de impacto entre plantas, un factor clave en hoteles, oficinas y entornos donde el confort acústico influye directamente en la experiencia del usuario. La absorción acústica (αw) de 0,20 complementa esta capacidad atenuando la reverberación dentro del propio espacio. La resistencia térmica de ≤ 0,17 m² K/W garantiza la compatibilidad con sistemas de suelo radiante, permitiendo una transmisión eficiente del calor sin comprometer el rendimiento de la instalación. La solidez del color a la luz (≥ 5) asegura que las tonalidades se mantengan estables frente a la exposición solar prolongada, un aspecto especialmente relevante en espacios con grandes superficies acristaladas. Con una clasificación de emisiones interiores A+ y su condición de producto reciclable, Compredis responde a las exigencias medioambientales y de calidad del aire interior que marcan los estándares actuales de construcción sostenible. La tensión corporal en marcha (≤ 2 kV) garantiza además la seguridad antiestática, evitando descargas molestas en espacios con equipamiento electrónico. Presentada en rollos de 400 cm de ancho, Compredis permite cubrir grandes superficies minimizando juntas y optimizando la instalación. Es una solución completa para interioristas, arquitectos y gestores de espacios que buscan un pavimento textil con carácter visual, rendimiento técnico contrastado y compromiso medioambiental.',
  '29a95ca6-6541-4c84-800f-fa51cbc294bf',
  NULL,
  1,
  'm²',
  false,
  true,
  NULL
) ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
